    def _story_metadata_payload(self, asset: dict[str, Any]) -> dict[str, Any]:
        generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(generation, dict):
            return {}
        meta = generation.get("storyIntent") or generation.get("story_intent") or generation.get("storyMetadata") or generation.get("story_metadata") or {}
        return meta if isinstance(meta, dict) else {}

    def _story_intent_value(self, asset: dict[str, Any]) -> str | None:
        meta = self._story_metadata_payload(asset)
        return self._normalize_story_enum(asset.get("story_intent") or meta.get("storyIntent") or meta.get("story_intent"), STORY_INTENTS)

    def _story_goal_value(self, asset: dict[str, Any]) -> str | None:
        meta = self._story_metadata_payload(asset)
        return self._normalize_story_enum(asset.get("story_goal") or meta.get("storyGoal") or meta.get("story_goal"), STORY_GOALS)

    def _story_style_value(self, asset: dict[str, Any]) -> str | None:
        meta = self._story_metadata_payload(asset)
        return self._normalize_story_enum(asset.get("story_style") or meta.get("storyStyle") or meta.get("story_style"), STORY_STYLES)

    def _normalize_story_enum(self, value: Any, allowed: set[str]) -> str | None:
        normalized = str(value or "").strip().lower().replace("-", "_").replace(" ", "_")
        return normalized if normalized in allowed else None

    def story_quality_gate_v1(self, rendered_asset_id: str) -> dict[str, Any]:
        asset = self.rendered_asset(rendered_asset_id)
        return self._story_quality_gate_for_asset(asset)

    def story_quality_report(
        self,
        *,
        creator: str,
        campaign_slug: str | None = None,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        inventory = self._build_surface_inventory(creator=creator_label, campaign_slug=campaign_slug)
        assets = inventory["assetsBySurface"].get("story") or []
        results = [self._story_quality_gate_for_asset(asset) for asset in assets]
        failures = sorted({
            reason
            for result in results
            for reason in result.get("failureReasons") or []
        })
        passed = sum(1 for result in results if result.get("story_quality_gate_passed"))
        return {
            "schema": "campaign_factory.story_quality_report.v1",
            "creator": creator_label,
            "campaign": slugify(campaign_slug) if campaign_slug else None,
            "storyAssetsAnalyzed": len(results),
            "passed": passed,
            "failed": len(results) - passed,
            "failureReasons": failures,
            "assets": results,
            "wouldWrite": False,
        }

    def _story_quality_gate_for_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        surface = normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface"))
        media_path = Path(str(asset.get("campaign_path") or asset.get("output_path") or ""))
        media_type = str(asset.get("media_type") or media_type_for_path(media_path)).lower()
        failures: list[str] = []
        warnings: list[str] = []
        if surface != "story":
            failures.append("not_story_surface")
        shape = probe_image_shape(media_path) if media_type == "image" else probe_video_shape(media_path)
        width = int((shape or {}).get("effectiveWidth") or (shape or {}).get("width") or 0)
        height = int((shape or {}).get("effectiveHeight") or (shape or {}).get("height") or 0)
        aspect = (width / height) if width and height else None
        geometry_passed = bool(width and height and abs((aspect or 0) - (9 / 16)) <= 0.0025 and width >= 1080 and height >= 1920)
        if not width or not height:
            failures.append("unknown_aspect_ratio")
        elif abs((aspect or 0) - (9 / 16)) > 0.0025:
            failures.append("invalid_story_aspect_ratio")
        elif width < 1080 or height < 1920:
            failures.append("low_resolution_story")
        black_bar_check = self._story_black_bar_check(media_path, media_type=media_type)
        if black_bar_check.get("blackBarsDetected"):
            failures.append("black_bars")
        if black_bar_check.get("warning"):
            warnings.append(str(black_bar_check["warning"]))
        quality = self._story_quality_metadata(asset)
        safe_zone_score = self._bounded_score(quality.get("story_safe_zone_score") or quality.get("storySafeZoneScore"), default=100)
        focal_score = self._bounded_score(quality.get("story_focal_safety_score") or quality.get("storyFocalSafetyScore"), default=100)
        text_score = self._bounded_score(quality.get("story_text_readability_score") or quality.get("storyTextReadabilityScore"), default=100)
        contains_text = self._truthy(quality.get("containsRenderedText") or quality.get("contains_rendered_text"))
        focal_reason = str(quality.get("focalFailureReason") or quality.get("focal_failure_reason") or "focal_safety_violation").strip()
        if safe_zone_score < 95:
            failures.append("safe_zone_violation")
        if focal_score < 95:
            failures.append(focal_reason or "focal_safety_violation")
        if contains_text and text_score < 95:
            failures.append("text_hidden")
        source_blockers = self._story_existing_asset_source_blockers(asset)
        failures.extend(source_blockers)
        no_text_check = self._story_no_text_check(media_path, media_type=media_type, quality=quality)
        if no_text_check["required"] and not no_text_check["passed"]:
            failures.append(no_text_check.get("failureReason") or "story_no_text_violation")
        failures = sorted(set(failures))
        return {
            "schema": "campaign_factory.story_quality_gate_v1",
            "assetId": asset.get("id"),
            "contentSurface": surface,
            "mediaType": media_type,
            "story_quality_gate_passed": not failures,
            "storyQualityGatePassed": not failures,
            "geometry": {
                "width": width,
                "height": height,
                "aspectRatio": aspect,
                "targetResolution": "1080x1920",
                "passed": geometry_passed,
            },
            "storyBlackBarCheck": black_bar_check,
            "story_safe_zone_score": safe_zone_score,
            "story_focal_safety_score": focal_score,
            "story_text_readability_score": text_score,
            "sourceLineageBlockers": source_blockers,
            "storySourceNative": not source_blockers,
            "storyNoTextRequired": no_text_check["required"],
            "storyNoTextPassed": no_text_check["passed"],
            "storyNoTextCheck": no_text_check,
            "visualQualityStatus": "passed" if not failures else "rejected",
            "failureReasons": failures,
            "warnings": sorted(set(warnings)),
            "wouldWrite": False,
        }

    def _story_quality_metadata(self, asset: dict[str, Any]) -> dict[str, Any]:
        generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(generation, dict):
            return {}
        quality = generation.get("storyQuality") or generation.get("story_quality") or {}
        return quality if isinstance(quality, dict) else {}

    def _bounded_score(self, value: Any, *, default: int) -> int:
        try:
            return max(0, min(100, int(value)))
        except (TypeError, ValueError):
            return default

    def _story_black_bar_check(self, media_path: Path, *, media_type: str) -> dict[str, Any]:
        if media_type != "image":
            return {
                "blackBarsDetected": False,
                "top": False,
                "bottom": False,
                "left": False,
                "right": False,
                "warning": "black_bar_pixel_check_only_available_for_images",
            }
        pixels = read_png_rgb_pixels(media_path)
        if not pixels.get("ok"):
            return {
                "blackBarsDetected": False,
                "top": False,
                "bottom": False,
                "left": False,
                "right": False,
                "warning": f"black_bar_pixel_check_unavailable:{pixels.get('error')}",
            }
        rows = pixels["pixels"]
        height = int(pixels["height"])
        width = int(pixels["width"])
        band_h = max(1, height // 12)
        band_w = max(1, width // 12)
        result = {
            "top": self._pixel_region_black(rows, x0=0, x1=width, y0=0, y1=band_h),
            "bottom": self._pixel_region_black(rows, x0=0, x1=width, y0=height - band_h, y1=height),
            "left": self._pixel_region_black(rows, x0=0, x1=band_w, y0=0, y1=height),
            "right": self._pixel_region_black(rows, x0=width - band_w, x1=width, y0=0, y1=height),
        }
        result["blackBarsDetected"] = any(result.values())
        return result

    def _story_no_text_check(self, media_path: Path, *, media_type: str, quality: dict[str, Any]) -> dict[str, Any]:
        required = self._truthy(
            quality.get("storyNoTextRequired")
            or quality.get("story_no_text_required")
            or quality.get("noWordsRequired")
            or quality.get("no_words_required")
        )
        if not required:
            return {
                "required": False,
                "passed": True,
                "detectedText": [],
                "checkedFrames": 0,
                "engine": "not_required",
            }
        if not media_path.exists():
            return {
                "required": True,
                "passed": False,
                "detectedText": [],
                "checkedFrames": 0,
                "engine": "tesseract",
                "error": "media_file_missing",
                "failureReason": "story_no_text_check_unavailable",
            }
        tesseract = shutil.which("tesseract")
        if not tesseract:
            return {
                "required": True,
                "passed": False,
                "detectedText": [],
                "checkedFrames": 0,
                "engine": "tesseract",
                "error": "tesseract_missing",
                "failureReason": "story_no_text_check_unavailable",
            }
        frames = self._story_ocr_frame_paths(media_path, media_type=media_type)
        if not frames:
            return {
                "required": True,
                "passed": False,
                "detectedText": [],
                "checkedFrames": 0,
                "engine": "tesseract",
                "error": "frame_extraction_failed",
                "failureReason": "story_no_text_check_unavailable",
            }
        detected: list[dict[str, Any]] = []
        try:
            for index, frame in enumerate(frames):
                detected.extend(self._story_ocr_detect_text(frame, frame_index=index))
        finally:
            for frame in frames:
                if frame != media_path:
                    try:
                        frame.unlink(missing_ok=True)
                    except OSError:
                        pass
        return {
            "required": True,
            "passed": not detected,
            "detectedText": detected,
            "checkedFrames": len(frames),
            "engine": "tesseract",
            "failureReason": "story_no_text_violation" if detected else "",
        }

    def _story_ocr_frame_paths(self, media_path: Path, *, media_type: str) -> list[Path]:
        if media_type == "image":
            return [media_path]
        if media_type != "video":
            return []
        ffmpeg = shutil.which("ffmpeg")
        if not ffmpeg:
            return []
        tmpdir = Path(tempfile.mkdtemp(prefix="story_ocr_"))
        frames: list[Path] = []
        for index, offset in enumerate((0, 1, 2)):
            frame = tmpdir / f"frame_{index}.png"
            result = subprocess.run(
                [ffmpeg, "-y", "-ss", str(offset), "-i", str(media_path), "-frames:v", "1", "-vf", "scale=1080:-1", str(frame)],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                check=False,
                timeout=20,
            )
            if result.returncode == 0 and frame.exists():
                frames.append(frame)
        return frames

    def _story_ocr_detect_text(self, image_path: Path, *, frame_index: int) -> list[dict[str, Any]]:
        result = subprocess.run(
            ["tesseract", str(image_path), "stdout", "--psm", "6", "tsv"],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=False,
            timeout=20,
        )
        if result.returncode != 0:
            return []
        detected: list[dict[str, Any]] = []
        for line in result.stdout.splitlines()[1:]:
            columns = line.split("\t")
            if len(columns) < 12:
                continue
            text = columns[11].strip()
            if not re.search(r"[A-Za-z0-9]{3,}", text):
                continue
            try:
                confidence = float(columns[10])
            except ValueError:
                confidence = 0.0
            if confidence >= 45:
                detected.append({"text": text, "confidence": confidence, "frameIndex": frame_index})
        return detected

    def _pixel_region_black(self, rows: list[list[tuple[int, int, int]]], *, x0: int, x1: int, y0: int, y1: int) -> bool:
        total = 0
        black = 0
        step_y = max(1, (y1 - y0) // 64)
        step_x = max(1, (x1 - x0) // 64)
        for y in range(max(0, y0), min(len(rows), y1), step_y):
            row = rows[y]
            for x in range(max(0, x0), min(len(row), x1), step_x):
                total += 1
                r, g, b = row[x]
                if r <= 8 and g <= 8 and b <= 8:
                    black += 1
        return bool(total and black / total >= 0.95)

    def story_gap_report(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        needs = self.creator_content_needs(creator=creator_label, date=date)
        inventory = self.story_inventory_report(creator=creator_label)
        accounts = []
        needs_story = 0
        satisfied = 0
        blocked = 0
        for account in needs.get("accounts") or []:
            story_obligations = [
                obligation for obligation in account.get("obligations") or []
                if obligation.get("surface") == "story"
            ]
            if not story_obligations:
                continue
            required = sum(int(item.get("required") or 0) for item in story_obligations)
            remaining = sum(int(item.get("remaining") or 0) for item in story_obligations)
            needed = remaining > 0
            is_satisfied = required > 0 and not needed
            is_blocked = needed and int(inventory.get("storyAssetsScheduleSafe") or 0) == 0
            needs_story += 1 if needed else 0
            satisfied += 1 if is_satisfied else 0
            blocked += 1 if is_blocked else 0
            accounts.append({
                "accountId": account.get("accountId"),
                "account": account.get("account"),
                "instagramAccountId": account.get("instagramAccountId"),
                "storyNeededToday": needed,
                "required": required,
                "remaining": remaining,
                "blocked": is_blocked,
                "blockedReason": "story_inventory_missing" if is_blocked else "",
                "wouldWrite": False,
            })
        return {
            "schema": "campaign_factory.story_gap_report.v1",
            "creator": creator_label,
            "date": datetime.fromisoformat(date).date().isoformat(),
            "accountsAnalyzed": len(accounts),
            "needsStoryToday": needs_story,
            "alreadySatisfied": satisfied,
            "blocked": blocked,
            "accounts": accounts,
            "wouldWrite": False,
        }

    def account_story_status(
        self,
        *,
        account_id: str,
        creator: str | None = None,
        date: str,
    ) -> dict[str, Any]:
        needs = self.account_content_needs(account_id=account_id, creator=creator, date=date)
        story_obligations = [
            item for item in needs.get("obligations") or []
            if item.get("surface") == "story"
        ]
        required = sum(int(item.get("required") or 0) for item in story_obligations)
        remaining = sum(int(item.get("remaining") or 0) for item in story_obligations)
        cadence = story_obligations[0].get("cadence") if story_obligations else None
        target_date = datetime.fromisoformat(date).date()
        last_story = self._last_surface_posted_at(
            account_id=needs.get("accountId") or account_id,
            instagram_account_id=needs.get("instagramAccountId"),
            surface="story",
            before_date=target_date + timedelta(days=1),
        )
        hours_since = None
        if last_story:
            try:
                reference = datetime.combine(target_date + timedelta(days=1), datetime_time.min, tzinfo=timezone.utc)
                posted = datetime.fromisoformat(last_story.replace("Z", "+00:00"))
                if posted.tzinfo is None:
                    posted = posted.replace(tzinfo=timezone.utc)
                hours_since = round((reference - posted).total_seconds() / 3600, 2)
            except ValueError:
                hours_since = None
        story_needed = remaining > 0
        if not story_obligations:
            status = "no_story_requirement"
        elif story_needed:
            status = "needs_story"
        else:
            status = "satisfied"
        return {
            "schema": "campaign_factory.account_story_status.v1",
            "creator": needs.get("creator"),
            "date": needs.get("date"),
            "accountId": needs.get("accountId"),
            "account": needs.get("account"),
            "instagramAccountId": needs.get("instagramAccountId"),
            "storyNeededToday": story_needed,
            "lastStoryPostedAt": last_story,
            "hoursSinceStory": hours_since,
            "storyCadence": cadence,
            "required": required,
            "remaining": remaining,
            "status": status,
            "wouldWrite": False,
        }

    def creator_story_summary(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        gap = self.story_gap_report(creator=creator_label, date=date)
        inventory = self.story_inventory_report(creator=creator_label)
        available = int(inventory.get("storyAssetsScheduleSafe") or 0)
        shortfall = max(0, int(gap.get("needsStoryToday") or 0) - available)
        return {
            "schema": "campaign_factory.creator_story_summary.v1",
            "creator": creator_label,
            "date": datetime.fromisoformat(date).date().isoformat(),
            "accounts": int(gap.get("accountsAnalyzed") or 0),
            "needsStoryToday": int(gap.get("needsStoryToday") or 0),
            "alreadySatisfied": int(gap.get("alreadySatisfied") or 0),
            "blocked": int(gap.get("blocked") or 0),
            "storyInventoryAvailable": available,
            "storyInventoryShortfall": shortfall,
            "storyReadiness": "ready" if shortfall == 0 else "blocked",
            "storyPublishingEnabled": False,
            "wouldWrite": False,
        }

    def creator_os_account_tiers(
        self,
        *,
        creator: str,
        threadsdash_report: dict[str, Any] | None = None,
        generated_at: str | None = None,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        report = threadsdash_report or {}
        accounts = [
            dict(item)
            for item in report.get("accounts") or []
            if isinstance(item, dict) and self._creator_label(item.get("creator") or creator_label) in {creator_label, "unknown"}
        ]
        health_report = self.creator_os_account_health_report(
            creator=creator_label,
            threadsdash_report=report,
            generated_at=generated_at,
        )
        health_by_account = {row["accountId"]: row for row in health_report.get("accounts") or []}
        rows = []
        for account in accounts:
            account_id = str(account.get("accountId") or account.get("id") or account.get("instagramAccountId") or "").strip()
            health = health_by_account.get(account_id) or self._creator_os_account_health_decision(account, missed=[])
            state = str(health.get("state") or "safe")
            tier = str(health.get("accountTier") or "normal")
            rows.append({
                "accountId": account_id,
                "username": account.get("username") or account.get("handle"),
                "creator": creator_label,
                "state": state,
                "tier": tier,
                "blockedReason": health.get("blockedReason") or "",
                "postingGuidance": health.get("postingGuidance") or self._creator_os_tier_posting_guidance(tier),
                "accountHealth": health,
                "wouldWrite": False,
            })
        return {
            "schema": "creator_os.account_tiers.v1",
            "generatedAt": generated_at or utc_now(),
            "creator": creator_label,
            "tierSummary": self._creator_os_account_tier_summary(rows, key="tier"),
            "accounts": rows,
            "wouldWrite": False,
            "inputs": {
                "threadsdashReportSchema": report.get("schema"),
            },
        }

    def creator_os_account_health_report(
        self,
        *,
        creator: str,
        threadsdash_report: dict[str, Any] | None = None,
        generated_at: str | None = None,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        report = threadsdash_report or {}
        accounts = [
            dict(item)
            for item in report.get("accounts") or []
            if isinstance(item, dict) and self._creator_label(item.get("creator") or creator_label) in {creator_label, "unknown"}
        ]
        missed_by_account: dict[str, list[dict[str, Any]]] = {}
        for missed in report.get("missedDispatches") or []:
            if not isinstance(missed, dict):
                continue
            account_id = str(missed.get("accountId") or missed.get("instagramAccountId") or missed.get("instagram_account_id") or "").strip()
            if account_id:
                missed_by_account.setdefault(account_id, []).append(missed)

        rows = []
        for account in accounts:
            account_id = str(account.get("accountId") or account.get("id") or account.get("instagramAccountId") or "").strip()
            rows.append(self._creator_os_account_health_decision(account, missed=missed_by_account.get(account_id, [])))

        summary = self._creator_os_account_health_summary(rows)
        return {
            "schema": "creator_os.account_health_report.v1",
            "generatedAt": generated_at or utc_now(),
            "creator": creator_label,
            "summary": summary,
            "accounts": rows,
            "wouldWrite": False,
            "inputs": {
                "threadsdashReportSchema": report.get("schema"),
                "missedDispatchCount": len(report.get("missedDispatches") or []),
            },
        }

    def creator_os_restricted_account_report(
        self,
        *,
        creator: str,
        threadsdash_report: dict[str, Any] | None = None,
        generated_at: str | None = None,
    ) -> dict[str, Any]:
        report = self.creator_os_account_health_report(
            creator=creator,
            threadsdash_report=threadsdash_report,
            generated_at=generated_at,
        )
        accounts = [
            row for row in report.get("accounts") or []
            if isinstance(row, dict) and (
                row.get("linkSharingRestricted")
                or (row.get("restrictionStatus") or {}).get("active")
                or row.get("recommendationEligibilityState") in {"limited", "not_recommended"}
            )
        ]
        return {
            "schema": "creator_os.restricted_account_report.v1",
            "generatedAt": report.get("generatedAt"),
            "creator": report.get("creator"),
            "restrictedAccounts": len(accounts),
            "accounts": accounts,
            "wouldWrite": False,
        }

