    def contentforge_visual_qc_failure_report(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        content_surface: str | None = "reel",
        lookback_days: int = 1,
        current_inventory: int | None = None,
        required_inventory: int = 225,
    ) -> dict[str, Any]:
        surface = normalize_content_surface(content_surface or "reel")
        assets = self._schedule_safe_production_assets(
            creator=creator,
            campaign_slug=campaign_slug,
            content_surface=surface,
            lookback_days=lookback_days,
        )
        variants = [asset for asset in assets if self._schedule_safe_is_variant_asset(asset)]
        failures = [
            self._contentforge_visual_qc_failure_for_asset(asset, surface)
            for asset in variants
        ]
        visual_failures = [failure for failure in failures if not failure["visualQcPassed"]]
        categories = self._contentforge_visual_qc_category_rows(visual_failures)
        ranked = sorted(
            categories,
            key=lambda row: (
                -int(row.get("estimatedInventoryGain") or 0),
                -int(row.get("count") or 0),
                int(row.get("estimatedOperatorMinutes") or 0),
                str(row.get("failureCategory") or ""),
            ),
        )
        top = ranked[0] if ranked else {
            "failureCategory": "",
            "count": 0,
            "repairable": False,
            "estimatedInventoryGain": 0,
        }
        top3 = [row["failureCategory"] for row in ranked[:3]]
        all_surface_assets = self._surface_report_assets(creator=creator, campaign_slug=campaign_slug)
        all_surface_assets = [
            asset for asset in all_surface_assets
            if normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")) == surface
        ]
        current = (
            int(current_inventory)
            if current_inventory is not None
            else sum(1 for item in self._build_surface_readiness(all_surface_assets) if item.get("canHandoff"))
        )
        top_gain = self._contentforge_visual_qc_recovered_inventory(visual_failures, [str(top.get("failureCategory") or "")])
        top3_gain = self._contentforge_visual_qc_recovered_inventory(visual_failures, top3)
        return {
            "schema": "creator_os.contentforge_visual_qc_failure_report.v1",
            "creator": creator,
            "campaign": campaign_slug,
            "contentSurface": surface,
            "lookbackDays": max(1, int(lookback_days or 1)),
            "freshProductionOnly": True,
            "variantsAnalyzed": len(variants),
            "visualQcPassed": len(variants) - len(visual_failures),
            "visualQcFailed": len(visual_failures),
            "failedVariants": visual_failures,
            "failureCategories": categories,
            "largestVisualQCLoss": {
                "largestFailureCategory": top.get("failureCategory") or "",
                "count": int(top.get("count") or 0),
                "repairable": bool(top.get("repairable")),
                "estimatedInventoryGain": int(top.get("estimatedInventoryGain") or 0),
            },
            "recoveryProjection": {
                "currentScheduleSafeAssets": current,
                "inventoryRecoveredIfTopVisualIssueFixed": top_gain,
                "inventoryRecoveredIfTop3VisualIssuesFixed": top3_gain,
                "requiredFor25Accounts": int(required_inventory),
                "remainingGap": max(0, int(required_inventory) - (current + top_gain)),
            },
            "mostImportantAnswer": self._contentforge_visual_qc_answer(top, len(visual_failures)),
            "wouldWrite": False,
        }

    def contentforge_visual_qc_waterfall(self, **kwargs: Any) -> dict[str, Any]:
        report = self.contentforge_visual_qc_failure_report(**kwargs)
        failed = list(report.get("failedVariants") or [])
        waterfall = {
            "variantsCreated": int(report.get("variantsAnalyzed") or 0),
            "visualQcPassed": int(report.get("visualQcPassed") or 0),
            "visualQcFailed": int(report.get("visualQcFailed") or 0),
            "operatorReviewRequired": sum(1 for item in failed if item.get("failureCategory") == "operator_visual_review_required"),
            "metadataFailures": sum(1 for item in failed if item.get("failureCategory") == "visual_metadata_missing"),
            "trueVisualFailures": sum(1 for item in failed if item.get("failureCategory") == "actual_visual_quality_failure"),
            "lineageFailures": sum(1 for item in failed if item.get("failureCategory") == "wrong_visual_lineage"),
            "captionPlacementFailures": sum(1 for item in failed if item.get("failureCategory") == "caption_placement_failure"),
        }
        return {
            "schema": "creator_os.contentforge_visual_qc_waterfall.v1",
            "creator": report.get("creator"),
            "contentSurface": report.get("contentSurface"),
            "lookbackDays": report.get("lookbackDays"),
            "waterfall": waterfall,
            "wouldWrite": False,
        }

