    def operator_inventory_review_batch_plan(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        content_surface: str | None = "reel",
        required_inventory: int = 225,
        current_inventory: int | None = None,
        target_unlock: int | None = None,
        max_batch_size: int | None = None,
    ) -> dict[str, Any]:
        unlock = self.multi_blocker_inventory_unlock_report(
            creator=creator,
            campaign_slug=campaign_slug,
            content_surface=content_surface,
            required_inventory=required_inventory,
            current_inventory=current_inventory,
        )
        shortfall = max(0, int(required_inventory) - int(unlock.get("currentScheduleSafeAssets") or 0))
        target = int(target_unlock) if target_unlock is not None else shortfall
        candidates = [
            self._operator_review_candidate_row(asset)
            for asset in unlock.get("blockedAssets") or []
            if self._operator_review_candidate_eligible(asset)
        ]
        candidates = sorted(
            candidates,
            key=lambda row: (
                -int(row.get("estimatedInventoryGain") or 0),
                int(row.get("estimatedOperatorMinutes") or 0),
                int(row.get("repairClassCount") or 0),
                str(row.get("assetId") or ""),
            ),
        )
        selected: list[dict[str, Any]] = []
        unlocked = 0
        for row in candidates:
            if max_batch_size is not None and len(selected) >= max(0, int(max_batch_size)):
                break
            if unlocked >= target:
                break
            selected.append(row)
            unlocked += int(row.get("estimatedInventoryGain") or 0)
        minutes = sum(int(row.get("estimatedOperatorMinutes") or 0) for row in selected)
        return {
            "schema": "creator_os.operator_inventory_review_batch_plan.v1",
            "creator": creator,
            "campaign": campaign_slug,
            "contentSurface": normalize_content_surface(content_surface or "reel"),
            "targetUnlock": target,
            "currentScheduleSafeAssets": int(unlock.get("currentScheduleSafeAssets") or 0),
            "requiredFor25Accounts": int(required_inventory),
            "shortfall": shortfall,
            "reviewCandidates": len(candidates),
            "recommendedReviewBatchSize": len(selected),
            "estimatedInventoryGain": unlocked,
            "estimatedOperatorMinutes": minutes,
            "wouldPass25GateAfterBatch": int(unlock.get("currentScheduleSafeAssets") or 0) + unlocked >= int(required_inventory),
            "remainingGapAfterBatch": max(0, int(required_inventory) - int(unlock.get("currentScheduleSafeAssets") or 0) - unlocked),
            "excludedRiskClasses": [
                "wrong_visual",
                "actual_visual_quality_failure",
                "wrong_visual_lineage",
                "aspect_ratio_failure",
                "duplicate_visual_failure",
                "audio_failure",
                "missing_burned_captions",
            ],
            "safeRepairsOnly": True,
            "reviewBatch": selected,
            "wouldWrite": False,
        }

    def operator_inventory_review_batch_summary(self, **kwargs: Any) -> dict[str, Any]:
        plan = self.operator_inventory_review_batch_plan(**kwargs)
        return {
            "schema": "creator_os.operator_inventory_review_batch_summary.v1",
            "creator": plan.get("creator"),
            "contentSurface": plan.get("contentSurface"),
            "targetUnlock": plan.get("targetUnlock"),
            "reviewCandidates": plan.get("reviewCandidates"),
            "recommendedReviewBatchSize": plan.get("recommendedReviewBatchSize"),
            "estimatedInventoryGain": plan.get("estimatedInventoryGain"),
            "estimatedOperatorMinutes": plan.get("estimatedOperatorMinutes"),
            "wouldPass25GateAfterBatch": plan.get("wouldPass25GateAfterBatch"),
            "remainingGapAfterBatch": plan.get("remainingGapAfterBatch"),
            "safeRepairsOnly": True,
            "wouldWrite": False,
        }

    def operator_review_simulator(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        content_surface: str | None = "reel",
        required_inventory: int = 225,
        current_inventory: int | None = None,
        approval_rates: list[int] | None = None,
    ) -> dict[str, Any]:
        plan = self.operator_inventory_review_batch_plan(
            creator=creator,
            campaign_slug=campaign_slug,
            content_surface=content_surface,
            required_inventory=required_inventory,
            current_inventory=current_inventory,
        )
        ordered = self._operator_review_execution_order(plan.get("reviewBatch") or [])
        rates = approval_rates or [25, 50, 75, 90, 100]
        scenarios = [
            self._operator_review_scenario(
                ordered,
                current_inventory=int(plan.get("currentScheduleSafeAssets") or 0),
                required_inventory=int(required_inventory),
                approval_rate=int(rate),
            )
            for rate in rates
        ]
        minimum = self._operator_review_minimum_path(
            ordered,
            current_inventory=int(plan.get("currentScheduleSafeAssets") or 0),
            required_inventory=int(required_inventory),
        )
        return {
            "schema": "creator_os.operator_review_simulator.v1",
            "creator": creator,
            "campaign": campaign_slug,
            "contentSurface": normalize_content_surface(content_surface or "reel"),
            "currentScheduleSafeAssets": int(plan.get("currentScheduleSafeAssets") or 0),
            "requiredFor25Accounts": int(required_inventory),
            "shortfall": max(0, int(required_inventory) - int(plan.get("currentScheduleSafeAssets") or 0)),
            "reviewCandidates": int(plan.get("reviewCandidates") or 0),
            "scenarios": scenarios,
            "minimumCertificationPath": minimum,
            "minimumAssetsReviewedToPass25Gate": int(minimum.get("minimumAssetsReviewedToPass25Gate") or 0),
            "minimumOperatorMinutesToPass25Gate": int(minimum.get("minimumOperatorMinutesToPass25Gate") or 0),
            "highestROIBatchType": self._operator_review_highest_roi_batch_type(ordered),
            "lowestRiskBatchType": self._operator_review_lowest_risk_batch_type(ordered),
            "recommendedExecutionOrder": self._operator_review_batch_order_labels(ordered),
            "wouldWrite": False,
        }

    def operator_review_scenarios(self, **kwargs: Any) -> dict[str, Any]:
        report = self.operator_review_simulator(**kwargs)
        return {
            "schema": "creator_os.operator_review_scenarios.v1",
            "creator": report.get("creator"),
            "contentSurface": report.get("contentSurface"),
            "scenarios": report.get("scenarios"),
            "wouldWrite": False,
        }

    def operator_review_efficiency_report(self, **kwargs: Any) -> dict[str, Any]:
        report = self.operator_review_simulator(**kwargs)
        return {
            "schema": "creator_os.operator_review_efficiency_report.v1",
            "creator": report.get("creator"),
            "contentSurface": report.get("contentSurface"),
            "highestROIBatchType": report.get("highestROIBatchType"),
            "lowestRiskBatchType": report.get("lowestRiskBatchType"),
            "recommendedExecutionOrder": report.get("recommendedExecutionOrder"),
            "minimumCertificationPath": report.get("minimumCertificationPath"),
            "wouldWrite": False,
        }

    def operator_review_minimum_certification_path(self, **kwargs: Any) -> dict[str, Any]:
        report = self.operator_review_simulator(**kwargs)
        return {
            "schema": "creator_os.operator_review_minimum_certification_path.v1",
            "creator": report.get("creator"),
            "contentSurface": report.get("contentSurface"),
            "minimumCertificationPath": report.get("minimumCertificationPath"),
            "minimumAssetsReviewedToPass25Gate": report.get("minimumAssetsReviewedToPass25Gate"),
            "minimumOperatorMinutesToPass25Gate": report.get("minimumOperatorMinutesToPass25Gate"),
            "wouldWrite": False,
        }

    def operator_review_master_report(self, **kwargs: Any) -> dict[str, Any]:
        report = self.operator_review_simulator(**kwargs)
        return {
            **report,
            "schema": "creator_os.operator_review_master_report.v1",
            "wouldWrite": False,
        }

    def _operator_review_execution_order(self, rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        return sorted(
            rows,
            key=lambda row: (
                self._operator_review_batch_priority(row.get("repairClasses") or []),
                int(row.get("estimatedOperatorMinutes") or 0),
                str(row.get("assetId") or ""),
            ),
        )

    def _operator_review_batch_priority(self, repair_classes: list[str]) -> int:
        classes = set(repair_classes)
        if classes == {"instagram_post_caption_quality_failed"}:
            return 0
        if classes <= {"instagram_post_caption_quality_failed", "discoverability_failure"}:
            return 1
        if classes <= {"instagram_post_caption_quality_failed", "operator_visual_review_required"}:
            return 2
        if "quarantined_asset" in classes:
            return 3
        return 4

    def _operator_review_batch_type(self, repair_classes: list[str]) -> str:
        classes = set(repair_classes)
        if classes == {"instagram_post_caption_quality_failed"}:
            return "caption_only"
        if classes <= {"instagram_post_caption_quality_failed", "discoverability_failure"}:
            return "caption_discoverability"
        if classes <= {"instagram_post_caption_quality_failed", "operator_visual_review_required"}:
            return "caption_visual_review"
        if "quarantined_asset" in classes:
            return "quarantine_review"
        return "mixed_review"

    def _operator_review_scenario(
        self,
        ordered_rows: list[dict[str, Any]],
        *,
        current_inventory: int,
        required_inventory: int,
        approval_rate: int,
    ) -> dict[str, Any]:
        reviewed = len(ordered_rows)
        recovered = min(reviewed, int(math.floor(reviewed * max(0, min(100, approval_rate)) / 100)))
        minutes = sum(int(row.get("estimatedOperatorMinutes") or 0) for row in ordered_rows)
        inventory = current_inventory + recovered
        return {
            "approvalRate": approval_rate,
            "assetsReviewed": reviewed,
            "assetsRecovered": recovered,
            "scheduleSafeInventory": inventory,
            "passes25AccountGate": inventory >= required_inventory,
            "operatorMinutes": minutes,
            "wouldWrite": False,
        }

    def _operator_review_minimum_path(
        self,
        ordered_rows: list[dict[str, Any]],
        *,
        current_inventory: int,
        required_inventory: int,
    ) -> dict[str, Any]:
        needed = max(0, required_inventory - current_inventory)
        selected = ordered_rows[:needed]
        minutes = sum(int(row.get("estimatedOperatorMinutes") or 0) for row in selected)
        reviewed_by_type: dict[str, int] = {}
        for row in selected:
            batch_type = self._operator_review_batch_type(row.get("repairClasses") or [])
            reviewed_by_type[batch_type] = reviewed_by_type.get(batch_type, 0) + 1
        return {
            "minimumAssetsReviewedToPass25Gate": len(selected),
            "minimumOperatorMinutesToPass25Gate": minutes,
            "passes25Gate": current_inventory + len(selected) >= required_inventory,
            "assumedApprovalRate": 100,
            "reviewedByBatchType": reviewed_by_type,
            "wouldWrite": False,
        }

    def _operator_review_highest_roi_batch_type(self, rows: list[dict[str, Any]]) -> str:
        by_type: dict[str, dict[str, int]] = {}
        for row in rows:
            batch_type = self._operator_review_batch_type(row.get("repairClasses") or [])
            bucket = by_type.setdefault(batch_type, {"gain": 0, "minutes": 0})
            bucket["gain"] += int(row.get("estimatedInventoryGain") or 0)
            bucket["minutes"] += int(row.get("estimatedOperatorMinutes") or 0)
        if not by_type:
            return ""
        return sorted(by_type, key=lambda key: (-(by_type[key]["gain"] / max(1, by_type[key]["minutes"])), key))[0]

    def _operator_review_lowest_risk_batch_type(self, rows: list[dict[str, Any]]) -> str:
        order = ["caption_only", "caption_discoverability", "caption_visual_review", "quarantine_review", "mixed_review"]
        present = {self._operator_review_batch_type(row.get("repairClasses") or []) for row in rows}
        return next((item for item in order if item in present), "")

    def _operator_review_batch_order_labels(self, rows: list[dict[str, Any]]) -> list[str]:
        order = []
        for row in rows:
            label = self._operator_review_batch_type(row.get("repairClasses") or [])
            if label not in order:
                order.append(label)
        return order

    def _operator_review_candidate_eligible(self, asset: dict[str, Any]) -> bool:
        classes = set(asset.get("repairClasses") or [])
        if not classes:
            return False
        excluded = {
            "wrong_visual",
            "audio_failure",
            "missing_burned_captions",
            "manifest_failure",
            "metadata_failure",
        }
        if classes & excluded:
            return False
        if asset.get("unrepairableBlockers"):
            return False
        return classes.issubset({
            "operator_visual_review_required",
            "instagram_post_caption_quality_failed",
            "discoverability_failure",
            "caption_placement_qc_failed",
            "quarantined_asset",
        })

    def _operator_review_candidate_row(self, asset: dict[str, Any]) -> dict[str, Any]:
        classes = list(asset.get("repairClasses") or [])
        minutes = sum(int(self.MULTI_BLOCKER_REPAIR_MINUTES.get(item, 10)) for item in classes)
        return {
            "assetId": asset.get("assetId") or "",
            "blockers": asset.get("blockers") or [],
            "repairClasses": classes,
            "repairClassCount": len(classes),
            "recommendedActions": self._operator_review_actions(classes),
            "estimatedInventoryGain": 1,
            "estimatedOperatorMinutes": minutes,
            "safeRepairsOnly": True,
            "wouldWrite": False,
        }

    def _operator_review_actions(self, repair_classes: list[str]) -> list[str]:
        actions = []
        if "operator_visual_review_required" in repair_classes:
            actions.append("operator_visual_review")
        if "quarantined_asset" in repair_classes:
            actions.append("review_quarantine_reason_do_not_clear_if_visual_risk")
        if "instagram_post_caption_quality_failed" in repair_classes:
            actions.append("replace_with_simple_safe_instagram_post_caption")
        if "discoverability_failure" in repair_classes:
            actions.append("remove_dm_link_or_platform_risk_language")
        if "caption_placement_qc_failed" in repair_classes:
            actions.append("rerun_caption_placement_qc_or_reject_if_text_overlaps")
        return actions

    def _multi_blocker_asset_row(self, readiness: dict[str, Any]) -> dict[str, Any]:
        blockers = sorted({str(reason).replace("publishability:", "") for reason in readiness.get("blockingReasons") or []})
        if len(blockers) > 1 and "handoff_manifest_missing" in blockers:
            blockers = [reason for reason in blockers if reason != "handoff_manifest_missing"]
        repair_classes = sorted({
            repair_class for repair_class in (self._multi_blocker_repair_class(reason) for reason in blockers)
            if repair_class
        })
        unrepairable = [reason for reason in blockers if not self._multi_blocker_repair_class(reason)]
        return {
            "assetId": readiness.get("assetId") or "",
            "blockers": blockers,
            "repairClasses": repair_classes,
            "unrepairableBlockers": unrepairable,
            "wouldBecomeScheduleSafeIfFixed": repair_classes if repair_classes and not unrepairable else [],
            "wouldWrite": False,
        }

    def _multi_blocker_repair_class(self, reason: str) -> str:
        lowered = reason.lower()
        if "operator_visual_review_required" in lowered:
            return "operator_visual_review_required"
        if "instagram_post_caption_quality_failed" in lowered or "missing_instagram_post_caption" in lowered or "instagram_post_caption_missing" in lowered:
            return "instagram_post_caption_quality_failed"
        if "caption_placement" in lowered:
            return "caption_placement_qc_failed"
        if "discoverability" in lowered or "unsafe_reel_caption" in lowered or "dm" in lowered or "link" in lowered:
            return "discoverability_failure"
        if "manifest" in lowered or "handoff" in lowered:
            return "manifest_failure"
        if "metadata" in lowered or "fingerprint" in lowered or "content_hash" in lowered or "caption_hash" in lowered or "caption_outcome_context" in lowered:
            return "metadata_failure"
        if "quarantined" in lowered:
            return "quarantined_asset"
        if "wrong_visual" in lowered or "visual_quality" in lowered or "story_quality" in lowered or "head_cutoff" in lowered:
            return "wrong_visual"
        if "missing_burned" in lowered:
            return "missing_burned_captions"
        if "audio" in lowered or "embedded_audio" in lowered or "missing_audio" in lowered:
            return "audio_failure"
        return ""

    def _multi_blocker_combo_rows(
        self,
        blocked_assets: list[dict[str, Any]],
        *,
        current_inventory: int,
        required_inventory: int,
    ) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        classes = list(self.MULTI_BLOCKER_REPAIR_CLASSES)
        for size in range(1, len(classes) + 1):
            for combo in combinations(classes, size):
                combo_list = list(combo)
                assets_unlocked = self._multi_blocker_assets_unlocked(blocked_assets, combo_list)
                minutes = self._multi_blocker_estimated_minutes(blocked_assets, combo_list)
                rows.append({
                    "repairCombo": combo_list,
                    "repairClasses": combo_list,
                    "assetsUnlocked": assets_unlocked,
                    "estimatedOperatorMinutes": minutes,
                    "repairDifficulty": self._multi_blocker_combo_difficulty(combo_list),
                    "remainingShortfall": max(0, int(required_inventory) - int(current_inventory) - assets_unlocked),
                    "wouldPass25Gate": int(current_inventory) + assets_unlocked >= int(required_inventory),
                    "wouldWrite": False,
                })
        return sorted(
            rows,
            key=lambda row: (
                len(row["repairClasses"]),
                -int(row["assetsUnlocked"]),
                int(row["estimatedOperatorMinutes"]),
                row["repairClasses"],
            ),
        )

    def _multi_blocker_assets_unlocked(self, blocked_assets: list[dict[str, Any]], repair_classes: list[str]) -> int:
        selected = {item for item in repair_classes if item}
        if not selected:
            return 0
        return sum(
            1 for asset in blocked_assets
            if asset.get("wouldBecomeScheduleSafeIfFixed")
            and set(asset.get("repairClasses") or []).issubset(selected)
        )

    def _multi_blocker_estimated_minutes(self, blocked_assets: list[dict[str, Any]], repair_classes: list[str]) -> int:
        total = 0
        for repair_class in repair_classes:
            impacted = sum(1 for asset in blocked_assets if repair_class in set(asset.get("repairClasses") or []))
            total += impacted * int(self.MULTI_BLOCKER_REPAIR_MINUTES.get(repair_class, 10))
        return total

    def _multi_blocker_combo_difficulty(self, repair_classes: list[str]) -> str:
        weights = {"low": 1, "medium": 2, "high": 3}
        worst = max((weights.get(self.MULTI_BLOCKER_REPAIR_DIFFICULTY.get(item, "high"), 3) for item in repair_classes), default=1)
        return {1: "low", 2: "medium", 3: "high"}.get(worst, "high")

    def _multi_blocker_best_combo(self, combo_rows: list[dict[str, Any]], size: int) -> dict[str, Any]:
        candidates = [row for row in combo_rows if len(row.get("repairClasses") or []) == size]
        if not candidates:
            return {}
        return sorted(
            candidates,
            key=lambda row: (-int(row.get("assetsUnlocked") or 0), int(row.get("estimatedOperatorMinutes") or 0), row.get("repairClasses") or []),
        )[0]

    def _multi_blocker_minimal_fix_set(
        self,
        combo_rows: list[dict[str, Any]],
        *,
        current_inventory: int,
        required_inventory: int,
    ) -> dict[str, Any]:
        passing = [row for row in combo_rows if row.get("wouldPass25Gate")]
        if passing:
            selected = sorted(
                passing,
                key=lambda row: (len(row.get("repairClasses") or []), int(row.get("estimatedOperatorMinutes") or 0), -int(row.get("assetsUnlocked") or 0)),
            )[0]
        else:
            selected = sorted(
                combo_rows,
                key=lambda row: (-int(row.get("assetsUnlocked") or 0), len(row.get("repairClasses") or []), int(row.get("estimatedOperatorMinutes") or 0)),
            )[0] if combo_rows else {}
        return {
            "repairClasses": selected.get("repairClasses") or [],
            "assetsUnlocked": int(selected.get("assetsUnlocked") or 0),
            "estimatedOperatorMinutes": int(selected.get("estimatedOperatorMinutes") or 0),
            "remainingShortfall": max(0, int(required_inventory) - int(current_inventory) - int(selected.get("assetsUnlocked") or 0)),
            "wouldPass25Gate": bool(selected.get("wouldPass25Gate")),
            "wouldWrite": False,
        }

    def _contentforge_visual_qc_failure_for_asset(self, asset: dict[str, Any], surface: str) -> dict[str, Any]:
        readiness = self._surface_handoff_readiness_for_asset(asset)
        publishability = self.explain_publishability(str(asset["id"])) if surface == "reel" else {}
        checks = publishability.get("checks") if isinstance(publishability.get("checks"), dict) else {}
        blockers = sorted({
            str(reason).replace("publishability:", "")
            for reason in list(readiness.get("blockingReasons") or []) + list(publishability.get("publishability_failure_reasons") or [])
        })
        visual_passed = bool(checks.get("operator_visual_review_passed", "operator_visual_review_required" not in blockers))
        category = "" if visual_passed else self._contentforge_visual_qc_failure_category(asset, blockers, readiness, publishability)
        non_visual_blockers = [
            blocker for blocker in blockers
            if self._contentforge_visual_qc_failure_category(asset, [blocker], readiness, publishability) != category
        ]
        inventory_gain = (
            1
            if category
            and self.CONTENTFORGE_VISUAL_QC_REPAIRABLE.get(category, False)
            and self._contentforge_non_visual_gates_pass(checks, readiness, publishability, non_visual_blockers)
            else 0
        )
        return {
            "assetId": asset["id"],
            "variantId": asset.get("variant_id") or "",
            "parentAssetId": asset.get("parent_asset_id") or "",
            "visualQcPassed": visual_passed,
            "failureCategory": category,
            "blockingReasons": blockers,
            "nonVisualBlockers": non_visual_blockers,
            "repairable": bool(self.CONTENTFORGE_VISUAL_QC_REPAIRABLE.get(category, False)),
            "estimatedInventoryGain": inventory_gain,
            "wouldWrite": False,
        }

    def _contentforge_visual_qc_failure_category(
        self,
        asset: dict[str, Any],
        blockers: list[str],
        readiness: dict[str, Any],
        publishability: dict[str, Any],
    ) -> str:
        text = " ".join(blockers + [
            str(asset.get("filename") or ""),
            str(asset.get("campaign_slug") or ""),
            str(asset.get("recipe") or ""),
            str(asset.get("output_path") or ""),
        ]).lower()
        if "operator_visual_review_required" in text:
            return "operator_visual_review_required"
        if any(token in text for token in ("caption_placement", "caption placement")):
            return "caption_placement_failure"
        if any(token in text for token in ("safe_zone", "safe zone", "focal")):
            return "safe_zone_failure"
        if any(token in text for token in ("readability", "caption_readability")):
            return "readability_failure"
        if "aspect_ratio" in text or "ratio" in text:
            return "aspect_ratio_failure"
        if "duplicate" in text or "cooldown" in text:
            return "duplicate_visual_failure"
        if any(token in text for token in ("wrong_visual", "passthrough", "wrong_approved_asset")):
            return "wrong_visual_lineage"
        if any(token in text for token in ("proof", "preview", "audio_preview", "surface_proof")):
            return "proof_asset_only"
        if "trial" in text:
            return "trial_asset_only"
        if any(token in text for token in ("metadata", "content_hash", "fingerprint", "caption_outcome_context", "caption_hash")):
            return "visual_metadata_missing"
        if any(token in text for token in ("visual_quality", "head_cutoff", "face_cutoff", "black_bars", "letterbox", "pillarbox")):
            return "actual_visual_quality_failure"
        if not blockers and not publishability.get("publishableCandidate") and not readiness.get("canHandoff"):
            return "visual_metadata_missing"
        return "unknown"

    def _contentforge_non_visual_gates_pass(
        self,
        checks: dict[str, Any],
        readiness: dict[str, Any],
        publishability: dict[str, Any],
        non_visual_blockers: list[str],
    ) -> bool:
        ignored = {"operator_visual_review_required"}
        remaining = [blocker for blocker in non_visual_blockers if blocker not in ignored and blocker != "handoff_manifest_missing"]
        return bool(
            not remaining
            and checks.get("caption_placement_qc_passed", True)
            and checks.get("discoverability_safe", readiness.get("discoverabilitySafe", True))
            and checks.get("instagram_post_caption_quality_passed", True)
        )

    def _contentforge_visual_qc_category_rows(self, failures: list[dict[str, Any]]) -> list[dict[str, Any]]:
        total = len(failures)
        rows = []
        for category in self.CONTENTFORGE_VISUAL_QC_CATEGORIES:
            matching = [item for item in failures if item.get("failureCategory") == category]
            rows.append({
                "failureCategory": category,
                "count": len(matching),
                "percentOfVisualFailures": round((len(matching) / total) * 100, 1) if total else 0,
                "repairable": bool(self.CONTENTFORGE_VISUAL_QC_REPAIRABLE.get(category, False)),
                "estimatedInventoryGain": sum(int(item.get("estimatedInventoryGain") or 0) for item in matching),
                "estimatedOperatorMinutes": len(matching) * int(self.CONTENTFORGE_VISUAL_QC_MINUTES.get(category, 10)),
                "wouldWrite": False,
            })
        return rows

    def _contentforge_visual_qc_recovered_inventory(self, failures: list[dict[str, Any]], categories: list[str]) -> int:
        selected = {category for category in categories if category}
        return sum(
            int(item.get("estimatedInventoryGain") or 0)
            for item in failures
            if item.get("failureCategory") in selected
        )

    def _contentforge_visual_qc_answer(self, top: dict[str, Any], total_failures: int) -> str:
        category = str(top.get("failureCategory") or "")
        count = int(top.get("count") or 0)
        if not category:
            return "No ContentForge visual QC failures were observed in the selected fresh production window."
        return (
            f"{count} of {total_failures} ContentForge visual QC failures are classified as "
            f"{category}; estimated schedule-safe inventory gain from fixing that category is "
            f"{int(top.get('estimatedInventoryGain') or 0)}."
        )

    def _schedule_safe_production_assets(
        self,
        *,
        creator: str | None,
        campaign_slug: str | None,
        content_surface: str,
        lookback_days: int,
    ) -> list[dict[str, Any]]:
        cutoff = datetime.now(timezone.utc) - timedelta(days=max(1, int(lookback_days or 1)))
        assets = self._surface_report_assets(creator=creator, campaign_slug=campaign_slug)
        return [
            asset for asset in assets
            if normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")) == content_surface
            and self._schedule_safe_asset_created_at(asset) >= cutoff
        ]

    def _schedule_safe_asset_created_at(self, asset: dict[str, Any]) -> datetime:
        raw = str(asset.get("created_at") or "").strip()
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except ValueError:
            return datetime(1970, 1, 1, tzinfo=timezone.utc)
        if parsed.tzinfo is None:
            return parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)

    def _schedule_safe_production_waterfall_rows(self, assets: list[dict[str, Any]], surface: str) -> list[dict[str, Any]]:
        parent_assets = [asset for asset in assets if not self._schedule_safe_is_variant_asset(asset)]
        variant_assets = [asset for asset in assets if self._schedule_safe_is_variant_asset(asset)]
        parent_ids = {str(asset["id"]) for asset in parent_assets}
        accepted_parents = [
            asset for asset in parent_assets
            if str(asset.get("review_state") or "").lower() in {"approved", "review_ready"}
            or str(asset.get("audit_status") or "").lower() in {"passed", "pass", "approved", "approved_candidate"}
        ]
        caption_families = self._schedule_safe_related_count("caption_families", "parent_asset_id", parent_ids)
        caption_versions = self._schedule_safe_related_count("caption_versions", "parent_asset_id", parent_ids)
        checks = [self._schedule_safe_production_variant_checks(asset, surface) for asset in variant_assets]
        visual = sum(1 for item in checks if item["visual_qc_passed"])
        placement = sum(1 for item in checks if item["visual_qc_passed"] and item["caption_placement_qc_passed"])
        discoverability = sum(1 for item in checks if item["visual_qc_passed"] and item["caption_placement_qc_passed"] and item["discoverability_passed"])
        caption_quality = sum(1 for item in checks if item["visual_qc_passed"] and item["caption_placement_qc_passed"] and item["discoverability_passed"] and item["instagram_post_caption_quality_passed"])
        publishability = sum(1 for item in checks if item["visual_qc_passed"] and item["caption_placement_qc_passed"] and item["discoverability_passed"] and item["instagram_post_caption_quality_passed"] and item["publishability_passed"])
        schedule_safe = sum(1 for item in checks if item["schedule_safe"])
        stage_counts = [
            ("raw_parent_reels", len(parent_assets), len(parent_assets)),
            ("accepted_parent_reels", len(parent_assets), len(accepted_parents)),
            ("caption_families_created", len(accepted_parents), caption_families),
            ("caption_families_accepted", caption_families, min(caption_families, caption_versions)),
            ("contentforge_variants_created", max(caption_versions, len(accepted_parents), len(variant_assets)), len(variant_assets)),
            ("visual_qc_passed", len(variant_assets), visual),
            ("caption_placement_qc_passed", visual, placement),
            ("discoverability_passed", placement, discoverability),
            ("instagram_post_caption_quality_passed", discoverability, caption_quality),
            ("publishability_passed", caption_quality, publishability),
            ("schedule_safe_assets_produced", publishability, schedule_safe),
        ]
        return [
            {
                "stage": stage,
                "inputCount": int(input_count),
                "outputCount": int(output_count),
                "lossCount": max(0, int(input_count) - int(output_count)),
                "yieldPct": round(self._ratio(output_count, input_count) * 100, 1),
            }
            for stage, input_count, output_count in stage_counts
        ]

    def _schedule_safe_is_variant_asset(self, asset: dict[str, Any]) -> bool:
        return bool(asset.get("parent_asset_id") or asset.get("variant_id"))

    def _schedule_safe_related_count(self, table: str, column: str, asset_ids: set[str]) -> int:
        if not asset_ids:
            return 0
        placeholders = ",".join("?" for _ in asset_ids)
        try:
            return int(self.conn.execute(
                f"SELECT COUNT(*) AS c FROM {table} WHERE {column} IN ({placeholders})",
                sorted(asset_ids),
            ).fetchone()["c"] or 0)
        except sqlite3.OperationalError:
            return 0

    def _schedule_safe_production_variant_checks(self, asset: dict[str, Any], surface: str) -> dict[str, Any]:
        readiness = self._surface_handoff_readiness_for_asset(asset)
        publishability = self.explain_publishability(str(asset["id"])) if surface == "reel" else {}
        checks = publishability.get("checks") if isinstance(publishability.get("checks"), dict) else {}
        blockers = {str(reason).replace("publishability:", "") for reason in readiness.get("blockingReasons") or []}
        blockers.update(str(reason) for reason in publishability.get("publishability_failure_reasons") or [])
        visual_passed = bool(checks.get("operator_visual_review_passed", "operator_visual_review_required" not in blockers))
        placement_passed = bool(checks.get("caption_placement_qc_passed", "caption_placement_qc_failed" not in blockers))
        discoverability_passed = bool(readiness.get("discoverabilitySafe") and checks.get("discoverability_safe", "discoverability_safety_failed" not in blockers))
        caption_quality_passed = bool(checks.get("instagram_post_caption_quality_passed", "instagram_post_caption_quality_failed" not in blockers))
        publishability_passed = bool(publishability.get("publishableCandidate")) if surface == "reel" else not blockers
        return {
            "assetId": asset["id"],
            "visual_qc_passed": visual_passed,
            "caption_placement_qc_passed": placement_passed,
            "discoverability_passed": discoverability_passed,
            "instagram_post_caption_quality_passed": caption_quality_passed,
            "publishability_passed": publishability_passed,
            "schedule_safe": bool(readiness.get("canHandoff")),
        }

    def _schedule_safe_production_largest_loss(self, waterfall: list[dict[str, Any]]) -> dict[str, Any]:
        total_loss = sum(int(row.get("lossCount") or 0) for row in waterfall)
        largest = max(waterfall, key=lambda row: (int(row.get("lossCount") or 0), str(row.get("stage") or "")), default={})
        loss = int(largest.get("lossCount") or 0)
        return {
            "largestLossGate": largest.get("stage") or "",
            "lossCount": loss,
            "percentOfTotalLoss": round((loss / max(1, total_loss)) * 100, 1) if total_loss else 0,
        }

    def _schedule_safe_production_capacity(
        self,
        *,
        current_inventory: int,
        daily_production: float,
        required_for_25: int,
    ) -> dict[str, Any]:
        targets = {
            "25Accounts": int(required_for_25),
            "50Accounts": 450,
            "100Accounts": 900,
        }
        projections: dict[str, Any] = {}
        for key, required in targets.items():
            shortfall = max(0, required - int(current_inventory or 0))
            days = math.ceil(shortfall / daily_production) if daily_production > 0 and shortfall > 0 else (0 if shortfall == 0 else None)
            projections[key] = {
                "requiredInventory": required,
                "currentInventory": int(current_inventory or 0),
                "shortfall": shortfall,
                "daysToReachBuffer": days,
                "blockedReason": "" if days is not None else "no_schedule_safe_production_observed",
            }
        return {
            "capacityProjections": projections,
            "daysToReach25AccountBuffer": projections["25Accounts"]["daysToReachBuffer"],
            "daysToReach50AccountBuffer": projections["50Accounts"]["daysToReachBuffer"],
            "daysToReach100AccountBuffer": projections["100Accounts"]["daysToReachBuffer"],
        }

    def _schedule_safe_required_parents_per_day(self, produced_per_day: float, produced: int, parent_count: int) -> int:
        if produced_per_day <= 0 or produced <= 0:
            return 0
        parents_per_asset = parent_count / max(1, produced)
        return int(math.ceil(75 * parents_per_asset))

    def _schedule_safe_required_variants_per_day(self, produced_per_day: float, produced: int, variant_count: int) -> int:
        if produced_per_day <= 0 or produced <= 0:
            return 0
        variants_per_asset = variant_count / max(1, produced)
        return int(math.ceil(75 * variants_per_asset))

    def _schedule_safe_production_summary_key(self, stage: str) -> str:
        return {
            "raw_parent_reels": "rawParents",
            "accepted_parent_reels": "acceptedParents",
            "caption_families_created": "captionFamilies",
            "caption_families_accepted": "captionFamiliesAccepted",
            "contentforge_variants_created": "variantsCreated",
            "visual_qc_passed": "visualQcPassed",
            "caption_placement_qc_passed": "captionPlacementPassed",
            "discoverability_passed": "discoverabilityPassed",
            "instagram_post_caption_quality_passed": "captionQualityPassed",
            "publishability_passed": "publishabilityPassed",
            "schedule_safe_assets_produced": "scheduleSafeAssets",
        }.get(stage, stage)

    def _fresh_reel_current_schedule_safe_inventory(
        self,
        *,
        creator: str | None,
        campaign_slug: str | None,
    ) -> int:
        assets = [
            asset for asset in self._surface_report_assets(creator=creator, campaign_slug=campaign_slug)
            if normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")) == "reel"
        ]
        return sum(1 for readiness in self._build_surface_readiness(assets) if readiness.get("canHandoff"))

    def _fresh_reel_downstream_schedule_safe_yield_pct(self) -> float:
        yield_pct = 100.0
        for stage, stage_yield, _risk in self.FRESH_REEL_STAGE_YIELDS:
            if stage == "parent_accepted":
                continue
            if stage in {
                "caption_family_created",
                "caption_versions_created",
                "contentforge_variants_created",
            }:
                continue
            yield_pct *= float(stage_yield) / 100
        return round(yield_pct, 1)

    def _fresh_reel_expected_stage_rows(
        self,
        *,
        raw_parent_candidates_needed: int,
        parents_needed: int,
        caption_families_needed: int,
        caption_versions_needed: int,
        variants_needed: int,
    ) -> list[dict[str, Any]]:
        counts = {
            "parent_accepted": (raw_parent_candidates_needed, parents_needed),
            "caption_family_created": (parents_needed, caption_families_needed),
            "caption_versions_created": (caption_families_needed, caption_versions_needed),
            "contentforge_variants_created": (caption_versions_needed, variants_needed),
        }
        current = variants_needed
        for stage, yield_pct, _risk in self.FRESH_REEL_STAGE_YIELDS:
            if stage in counts:
                continue
            output = int(round(current * (float(yield_pct) / 100)))
            counts[stage] = (current, output)
            current = output
        rows = []
        for stage, yield_pct, risk in self.FRESH_REEL_STAGE_YIELDS:
            input_count, output_count = counts.get(stage, (0, 0))
            rows.append({
                "stage": stage,
                "expectedInput": int(input_count),
                "expectedOutput": int(output_count),
                "assumedYieldPct": float(yield_pct),
                "risk": risk,
                "evidence": self._fresh_reel_stage_evidence(stage),
            })
        return rows

    def _fresh_reel_stage_evidence(self, stage: str) -> str:
        if stage == "parent_accepted":
            return "measured_post_gate_parent_trials"
        if stage == "discoverability_passed":
            return "upstream_discoverability_gate_fixture_proof"
        if stage in {
            "visual_qc_passed",
            "publishability_passed",
            "schedule_safe_asset_produced",
        }:
            return "conservative_assumption_pending_fresh_schedule_safe_batch"
        return "deterministic_pipeline_step_assumption_pending_batch_verification"

    def _fresh_reel_execution_batches(
        self,
        *,
        fresh_needed: int,
        downstream_yield_pct: float,
        variants_per_parent: int,
        batch_target: int,
    ) -> list[dict[str, Any]]:
        batches = []
        remaining = max(0, int(fresh_needed or 0))
        target = max(1, int(batch_target or 90))
        batch_index = 1
        while remaining > 0:
            schedule_safe_target = min(target, remaining)
            variants_required = int(math.ceil(schedule_safe_target / max(0.01, downstream_yield_pct / 100)))
            parents_required = int(math.ceil(variants_required / max(1, variants_per_parent)))
            batches.append({
                "batchId": f"fresh_reel_batch_{batch_index:02d}",
                "targetScheduleSafeAssets": schedule_safe_target,
                "parentsRequired": parents_required,
                "captionFamiliesRequired": parents_required,
                "variantsRequired": variants_required,
                "expectedScheduleSafeOutput": schedule_safe_target,
                "gatesToVerify": list(self.FRESH_REEL_GATES_TO_VERIFY),
                "wouldWrite": False,
            })
            remaining -= schedule_safe_target
            batch_index += 1
        return batches

    def _inventory_recovery_blocked_asset(self, readiness: dict[str, Any]) -> dict[str, Any]:
        blockers = sorted({str(reason).replace("publishability:", "") for reason in readiness.get("blockingReasons") or []})
        if len(blockers) > 1 and "handoff_manifest_missing" in blockers:
            blockers = [reason for reason in blockers if reason != "handoff_manifest_missing"]
        classes = sorted({self._inventory_recovery_class_for_blocker(reason) for reason in blockers})
        return {
            "assetId": readiness.get("assetId") or "",
            "contentSurface": readiness.get("contentSurface") or "",
            "blockingReasons": blockers,
            "repairClasses": classes or ["other"],
            "wouldWrite": False,
        }

    def _inventory_recovery_class_for_blocker(self, reason: str) -> str:
        lowered = reason.lower()
        if any(token in lowered for token in ("instagram_post_caption_quality_failed", "missing_instagram_post_caption", "instagram_post_caption_missing")):
            return "caption_only"
        if "caption_placement" in lowered:
            return "caption_placement_qc"
        if "missing_burned" in lowered or "missing_burned_captions" in lowered:
            return "missing_burned_captions"
        if "operator_visual_review_required" in lowered:
            return "operator_visual_review_required"
        if "quarantined" in lowered:
            return "quarantined_asset"
        if "wrong_visual" in lowered or "visual_quality" in lowered or "story_quality" in lowered or "head_cutoff" in lowered:
            return "wrong_visual"
        if "audio" in lowered or "embedded_audio" in lowered or "missing_audio" in lowered:
            return "audio_failure"
        if "manifest" in lowered or "handoff" in lowered:
            return "manifest_failure"
        if "metadata" in lowered or "fingerprint" in lowered or "content_hash" in lowered or "caption_hash" in lowered or "caption_outcome_context" in lowered:
            return "metadata_failure"
        if "discoverability" in lowered or "dm" in lowered or "link" in lowered:
            return "discoverability_failure"
        return "other"

    def _inventory_recovery_class_rows(self, blocked_assets: list[dict[str, Any]]) -> list[dict[str, Any]]:
        total = len(blocked_assets)
        rows: list[dict[str, Any]] = []
        for repair_class in self.INVENTORY_RECOVERY_CLASSES:
            assets_with_class = [asset for asset in blocked_assets if repair_class in set(asset.get("repairClasses") or [])]
            unlocked = self._inventory_recovery_assets_unlocked(blocked_assets, [repair_class])
            minutes_per_asset = self.INVENTORY_RECOVERY_MINUTES[repair_class]
            rows.append({
                "repairClass": repair_class,
                "blockedAssets": len(assets_with_class),
                "repairableAssets": len(assets_with_class),
                "scheduleSafeAssetsRecoverable": unlocked,
                "percentOfTotalBlockedInventory": round((len(assets_with_class) / total) * 100, 1) if total else 0,
                "estimatedOperatorMinutes": len(assets_with_class) * minutes_per_asset,
                "estimatedMinutesPerAsset": minutes_per_asset,
                "repairDifficulty": self.INVENTORY_RECOVERY_DIFFICULTY[repair_class],
                "wouldWrite": False,
            })
        return rows

    def _inventory_recovery_assets_unlocked(self, blocked_assets: list[dict[str, Any]], repaired_classes: list[str]) -> int:
        repaired = {item for item in repaired_classes if item}
        if not repaired:
            return 0
        return sum(
            1 for asset in blocked_assets
            if set(asset.get("repairClasses") or []) and set(asset.get("repairClasses") or []).issubset(repaired)
        )

    def _inventory_recovery_priorities(self, rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        difficulty_weight = {"low": 1, "medium": 2, "high": 3}
        ranked = []
        for row in rows:
            minutes = max(1, int(row.get("estimatedOperatorMinutes") or 0))
            gain = int(row.get("scheduleSafeAssetsRecoverable") or 0)
            blocked = int(row.get("blockedAssets") or 0)
            difficulty = str(row.get("repairDifficulty") or "high")
            score = round(((gain * 100) + blocked) / (minutes * difficulty_weight.get(difficulty, 3)), 4)
            ranked.append({
                **row,
                "estimatedInventoryGain": gain,
                "roiScore": score,
            })
        return sorted(
            ranked,
            key=lambda item: (
                -int(item.get("estimatedInventoryGain") or 0),
                -float(item.get("roiScore") or 0),
                int(item.get("estimatedOperatorMinutes") or 0),
                str(item.get("repairClass") or ""),
            ),
        )

    def inventory_factory_readiness_report(
        self,
        *,
        accounts: int = 200,
        posts_per_account_per_day: int = 3,
        available_inventory: int = 0,
        execution_readiness: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        audit = self.inventory_factory_audit(accounts=accounts, posts_per_account_per_day=posts_per_account_per_day)
        yield_report = self.inventory_yield_analysis()
        slo = self.inventory_slo_report(
            accounts=accounts,
            posts_per_account_per_day=posts_per_account_per_day,
            creators=3,
            minimum_inventory_days=3,
            current_validated_drafts=available_inventory,
        )
        exceptions = self.inventory_exception_audit(execution_readiness=execution_readiness)
        daily_demand = int(slo.get("dailyPostObligations") or 0)
        current_score = self._score_fraction(available_inventory, int(slo.get("minimumValidatedDraftBuffer") or 1))
        capacity_score = self._score_fraction(audit.get("scheduleSafeInventoryCapacity") or 0, daily_demand)
        buffer_score = self._score_fraction(available_inventory, int(slo.get("minimumValidatedDraftBuffer") or 1))
        yield_score = round(10 * min(1.0, max(
            yield_report.get("parentToVariantYield") or 0,
            yield_report.get("variantToValidatedYield") or 0,
            yield_report.get("validatedToScheduleSafeYield") or 0,
        )), 1)
        exception_score = max(0.0, round(10 - ((exceptions.get("avoidableLossPct") or 0) / 20), 1))
        overall = round((current_score + capacity_score + buffer_score + yield_score + exception_score) / 5, 1)
        return {
            "schema": "creator_os.inventory_factory_readiness_report.v1",
            "currentInventoryScore": current_score,
            "inventoryCapacityScore": capacity_score,
            "inventoryBufferScore": buffer_score,
            "inventoryYieldScore": yield_score,
            "inventoryExceptionScore": exception_score,
            "overallInventoryReadiness": overall,
            "inputs": {
                "accounts": accounts,
                "postsPerAccountPerDay": posts_per_account_per_day,
                "availableInventory": available_inventory,
            },
            "wouldWrite": False,
        }

    def inventory_factory_master_report(
        self,
        *,
        accounts: int = 200,
        posts_per_account_per_day: int = 3,
        available_inventory: int = 0,
        execution_readiness: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        audit = self.inventory_factory_audit(accounts=accounts, posts_per_account_per_day=posts_per_account_per_day)
        yield_report = self.inventory_yield_analysis()
        buffer = self.inventory_buffer_policy_plan(
            creator="All",
            surface="all",
            daily_demand=max(0, int(accounts or 0)) * max(0, int(posts_per_account_per_day or 0)),
            buffer_target_days=3,
            available_inventory=available_inventory,
        )
        simulation = self.inventory_consumption_simulation(available_inventory=available_inventory)
        production = self.inventory_production_requirements(accounts=accounts, posts_per_account_per_day=posts_per_account_per_day)
        exceptions = self.inventory_exception_audit(execution_readiness=execution_readiness)
        score = self.inventory_factory_readiness_report(
            accounts=accounts,
            posts_per_account_per_day=posts_per_account_per_day,
            available_inventory=available_inventory,
            execution_readiness=execution_readiness,
        )
        return {
            "schema": "creator_os.inventory_factory_master_report.v1",
            "currentInventoryReadiness": score,
            "inventoryBottlenecks": {
                "largestBottleneck": audit["largestBottleneck"],
                "limitingStage": audit["limitingStage"],
                "inventoryLostByStage": audit["inventoryLostByStage"],
            },
            "inventoryYieldAnalysis": yield_report,
            "bufferRequirements": buffer,
            "consumptionSimulations": simulation["simulations"],
            "productionRequirements": production,
            "exceptionAnalysis": exceptions,
            "inventoryScore": score,
            "requirementsFor200Accounts": self._road_to_accounts_payload(
                accounts=200,
                production=self.inventory_production_requirements(accounts=200, posts_per_account_per_day=posts_per_account_per_day),
            ),
            "requirementsFor500Accounts": self._road_to_accounts_payload(
                accounts=500,
                production=self.inventory_production_requirements(accounts=500, posts_per_account_per_day=posts_per_account_per_day),
            ),
            "wouldWrite": False,
        }

    def reel_factory_parent_throughput_proof(
        self,
        *,
        required_parents_per_day: int = 53,
        lookback_days: int = 1,
    ) -> dict[str, Any]:
        required = max(1, int(required_parents_per_day or 53))
        metrics = self._reel_factory_parent_metrics()
        yield_report = self.reel_factory_yield_analysis(metrics=metrics)
        capacity = self.reel_factory_capacity_model(required_parents_per_day=required)
        overall_rate = float(yield_report.get("overallYieldRate") or 0)
        required_raw = math.ceil(required / overall_rate) if overall_rate > 0 else int(capacity["passRateScenarios"]["60%"])
        schedule_safe_count = int(metrics["scheduleSafe"])
        daily_capacity = schedule_safe_count // max(1, int(lookback_days or 1))
        can_produce = daily_capacity >= required and overall_rate >= 0.60
        return {
            "schema": "creator_os.reel_factory_parent_throughput_proof.v1",
            "canProduce53QualityParentsPerDay": bool(can_produce and required == 53),
            "canProduceRequiredQualityParentsPerDay": bool(can_produce),
            "confidence": self._reel_factory_confidence(metrics),
            "limitingStep": yield_report.get("largestDropoff") or "raw_candidate_supply",
            "requiredParentsPerDay": required,
            "measuredParentCapacityPerDay": daily_capacity,
            "requiredRawCandidatesPerDay": required_raw,
            "qualityParentPassRate": float(yield_report.get("qcPassRate") or 0),
            "publishabilityPassRate": float(yield_report.get("publishabilityPassRate") or 0),
            "captionFamilyEligibleRate": float(yield_report.get("captionFamilyEligibleRate") or 0),
            "audioValidRate": float(yield_report.get("audioValidRate") or 0),
            "handoffReadyRate": float(yield_report.get("handoffReadyRate") or 0),
            "operatorReviewMinutesPerParent": self._operator_review_minutes_per_parent(metrics),
            "intake": self._reel_factory_intake_metrics(metrics),
            "parentCreation": self._reel_factory_parent_creation_metrics(metrics),
            "qualityGates": self._reel_factory_quality_gate_metrics(yield_report),
            "operationalReadiness": self._reel_factory_operational_readiness_metrics(yield_report),
            "humanCost": self._reel_factory_human_cost(metrics),
            "yieldFunnel": yield_report.get("funnel") or [],
            "wouldWrite": False,
        }

    def reel_factory_yield_analysis(self, *, metrics: dict[str, int] | None = None) -> dict[str, Any]:
        values = metrics or self._reel_factory_parent_metrics()
        funnel = [
            {"stage": "raw_candidates", "count": int(values["rawCandidates"])},
            {"stage": "parent_candidates", "count": int(values["parentCandidates"])},
            {"stage": "qc_pass", "count": int(values["qcPass"])},
            {"stage": "publishability_pass", "count": int(values["publishabilityPass"])},
            {"stage": "handoff_ready", "count": int(values["handoffReady"])},
            {"stage": "schedule_safe", "count": int(values["scheduleSafe"])},
        ]
        transitions = []
        for before, after in zip(funnel, funnel[1:]):
            rate = self._ratio(after["count"], before["count"])
            transitions.append({
                "from": before["stage"],
                "to": after["stage"],
                "fromCount": before["count"],
                "toCount": after["count"],
                "yieldRate": rate,
                "yieldPct": round(rate * 100, 1),
                "lost": max(0, before["count"] - after["count"]),
            })
        non_zero = [row for row in transitions if row["fromCount"] > 0]
        largest_dropoff_row = min(non_zero, key=lambda row: row["yieldRate"]) if non_zero else transitions[0]
        overall_rate = self._ratio(funnel[-1]["count"], funnel[0]["count"])
        return {
            "schema": "creator_os.reel_factory_yield_analysis.v1",
            "funnel": funnel,
            "transitions": transitions,
            "overallYieldRate": overall_rate,
            "overallYieldPct": round(overall_rate * 100, 1),
            "rawCandidateToParentRate": self._ratio(values["parentCandidates"], values["rawCandidates"]),
            "qcPassRate": self._ratio(values["qcPass"], values["parentCandidates"]),
            "publishabilityPassRate": self._ratio(values["publishabilityPass"], values["qcPass"]),
            "captionFamilyEligibleRate": self._ratio(values["captionFamilyEligible"], values["parentCandidates"]),
            "audioValidRate": self._ratio(values["audioValid"], values["parentCandidates"]),
            "handoffReadyRate": self._ratio(values["handoffReady"], values["publishabilityPass"]),
            "scheduleSafeRate": self._ratio(values["scheduleSafe"], values["handoffReady"]),
            "largestDropoff": largest_dropoff_row["to"],
            "wouldWrite": False,
        }

    def reel_factory_failure_analysis(self) -> dict[str, Any]:
        metrics = self._reel_factory_parent_metrics()
        yield_report = self.reel_factory_yield_analysis(metrics=metrics)
        lost_by_stage = {
            row["to"]: int(row["lost"])
            for row in yield_report.get("transitions") or []
        }
        failure_specs = [
            ("source_acquisition", "raw candidate supply", max(0, 53 - int(metrics["rawCandidates"])), "high", 0),
            ("render_throughput", "rendered parent candidates below required rate", lost_by_stage.get("parent_candidates", 0), "high", 8),
            ("quality_review", "visual/caption QC failed", lost_by_stage.get("qc_pass", 0), "high", 6),
            ("publishability", "publishability gate failed", lost_by_stage.get("publishability_pass", 0), "high", 12),
            ("handoff_readiness", "handoff manifest or distribution readiness failed", lost_by_stage.get("handoff_ready", 0), "medium", 5),
            ("schedule_safe_inventory", "parent passed earlier gates but is not schedule-safe", lost_by_stage.get("schedule_safe", 0), "medium", 4),
        ]
        failures = [
            {
                "failure": failure,
                "frequency": frequency,
                "impact": impact,
                "repairCostMinutes": repair,
                "operationalImpactScore": frequency * max(1, repair),
            }
            for failure, reason, frequency, impact, repair in failure_specs
        ]
        failures = sorted(failures, key=lambda item: (-int(item["operationalImpactScore"]), item["failure"]))
        what_breaks = failures[0]["failure"] if failures else "unknown"
        return {
            "schema": "creator_os.reel_factory_failure_analysis.v1",
            "failures": failures,
            "whatBreaksFirst": what_breaks,
            "categories": [
                "generation_throughput",
                "render_throughput",
                "quality_review",
                "audio_validation",
                "caption_placement",
                "publishability",
                "operator_review",
                "handoff_readiness",
                "inventory_management",
            ],
            "wouldWrite": False,
        }

    def reel_factory_capacity_model(self, *, required_parents_per_day: int = 53) -> dict[str, Any]:
        required = max(1, int(required_parents_per_day or 53))
        scenarios = {
            "95%": math.ceil(required / 0.95),
            "90%": math.ceil(required / 0.90),
            "80%": math.ceil(required / 0.80),
            "70%": math.ceil(required / 0.70),
            "60%": math.ceil(required / 0.60),
        }
        return {
            "schema": "creator_os.reel_factory_capacity_model.v1",
            "requiredParentsPerDay": required,
            "passRateScenarios": scenarios,
            "wouldWrite": False,
        }

    def reel_factory_200_account_readiness(self) -> dict[str, Any]:
        scaling = {}
        for accounts in (25, 50, 100, 200, 500):
            production = self.inventory_production_requirements(accounts=accounts, posts_per_account_per_day=3)
            proof = self.reel_factory_parent_throughput_proof(required_parents_per_day=int(production["requiredParentsPerDay"]))
            scaling[f"{accounts}Accounts"] = {
                "accounts": accounts,
                "requiredParentsPerDay": int(production["requiredParentsPerDay"]),
                "requiredValidatedDraftsPerDay": int(production["requiredValidatedDraftsPerDay"]),
                "requiredInventoryBuffer": int(production["postsPerDay"]) * 3,
                "largestBottleneck": proof["limitingStep"],
                "confidence": proof["confidence"],
                "canSupport": bool(proof["canProduceRequiredQualityParentsPerDay"]),
                "wouldWrite": False,
            }
        return {
            "schema": "creator_os.reel_factory_200_account_readiness.v1",
            "requiredParentsPerDay": scaling["200Accounts"]["requiredParentsPerDay"],
            "scalingAnalysis": scaling,
            "wouldWrite": False,
        }

    def reel_factory_master_report(self) -> dict[str, Any]:
        proof = self.reel_factory_parent_throughput_proof(required_parents_per_day=53)
        yield_report = self.reel_factory_yield_analysis()
        failure = self.reel_factory_failure_analysis()
        capacity = self.reel_factory_capacity_model(required_parents_per_day=53)
        readiness = self.reel_factory_200_account_readiness()
        final = {
            "currentParentFactoryRating": self._reel_factory_rating(proof),
            "canSupport200Accounts": bool(proof["canProduce53QualityParentsPerDay"]),
            "requiredParentsPerDay": 53,
            "requiredRawCandidatesPerDay": int(proof["requiredRawCandidatesPerDay"]),
            "largestBottleneck": str(proof["limitingStep"]),
            "largestHumanBottleneck": "operator_review" if proof["operatorReviewMinutesPerParent"] > 0 else "quality_review_capacity_unproven",
            "largestTechnicalBottleneck": str(proof["limitingStep"]),
            "recommendedNextSprint": "run_measured_reel_factory_53_parent_day_throughput_trial",
        }
        return {
            "schema": "creator_os.reel_factory_master_report.v1",
            "parentThroughputProof": proof,
            "yieldAnalysis": yield_report,
            "failureAnalysis": failure,
            "capacityModel": capacity,
            "readinessAtScale": readiness,
            "finalVerdict": final,
            "wouldWrite": False,
        }

    def parent_factory_yield_waterfall(self, *, required_parents_per_day: int = 53) -> dict[str, Any]:
        required = max(1, int(required_parents_per_day or 53))
        metrics = self._reel_factory_parent_metrics()
        counts = self._parent_factory_detailed_stage_counts(metrics)
        stages = []
        previous_count = counts["raw_candidate"]
        for idx, stage in enumerate(self._parent_factory_stage_order()):
            output_count = counts[stage]
            input_count = output_count if idx == 0 else previous_count
            stages.append({
                "stage": stage,
                "inputCount": input_count,
                "outputCount": output_count,
                "yieldPct": round(self._ratio(output_count, input_count) * 100, 1),
                "lossCount": max(0, input_count - output_count),
                "wouldWrite": False,
            })
            previous_count = output_count
        overall_rate = self._ratio(counts["parent_accepted"], counts["raw_candidate"])
        required_raw = math.ceil(required / overall_rate) if overall_rate > 0 else required
        return {
            "schema": "creator_os.parent_factory_yield_waterfall.v1",
            "requiredParentsPerDay": required,
            "overallYieldRate": overall_rate,
            "overallYieldPct": round(overall_rate * 100, 1),
            "requiredRawCandidatesPerDay": required_raw,
            "stages": stages,
            "wouldWrite": False,
        }

    def parent_factory_loss_analysis(self, *, required_parents_per_day: int = 53) -> dict[str, Any]:
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=required_parents_per_day)
        rejection = self.parent_factory_rejection_report(waterfall=waterfall)
        losses = [row for row in waterfall.get("stages") or [] if int(row.get("lossCount") or 0) > 0]
        largest = max(losses, key=lambda row: int(row["lossCount"]))["stage"] if losses else ""
        repairable = [
            row for row in rejection.get("rejectionReasons") or []
            if row.get("repairable") and int(row.get("frequency") or 0) > 0
        ]
        non_repairable = [
            row for row in rejection.get("rejectionReasons") or []
            if not row.get("repairable") and int(row.get("frequency") or 0) > 0
        ]
        largest_repairable = max(repairable, key=lambda row: int(row["frequency"]))["reason"] if repairable else ""
        largest_non_repairable = max(non_repairable, key=lambda row: int(row["frequency"]))["reason"] if non_repairable else ""
        roi = self._parent_factory_highest_roi(rejection.get("rejectionReasons") or [])
        return {
            "schema": "creator_os.parent_factory_loss_analysis.v1",
            "largestLossStage": largest,
            "largestRepairableLossStage": largest_repairable,
            "largestNonRepairableLossStage": largest_non_repairable,
            "highestROIImprovement": roi,
            "losses": losses,
            "wouldWrite": False,
        }

    def parent_factory_rejection_report(self, *, waterfall: dict[str, Any] | None = None) -> dict[str, Any]:
        source = waterfall or self.parent_factory_yield_waterfall()
        stage_losses = {row["stage"]: int(row.get("lossCount") or 0) for row in source.get("stages") or []}
        total_failures = sum(stage_losses.values())
        discoverability_loss = self.parent_factory_discoverability_loss_analysis(waterfall=source)
        specs = [
            ("render_failure", "render_success", True, "medium", "stabilize render worker throughput and retry classification"),
            ("visual_qc_failure", "visual_qc_pass", True, "medium", "tighten source selection and visual preflight"),
            ("caption_burn_failure", "caption_burn_pass", True, "low", "repair caption sidecar/render recipe contract"),
            ("audio_invalid", "audio_validation_pass", True, "medium", "repair embedded AAC verification before parent approval"),
            ("discoverability_violation", "discoverability_safety_pass", True, "low", "block unsafe captions earlier in intake"),
            ("publishability_failure", "publishability_pass", True, "high", "fix publishability blockers before parent registration"),
            ("manifest_failure", "handoff_ready", True, "medium", "rebuild handoff manifest and distribution metadata"),
            ("schedule_safe_failure", "schedule_safe", True, "medium", "repair distribution-plan/account-readiness linkage"),
            ("manual_review_rejection", "parent_accepted", False, "high", "replace rejected creative with stronger raw candidate"),
            ("duplicate_risk", "parent_accepted", False, "medium", "import more unique raw candidate supply"),
        ]
        rows = []
        for reason, stage, repairable, difficulty, next_action in specs:
            frequency = int(stage_losses.get(stage) or 0)
            rows.append({
                "reason": reason,
                "stage": stage,
                "frequency": frequency,
                "percentOfFailures": round((frequency / total_failures) * 100, 1) if total_failures else 0,
                "repairable": repairable,
                "estimatedFixDifficulty": difficulty,
                "nextAction": next_action,
                "wouldWrite": False,
            })
        rows = sorted(rows, key=lambda row: (-int(row["frequency"]), str(row["reason"])))
        return {
            "schema": "creator_os.parent_factory_rejection_report.v1",
            "totalFailures": total_failures,
            "rejectionReasons": rows,
            "discoverabilityLossAnalysis": discoverability_loss,
            "wouldWrite": False,
        }

    def parent_factory_discoverability_loss_analysis(self, *, waterfall: dict[str, Any] | None = None) -> dict[str, Any]:
        source = waterfall or self.parent_factory_yield_waterfall()
        stage_losses = {row["stage"]: int(row.get("lossCount") or 0) for row in source.get("stages") or []}
        discoverability_stage_loss = int(stage_losses.get("discoverability_safety_pass") or 0)
        categories = {
            "dm_language": 0,
            "link_language": 0,
            "off_platform_reference": 0,
            "onlyfans_reference": 0,
            "telegram_reference": 0,
            "snapchat_reference": 0,
            "whatsapp_reference": 0,
            "bio_reference": 0,
            "cta_language": 0,
            "other": 0,
        }
        captured_evidence = self._parent_factory_captured_discoverability_evidence()
        evidence_source = captured_evidence or self._parent_factory_observed_discoverability_terms()
        for term in evidence_source:
            categories[self._discoverability_loss_category(term.get("reason", ""), term.get("matchedText", ""))] += 1
        observed_failures = sum(categories.values())
        if discoverability_stage_loss > observed_failures:
            categories["other"] += discoverability_stage_loss - observed_failures
        total = max(discoverability_stage_loss, sum(categories.values()))
        generation_categories = {
            "off_platform_reference",
            "onlyfans_reference",
            "telegram_reference",
            "snapchat_reference",
            "whatsapp_reference",
        }
        caption_categories = {"dm_language", "link_language", "bio_reference", "cta_language"}
        generation_count = sum(categories[name] for name in generation_categories)
        caption_count = sum(categories[name] for name in caption_categories)
        registration_count = categories["other"]
        rows = [
            {
                "category": category,
                "frequency": count,
                "percentOfDiscoverabilityFailures": round((count / total) * 100, 1) if total else 0,
                "preventableAt": self._discoverability_prevention_stage(category),
                "wouldWrite": False,
            }
            for category, count in categories.items()
        ]
        return {
            "schema": "creator_os.parent_factory_discoverability_loss_analysis.v1",
            "discoverabilityStageLoss": discoverability_stage_loss,
            "capturedEvidenceCount": len(captured_evidence),
            "observedClassifiedFailures": observed_failures,
            "discoverabilityRejectionCategories": rows,
            "percentPreventableAtGeneration": round((generation_count / total) * 100, 1) if total else 0,
            "percentPreventableAtCaptionCreation": round((caption_count / total) * 100, 1) if total else 0,
            "percentPreventableAtRegistration": round((registration_count / total) * 100, 1) if total else 0,
            "wouldWrite": False,
        }

    def parent_factory_quality_gate_analysis(self) -> dict[str, Any]:
        waterfall = self.parent_factory_yield_waterfall()
        gates = []
        for row in waterfall.get("stages") or []:
            if row["stage"] == "raw_candidate":
                continue
            gates.append({
                "gate": row["stage"],
                "passRate": row["yieldPct"],
                "inputCount": row["inputCount"],
                "passed": row["outputCount"],
                "failed": row["lossCount"],
                "blocking": row["lossCount"] > 0,
                "wouldWrite": False,
            })
        return {
            "schema": "creator_os.parent_factory_quality_gate_analysis.v1",
            "qualityGates": gates,
            "wouldWrite": False,
        }

    def parent_factory_optimization_plan(self, *, required_parents_per_day: int = 53) -> dict[str, Any]:
        required = max(1, int(required_parents_per_day or 53))
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=required)
        rejection = self.parent_factory_rejection_report(waterfall=waterfall)
        current_yield = float(waterfall.get("overallYieldPct") or 0)
        scenarios = {}
        scenario_values = [current_yield, 10, 15, 20, 25, 30, 40, 50]
        for value in scenario_values:
            if value <= 0:
                continue
            label = f"{value:.1f}%" if value == current_yield and value % 1 else f"{int(value)}%"
            scenarios[label] = {
                "yieldPct": round(value, 1),
                "rawCandidatesNeededFor53Parents": math.ceil(required / (value / 100)),
                "wouldWrite": False,
            }
        top_fixes = self._parent_factory_top_fixes(rejection.get("rejectionReasons") or [])
        expected_yield = min(50.0, max(current_yield, current_yield + sum(float(item.get("estimatedYieldLiftPct") or 0) for item in top_fixes[:3])))
        return {
            "schema": "creator_os.parent_factory_optimization_plan.v1",
            "currentYieldPct": round(current_yield, 1),
            "currentRawCandidatesNeededFor53Parents": int(waterfall.get("requiredRawCandidatesPerDay") or 0),
            "yieldScenarios": scenarios,
            "humanBottleneckAnalysis": self._parent_factory_human_bottleneck(required=required, rejection=rejection),
            "whatThreeFixesIncreaseYieldFastest": top_fixes[:3],
            "expectedYieldAfterFixes": round(expected_yield, 1),
            "newRawCandidatesNeededFor53Parents": math.ceil(required / max(0.01, expected_yield / 100)),
            "canSupport200AccountsAfterFixes": expected_yield >= 40,
            "wouldWrite": False,
        }

    def parent_factory_master_optimization_report(self, *, required_parents_per_day: int = 53) -> dict[str, Any]:
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=required_parents_per_day)
        loss = self.parent_factory_loss_analysis(required_parents_per_day=required_parents_per_day)
        rejection = self.parent_factory_rejection_report(waterfall=waterfall)
        quality = self.parent_factory_quality_gate_analysis()
        optimization = self.parent_factory_optimization_plan(required_parents_per_day=required_parents_per_day)
        top_fixes = optimization.get("whatThreeFixesIncreaseYieldFastest") or []
        single_fix = top_fixes[0]["fix"] if top_fixes else loss.get("highestROIImprovement", "")
        acceptance = {
            "whyYieldIs8_2Pct": self._parent_factory_yield_explanation(waterfall, loss),
            "whatSingleFixImprovesYieldMost": single_fix,
            "whatThreeFixesIncreaseYieldFastest": [item["fix"] for item in top_fixes[:3]],
            "expectedYieldAfterFixes": optimization["expectedYieldAfterFixes"],
            "newRawCandidatesNeededFor53Parents": optimization["newRawCandidatesNeededFor53Parents"],
            "canSupport200AccountsAfterFixes": optimization["canSupport200AccountsAfterFixes"],
            "wouldWrite": False,
        }
        return {
            "schema": "creator_os.parent_factory_master_optimization_report.v1",
            "yieldWaterfall": waterfall,
            "lossAnalysis": loss,
            "rejectionReport": rejection,
            "discoverabilityLossAnalysis": rejection.get("discoverabilityLossAnalysis"),
            "qualityGateAnalysis": quality,
            "optimizationPlan": optimization,
            "acceptanceCriteria": acceptance,
            "wouldWrite": False,
        }

    def discoverability_intake_gate(self, payload: dict[str, Any]) -> dict[str, Any]:
        fields = self._discoverability_gate_fields(payload, {
            "source_caption",
            "source_prompt",
            "content_perception",
            "reference_caption",
        })
        return self._discoverability_gate_result("intake", fields)

    def discoverability_generation_gate(self, payload: dict[str, Any]) -> dict[str, Any]:
        fields = self._discoverability_gate_fields(payload, {
            "source_caption",
            "source_prompt",
            "content_perception",
            "reference_caption",
            "prompt",
            "hook",
            "hooks",
            "generated_caption",
            "caption_text",
            "caption_cta",
            "instagram_post_caption",
        })
        return self._discoverability_gate_result("generation", fields)

    def discoverability_pre_render_gate(self, payload: dict[str, Any]) -> dict[str, Any]:
        fields = self._discoverability_gate_fields(payload, set(payload.keys()))
        return self._discoverability_gate_result("pre_render", fields)

    def discoverability_violation_origin_map(self) -> dict[str, Any]:
        evidence = self._parent_factory_captured_discoverability_evidence()
        fallback = self._parent_factory_observed_discoverability_terms()
        source = evidence or fallback
        stages: dict[str, int] = {
            "source_content_perception": 0,
            "prompt_generation": 0,
            "caption_generation": 0,
            "burned_caption_generation": 0,
            "caption_family_generation": 0,
            "parent_registration": 0,
            "publishability_validation": 0,
        }
        for item in source:
            stage = self._discoverability_origin_stage(str(item.get("sourceField") or ""), str(item.get("reason") or ""))
            stages[stage] = stages.get(stage, 0) + 1
        if not any(stages.values()):
            stages["publishability_validation"] = int(self.parent_factory_discoverability_loss_analysis().get("discoverabilityStageLoss") or 0)
        total = sum(stages.values())
        before_render = sum(stages[name] for name in ("source_content_perception", "prompt_generation", "caption_generation", "caption_family_generation"))
        before_registration = before_render + stages["burned_caption_generation"]
        first = next((stage for stage, count in stages.items() if count > 0), "publishability_validation")
        earliest = first if first != "publishability_validation" else "caption_generation"
        return {
            "schema": "creator_os.discoverability_violation_origin_map.v1",
            "whereViolationsFirstAppear": first,
            "earliestPreventableStage": earliest,
            "percentPreventableBeforeRender": round((before_render / total) * 100, 1) if total else 0,
            "percentPreventableBeforeRegistration": round((before_registration / total) * 100, 1) if total else 0,
            "stageCounts": stages,
            "evidenceSource": "captured_rejection_evidence" if evidence else "observed_caption_scan",
            "wouldWrite": False,
        }

    def parent_factory_recoverable_yield(self) -> dict[str, Any]:
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        counts = {row["stage"]: int(row.get("outputCount") or 0) for row in waterfall.get("stages") or []}
        raw = max(1, int(counts.get("raw_candidate") or 0))
        discoverability_in = int(next((row.get("inputCount") for row in waterfall.get("stages") or [] if row.get("stage") == "discoverability_safety_pass"), 0) or 0)
        publishability_in = int(next((row.get("inputCount") for row in waterfall.get("stages") or [] if row.get("stage") == "publishability_pass"), 0) or 0)
        accepted = int(counts.get("parent_accepted") or 0)
        discoverability_fixed = max(accepted, discoverability_in)
        publishability_fixed = max(accepted, publishability_in)
        both_fixed = max(discoverability_fixed, publishability_fixed)
        return {
            "schema": "creator_os.parent_factory_recoverable_yield.v1",
            "currentYieldPct": round(self._ratio(accepted, raw) * 100, 1),
            "yieldIfDiscoverabilityFixed": round(self._ratio(discoverability_fixed, raw) * 100, 1),
            "yieldIfPublishabilityFixed": round(self._ratio(publishability_fixed, raw) * 100, 1),
            "yieldIfBothFixed": round(self._ratio(both_fixed, raw) * 100, 1),
            "expectedAcceptedParentsPerDay": both_fixed,
            "requiredRawCandidatesFor53Parents": math.ceil(53 / max(0.0001, self._ratio(both_fixed, raw))),
            "measured": True,
            "wouldWrite": False,
        }

    def parent_factory_throughput_recovery_plan(self) -> dict[str, Any]:
        recovery = self.parent_factory_recoverable_yield()
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        counts = {row["stage"]: int(row.get("outputCount") or 0) for row in waterfall.get("stages") or []}
        current = int(counts.get("parent_accepted") or 0)
        loss = self.parent_factory_loss_analysis(required_parents_per_day=53)
        expected_gain = max(0, int(recovery.get("expectedAcceptedParentsPerDay") or 0) - current)
        return {
            "schema": "creator_os.parent_factory_throughput_recovery_plan.v1",
            "requiredParentsPerDay": 53,
            "currentParentsPerDay": current,
            "gap": max(0, 53 - current),
            "largestLossStage": loss.get("largestLossStage") or "",
            "highestROIRepair": "move_discoverability_policy_to_generation_and_pre_render_gates",
            "expectedGainFromRepair": expected_gain,
            "wouldWrite": False,
        }

    def parent_factory_53_parent_feasibility(self) -> dict[str, Any]:
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        raw = int((waterfall.get("stages") or [{}])[0].get("outputCount") or 0)
        recovery = self.parent_factory_recoverable_yield()
        required_yield = round((53 / max(1, raw)) * 100, 1)
        fixed_yield = float(recovery.get("yieldIfBothFixed") or 0)
        return {
            "schema": "creator_os.parent_factory_53_parent_feasibility.v1",
            "canReach53ParentsWithoutMoreCandidates": int(recovery.get("currentYieldPct") or 0) >= required_yield,
            "canReach53ParentsWithYieldImprovements": fixed_yield >= required_yield,
            "minimumYieldRequired": required_yield,
            "minimumCandidatesRequired": raw,
            "highestROIChange": "discoverability_pre_render_gate",
            "recommendedNextImplementation": "enforce discoverability_generation_gate before caption render and parent registration",
            "wouldWrite": False,
        }

    def parent_factory_secondary_loss_analysis(self) -> dict[str, Any]:
        current = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        after = self.parent_factory_waterfall_after_discoverability()
        ranked = [
            {
                "stage": row["stage"],
                "lossCount": int(row.get("lossCount") or 0),
                "yieldPct": row.get("yieldPct"),
                "reason": self._secondary_loss_reason(row["stage"], int(row.get("lossCount") or 0)),
                "wouldWrite": False,
            }
            for row in after.get("stages") or []
            if row["stage"] != "raw_candidate"
        ]
        ranked = sorted(ranked, key=lambda row: (-int(row["lossCount"]), str(row["stage"])))
        measured_loss = ranked[0] if ranked and int(ranked[0].get("lossCount") or 0) > 0 else None
        next_stage = measured_loss["stage"] if measured_loss else "none_measured_after_discoverability"
        next_bottleneck = measured_loss["reason"] if measured_loss else "downstream_sample_size_uncertainty"
        model = self.parent_factory_true_yield_model()
        return {
            "schema": "creator_os.parent_factory_secondary_loss_analysis.v1",
            "discoverabilityRemoved": True,
            "newLargestLossStage": next_stage,
            "nextBottleneck": next_bottleneck,
            "rankedLossStages": ranked,
            "currentYieldPct": current["overallYieldPct"],
            "realisticYieldAfterDiscoverabilityRepair": model["realisticYieldAfterDiscoverabilityRepair"],
            "requiredCandidatesFor53Parents": model["requiredCandidatesFor53Parents"],
            "highestROIAfterDiscoverability": "increase downstream sample size with a measured recovered-candidate trial",
            "wouldWrite": False,
        }

    def parent_factory_waterfall_after_discoverability(self) -> dict[str, Any]:
        current = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        current_stages = current.get("stages") or []
        raw = int(current_stages[0].get("outputCount") or 0) if current_stages else 0
        stages = []
        previous = raw
        for row in current_stages:
            stage = row["stage"]
            if stage == "discoverability_safety_pass":
                continue
            if stage == "raw_candidate":
                output = raw
            elif stage in {"publishability_pass", "handoff_ready", "schedule_safe", "parent_accepted"}:
                output = previous
            else:
                output = int(row.get("outputCount") or 0)
            stages.append({
                "stage": stage,
                "inputCount": previous if stage != "raw_candidate" else output,
                "outputCount": output,
                "yieldPct": round(self._ratio(output, previous if stage != "raw_candidate" else output) * 100, 1),
                "lossCount": max(0, (previous if stage != "raw_candidate" else output) - output),
                "wouldWrite": False,
            })
            previous = output
        downstream = self._post_discoverability_downstream_confidence()
        return {
            "schema": "creator_os.parent_factory_waterfall_after_discoverability.v1",
            "discoverabilityRemoved": True,
            "stages": stages,
            "theoreticalAcceptedParents": previous,
            "downstreamEvidence": downstream,
            "wouldWrite": False,
        }

    def parent_factory_true_yield_model(self) -> dict[str, Any]:
        current = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        stages = current.get("stages") or []
        raw = int(stages[0].get("outputCount") or 0) if stages else 0
        accepted = int(stages[-1].get("outputCount") or 0) if stages else 0
        downstream = self._post_discoverability_downstream_confidence()
        realistic_accepts = math.floor(raw * downstream["confidenceAdjustedPassRate"])
        realistic_yield = round(self._ratio(realistic_accepts, raw) * 100, 1)
        theoretical = self.parent_factory_recoverable_yield()
        return {
            "schema": "creator_os.parent_factory_true_yield_model.v1",
            "discoverabilityRemoved": True,
            "currentYieldPct": round(self._ratio(accepted, raw) * 100, 1),
            "theoreticalUpperBoundYieldPct": theoretical["yieldIfDiscoverabilityFixed"],
            "realisticYieldAfterDiscoverabilityRepair": realistic_yield,
            "acceptedParentsPer245Candidates": realistic_accepts,
            "requiredCandidatesFor53Parents": math.ceil(53 / max(0.0001, realistic_yield / 100)),
            "downstreamEvidence": downstream,
            "modelNote": "confidence_adjusted_downstream_pass_rate_from_clean_candidates",
            "wouldWrite": False,
        }

    def parent_factory_realistic_53_parent_plan(self) -> dict[str, Any]:
        secondary = self.parent_factory_secondary_loss_analysis()
        model = self.parent_factory_true_yield_model()
        accepted = int(model.get("acceptedParentsPer245Candidates") or 0)
        return {
            "schema": "creator_os.parent_factory_realistic_53_parent_plan.v1",
            "discoverabilityRemoved": True,
            "newLargestLossStage": secondary["newLargestLossStage"],
            "expectedRealYieldPct": model["realisticYieldAfterDiscoverabilityRepair"],
            "acceptedParentsPer245Candidates": accepted,
            "canReach53Parents": accepted >= 53,
            "nextBottleneck": secondary["nextBottleneck"],
            "rankedLossStages": secondary["rankedLossStages"],
            "currentYieldPct": model["currentYieldPct"],
            "realisticYieldAfterDiscoverabilityRepair": model["realisticYieldAfterDiscoverabilityRepair"],
            "requiredCandidatesFor53Parents": model["requiredCandidatesFor53Parents"],
            "highestROIAfterDiscoverability": secondary["highestROIAfterDiscoverability"],
            "wouldWrite": False,
        }

    def exception_queue_report(
        self,
        *,
        daily_plan: dict[str, Any] | None = None,
        execution_readiness: dict[str, Any] | None = None,
        publishability_report: dict[str, Any] | None = None,
        surface_readiness_report: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        exceptions: list[dict[str, Any]] = []
        daily = daily_plan or {}
        readiness = execution_readiness or {}
        for account in daily.get("accounts") or []:
            if not isinstance(account, dict):
                continue
            reason = str(account.get("blockedReason") or "")
            if str(account.get("state") or "") == "blocked" and reason:
                exceptions.append(self._exception_queue_item(
                    severity="high",
                    system="account_health",
                    account=account.get("accountId"),
                    asset="",
                    reason=reason,
                    next_action="resolve_account_blocker",
                ))
        for creator in daily.get("creators") or []:
            if not isinstance(creator, dict):
                continue
            shortfall = int(creator.get("inventoryShortfall") or 0)
            if shortfall > 0:
                exceptions.append(self._exception_queue_item(
                    severity="critical",
                    system="inventory",
                    account="",
                    asset="",
                    reason="inventory_shortfall",
                    next_action="create_or_import_schedule_safe_inventory",
                    count=shortfall,
                ))
            for surface, row in (creator.get("surfaceShortfalls") or {}).items():
                if isinstance(row, dict) and int(row.get("shortfall") or 0) > 0:
                    exceptions.append(self._exception_queue_item(
                        severity="high",
                        system="surface_inventory",
                        account="",
                        asset="",
                        reason=f"{normalize_content_surface(surface)}_inventory_shortfall",
                        next_action="fill_surface_inventory_buffer",
                        count=int(row.get("shortfall") or 0),
                    ))
        for blocker in readiness.get("blockers") or []:
            exceptions.append(self._exception_queue_item(
                severity=self._exception_severity_for_reason(str(blocker)),
                system="execution_readiness",
                account="",
                asset="",
                reason=str(blocker),
                next_action=self._exception_next_action(str(blocker)),
            ))
        for source, system in ((publishability_report or {}, "publishability"), (surface_readiness_report or {}, "surface_readiness")):
            for item in source.get("assets") or source.get("items") or []:
                if not isinstance(item, dict):
                    continue
                for reason in item.get("blockingReasons") or item.get("failureReasons") or []:
                    exceptions.append(self._exception_queue_item(
                        severity=self._exception_severity_for_reason(str(reason)),
                        system=system,
                        account=item.get("accountId") or "",
                        asset=item.get("assetId") or item.get("renderedAssetId") or "",
                        reason=str(reason),
                        next_action=self._exception_next_action(str(reason)),
                    ))
        return {
            "schema": "creator_os.exception_queue_report.v1",
            "exceptionCount": len(exceptions),
            "exceptions": exceptions,
            "wouldWrite": False,
        }

    def exception_queue_summary(self, **kwargs: Any) -> dict[str, Any]:
        report = self.exception_queue_report(**kwargs)
        by_severity: dict[str, int] = {}
        by_system: dict[str, int] = {}
        by_owner: dict[str, int] = {}
        for item in report.get("exceptions") or []:
            severity = str(item.get("severity") or "low")
            system = str(item.get("system") or "unknown")
            owner = str(item.get("owner") or "operator")
            by_severity[severity] = by_severity.get(severity, 0) + 1
            by_system[system] = by_system.get(system, 0) + 1
            by_owner[owner] = by_owner.get(owner, 0) + 1
        return {
            "schema": "creator_os.exception_queue_summary.v1",
            "exceptionCount": int(report.get("exceptionCount") or 0),
            "bySeverity": dict(sorted(by_severity.items())),
            "bySystem": dict(sorted(by_system.items())),
            "byOwner": dict(sorted(by_owner.items())),
            "largestQueue": max(by_system.items(), key=lambda item: item[1])[0] if by_system else "",
            "wouldWrite": False,
        }

    def exception_queue_priority_report(self, **kwargs: Any) -> dict[str, Any]:
        report = self.exception_queue_report(**kwargs)
        rank = {"critical": 0, "high": 1, "medium": 2, "low": 3}
        exceptions = sorted(
            report.get("exceptions") or [],
            key=lambda item: (
                rank.get(str(item.get("severity") or "low"), 9),
                -int(item.get("blockingInventory") or 0),
                -int(item.get("blockingAccounts") or 0),
                str(item.get("exceptionId") or ""),
            ),
        )
        return {
            "schema": "creator_os.exception_queue_priority_report.v1",
            "exceptionCount": len(exceptions),
            "exceptions": exceptions,
            "topPriority": exceptions[0] if exceptions else None,
            "wouldWrite": False,
        }

    def exception_queue_owner_report(self, **kwargs: Any) -> dict[str, Any]:
        report = self.exception_queue_report(**kwargs)
        grouped: dict[str, dict[str, Any]] = {}
        for item in report.get("exceptions") or []:
            owner = str(item.get("owner") or "operator")
            row = grouped.setdefault(owner, {
                "owner": owner,
                "exceptionCount": 0,
                "critical": 0,
                "high": 0,
                "medium": 0,
                "low": 0,
                "estimatedResolutionMinutes": 0,
                "blockingAccounts": 0,
                "blockingInventory": 0,
                "nextActions": [],
                "wouldWrite": False,
            })
            severity = str(item.get("severity") or "low")
            row["exceptionCount"] += 1
            if severity in {"critical", "high", "medium", "low"}:
                row[severity] += 1
            row["estimatedResolutionMinutes"] += int(item.get("estimatedResolutionMinutes") or 0)
            row["blockingAccounts"] += int(item.get("blockingAccounts") or 0)
            row["blockingInventory"] += int(item.get("blockingInventory") or 0)
            action = str(item.get("nextAction") or "")
            if action and action not in row["nextActions"]:
                row["nextActions"].append(action)
        owners = sorted(grouped.values(), key=lambda row: (-int(row["critical"]), -int(row["high"]), -int(row["exceptionCount"]), row["owner"]))
        return {
            "schema": "creator_os.exception_queue_owner_report.v1",
            "owners": owners,
            "wouldWrite": False,
        }

    def parent_factory_autopilot_plan(
        self,
        *,
        accounts: int = 200,
        posts_per_account_per_day: int = 3,
    ) -> dict[str, Any]:
        production = self.inventory_production_requirements(accounts=accounts, posts_per_account_per_day=posts_per_account_per_day)
        required_parents = int(production.get("requiredParentsPerDay") or 0)
        metrics = self._reel_factory_parent_metrics()
        available = int(metrics.get("scheduleSafe") or 0)
        waterfall = self.parent_factory_yield_waterfall(required_parents_per_day=max(1, required_parents or 1))
        shortfall = max(0, required_parents - available)
        return {
            "schema": "creator_os.parent_factory_autopilot_plan.v1",
            "requiredParentsToday": required_parents,
            "availableParents": available,
            "shortfall": shortfall,
            "requiredRawCandidates": int(waterfall.get("requiredRawCandidatesPerDay") or required_parents),
            "requiredCaptionFamilies": required_parents,
            "requiredVariants": int(production.get("requiredVariantsPerDay") or 0),
            "requiredValidatedDrafts": int(production.get("requiredValidatedDraftsPerDay") or 0),
            "largestBottleneck": self.parent_factory_loss_analysis(required_parents_per_day=max(1, required_parents or 1)).get("largestLossStage"),
            "nextAction": "produce_or_import_parent_reels" if shortfall else "hold_parent_factory",
            "wouldWrite": False,
        }

    def parent_factory_shortfall_report(self, **kwargs: Any) -> dict[str, Any]:
        plan = self.parent_factory_autopilot_plan(**kwargs)
        return {
            **plan,
            "schema": "creator_os.parent_factory_shortfall_report.v1",
            "canMeetToday": int(plan.get("shortfall") or 0) == 0,
            "wouldWrite": False,
        }

    def parent_factory_production_targets(self, **kwargs: Any) -> dict[str, Any]:
        plan = self.parent_factory_autopilot_plan(**kwargs)
        return {
            "schema": "creator_os.parent_factory_production_targets.v1",
            "requiredParentsToday": plan["requiredParentsToday"],
            "requiredRawCandidates": plan["requiredRawCandidates"],
            "requiredCaptionFamilies": plan["requiredCaptionFamilies"],
            "requiredVariants": plan["requiredVariants"],
            "dailyTargets": {
                "parents": plan["requiredParentsToday"],
                "rawCandidates": plan["requiredRawCandidates"],
                "captionFamilies": plan["requiredCaptionFamilies"],
                "variants": plan["requiredVariants"],
            },
            "wouldWrite": False,
        }

    def inventory_autopilot_plan(
        self,
        *,
        accounts: int = 200,
        posts_per_account_per_day: int = 3,
        available_inventory: int = 0,
        buffer_target_days: int = 3,
        surface: str = "reel",
    ) -> dict[str, Any]:
        daily_demand = max(0, int(accounts or 0)) * max(0, int(posts_per_account_per_day or 0))
        policy = self.inventory_buffer_policy_plan(
            creator="All",
            surface=surface,
            daily_demand=daily_demand,
            buffer_target_days=buffer_target_days,
            available_inventory=available_inventory,
        )
        days_remaining = round(max(0, int(available_inventory or 0)) / max(1, daily_demand), 2)
        repair_actions = self._inventory_repair_actions(policy)
        return {
            "schema": "creator_os.inventory_autopilot_plan.v1",
            "surface": normalize_content_surface(surface),
            "dailyDemand": daily_demand,
            "requiredInventory": policy["requiredInventory"],
            "availableInventory": policy["availableInventory"],
            "shortfall": policy["shortfall"],
            "daysRemaining": days_remaining,
            "health": policy["health"],
            "repairActions": repair_actions,
            "wouldWrite": False,
        }

