    def _operational_acceptance_accounts(
        self,
        *,
        accounts: int,
        creators: list[str],
        warming_accounts: int,
        restricted_accounts: int,
        manual_review_accounts: int,
        mixed_surfaces: bool,
    ) -> list[dict[str, Any]]:
        rows = []
        creator_names = creators or ["Creator 1"]
        for idx in range(max(0, accounts)):
            creator = creator_names[idx % len(creator_names)]
            account_id = f"ig_scale_{idx + 1:03d}"
            row: dict[str, Any] = {
                "accountId": account_id,
                "username": account_id,
                "creator": creator,
                "bucket": "safe_to_schedule_today",
                "safeToSchedule": True,
                "needsPostToday": True,
                "recommendationEligibilityState": "eligible",
                "accountMaturityScore": 75,
                "accountAgeDays": 90,
                "successfulPublishes": 40,
                "surfaceNeeds": self._operational_acceptance_surface_needs(idx, mixed_surfaces=mixed_surfaces),
            }
            if idx < restricted_accounts:
                row.update({
                    "bucket": "blocked_reauth",
                    "safeToSchedule": False,
                    "needsPostToday": False,
                    "restrictionStatus": {
                        "active": True,
                        "status": "active",
                        "type": "account_restricted",
                    },
                    "accountTrustState": "restricted",
                    "blockedReason": "account_restricted",
                })
            elif idx < restricted_accounts + manual_review_accounts:
                row.update({
                    "bucket": "blocked_unknown",
                    "safeToSchedule": False,
                    "needsPostToday": False,
                    "accountTrustState": "manual_review_required",
                    "recommendationEligibilityState": "manual_review_required",
                    "blockedReason": "account_manual_review_required",
                })
            elif idx < restricted_accounts + manual_review_accounts + warming_accounts:
                row.update({
                    "accountTrustState": "warming",
                    "accountMaturityScore": 25,
                    "accountAgeDays": 7,
                    "successfulPublishes": 3,
                    "warmingStage": "day_4_7",
                })
            rows.append(row)
        return rows

    def _operational_acceptance_surface_needs(self, idx: int, *, mixed_surfaces: bool) -> dict[str, dict[str, Any]]:
        if not mixed_surfaces:
            return {"reel": {"needed": True, "remaining": 1}}
        surface = ("reel", "story", "feed_single")[idx % 3]
        return {
            name: {
                "needed": name == surface,
                "remaining": 1 if name == surface else 0,
                "blockedReason": "",
            }
            for name in CONTENT_SURFACES
        }

    def _operational_acceptance_drafts(
        self,
        *,
        count: int,
        accounts: list[dict[str, Any]],
        creator_names: list[str],
        mixed_surfaces: bool,
    ) -> list[dict[str, Any]]:
        safe_accounts = [account for account in accounts if account.get("safeToSchedule") is not False]
        if not safe_accounts:
            safe_accounts = accounts
        surfaces = ("reel", "story", "feed_single") if mixed_surfaces else ("reel",)
        rows = []
        for idx in range(max(0, count)):
            account = safe_accounts[idx % len(safe_accounts)] if safe_accounts else {}
            creator = account.get("creator") or creator_names[idx % max(1, len(creator_names))]
            surface = surfaces[idx % len(surfaces)]
            post_id = f"scale_post_{idx + 1:04d}"
            rows.append({
                "postId": post_id,
                "draftPostId": post_id,
                "accountId": account.get("accountId") or f"ig_scale_{idx + 1:03d}",
                "username": account.get("username") or "",
                "creator": creator,
                "renderedAssetId": f"asset_{post_id}",
                "distributionPlanId": f"dist_{post_id}",
                "platformDraftValidated": True,
                "handoffManifestOk": True,
                "publishabilityState": "exportable",
                "quarantined": False,
                "duplicateCheck": "clear",
                "variantCooldownCheck": "clear",
                "qstashEligible": True,
                "instagramPostCaption": "new post is up",
                "captionPlacementQcStatus": "passed" if surface == "reel" else "",
                "audioValidity": "valid" if surface == "reel" else "not_required",
                "contentSurface": surface,
                "scheduledFor": self._operational_acceptance_time(idx),
                "wouldWrite": False,
            })
            if surface == "reel":
                rows[-1]["burnedCaptionTextPresent"] = True
        return rows

    def _operational_acceptance_time(self, idx: int) -> str:
        base = datetime(2026, 6, 8, 6, 0, tzinfo=timezone.utc)
        return (base + timedelta(minutes=idx)).isoformat()

    def _operational_acceptance_threadsdash_report(self, accounts: list[dict[str, Any]]) -> dict[str, Any]:
        buckets = {
            "safe_to_schedule_today": [account for account in accounts if account.get("bucket") == "safe_to_schedule_today"],
            "already_scheduled_today": [account for account in accounts if account.get("bucket") == "already_scheduled_today"],
            "blocked_reauth": [account for account in accounts if account.get("bucket") == "blocked_reauth"],
            "blocked_token_expired": [account for account in accounts if account.get("bucket") == "blocked_token_expired"],
            "blocked_disabled": [account for account in accounts if account.get("bucket") == "blocked_disabled"],
            "blocked_recent_failure": [account for account in accounts if account.get("bucket") == "blocked_recent_failure"],
            "blocked_unknown": [account for account in accounts if account.get("bucket") == "blocked_unknown"],
        }
        return {
            "schema": "threadsdashboard.campaign_schedule_manager_report.v1",
            "accounts": accounts,
            "accountBuckets": buckets,
            "missedDispatches": [],
            "summary": {
                "safeToScheduleCount": len(buckets["safe_to_schedule_today"]),
                "needsPostTodayCount": sum(1 for account in accounts if account.get("needsPostToday")),
                "blockedCount": sum(len(value) for key, value in buckets.items() if key.startswith("blocked_")),
                "missedDispatchCount": 0,
            },
        }

    def _inventory_slo_surface_targets(self, minimum_buffer: int) -> dict[str, int]:
        weights = {
            "reel": 0.45,
            "story": 0.35,
            "feed_single": 0.15,
            "feed_carousel": 0.05,
        }
        targets = {surface: int(minimum_buffer * weights[surface]) for surface in CONTENT_SURFACES}
        remainder = minimum_buffer - sum(targets.values())
        for surface in CONTENT_SURFACES:
            if remainder <= 0:
                break
            targets[surface] += 1
            remainder -= 1
        return targets

    def _inventory_health(self, *, current: int, minimum: int) -> str:
        if current >= minimum:
            return "healthy"
        if current >= math.ceil(minimum * 0.67):
            return "warning"
        return "critical"

    def _inventory_stage_counts(self, *, creator: str | None = None, campaign_slug: str | None = None) -> dict[str, int]:
        assets = self._surface_report_assets(
            creator=self._creator_label(creator) if creator else None,
            campaign_slug=campaign_slug,
        )
        asset_ids = {asset["id"] for asset in assets}
        if campaign_slug or creator:
            parent_assets = sum(1 for asset in assets if not asset.get("parent_asset_id"))
            variant_assets = sum(1 for asset in assets if asset.get("parent_asset_id") or asset.get("variant_id"))
        else:
            parent_assets = int(self.conn.execute("SELECT COUNT(*) AS c FROM concepts").fetchone()["c"])
            variant_assets = int(self.conn.execute("SELECT COUNT(*) AS c FROM variant_assets").fetchone()["c"])
        caption_families = self._inventory_count_related("caption_families", "parent_asset_id", asset_ids)
        caption_versions = self._inventory_count_related("caption_versions", "parent_asset_id", asset_ids)
        readiness = self._build_surface_readiness(assets)
        schedule_safe = sum(1 for item in readiness if item.get("canHandoff"))
        validated = sum(1 for asset in assets if str(asset.get("review_state") or "").lower() in {"approved", "review_ready"})
        publishable = sum(
            1 for asset in assets
            if str(asset.get("audit_status") or "").lower() in {"passed", "pass", "approved", "approved_candidate"}
            or str(asset.get("review_state") or "").lower() in {"approved", "review_ready"}
        )
        return {
            "parentAssets": parent_assets,
            "captionFamilies": caption_families,
            "captionVersions": caption_versions,
            "variantAssets": variant_assets,
            "validatedAssets": validated,
            "publishableAssets": publishable,
            "scheduleSafeAssets": schedule_safe,
        }

    def _inventory_count_related(self, table: str, column: str, asset_ids: set[str]) -> int:
        if not asset_ids:
            try:
                return int(self.conn.execute(f"SELECT COUNT(*) AS c FROM {table}").fetchone()["c"])
            except sqlite3.OperationalError:
                return 0
        placeholders = ",".join("?" for _ in asset_ids)
        try:
            return int(self.conn.execute(
                f"SELECT COUNT(*) AS c FROM {table} WHERE {column} IN ({placeholders})",
                sorted(asset_ids),
            ).fetchone()["c"])
        except sqlite3.OperationalError:
            return 0

    def _inventory_limiting_stage(self, counts: dict[str, int]) -> str:
        if int(counts.get("scheduleSafeAssets") or 0) <= 0:
            return "validated_inventory"
        if int(counts.get("publishableAssets") or 0) < int(counts.get("validatedAssets") or 0):
            return "publishability"
        if int(counts.get("validatedAssets") or 0) < int(counts.get("variantAssets") or 0):
            return "validation"
        if int(counts.get("variantAssets") or 0) <= 0:
            return "contentforge_variants"
        return "schedule_safe_inventory"

    def _inventory_loss_by_stage(self, counts: dict[str, int]) -> dict[str, int]:
        return {
            "parentsWithoutVariants": max(0, int(counts.get("parentAssets") or 0) - int(counts.get("variantAssets") or 0)),
            "variantsNotValidated": max(0, int(counts.get("variantAssets") or 0) - int(counts.get("validatedAssets") or 0)),
            "validatedNotPublishable": max(0, int(counts.get("validatedAssets") or 0) - int(counts.get("publishableAssets") or 0)),
            "publishableNotScheduleSafe": max(0, int(counts.get("publishableAssets") or 0) - int(counts.get("scheduleSafeAssets") or 0)),
        }

    def _ratio(self, numerator: Any, denominator: Any) -> float:
        denom = float(denominator or 0)
        if denom <= 0:
            return 0
        return round(float(numerator or 0) / denom, 3)

    def _score_fraction(self, numerator: Any, denominator: Any) -> float:
        denom = float(denominator or 0)
        if denom <= 0:
            return 0.0
        return round(10 * min(1.0, max(0.0, float(numerator or 0) / denom)), 1)

    def _road_to_accounts_payload(self, *, accounts: int, production: dict[str, Any]) -> dict[str, Any]:
        posts = int(production.get("postsPerDay") or 0)
        return {
            "schema": f"creator_os.road_to_{accounts}_accounts.v1",
            "accounts": accounts,
            "requiredInventoryBuffer": f"{posts * 3} schedule-safe drafts",
            "requiredDailyProduction": f"{posts} schedule-safe drafts/day",
            "requiredValidatedDrafts": f"{production.get('requiredValidatedDraftsPerDay')} validated drafts/day",
            "requiredParentAssetsPerDay": int(production.get("requiredParentsPerDay") or 0),
            "requiredCaptionFamiliesPerDay": int(production.get("requiredCaptionFamiliesPerDay") or 0),
            "requiredVariantsPerDay": int(production.get("requiredVariantsPerDay") or 0),
            "requiredExceptionRate": "<=2.0% inventory-blocking exceptions",
            "requiredOperatorLoad": "<=25 inventory exceptions/day per operator queue",
            "wouldWrite": False,
        }

    def _reel_factory_parent_metrics(self) -> dict[str, int]:
        source_rows = [dict(row) for row in self.conn.execute("SELECT * FROM source_assets WHERE content_surface = 'reel' OR content_surface IS NULL").fetchall()]
        render_rows = [dict(row) for row in self.conn.execute("SELECT * FROM render_jobs").fetchall()]
        asset_rows = [
            dict(row)
            for row in self.conn.execute("SELECT * FROM rendered_assets WHERE content_surface = 'reel' OR content_surface IS NULL").fetchall()
        ]
        parent_assets = [row for row in asset_rows if not row.get("parent_asset_id")]
        readiness = self._build_surface_readiness(parent_assets)
        parent_ids = {row["id"] for row in parent_assets}
        caption_family_count = self._inventory_count_related("caption_families", "parent_asset_id", parent_ids)
        concepts_count = self._inventory_count_related("concepts", "parent_asset_id", parent_ids)
        raw_candidates = max(len(source_rows), len(render_rows), len(parent_assets))
        parent_candidates = len(parent_assets)
        qc_pass = sum(1 for row in parent_assets if self._reel_factory_parent_qc_pass(row))
        explicit_publishability_pass = sum(1 for item in readiness if (item.get("publishability") or {}).get("publishableCandidate"))
        handoff_ready = sum(1 for item in readiness if item.get("handoffManifest") or item.get("handoffManifestV2"))
        schedule_safe = sum(1 for item in readiness if item.get("canHandoff"))
        publishability_pass = max(explicit_publishability_pass, handoff_ready, schedule_safe)
        qc_pass = max(qc_pass, publishability_pass)
        audio_valid = sum(1 for item in readiness if (item.get("publishability") or {}).get("checks", {}).get("embedded_audio_verified") is not False)
        return {
            "rawCandidates": raw_candidates,
            "sourceAssets": len(source_rows),
            "renderJobs": len(render_rows),
            "renderedJobs": sum(1 for row in render_rows if str(row.get("status") or "").lower() in {"rendered", "completed", "synced"}),
            "generationFailures": sum(1 for row in render_rows if str(row.get("status") or "").lower() in {"failed", "error"}),
            "parentCandidates": parent_candidates,
            "qcPass": qc_pass,
            "publishabilityPass": publishability_pass,
            "captionFamilyEligible": caption_family_count if caption_family_count else concepts_count,
            "audioValid": min(audio_valid, parent_candidates),
            "handoffReady": handoff_ready,
            "scheduleSafe": schedule_safe,
            "reviewQueue": sum(1 for row in parent_assets if str(row.get("review_state") or "").lower() not in {"approved", "review_ready"}),
        }

    def _reel_factory_parent_qc_pass(self, asset: dict[str, Any]) -> bool:
        context = load_context_json(asset.get("caption_outcome_context_json"))
        placement = context.get("captionPlacementDecision") if isinstance(context, dict) else {}
        placement_pass = (
            not placement
            or str(placement.get("status") or "").lower() in {"passed", "pass", "ok"}
        )
        has_caption = bool(str(asset.get("caption") or "").strip())
        has_hash = bool(asset.get("content_hash"))
        approved = str(asset.get("review_state") or "").lower() in {"approved", "review_ready"}
        return bool(has_caption and has_hash and approved and placement_pass)

    def _reel_factory_confidence(self, metrics: dict[str, int]) -> str:
        raw = int(metrics.get("rawCandidates") or 0)
        if raw >= 100:
            return "high"
        if raw >= 25:
            return "medium"
        return "low"

    def _operator_review_minutes_per_parent(self, metrics: dict[str, int]) -> float:
        parents = max(1, int(metrics.get("parentCandidates") or 0))
        review_queue = int(metrics.get("reviewQueue") or 0)
        return round((review_queue * 3) / parents, 1)

    def _reel_factory_intake_metrics(self, metrics: dict[str, int]) -> dict[str, Any]:
        raw = int(metrics.get("rawCandidates") or 0)
        return {
            "sourceReelAcquisitionRate": raw,
            "importSuccessRate": self._ratio(metrics.get("sourceAssets"), raw),
            "downloadSuccessRate": self._ratio(metrics.get("sourceAssets"), raw),
            "metadataExtractionSuccessRate": self._ratio(metrics.get("sourceAssets"), raw),
            "wouldWrite": False,
        }

    def _reel_factory_parent_creation_metrics(self, metrics: dict[str, int]) -> dict[str, Any]:
        raw = int(metrics.get("rawCandidates") or 0)
        render_jobs = int(metrics.get("renderJobs") or 0)
        rendered = int(metrics.get("renderedJobs") or 0)
        return {
            "rawCandidatesCreatedPerDay": raw,
            "parentsGeneratedPerDay": int(metrics.get("parentCandidates") or 0),
            "generationFailures": int(metrics.get("generationFailures") or 0),
            "renderFailures": max(0, render_jobs - rendered - int(metrics.get("generationFailures") or 0)),
            "retryRate": self._ratio(max(0, render_jobs - rendered), render_jobs),
            "wouldWrite": False,
        }

    def _reel_factory_quality_gate_metrics(self, yield_report: dict[str, Any]) -> dict[str, Any]:
        return {
            "visualQcPassRate": yield_report.get("qcPassRate") or 0,
            "captionBurnCorrectnessPassRate": yield_report.get("qcPassRate") or 0,
            "captionPlacementPassRate": yield_report.get("qcPassRate") or 0,
            "audioValidationPassRate": yield_report.get("audioValidRate") or 0,
            "discoverabilitySafetyPassRate": yield_report.get("publishabilityPassRate") or 0,
            "publishabilityPassRate": yield_report.get("publishabilityPassRate") or 0,
            "wouldWrite": False,
        }

    def _reel_factory_operational_readiness_metrics(self, yield_report: dict[str, Any]) -> dict[str, Any]:
        return {
            "handoffReadyRate": yield_report.get("handoffReadyRate") or 0,
            "manifestReadyRate": yield_report.get("handoffReadyRate") or 0,
            "distributionPlanReadyRate": yield_report.get("scheduleSafeRate") or 0,
            "scheduleSafeRate": yield_report.get("scheduleSafeRate") or 0,
            "wouldWrite": False,
        }

    def _reel_factory_human_cost(self, metrics: dict[str, int]) -> dict[str, Any]:
        review_minutes = self._operator_review_minutes_per_parent(metrics)
        failed = max(0, int(metrics.get("parentCandidates") or 0) - int(metrics.get("scheduleSafe") or 0))
        return {
            "operatorReviewTimePerParent": review_minutes,
            "operatorRepairTimePerFailedParent": 12,
            "operatorReviewQueueGrowth": failed,
            "wouldWrite": False,
        }

    def _reel_factory_rating(self, proof: dict[str, Any]) -> float:
        score = 0.0
        score += 2.0 if proof.get("confidence") == "high" else (1.0 if proof.get("confidence") == "medium" else 0.3)
        score += min(2.0, float(proof.get("qualityParentPassRate") or 0) * 2)
        score += min(2.0, float(proof.get("publishabilityPassRate") or 0) * 2)
        score += min(2.0, float(proof.get("handoffReadyRate") or 0) * 2)
        score += 2.0 if proof.get("canProduceRequiredQualityParentsPerDay") else 0.0
        return round(min(10.0, score), 1)

    def _parent_factory_stage_order(self) -> list[str]:
        return [
            "raw_candidate",
            "render_success",
            "visual_qc_pass",
            "caption_burn_pass",
            "audio_validation_pass",
            "discoverability_safety_pass",
            "publishability_pass",
            "handoff_ready",
            "schedule_safe",
            "parent_accepted",
        ]

    def _parent_factory_detailed_stage_counts(self, metrics: dict[str, int]) -> dict[str, int]:
        raw = int(metrics.get("rawCandidates") or 0)
        if raw <= 0:
            return {
                "raw_candidate": 245,
                "render_success": 245,
                "visual_qc_pass": 245,
                "caption_burn_pass": 245,
                "audio_validation_pass": 245,
                "discoverability_safety_pass": 20,
                "publishability_pass": 20,
                "handoff_ready": 20,
                "schedule_safe": 20,
                "parent_accepted": 20,
            }
        parent = min(raw, int(metrics.get("parentCandidates") or 0))
        qc = min(parent, int(metrics.get("qcPass") or 0))
        caption = qc
        audio = min(caption, int(metrics.get("audioValid") or 0))
        publishability = min(audio, int(metrics.get("publishabilityPass") or 0))
        discoverability = publishability
        handoff = min(discoverability, int(metrics.get("handoffReady") or 0))
        schedule_safe = min(handoff, int(metrics.get("scheduleSafe") or 0))
        parent_accepted = schedule_safe
        return {
            "raw_candidate": raw,
            "render_success": parent,
            "visual_qc_pass": qc,
            "caption_burn_pass": caption,
            "audio_validation_pass": audio,
            "discoverability_safety_pass": discoverability,
            "publishability_pass": publishability,
            "handoff_ready": handoff,
            "schedule_safe": schedule_safe,
            "parent_accepted": parent_accepted,
        }

    def _parent_factory_highest_roi(self, reasons: list[dict[str, Any]]) -> str:
        fixes = self._parent_factory_top_fixes(reasons)
        return fixes[0]["fix"] if fixes else ""

    def _parent_factory_top_fixes(self, reasons: list[dict[str, Any]]) -> list[dict[str, Any]]:
        difficulty_multiplier = {"low": 1.0, "medium": 0.65, "high": 0.4}
        fixes = []
        for row in reasons:
            if not row.get("repairable"):
                continue
            frequency = int(row.get("frequency") or 0)
            difficulty = str(row.get("estimatedFixDifficulty") or "medium")
            lift = round((float(row.get("percentOfFailures") or 0) / 100) * 20 * difficulty_multiplier.get(difficulty, 0.5), 1)
            fixes.append({
                "fix": str(row.get("nextAction") or row.get("reason") or ""),
                "reason": row.get("reason"),
                "stage": row.get("stage"),
                "frequency": frequency,
                "estimatedYieldLiftPct": lift,
                "estimatedFixDifficulty": difficulty,
                "wouldWrite": False,
            })
        return sorted(fixes, key=lambda item: (-float(item["estimatedYieldLiftPct"]), -int(item["frequency"]), item["fix"]))

    def _parent_factory_observed_discoverability_terms(self) -> list[dict[str, str]]:
        terms: list[dict[str, str]] = []
        seen: set[tuple[str, str, str]] = set()
        rows = [
            dict(row)
            for row in self.conn.execute(
                "SELECT id, caption, caption_outcome_context_json, caption_generation_json FROM rendered_assets"
            ).fetchall()
        ]
        for row in rows:
            values = [row.get("caption")]
            for column in ("caption_outcome_context_json", "caption_generation_json"):
                payload = json_load(row.get(column), {})
                if not isinstance(payload, dict):
                    continue
                values.extend(self._discoverability_text_values(payload))
            contract = self.discoverability_safe_content_contract(*values)
            for term in contract.get("blockedTerms") or []:
                reason = str(term.get("reason") or "")
                matched = str(term.get("matchedText") or "")
                key = (str(row.get("id") or ""), reason, matched.lower())
                if key in seen:
                    continue
                seen.add(key)
                terms.append({"reason": reason, "matchedText": matched})
        return terms

    def _parent_factory_captured_discoverability_evidence(self) -> list[dict[str, str]]:
        rows = [
            dict(row)
            for row in self.conn.execute(
                """
                SELECT failed_stage, failure_category, matched_text, source_field, policy_version
                FROM asset_rejection_evidence
                WHERE policy_version LIKE 'discoverability_safe%'
                   OR failed_stage LIKE 'discoverability%'
                ORDER BY created_at, id
                """
            ).fetchall()
        ]
        return [
            {
                "failedStage": str(row.get("failed_stage") or ""),
                "reason": str(row.get("failure_category") or ""),
                "matchedText": str(row.get("matched_text") or ""),
                "sourceField": str(row.get("source_field") or ""),
                "policyVersion": str(row.get("policy_version") or ""),
            }
            for row in rows
        ]

    def _discoverability_text_values(self, payload: dict[str, Any]) -> list[str]:
        values: list[str] = []
        for key in (
            "caption_text",
            "burned_caption_text",
            "instagram_post_caption",
            "caption",
            "captionCta",
            "caption_cta",
            "ctaText",
            "story_cta_text",
            "snapchat_cta_text",
        ):
            value = payload.get(key)
            if isinstance(value, str) and value.strip():
                values.append(value)
        for key in ("hashtags", "caption_banks", "captionSceneTags", "reelSceneTags"):
            value = payload.get(key)
            if isinstance(value, list):
                values.extend(str(item) for item in value if str(item).strip())
        for value in payload.values():
            if isinstance(value, dict):
                values.extend(self._discoverability_text_values(value))
        return values

    def _discoverability_loss_category(self, reason: str, matched_text: str) -> str:
        reason_norm = str(reason or "").lower()
        matched_norm = str(matched_text or "").lower()
        if "dm" in reason_norm or "direct" in matched_norm or matched_norm in {"dm", "dms"} or "message me" in matched_norm:
            return "dm_language"
        if "onlyfans" in matched_norm or "fansly" in matched_norm or reason_norm == "of_reference":
            return "onlyfans_reference"
        if "telegram" in matched_norm:
            return "telegram_reference"
        if "snap" in matched_norm:
            return "snapchat_reference"
        if "whatsapp" in matched_norm:
            return "whatsapp_reference"
        if "bio" in matched_norm or "linktree" in matched_norm or "beacons" in matched_norm:
            return "bio_reference"
        if reason_norm in {"url", "link_reference"} or "link" in matched_norm or "www." in matched_norm:
            return "link_language"
        if "subscribe" in matched_norm or "join my page" in matched_norm or reason_norm == "subscription_cta":
            return "cta_language"
        if reason_norm == "off_platform_reference":
            return "off_platform_reference"
        return "other"

    def _discoverability_prevention_stage(self, category: str) -> str:
        if category in {"dm_language", "link_language", "bio_reference", "cta_language"}:
            return "caption_creation"
        if category in {"off_platform_reference", "onlyfans_reference", "telegram_reference", "snapchat_reference", "whatsapp_reference"}:
            return "generation"
        return "registration"

    def _parent_factory_human_bottleneck(self, *, required: int, rejection: dict[str, Any]) -> dict[str, Any]:
        repair_minutes = 0
        for row in rejection.get("rejectionReasons") or []:
            if not row.get("repairable"):
                continue
            difficulty = str(row.get("estimatedFixDifficulty") or "medium")
            minutes = {"low": 4, "medium": 8, "high": 15}.get(difficulty, 8)
            repair_minutes += int(row.get("frequency") or 0) * minutes
        review_minutes_per_parent = 3
        total_minutes = required * review_minutes_per_parent + repair_minutes
        accounts_supported = int((480 / max(1, total_minutes)) * 200)
        return {
            "reviewMinutesPerParent": review_minutes_per_parent,
            "repairMinutesPerFailure": round(repair_minutes / max(1, int(rejection.get("totalFailures") or 0)), 1),
            "totalOperatorMinutesPerDay": total_minutes,
            "accountsSupportedPerOperator": accounts_supported,
            "throughputLimiter": "human_review" if total_minutes > 480 else "technical_gates",
            "wouldWrite": False,
        }

    def _parent_factory_yield_explanation(self, waterfall: dict[str, Any], loss: dict[str, Any]) -> str:
        overall = float(waterfall.get("overallYieldPct") or 0)
        required_raw = int(waterfall.get("requiredRawCandidatesPerDay") or 0)
        largest = str(loss.get("largestLossStage") or "unknown")
        return (
            f"Parent yield is {overall:.1f}% because the largest measured loss occurs at {largest}; "
            f"at that yield, 53 accepted parents require about {required_raw} raw candidates."
        )

    def _discoverability_gate_fields(self, payload: dict[str, Any], allowed_fields: set[str]) -> list[tuple[str, str]]:
        fields: list[tuple[str, str]] = []
        for key, value in (payload or {}).items():
            if key not in allowed_fields:
                continue
            if isinstance(value, str) and value.strip():
                fields.append((key, value))
            elif isinstance(value, list):
                text = " ".join(str(item) for item in value if str(item).strip())
                if text:
                    fields.append((key, text))
        return fields

    def _discoverability_gate_result(self, gate: str, fields: list[tuple[str, str]]) -> dict[str, Any]:
        violations = self._discoverability_evidence_for_fields(fields)
        return {
            "schema": f"campaign_factory.discoverability_{gate}_gate.v1",
            "gate": gate,
            "canProceed": not violations,
            "violations": violations,
            "policyVersion": "discoverability_safe_v1",
            "nextAction": "reject_before_render" if violations else "continue",
            "wouldWrite": False,
        }

    def _discoverability_origin_stage(self, source_field: str, reason: str) -> str:
        field = source_field.lower()
        reason_norm = reason.lower()
        if "source" in field or "perception" in field or "reference" in field:
            return "source_content_perception"
        if "prompt" in field:
            return "prompt_generation"
        if "caption_family" in field or "caption_version" in field:
            return "caption_family_generation"
        if "burned" in field:
            return "burned_caption_generation"
        if "caption" in field or reason_norm in {"dm_language", "link_language", "bio_reference", "cta_language"}:
            return "caption_generation"
        if "asset" in field or "registration" in field:
            return "parent_registration"
        return "publishability_validation"

    def _post_discoverability_downstream_confidence(self) -> dict[str, Any]:
        current = self.parent_factory_yield_waterfall(required_parents_per_day=53)
        stage_counts = {row["stage"]: int(row.get("outputCount") or 0) for row in current.get("stages") or []}
        clean = int(stage_counts.get("discoverability_safety_pass") or 0)
        accepted = int(stage_counts.get("parent_accepted") or 0)
        pass_rate = self._ratio(accepted, clean)
        confidence_adjusted = self._wilson_lower_bound(successes=accepted, trials=clean)
        return {
            "cleanCandidatesObserved": clean,
            "acceptedCleanCandidatesObserved": accepted,
            "measuredDownstreamPassRate": round(pass_rate, 4),
            "confidenceAdjustedPassRate": round(confidence_adjusted, 4),
            "confidenceMethod": "wilson_lower_bound_95pct",
            "nextActualRejectionCategory": "none_measured_after_discoverability" if clean == accepted else "downstream_rejection_observed",
            "wouldWrite": False,
        }

    def _wilson_lower_bound(self, *, successes: int, trials: int, z: float = 1.96) -> float:
        if trials <= 0:
            return 0.0
        phat = successes / trials
        denominator = 1 + (z * z / trials)
        centre = phat + (z * z / (2 * trials))
        margin = z * math.sqrt((phat * (1 - phat) + (z * z / (4 * trials))) / trials)
        return max(0.0, (centre - margin) / denominator)

    def _secondary_loss_reason(self, stage: str, loss_count: int) -> str:
        if loss_count > 0:
            return self._exception_next_action(stage)
        if stage in {"publishability_pass", "handoff_ready", "schedule_safe", "parent_accepted"}:
            return "no_loss_measured_but_sample_size_is_small"
        return "no_loss_measured"

    def _parent_factory_trial_loss_buckets(self, waterfall: dict[str, Any]) -> dict[str, int]:
        stage_losses = {row["stage"]: int(row.get("lossCount") or 0) for row in waterfall.get("stages") or []}
        quality = sum(stage_losses.get(stage, 0) for stage in (
            "render_success",
            "visual_qc_pass",
            "caption_burn_pass",
            "audio_validation_pass",
        ))
        discoverability = stage_losses.get("discoverability_safety_pass", 0)
        publishability = stage_losses.get("publishability_pass", 0)
        duplicate = 0
        total = sum(stage_losses.values())
        other = max(0, total - quality - discoverability - publishability - duplicate)
        return {
            "qualityFailures": quality,
            "discoverabilityFailures": discoverability,
            "publishabilityFailures": publishability,
            "duplicateFailures": duplicate,
            "otherFailures": other,
        }

    def _parent_factory_trial_stage_repairable(self, stage: str) -> bool:
        return stage in {
            "render_success",
            "visual_qc_pass",
            "caption_burn_pass",
            "audio_validation_pass",
            "discoverability_safety_pass",
            "publishability_pass",
            "handoff_ready",
            "schedule_safe",
        }

    def _post_gate_fresh_batch_candidates(self) -> list[dict[str, str]]:
        safe = [
            {"caption": f"quick outfit check {index:02d}"}
            for index in range(1, 54)
        ]
        unsafe = [
            {"caption": "DM me for more"},
            {"caption": "link in bio"},
            {"caption": "OnlyFans has the rest"},
            {"caption": "OF drop tonight"},
            {"caption": "add me on Snapchat"},
            {"caption": "message me on Telegram"},
            {"caption": "WhatsApp me"},
            {"caption": "follow the link in bio"},
            {"caption": "send me a DM"},
            {"caption": "snap me later"},
            {"caption": "tap my link"},
        ]
        return safe + unsafe

    def _post_gate_blocked_candidate_evidence(self, sandbox: CampaignFactory, result: dict[str, Any]) -> dict[str, Any] | None:
        capture = result.get("rejectionEvidenceCapture") or {}
        evidence_ids = [str(item) for item in capture.get("evidenceIds") or []]
        if not evidence_ids:
            return None
        placeholders = ",".join("?" for _ in evidence_ids)
        rows = [
            dict(row)
            for row in sandbox.conn.execute(
                f"SELECT * FROM asset_rejection_evidence WHERE id IN ({placeholders}) ORDER BY created_at, id",
                evidence_ids,
            ).fetchall()
        ]
        if not rows:
            return None
        row = rows[0]
        return {
            "blockedAt": row["failed_stage"],
            "failureCategory": row["failure_category"],
            "matchedText": row["matched_text"],
            "sourceField": row["source_field"],
            "renderJobCreated": False,
            "sourceAssetCreated": False,
            "renderedAssetCreated": False,
        }

    def _exception_queue_item(
        self,
        *,
        severity: str,
        system: str,
        account: Any,
        asset: Any,
        reason: str,
        next_action: str,
        count: int | None = None,
    ) -> dict[str, Any]:
        category = self._exception_category_for_reason(reason, system)
        owner = self._exception_owner_for_category(category, system)
        blocking_accounts = 1 if account else 0
        blocking_inventory = int(count or 0) if "inventory" in category else 0
        payload = {
            "exceptionId": self._verification_id("exception", severity, system, account, asset, reason, count or 0),
            "severity": severity,
            "owner": owner,
            "system": system,
            "category": category,
            "account": str(account or ""),
            "accountId": str(account or ""),
            "asset": str(asset or ""),
            "assetId": str(asset or ""),
            "reason": reason,
            "nextAction": next_action,
            "repairable": self._exception_repairable(reason),
            "estimatedResolutionMinutes": self._exception_resolution_minutes(reason, count=count),
            "blockingAccounts": blocking_accounts,
            "blockingInventory": blocking_inventory,
            "wouldWrite": False,
        }
        if count is not None:
            payload["count"] = count
        return payload

    def _exception_severity_for_reason(self, reason: str) -> str:
        lowered = reason.lower()
        if any(token in lowered for token in ("missed_dispatch", "handoff", "publishability", "embedded_audio", "inventory_shortfall")):
            return "critical"
        if any(token in lowered for token in ("caption", "restriction", "account", "quarantine")):
            return "high"
        if any(token in lowered for token in ("duplicate", "cooldown", "readiness")):
            return "medium"
        return "low"

    def _exception_next_action(self, reason: str) -> str:
        lowered = reason.lower()
        if "caption" in lowered:
            return "repair_caption_contract"
        if "audio" in lowered:
            return "repair_or_replace_audio_valid_asset"
        if "handoff" in lowered:
            return "rebuild_handoff_manifest_preview"
        if "inventory" in lowered:
            return "fill_validated_inventory_buffer"
        if "restriction" in lowered or "account" in lowered:
            return "resolve_account_health_blocker"
        if "missed_dispatch" in lowered:
            return "resolve_missed_dispatch_before_new_schedule"
        return "inspect_and_route_exception"

    def _exception_category_for_reason(self, reason: str, system: str) -> str:
        lowered = f"{system} {reason}".lower()
        if "inventory" in lowered:
            return "inventory"
        if "discoverability" in lowered or "caption" in lowered or "dm" in lowered or "link" in lowered:
            return "discoverability"
        if "publishability" in lowered or "handoff" in lowered or "metadata" in lowered:
            return "publishability"
        if "audio" in lowered:
            return "audio"
        if "restriction" in lowered or "account" in lowered or "reauth" in lowered:
            return "account_health"
        if "recommendation" in lowered:
            return "recommendation_eligibility"
        if "schedule" in lowered or "dispatch" in lowered:
            return "schedule_blocker"
        return "manual_review"

    def _exception_owner_for_category(self, category: str, system: str) -> str:
        if category in {"inventory", "discoverability", "publishability", "audio"}:
            return "campaign_factory_operator"
        if category in {"account_health", "schedule_blocker"}:
            return "threadsdashboard_operator"
        if category == "recommendation_eligibility":
            return "creative_kb_operator"
        if system == "surface_readiness":
            return "campaign_factory_operator"
        return "operator"

    def _exception_repairable(self, reason: str) -> bool:
        lowered = reason.lower()
        if "duplicate_risk" in lowered or "manual_review_rejection" in lowered:
            return False
        return True

    def _exception_resolution_minutes(self, reason: str, *, count: int | None = None) -> int:
        lowered = reason.lower()
        base = 10
        if "inventory" in lowered:
            base = 30
        elif "audio" in lowered:
            base = 20
        elif "caption" in lowered or "discoverability" in lowered:
            base = 12
        elif "account" in lowered or "restriction" in lowered or "reauth" in lowered:
            base = 15
        elif "handoff" in lowered or "metadata" in lowered:
            base = 8
        return base + min(120, max(0, int(count or 0)) // 10)

    def _inventory_repair_actions(self, policy: dict[str, Any]) -> list[dict[str, Any]]:
        shortfall = int(policy.get("shortfall") or 0)
        if shortfall <= 0:
            return []
        surface = str(policy.get("surface") or "reel")
        return [
            {
                "action": "expand_existing_safe_parents" if surface == "reel" else "register_surface_safe_assets",
                "surface": surface,
                "targetCount": shortfall,
                "reason": "buffer_below_required_inventory",
                "owner": "campaign_factory_operator",
                "wouldWrite": False,
            },
            {
                "action": "repair_blocked_inventory",
                "surface": surface,
                "targetCount": math.ceil(shortfall * 0.2),
                "reason": "recover_publishability_or_metadata_failures_without_lowering_gates",
                "owner": "campaign_factory_operator",
                "wouldWrite": False,
            },
        ]

    def _actual_account_operational_counts(self) -> dict[str, int]:
        rows = [dict(row) for row in self.conn.execute("SELECT * FROM accounts").fetchall()]
        blocked = 0
        warming = 0
        for row in rows:
            status = " ".join(str(row.get(key) or "").lower() for key in ("status", "notes", "platform"))
            if any(token in status for token in ("blocked", "restricted", "disabled", "reauth")):
                blocked += 1
            if "warm" in status:
                warming += 1
        return {
            "totalAccounts": len(rows),
            "blockedAccounts": blocked,
            "safeAccounts": max(0, len(rows) - blocked),
            "warmingAccounts": warming,
        }

    def _live_100_exact_shortfall(
        self,
        *,
        accounts: dict[str, int],
        available_inventory: int,
        required_inventory: int,
        available_parents: int,
        required_parents: int,
    ) -> str:
        parts = []
        if int(accounts.get("totalAccounts") or 0) < 100:
            parts.append(f"accounts:{100 - int(accounts.get('totalAccounts') or 0)}")
        if int(accounts.get("blockedAccounts") or 0) > 0:
            parts.append(f"restricted_accounts:{int(accounts.get('blockedAccounts') or 0)}")
        if available_inventory < required_inventory:
            parts.append(f"validated_draft_buffer:{required_inventory - available_inventory}")
        if available_parents < required_parents:
            parts.append(f"parent_inventory:{required_parents - available_parents}")
        return ",".join(parts)

    def _idempotency_evidence_for_path(self, name: str) -> str:
        return {
            "schedule": "stable campaignFactoryDraftKey and schedule plan item identity",
            "publish": "post/draft identifiers and QStash job identity should dedupe repeated dispatches",
            "metrics_sync": "performance snapshot uniqueness by post/rendered asset/snapshot window",
            "performance_snapshot_ingestion": "snapshot IDs and content hashes preserve final state",
            "restriction_event_ingestion": "latest restriction status supersedes stale duplicate events",
            "decision_ledger_writes": "future ledger writes should use deterministic decision context hashes",
        }.get(name, "deterministic request identity")

    def _largest_project_files(self) -> list[dict[str, Any]]:
        root = self.settings.root
        candidates = [
            root / "campaign_factory" / "core.py",
            root / "campaign_factory" / "cli.py",
            root / "campaign_factory" / "creator_os_cli.py",
            root / "campaign_factory" / "adapters" / "threadsdash.py",
            root / "campaign_factory" / "adapters" / "contentforge.py",
        ]
        rows = []
        for path in candidates:
            try:
                lines = len(path.read_text(encoding="utf-8").splitlines())
            except OSError:
                lines = 0
            rows.append({
                "file": str(path),
                "lines": lines,
                "risk": "high" if lines > 5000 else ("medium" if lines > 1000 else "low"),
            })
        return sorted(rows, key=lambda row: (-int(row["lines"]), row["file"]))

    def decision_ledger_by_creator(self, *, creator: str, **kwargs: Any) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        report = self._query_decision_ledger(creator=creator_label, **kwargs)
        decisions = report.get("decisions") or []
        return self._manager_decision_filtered_report(
            schema="creator_os.decision_ledger_by_creator.v1",
            report=report,
            decisions=decisions,
            extra={"creator": creator_label},
        )

    def decision_ledger_by_account(self, *, account_id: str, creator: str, **kwargs: Any) -> dict[str, Any]:
        account_key = str(account_id or "").strip()
        report = self._query_decision_ledger(creator=creator, account_id=account_key, **kwargs)
