    def prepare_reel_inputs(
        self,
        *,
        campaign_slug: str,
        hooks: list[str | dict[str, Any]],
        recipes: list[str] | None = None,
        caption_color: str | None = None,
        notes: str | None = None,
        force_new: bool = False,
    ) -> dict[str, Any]:
        if not hooks:
            raise ValueError("at least one hook is required")
        campaign = self.campaign_by_slug(campaign_slug)
        pipeline_job = self.create_pipeline_job(
            "prepare_reel",
            campaign["id"],
            {
                "campaign": campaign_slug,
                "hookCount": len(hooks),
                "recipes": recipes or [],
                "captionColor": caption_color or "auto",
                "notes": notes,
                "forceNew": force_new,
            },
        )
        self.start_pipeline_job(pipeline_job["id"])
        try:
            sources = [source for source in self.assets_for_campaign(campaign["id"]) if source.get("media_type") == "video"]
            if not sources:
                raise ValueError("no video sources available for reel input preparation")
            raw_dir = self.settings.reel_factory_root / "00_source_videos"
            cap_dir = self.settings.reel_factory_root / "01_captions"
            raw_dir.mkdir(parents=True, exist_ok=True)
            cap_dir.mkdir(parents=True, exist_ok=True)
            prepared = []
            reused_existing = []
            next_num = self._next_reel_clip_number(raw_dir)
            for source_index, source in enumerate(sources):
                existing = self.conn.execute("SELECT * FROM render_jobs WHERE source_asset_id = ?", (source["id"],)).fetchone()
                if existing and not force_new:
                    reused_existing.append(dict(existing))
                    continue
                clip_stem = f"clip_{next_num:03d}"
                next_num += 1
                src_path = Path(source["stored_path"])
                source_hooks = self._rotate_hooks_for_source(hooks, source_index)
                generation_gate = self.discoverability_generation_gate({"hook": source_hooks})
                if not generation_gate["canProceed"]:
                    capture = self._capture_discoverability_gate_rejection_evidence(
                        gate_result=generation_gate,
                        failed_stage="discoverability_generation_gate",
                        campaign_id=campaign["id"],
                        source_asset_id=source["id"],
                        content_surface="reel",
                        commit=False,
                    )
                    self.record_event(
                        "discoverability_generation_blocked",
                        campaign_id=campaign["id"],
                        source_asset_id=source["id"],
                        pipeline_job_id=pipeline_job["id"],
                        status="warning",
                        message=f"Render input blocked by discoverability generation gate: {source['id']}",
                        metadata={"capturedCount": capture["capturedCount"]},
                        commit=False,
                    )
                    self.conn.commit()
                    self.finish_pipeline_job(
                        pipeline_job["id"],
                        {"preparedCount": len(prepared), "blockedAt": "discoverability_generation_gate"},
                    )
                    return {
                        "campaign": campaign,
                        "prepared": prepared,
                        "reusedExisting": reused_existing,
                        "canProceed": False,
                        "blockedAt": "discoverability_generation_gate",
                        "discoverabilityGate": generation_gate,
                        "rejectionEvidenceCapture": capture,
                        "pipelineJobId": pipeline_job["id"],
                    }
                reel_video = raw_dir / f"{clip_stem}.mp4"
                shutil.copy2(src_path, reel_video)
                render_hooks, hook_metadata = self._reel_sidecar_hooks(source_hooks)
                sidecar = {
                    "hooks": render_hooks,
                    "recipes": recipes or None,
                    "caption_color": caption_color or "auto",
                    "notes": notes or f"campaign_factory source {source['id']}",
                }
                if hook_metadata:
                    sidecar["hook_metadata"] = hook_metadata
                (cap_dir / f"{clip_stem}.json").write_text(json.dumps(sidecar, indent=2, ensure_ascii=False), encoding="utf-8")
                job_id = new_id("render")
                now = utc_now()
                self.conn.execute(
                    """
                    INSERT INTO render_jobs
                    (id, campaign_id, source_asset_id, reel_clip_stem, hooks_json, recipes_json, caption_color, status, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 'prepared', ?, ?)
                    """,
                    (job_id, campaign["id"], source["id"], clip_stem, json.dumps(source_hooks, ensure_ascii=False), json.dumps(recipes or []), caption_color, now, now),
                )
                render_graph_id = self.ensure_graph_node(
                    "render_job",
                    local_table="render_jobs",
                    local_id=job_id,
                    payload={"campaignId": campaign["id"], "sourceAssetId": source["id"], "clip": clip_stem, "recipes": recipes or []},
                )
                self.ensure_graph_edge(
                    self.graph_id_for("source_assets", source["id"], entity_type="source_asset"),
                    render_graph_id,
                    "source_asset_to_render_job",
                    evidence={"clip": clip_stem, "pipelineJobId": pipeline_job["id"]},
                )
                prepared.append(dict(self.conn.execute("SELECT * FROM render_jobs WHERE id = ?", (job_id,)).fetchone()))
            result = {"campaign": campaign, "prepared": prepared, "reusedExisting": reused_existing}
            self.record_event(
                "reel_inputs_prepared",
                campaign_id=campaign["id"],
                pipeline_job_id=pipeline_job["id"],
                status="success",
                message=f"Prepared reel inputs for {len(prepared)} sources",
                metadata={
                    "sourceCount": len(sources),
                    "preparedCount": len(prepared),
                    "reusedExistingCount": len(reused_existing),
                    "hookCount": len(hooks),
                    "recipes": recipes or [],
                    "captionColor": caption_color or "auto",
                    "forceNew": force_new,
                },
                commit=False,
            )
            self.conn.commit()
            self.finish_pipeline_job(
                pipeline_job["id"],
                {"preparedCount": len(prepared), "reusedExistingCount": len(reused_existing), "sourceCount": len(sources)},
            )
            result["pipelineJobId"] = pipeline_job["id"]
            return result
        except Exception as exc:
            self.record_event(
                "reel_inputs_prepared",
                campaign_id=campaign["id"],
                pipeline_job_id=pipeline_job["id"],
                status="failure",
                message=f"Prepare reel inputs failed: {exc}",
                metadata={"error": str(exc)},
            )
            self.fail_pipeline_job(pipeline_job["id"], str(exc))
            raise

    def _rotate_hooks_for_source(self, hooks: list[str | dict[str, Any]], source_index: int) -> list[str | dict[str, Any]]:
        if len(hooks) <= 1:
            return list(hooks)
        offset = source_index % len(hooks)
        return [*hooks[offset:], *hooks[:offset]]

    def _reel_sidecar_hooks(self, hooks: list[str | dict[str, Any]]) -> tuple[list[str | dict[str, Any]], list[dict[str, Any]]]:
        render_hooks: list[str | dict[str, Any]] = []
        hook_metadata: list[dict[str, Any]] = []
        for idx, hook in enumerate(hooks):
            if isinstance(hook, dict):
                if "segments" in hook:
                    render_hooks.append(hook)
                else:
                    render_hooks.append(str(hook.get("text") or "").strip())
                metadata = dict(hook)
                metadata["hookIndex"] = idx
                hook_metadata.append(metadata)
            else:
                render_hooks.append(hook)
        return render_hooks, hook_metadata

    def _next_reel_clip_number(self, raw_dir: Path) -> int:
        nums = []
        for path in raw_dir.glob("clip_*.mp4"):
            try:
                nums.append(int(path.stem.split("_")[-1]))
            except ValueError:
                pass
        return max(nums, default=0) + 1

    def run_reel_factory(
        self,
        *,
        campaign_slug: str,
        workers: int = 3,
        dry_run: bool = False,
        caption_band: str = "auto",
        caption_color: str = "light",
        caption_style: str = "ig",
        caption_font: str = "Instagram Sans Condensed",
        caption_placement_qc: bool = True,
        phone_finalize: bool = True,
        rerender_all: bool = False,
        max_outputs_per_clip: int | None = None,
    ) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        pipeline_job = self.create_pipeline_job(
            "run_reel",
            campaign["id"],
            {
                "campaign": campaign_slug,
                "workers": workers,
                "dryRun": dry_run,
                "captionBand": caption_band,
                "captionColor": caption_color,
                "captionStyle": caption_style,
                "captionFont": caption_font,
                "captionPlacementQc": caption_placement_qc,
                "phoneFinalize": phone_finalize,
                "rerenderAll": rerender_all,
                "maxOutputsPerClip": max_outputs_per_clip,
            },
        )
        self.start_pipeline_job(pipeline_job["id"])
        started = time.time()
        try:
            if rerender_all:
                jobs = self.conn.execute(
                    "SELECT * FROM render_jobs WHERE campaign_id = ? ORDER BY created_at",
                    (campaign["id"],),
                ).fetchall()
            else:
                jobs = self.conn.execute(
                    "SELECT * FROM render_jobs WHERE campaign_id = ? AND status IN ('prepared', 'failed') ORDER BY created_at",
                    (campaign["id"],),
                ).fetchall()
            runs: list[dict[str, Any]] = []
            for job in jobs:
                cmd = [
                    reel_factory_python(self.settings.reel_factory_root),
                    "reel_pipeline.py",
                    "--root",
                    str(self.settings.reel_factory_root),
                    "--workers",
                    str(workers),
                    "--only-clip",
                    job["reel_clip_stem"],
                ]
                recipes = json_load(job["recipes_json"], [])
                if recipes:
                    cmd.extend(["--recipes", *recipes])
                color = caption_color or job["caption_color"]
                if color:
                    cmd.extend(["--color", color])
                if caption_band:
                    cmd.extend(["--band", caption_band])
                if caption_style:
                    cmd.extend(["--style", caption_style])
                if caption_font:
                    cmd.extend(["--font", caption_font])
                if caption_placement_qc:
                    cmd.append("--caption-placement-qc")
                if max_outputs_per_clip is not None:
                    cmd.extend(["--per-clip", str(max(1, int(max_outputs_per_clip)))])
                cmd.append("--phone-finalize" if phone_finalize else "--no-phone-finalize")
                if dry_run:
                    cmd.append("--dry-run")
                if rerender_all:
                    cmd.append("--rerender-all")
                self.record_event(
                    "reel_render_started",
                    campaign_id=campaign["id"],
                    source_asset_id=job["source_asset_id"],
                    render_job_id=job["id"],
                    pipeline_job_id=pipeline_job["id"],
                    status="info",
                    message=f"Started reel render for {job['reel_clip_stem']}",
                    metadata={"clip": job["reel_clip_stem"], "command": cmd},
                    commit=False,
                )
                result = subprocess.run(cmd, cwd=self.settings.reel_factory_root, text=True, capture_output=True, check=False)
                status = job["status"] if dry_run and result.returncode == 0 else ("rendered" if result.returncode == 0 else "failed")
                error = result.stderr[-2000:] or None
                now = utc_now()
                self.conn.execute(
                    "UPDATE render_jobs SET status = ?, error = ?, updated_at = ? WHERE id = ?",
                    (status, error, now, job["id"]),
                )
                self.record_event(
                    "reel_render_completed" if result.returncode == 0 else "reel_render_failed",
                    campaign_id=campaign["id"],
                    source_asset_id=job["source_asset_id"],
                    render_job_id=job["id"],
                    pipeline_job_id=pipeline_job["id"],
                    status="success" if result.returncode == 0 else "failure",
                    message=f"{'Completed' if result.returncode == 0 else 'Failed'} reel render for {job['reel_clip_stem']}",
                    metadata={"clip": job["reel_clip_stem"], "returncode": result.returncode, "stderr": error},
                    commit=False,
                )
                runs.append({
                    "renderJobId": job["id"],
                    "clip": job["reel_clip_stem"],
                    "command": cmd,
                    "returncode": result.returncode,
                    "stdout": result.stdout,
                    "stderr": result.stderr,
                })
            self.conn.commit()
            returncode = next((run["returncode"] for run in runs if run["returncode"] != 0), 0)
            result_payload = {
                "campaign": campaign,
                "returncode": returncode,
                "runs": runs,
                "elapsed_seconds": round(time.time() - started, 2),
                "pipelineJobId": pipeline_job["id"],
            }
            if returncode == 0:
                self.finish_pipeline_job(pipeline_job["id"], {
                    "returncode": returncode,
                    "runCount": len(runs),
                    "elapsed_seconds": result_payload["elapsed_seconds"],
                })
            else:
                self.fail_pipeline_job(pipeline_job["id"], f"reel_factory returned {returncode}", {
                    "returncode": returncode,
                    "runCount": len(runs),
                    "elapsed_seconds": result_payload["elapsed_seconds"],
                })
            return result_payload
        except Exception as exc:
            self.record_event(
                "reel_render_failed",
                campaign_id=campaign["id"],
                pipeline_job_id=pipeline_job["id"],
                status="failure",
                message=f"Run reel_factory failed: {exc}",
                metadata={"error": str(exc)},
            )
            self.fail_pipeline_job(pipeline_job["id"], str(exc))
            raise

    def sync_reel_outputs(self, *, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        pipeline_job = self.create_pipeline_job("sync_reel", campaign["id"], {"campaign": campaign_slug})
        self.start_pipeline_job(pipeline_job["id"])
        model_slug = self._model_slug_for_campaign(campaign["id"])
        dirs = self.campaign_dirs(model_slug, campaign["slug"])
        manifest_db = self.settings.reel_factory_root / "manifest.sqlite"
        reel_conn: sqlite3.Connection | None = None
        try:
            if not manifest_db.exists():
                raise FileNotFoundError(f"reel_factory manifest not found: {manifest_db}")
            reel_conn = sqlite3.connect(manifest_db)
            reel_conn.row_factory = sqlite3.Row
            variation_cols = {
                row["name"]
                for row in reel_conn.execute("PRAGMA table_info(variations)").fetchall()
            }
            clip_col = "video_id" if "video_id" in variation_cols else "clip"
            jobs = self.conn.execute("SELECT * FROM render_jobs WHERE campaign_id = ?", (campaign["id"],)).fetchall()
            synced = []
            new_synced = 0
            for job in jobs:
                rows = reel_conn.execute(
                    f"""
                    SELECT job_key, recipe, recipe_params_json, caption_text, output_path, review_state
                    FROM variations
                    WHERE {clip_col} = ? AND status = 'ok'
                    ORDER BY encoded_at, output_path
                    """,
                    (job["reel_clip_stem"],),
                ).fetchall()
                for row in rows:
                    output_path = Path(row["output_path"])
                    if not output_path.exists():
                        continue
                    digest = sha256_file(output_path)
                    params = json_load(row["recipe_params_json"], {})
                    reel_lineage = params.get("_lineage") if isinstance(params.get("_lineage"), dict) else {}
                    existing = self.conn.execute(
                        "SELECT * FROM rendered_assets WHERE campaign_id = ? AND content_hash = ?",
                        (campaign["id"], digest),
                    ).fetchone()
                    if existing:
                        self._backfill_synced_reel_output_lineage(
                            asset=dict(existing),
                            clip_stem=job["reel_clip_stem"],
                            caption_text=str(row["caption_text"] or "").strip(),
                            recipe=str(row["recipe"] or ""),
                            output_path=str(output_path),
                            rendered_path=str(existing["campaign_path"] or existing["output_path"] or output_path),
                            creator_model=model_slug,
                            lineage=reel_lineage,
                        )
                        refreshed = self.conn.execute(
                            "SELECT * FROM rendered_assets WHERE id = ?",
                            (existing["id"],),
                        ).fetchone()
                        synced.append(dict(refreshed or existing))
                        continue
                    dest = dirs["rendered"] / output_path.name
                    if output_path.resolve() != dest.resolve():
                        shutil.copy2(output_path, dest)
                    rendered_id = new_id("asset")
                    now = utc_now()
                    caption_text = str(row["caption_text"] or "").strip()
                    caption_hash_value = self._text_hash(caption_text) if caption_text else None
                    caption_generation = self._caption_generation_for_clip(job["reel_clip_stem"])
                    lineage = {**caption_generation, **reel_lineage}
                    caption_context = self._caption_outcome_context_for_reel_output(
                        clip_stem=job["reel_clip_stem"],
                        caption_text=caption_text,
                        caption_hash=caption_hash_value,
                        recipe=str(row["recipe"] or ""),
                        source_path=str(output_path),
                        rendered_path=str(dest),
                        creator_model=model_slug,
                        lineage=lineage,
                    )
                    if caption_generation.get("audioIntent") is None:
                        audio_intent = self._audio_intent_from_reference_recommendations(caption_generation, now=now)
                        if audio_intent:
                            caption_generation["audioIntent"] = audio_intent
                    if caption_text:
                        post_caption = self._suggest_simple_instagram_post_caption(
                            asset_id=rendered_id,
                            current_caption="",
                            burned_caption=caption_text,
                        )
                        caption_context["instagram_post_caption"] = post_caption
                        caption_context["instagram_post_caption_hash"] = self._text_hash(post_caption)
                        caption_context["burned_caption_text"] = caption_text
                        caption_context["burned_caption_hash"] = caption_hash_value
                        caption_generation["instagramPostCaption"] = {
                            "instagram_post_caption": post_caption,
                            "instagramPostCaption": post_caption,
                            "instagram_post_caption_hash": self._text_hash(post_caption),
                            "post_caption_style": "simple_native",
                            "hashtags": [],
                        }
                    caption_generation["captionHash"] = caption_hash_value
                    caption_generation["captionOutcomeContext"] = caption_context
                    self.conn.execute(
                        """
                        INSERT INTO rendered_assets
                        (id, campaign_id, source_asset_id, render_job_id, content_hash, output_path, campaign_path, filename,
                         caption, caption_hash, caption_bank, caption_banks_json, creator_mix, creator_model, frame_type,
                         length_class, format_class, caption_fit_version, suitability_decision, suitability_reason,
                         source_clip, caption_outcome_context_json, caption_generation_json, recipe, target_ratio,
                         review_state, created_at, updated_at)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                        """,
                        (
                            rendered_id, campaign["id"], job["source_asset_id"], job["id"], digest, str(output_path), str(dest), dest.name,
                            caption_text, caption_hash_value, caption_context.get("caption_bank"),
                            json.dumps(caption_context.get("caption_banks") or [], ensure_ascii=False, sort_keys=True),
                            caption_context.get("creator_mix"), caption_context.get("creator_model"),
                            caption_context.get("frame_type"), caption_context.get("length_class"),
                            caption_context.get("format_class"), caption_context.get("caption_fit_version"),
                            caption_context.get("suitability_decision"), caption_context.get("suitability_reason"),
                            caption_context.get("source_clip"),
                            json.dumps(caption_context, ensure_ascii=False, sort_keys=True),
                            json.dumps(sanitize_for_storage(caption_generation), ensure_ascii=False, sort_keys=True),
                            row["recipe"], params.get("_target_ratio") or self._ratio_from_filename(dest.name),
                            row["review_state"] or "draft", now, now,
                        ),
                    )
                    synced_asset = dict(self.conn.execute("SELECT * FROM rendered_assets WHERE id = ?", (rendered_id,)).fetchone())
                    rendered_graph_id = self.ensure_graph_node(
                        "rendered_asset",
                        local_table="rendered_assets",
                        local_id=rendered_id,
                        payload={
                            "campaignId": campaign["id"],
                            "sourceAssetId": job["source_asset_id"],
                            "renderJobId": job["id"],
                            "contentHash": digest,
                            "filename": dest.name,
                            "recipe": row["recipe"],
                        },
                    )
                    self.ensure_graph_edge(
                        self.graph_id_for("render_jobs", job["id"], entity_type="render_job"),
                        rendered_graph_id,
                        "render_job_to_rendered_asset",
                        evidence={"jobKey": row["job_key"], "pipelineJobId": pipeline_job["id"]},
                    )
                    self.ensure_graph_edge(
                        self.graph_id_for("source_assets", job["source_asset_id"], entity_type="source_asset"),
                        rendered_graph_id,
                        "source_asset_to_rendered_asset",
                        evidence={"recipe": row["recipe"], "pipelineJobId": pipeline_job["id"]},
                    )
                    synced.append(synced_asset)
                    new_synced += 1
                    self.record_event(
                        "rendered_asset_synced",
                        campaign_id=campaign["id"],
                        source_asset_id=job["source_asset_id"],
                        rendered_asset_id=rendered_id,
                        render_job_id=job["id"],
                        pipeline_job_id=pipeline_job["id"],
                        status="success",
                        message=f"Rendered asset synced: {dest.name}",
                        metadata={"filename": dest.name, "contentHash": digest, "recipe": row["recipe"], "outputPath": str(output_path)},
                        commit=False,
                    )
            result = {"campaign": campaign, "synced": synced, "pipelineJobId": pipeline_job["id"]}
            self.conn.commit()
            self.finish_pipeline_job(pipeline_job["id"], {"syncedCount": len(synced), "newSyncedCount": new_synced})
            return result
        except Exception as exc:
            self.record_event(
                "rendered_asset_synced",
                campaign_id=campaign["id"],
                pipeline_job_id=pipeline_job["id"],
                status="failure",
                message=f"Sync rendered outputs failed: {exc}",
                metadata={"error": str(exc)},
            )
            self.fail_pipeline_job(pipeline_job["id"], str(exc))
            raise
        finally:
            if reel_conn:
                reel_conn.close()

    def _model_slug_for_campaign(self, campaign_id: str) -> str:
        row = self.conn.execute(
            """
            SELECT m.slug FROM source_assets s
            JOIN models m ON m.id = s.model_id
            WHERE s.campaign_id = ?
            LIMIT 1
            """,
            (campaign_id,),
        ).fetchone()
        return row["slug"] if row else "unassigned"

    def _ratio_from_filename(self, filename: str) -> str:
        return "4:5" if "_4x5_" in filename else "9:16"

    def _caption_generation_for_clip(self, clip_stem: str) -> dict[str, Any]:
        sidecar = self.settings.reel_factory_root / "01_captions" / f"{clip_stem}.json"
        if not sidecar.exists():
            return {}
        try:
            payload = json_load(sidecar.read_text(encoding="utf-8"), {})
        except OSError:
            return {}
        if not isinstance(payload, dict):
            return {}
        hook_metadata = payload.get("hook_metadata") if isinstance(payload.get("hook_metadata"), list) else []
        generation = payload.get("generation")
        if not isinstance(generation, dict):
            generation_payload = {}
        else:
            generation_payload = {
                "generationId": generation.get("generation_id") or generation.get("generationId"),
                "model": generation.get("model"),
                "backend": generation.get("backend"),
                "createdAt": generation.get("created_at") or generation.get("createdAt"),
                "promptHash": generation.get("prompt_hash") or generation.get("promptHash"),
                "captionHashes": generation.get("caption_hashes") or generation.get("captionHashes") or [],
                "quality": generation.get("quality") or [],
            }
        reference_meta = next((item for item in hook_metadata if isinstance(item, dict) and item.get("referenceClusterKey")), None)
        if reference_meta:
            generation_payload["referencePattern"] = {
                "clusterKey": reference_meta.get("referenceClusterKey"),
                "label": reference_meta.get("referenceLabel"),
                "hookType": reference_meta.get("hookType"),
                "captionArchetype": reference_meta.get("captionArchetype"),
            }
            generation_payload["audioRecommendations"] = reference_meta.get("audioRecommendations") or {}
        return generation_payload

    def _caption_outcome_context_for_reel_output(
        self,
        *,
        clip_stem: str,
        caption_text: str,
        caption_hash: str | None,
        recipe: str,
        source_path: str,
        rendered_path: str,
        creator_model: str,
        lineage: dict[str, Any],
    ) -> dict[str, Any]:
        context = build_caption_outcome_context(
            caption_text=caption_text,
            caption_hash=caption_hash,
            render_recipe=recipe,
            source_clip=source_path,
            rendered_output=rendered_path,
            creator_model=creator_model,
            lineage=lineage,
        )
        lineage_placement_decision = self._lineage_placement_decision(lineage)
        placement_policy = (
            context.get("captionPlacementPolicy")
            or self._lineage_first_present(lineage, "captionPlacementPolicy")
            or "focal_safe_v1"
        )
        placement_decision = context.get("captionPlacementDecision")
        if isinstance(lineage_placement_decision, dict) and lineage_placement_decision.get("status") in {"passed", "failed"}:
            placement_decision = lineage_placement_decision
        elif not isinstance(placement_decision, dict) or not placement_decision.get("status"):
            placement_decision = lineage_placement_decision
        if not isinstance(placement_decision, dict) or not placement_decision.get("status"):
            placement_decision = {
                "status": "pending",
                "selectedLane": self._caption_lane_from_render_recipe(recipe),
                "reason": "ContentForge safe-zone review must pass before schedule-safe handoff.",
            }
        elif not placement_decision.get("selectedLane"):
            placement_decision = {
                **placement_decision,
                "selectedLane": self._caption_lane_from_render_recipe(recipe),
            }
        context.update({
            "caption_bank": context.get("caption_bank") or "reel_factory_reference",
            "caption_banks": context.get("caption_banks") or ["reel_factory_reference"],
            "creator_mix": context.get("creator_mix") or creator_model,
            "creator_model": context.get("creator_model") or creator_model,
            "frame_type": context.get("frame_type") or "selfie_video",
            "length_class": context.get("length_class") or "short",
            "format_class": context.get("format_class") or "reel",
            "caption_fit_version": context.get("caption_fit_version") or "reel_factory_sync_v1",
            "suitability_decision": context.get("suitability_decision") or "allowed",
            "suitability_reason": context.get("suitability_reason") or "synced from Reel Factory output",
            "reel_clip_stem": clip_stem,
            "captionPlacementPolicy": placement_policy,
            "captionPlacementDecision": placement_decision,
        })
        return context

    def _lineage_first_present(self, lineage: dict[str, Any] | None, key: str) -> Any:
        if not isinstance(lineage, dict):
            return None
        candidates = [
            lineage,
            lineage.get("captionBank"),
            lineage.get("captionOutcomeContext"),
            lineage.get("captionLineage"),
            lineage.get("caption_lineage"),
        ]
        for candidate in candidates:
            if isinstance(candidate, dict) and candidate.get(key) is not None:
                return candidate.get(key)
        return None

    def _lineage_placement_decision(self, lineage: dict[str, Any] | None) -> dict[str, Any] | None:
        if not isinstance(lineage, dict):
            return None
        decisions: list[dict[str, Any]] = []
        for candidate in (
            lineage,
            lineage.get("captionBank"),
            lineage.get("captionOutcomeContext"),
            lineage.get("captionLineage"),
            lineage.get("caption_lineage"),
        ):
            if not isinstance(candidate, dict):
                continue
            decision = candidate.get("captionPlacementDecision")
            if isinstance(decision, dict):
                decisions.append(decision)
        for decision in decisions:
            if decision.get("status") in {"passed", "failed"}:
                return decision
        return decisions[0] if decisions else None

    def _caption_lane_from_render_recipe(self, recipe: str | None) -> str:
        raw = str(recipe or "").lower()
        if "top" in raw:
            return "top"
        if "caption_bg" in raw or "bottom" in raw:
            return "bottom"
        return "center"

    def _audio_intent_from_reference_recommendations(self, payload: dict[str, Any], *, now: str) -> dict[str, Any]:
        recommendations = (payload.get("audioRecommendations") or {}).get("recommendations")
        if not isinstance(recommendations, list):
            recommendations = []
        selected = next((item for item in recommendations if isinstance(item, dict) and str(item.get("audioId") or "").strip()), None)
        if not selected:
            return {
                "schema": "pipeline.audio_intent.v1",
                "mode": "native_platform_audio",
                "required": True,
                "status": "missing",
                "platform": "instagram",
                "source": "reference_audio_recommendations",
                "operator_selection": {},
            }
        audio_id = str(selected.get("audioId") or "").strip()
        audio_title = str(selected.get("audioTitle") or selected.get("title") or "").strip()
        artist = str(selected.get("artistName") or selected.get("artist_name") or "").strip()
        return {
            "schema": "pipeline.audio_intent.v1",
            "mode": "native_platform_audio",
            "required": True,
            "status": "attached",
            "platform": "instagram",
            "source": "reference_audio_recommendations",
            "operator_selection": {
                "audio_id": audio_id,
                "track_id": audio_id,
                "platform_audio_id": audio_id,
                "native_audio_id": audio_id,
                "audio_title": audio_title,
                "track_name": audio_title,
                "artist_name": artist,
                "source": "reference_audio_recommendations",
                "selection_source": "reference_audio_recommendations",
                "selected_reason": str(selected.get("instruction") or "reference pattern audio recommendation").strip(),
                "selected_at": now,
                "attached_at": now,
            },
            "gates": {
                "allow_draft_export": True,
                "allow_preview_schedule": True,
                "allow_live_schedule": False,
                "allow_publish": False,
            },
        }

    def _backfill_synced_reel_output_lineage(
        self,
        *,
        asset: dict[str, Any],
        clip_stem: str,
        caption_text: str,
        recipe: str,
        output_path: str,
        rendered_path: str,
        creator_model: str,
        lineage: dict[str, Any] | None = None,
    ) -> bool:
        existing_context = load_context_json(asset.get("caption_outcome_context_json"))
        existing_generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(existing_generation, dict):
            existing_generation = {}
        existing_decision = existing_context.get("captionPlacementDecision") if isinstance(existing_context, dict) else {}
        if (
            asset.get("caption_hash")
            and existing_context
            and isinstance(existing_generation.get("audioIntent"), dict)
            and isinstance(existing_decision, dict)
            and existing_decision.get("status") in {"passed", "failed"}
        ):
            return False
        now = utc_now()
        caption_hash_value = asset.get("caption_hash") or (self._text_hash(caption_text) if caption_text else None)
        reel_lineage = lineage if isinstance(lineage, dict) else {}
        caption_generation = {**self._caption_generation_for_clip(clip_stem), **reel_lineage, **existing_generation}
        caption_context = self._caption_outcome_context_for_reel_output(
            clip_stem=clip_stem,
            caption_text=caption_text or str(asset.get("caption") or "").strip(),
            caption_hash=caption_hash_value,
            recipe=recipe or str(asset.get("recipe") or ""),
            source_path=output_path,
            rendered_path=rendered_path,
            creator_model=creator_model,
            lineage={**caption_generation, **existing_context},
        )
        if not isinstance(caption_generation.get("audioIntent"), dict):
            audio_intent = self._audio_intent_from_reference_recommendations(caption_generation, now=now)
            if audio_intent:
                caption_generation["audioIntent"] = audio_intent
        burned_caption = caption_text or str(asset.get("caption") or "").strip()
        if burned_caption:
            post_caption = self._suggest_simple_instagram_post_caption(
                asset_id=str(asset["id"]),
                current_caption="",
                burned_caption=burned_caption,
            )
            caption_context["instagram_post_caption"] = post_caption
            caption_context["instagram_post_caption_hash"] = self._text_hash(post_caption)
            caption_context["burned_caption_text"] = burned_caption
            caption_context["burned_caption_hash"] = caption_hash_value
            caption_generation["instagramPostCaption"] = {
                "instagram_post_caption": post_caption,
                "instagramPostCaption": post_caption,
                "instagram_post_caption_hash": self._text_hash(post_caption),
                "post_caption_style": "simple_native",
                "hashtags": [],
            }
        caption_generation["captionHash"] = caption_hash_value
        caption_generation["captionOutcomeContext"] = caption_context
        self.conn.execute(
            """
            UPDATE rendered_assets
            SET caption = COALESCE(NULLIF(caption, ''), ?),
                caption_hash = COALESCE(caption_hash, ?),
                caption_bank = COALESCE(NULLIF(caption_bank, ''), ?),
                caption_banks_json = CASE WHEN caption_banks_json IS NULL OR caption_banks_json = '' OR caption_banks_json = '[]' THEN ? ELSE caption_banks_json END,
                creator_mix = COALESCE(NULLIF(creator_mix, ''), ?),
                creator_model = COALESCE(NULLIF(creator_model, ''), ?),
                frame_type = COALESCE(NULLIF(frame_type, ''), ?),
                length_class = COALESCE(NULLIF(length_class, ''), ?),
                format_class = COALESCE(NULLIF(format_class, ''), ?),
                caption_fit_version = COALESCE(NULLIF(caption_fit_version, ''), ?),
                suitability_decision = COALESCE(NULLIF(suitability_decision, ''), ?),
                suitability_reason = COALESCE(NULLIF(suitability_reason, ''), ?),
                source_clip = COALESCE(NULLIF(source_clip, ''), ?),
                caption_outcome_context_json = ?,
                caption_generation_json = ?,
                updated_at = ?
            WHERE id = ?
            """,
            (
                burned_caption,
                caption_hash_value,
                caption_context.get("caption_bank"),
                json.dumps(caption_context.get("caption_banks") or [], ensure_ascii=False, sort_keys=True),
                caption_context.get("creator_mix"),
                caption_context.get("creator_model"),
                caption_context.get("frame_type"),
                caption_context.get("length_class"),
                caption_context.get("format_class"),
                caption_context.get("caption_fit_version"),
                caption_context.get("suitability_decision"),
                caption_context.get("suitability_reason"),
                caption_context.get("source_clip"),
                json.dumps(caption_context, ensure_ascii=False, sort_keys=True),
                json.dumps(sanitize_for_storage(caption_generation), ensure_ascii=False, sort_keys=True),
                now,
                asset["id"],
            ),
        )
        return True

    def review_rendered_asset(
        self,
        rendered_asset_id: str,
        *,
        decision: str,
        notes: str | None = None,
        require_safe_audit: bool = False,
    ) -> dict[str, Any]:
        if decision not in {"approved", "rejected"}:
            raise ValueError("decision must be approved or rejected")
        row = self.conn.execute("SELECT * FROM rendered_assets WHERE id = ?", (rendered_asset_id,)).fetchone()
        if not row:
            raise ValueError(f"rendered asset not found: {rendered_asset_id}")
        approvable_audit_statuses = {"approved_candidate", "needs_review"}
        if decision == "approved" and require_safe_audit and row["audit_status"] not in approvable_audit_statuses:
            raise ValueError(
                f"approval blocked: audit_status:{row['audit_status']}; run audit or use an explicit force override"
            )
        now = utc_now()
        decision_id = new_id("approval")
        self.conn.execute("UPDATE rendered_assets SET review_state = ?, updated_at = ? WHERE id = ?", (decision, now, rendered_asset_id))
        self.conn.execute(
            "INSERT INTO approval_decisions (id, campaign_id, rendered_asset_id, decision, notes, created_at) VALUES (?, ?, ?, ?, ?, ?)",
            (decision_id, row["campaign_id"], rendered_asset_id, decision, notes, now),
        )
        approval_graph_id = self.ensure_graph_node(
            "approval_decision",
            local_table="approval_decisions",
            local_id=decision_id,
            payload={"decision": decision, "renderedAssetId": rendered_asset_id, "notes": notes},
        )
        self.ensure_graph_edge(
            self.graph_id_for("rendered_assets", rendered_asset_id, entity_type="rendered_asset"),
            approval_graph_id,
            "rendered_asset_to_approval_decision",
            evidence={"decision": decision},
        )
        self.record_event(
            "asset_approved" if decision == "approved" else "asset_rejected",
            campaign_id=row["campaign_id"],
            source_asset_id=row["source_asset_id"],
            rendered_asset_id=rendered_asset_id,
            status="success",
            message=f"Asset {decision}: {row['filename']}",
            metadata={"decision": decision, "notes": notes, "approvalDecisionId": decision_id},
            commit=False,
        )
        self.conn.commit()
        return dict(self.conn.execute("SELECT * FROM rendered_assets WHERE id = ?", (rendered_asset_id,)).fetchone())

    def approve_rendered_asset(
        self,
        rendered_asset_id: str,
        *,
        notes: str | None = None,
        require_safe_audit: bool = False,
    ) -> dict[str, Any]:
        return self.review_rendered_asset(
            rendered_asset_id,
            decision="approved",
            notes=notes,
            require_safe_audit=require_safe_audit,
        )

    def make_batch(
        self,
        *,
        folder: Path,
        campaign_slug: str,
        model_slug: str,
        output_format: str = "auto",
        variant_count: int = 20,
        reference_pattern: str | None = "auto",
        contentforge_base_url: str | None = None,
        user_id: str | None = None,
        dry_run_export: bool = True,
        workers: int = 3,
        recipes: list[str] | None = None,
        auto_approve_warning_only: bool = True,
        source_prompt: str | None = None,
        import_notes: str | None = None,
    ) -> dict[str, Any]:
        from .adapters.contentforge import audit_campaign
        from .adapters.threadsdash import evaluate_export_readiness, export_threadsdash

        selected_format = output_format if output_format in {"reel", "slideshow", "auto"} else "auto"
        pipeline_job = self.create_pipeline_job(
            "make_batch",
            None,
            {
                "folder": str(folder),
                "campaign": campaign_slug,
                "model": model_slug,
                "format": selected_format,
                "variantCount": variant_count,
                "referencePattern": reference_pattern,
                "contentforgeBaseUrl": contentforge_base_url,
                "hasUserId": bool(user_id),
                "dryRunExport": dry_run_export,
                "workers": workers,
                "recipes": recipes or [],
                "autoApproveWarningOnly": auto_approve_warning_only,
                "hasSourcePrompt": bool(source_prompt),
            },
        )
        self.start_pipeline_job(pipeline_job["id"])
        try:
            result: dict[str, Any] = {
                "schema": "campaign_factory.make_batch.v1",
                "campaign": campaign_slug,
                "pipelineJobId": pipeline_job["id"],
                "import": None,
                "referenceImport": None,
                "referenceSelection": None,
                "prepare": None,
                "run": None,
                "sync": None,
                "audit": None,
                "autoApproved": [],
                "readiness": None,
                "dryRunExport": None,
                "dashboard": None,
                "format": selected_format,
                "reviewReady": [],
            }
            imported = self.import_folder(
                Path(folder),
                campaign_slug=campaign_slug,
                model_slug=model_slug,
                platform="instagram",
                source_prompt=source_prompt,
                notes=import_notes or "make-batch source import",
            )
            result["import"] = {
                "importedCount": len(imported.get("imported") or []),
                "duplicateCount": len(imported.get("duplicates") or []),
                "ignoredCount": len(imported.get("ignored") or []),
                "campaignId": imported["campaign"]["id"],
                "campaignSlug": imported["campaign"]["slug"],
                "modelSlug": imported["model"]["slug"],
            }
            self.set_pipeline_job_campaign(pipeline_job["id"], imported["campaign"]["id"])

            if not self.reference_patterns(limit=1)["patterns"]:
                bank_path = self.settings.reference_reels_root / "learning" / "campaign_reference_bank.json"
                prompt_pack_path = self.settings.reference_reels_root / "learning" / "higgsfield_prompt_pack_top300.json"
                if bank_path.exists():
                    reference_import = self.import_reference_bank(
                        bank_path,
                        prompt_pack_path if prompt_pack_path.exists() else None,
                    )
                    result["referenceImport"] = {
                        "patternsImported": reference_import.get("patternsImported"),
                        "bankPath": reference_import.get("bankPath"),
                    }

            cluster_key = None if not reference_pattern or reference_pattern == "auto" else reference_pattern
            source_mix = self._campaign_source_media_summary(imported["campaign"]["id"])
            formats_to_run = self._formats_for_batch(selected_format, source_mix)
            result["sourceMix"] = source_mix
            result["formatsRun"] = formats_to_run
            source_prompt_payload = json_load(source_prompt, {}) if source_prompt else {}
            finished_format_type = (
                source_prompt_payload.get("formatType")
                if isinstance(source_prompt_payload, dict)
                and source_prompt_payload.get("schema") == "campaign_factory.finished_video_intake.v1"
                else None
            )
            reel_caption_band = self._finished_video_caption_band(str(finished_format_type)) if finished_format_type else "auto"
            reel_caption_font = self._finished_video_caption_font(str(finished_format_type)) if finished_format_type else "Instagram Sans Condensed"

            prepared_by_format: dict[str, Any] = {}
            pattern: dict[str, Any] = {}
            for format_name in formats_to_run:
                if format_name == "slideshow":
                    prepared = self._run_slideshow_pack(
                        campaign_slug=campaign_slug,
                        variant_count=max(1, min(int(variant_count or 20), 100)),
                        title=campaign_slug.replace("_", " ").title(),
                        cluster_key=cluster_key,
                        media_types={"image"} if source_mix.get("image", 0) else {"video"},
                    )
                    prepared_by_format["slideshow"] = prepared
                else:
                    if finished_format_type:
                        selection = self.select_reference_pattern(
                            campaign_slug,
                            cluster_key=cluster_key,
                            variant_count=max(1, min(int(variant_count or 20), 100)),
                            notes="make-batch finished-video reference render",
                        )
                        pattern = selection["pattern"]
                        hooks = self.finished_video_hooks(
                            str(finished_format_type),
                            pattern,
                            count=max(1, min(int(variant_count or 20), 100)),
                        )
                        prepare = self.prepare_reel_inputs(
                            campaign_slug=campaign_slug,
                            hooks=hooks,
                            recipes=recipes,
                            caption_color="auto",
                            notes="finished-video native caption render",
                            force_new=True,
                        )
                        prepared = {
                            "schema": "campaign_factory.prepare_from_reference.v1",
                            "campaign": campaign_slug,
                            "selection": {**selection, "hooks": hooks},
                            "prepare": prepare,
                        }
                    else:
                        prepared = self.prepare_reel_from_reference(
                            campaign_slug=campaign_slug,
                            cluster_key=cluster_key,
                            variant_count=max(1, min(int(variant_count or 20), 100)),
                            recipes=recipes,
                            caption_color="auto",
                            notes="make-batch reference render",
                            force_new=True,
                        )
                    prepared_by_format["reel"] = prepared
                    run_result = self.run_reel_factory(
                        campaign_slug=campaign_slug,
                        workers=workers,
                        dry_run=False,
                        caption_band=reel_caption_band,
                        caption_color="light",
                        caption_style="ig",
                        caption_font=reel_caption_font,
                        phone_finalize=True,
                        max_outputs_per_clip=max(1, min(int(variant_count or 20), 100)),
                    )
                    sync_result = self.sync_reel_outputs(campaign_slug=campaign_slug)
                    sync_retries: list[dict[str, Any]] = []
                    prepared_jobs = (prepared.get("prepare") or {}).get("prepared") or prepared.get("prepared") or []
                    expected_sync_count = max(1, len(prepared_jobs))
                    if (
                        run_result.get("returncode") == 0
                        and len(sync_result.get("synced") or []) < expected_sync_count
                    ):
                        time.sleep(1.0)
                        sync_retry = self.sync_reel_outputs(campaign_slug=campaign_slug)
                        sync_retry_count = len(sync_retry.get("synced") or [])
                        sync_retries.append({
                            "kind": "poll",
                            "expectedSyncedCount": expected_sync_count,
                            "syncedCount": sync_retry_count,
                        })
                        if sync_retry_count >= expected_sync_count:
                            sync_result = sync_retry
                        else:
                            rerun_result = self.run_reel_factory(
                                campaign_slug=campaign_slug,
                                workers=workers,
                                dry_run=False,
                                caption_band=reel_caption_band,
                                caption_color="light",
                                caption_style="ig",
                                caption_font=reel_caption_font,
                                phone_finalize=True,
                                rerender_all=True,
                                max_outputs_per_clip=max(1, min(int(variant_count or 20), 100)),
                            )
                            sync_retry = self.sync_reel_outputs(campaign_slug=campaign_slug)
                            sync_retry_count = len(sync_retry.get("synced") or [])
                            sync_retries.append({
                                "kind": "rerun",
                                "returncode": rerun_result.get("returncode"),
                                "expectedSyncedCount": expected_sync_count,
                                "syncedCount": sync_retry_count,
                            })
                            if sync_retry_count > len(sync_result.get("synced") or []):
                                sync_result = sync_retry
                    prepared["run"] = {
                        "returncode": run_result.get("returncode"),
                        "runCount": len(run_result.get("runs") or []),
                        "elapsedSeconds": run_result.get("elapsed_seconds"),
                    }
                    prepared["sync"] = {"syncedCount": len(sync_result.get("synced") or []), "retries": sync_retries}
                if not pattern:
                    pattern = ((prepared.get("selection") or {}).get("pattern") or {})

            result["referenceSelection"] = {
                "label": pattern.get("label"),
                "clusterKey": pattern.get("clusterKey"),
                "variantCount": max(1, min(int(variant_count or 20), 100)),
                "recipes": recipes or ((pattern.get("raw") or {}).get("bank") or {}).get("suggestedVariantRecipes") or [],
            }
            prepare_payloads = [item.get("prepare") or {} for item in prepared_by_format.values()]
            result["prepare"] = {
                "preparedCount": sum(len(payload.get("prepared") or []) for payload in prepare_payloads),
                "reusedExistingCount": sum(len(payload.get("reusedExisting") or []) for payload in prepare_payloads),
                "sourceCount": sum(source_mix.values()),
                "byFormat": {
                    format_name: {
                        "preparedCount": len((payload.get("prepare") or {}).get("prepared") or []),
                        "reusedExistingCount": len((payload.get("prepare") or {}).get("reusedExisting") or []),
                    }
                    for format_name, payload in prepared_by_format.items()
                },
            }
            result["run"] = {
                "runCount": sum((payload.get("run") or {}).get("runCount") or 0 for payload in prepared_by_format.values()),
                "byFormat": {format_name: payload.get("run") for format_name, payload in prepared_by_format.items()},
            }
            result["sync"] = {
                "syncedCount": sum((payload.get("sync") or {}).get("syncedCount") or len((payload.get("prepare") or {}).get("prepared") or []) for payload in prepared_by_format.values()),
                "byFormat": {format_name: payload.get("sync") or {"syncedCount": len((payload.get("prepare") or {}).get("prepared") or [])} for format_name, payload in prepared_by_format.items()},
            }
            audit_result = audit_campaign(
                self,
                campaign_slug=campaign_slug,
                min_score=85,
                contentforge_base_url=contentforge_base_url,
            )
            reports = audit_result.get("reports") or []
            result["audit"] = {
                "reportCount": len(reports),
                "failedCount": sum(1 for report in reports if report.get("failedChecks")),
                "warningCount": sum(1 for report in reports if report.get("warnings") or report.get("overallVerdict") == "warn"),
            }

            if auto_approve_warning_only:
                for asset in self.dashboard(campaign_slug).get("rendered") or []:
                    if asset.get("review_state") == "approved":
                        continue
                    latest = asset.get("latest_audit") or {}
                    readiness = latest.get("readinessSummary") or {}
                    blocking = list(latest.get("failedChecks") or []) + list(readiness.get("blockingReasons") or [])
                    if latest and not blocking:
                        self.conn.execute(
                            "UPDATE rendered_assets SET review_state = ?, updated_at = ? WHERE id = ?",
                            ("review_ready", utc_now(), asset["id"]),
                        )
                        self.record_event(
                            "asset_review_ready",
                            campaign_id=asset["campaign_id"],
                            source_asset_id=asset["source_asset_id"],
                            rendered_asset_id=asset["id"],
                            pipeline_job_id=pipeline_job["id"],
                            status="success",
                            message=f"Asset marked review-ready: {asset['filename']}",
                            metadata={"reason": "warning_only_or_ready"},
                            commit=False,
                        )
                        result["reviewReady"].append({"renderedAssetId": asset["id"], "filename": asset["filename"]})
                self.conn.commit()

            if user_id:
                readiness_result = evaluate_export_readiness(self, campaign_slug=campaign_slug, user_id=user_id)
                result["readiness"] = {
                    "expectedDraftCount": readiness_result.get("expectedDraftCount"),
                    "liveExportAllowed": readiness_result.get("liveExportAllowed"),
                    "blockingReasonCount": len(readiness_result.get("blockingReasons") or []),
                    "warningCount": len(readiness_result.get("warnings") or []),
                }
                if dry_run_export:
                    export_result = export_threadsdash(self, campaign_slug=campaign_slug, user_id=user_id, dry_run=True)
                    result["dryRunExport"] = {
                        "draftCount": export_result.get("draftCount"),
                        "path": export_result.get("path"),
                        "dryRun": export_result.get("dryRun"),
                    }
            health = self.campaign_health(campaign_slug)
            ranking = self.ranking(campaign_slug)["assets"][:5]
            result["dashboard"] = {
                "health": health,
                "topRanked": [
                    {
                        "renderedAssetId": item.get("renderedAssetId"),
                        "filename": item.get("filename"),
                        "score": item.get("score"),
                        "exportState": item.get("exportState"),
                    }
                    for item in ranking
                ],
            }
            self.record_event(
                "make_batch_completed",
                campaign_id=imported["campaign"]["id"],
                pipeline_job_id=pipeline_job["id"],
                status="success",
                message=f"Make batch completed: {campaign_slug}",
                metadata={
                    "importedCount": len((imported.get("imported") or [])),
                    "syncedCount": (result.get("sync") or {}).get("syncedCount"),
                    "reviewReadyCount": len(result["reviewReady"]),
                    "draftCount": (result.get("dryRunExport") or {}).get("draftCount"),
                },
            )
            self.finish_pipeline_job(pipeline_job["id"], {
                "campaign": campaign_slug,
                "importedCount": len((imported.get("imported") or [])),
                "syncedCount": (result.get("sync") or {}).get("syncedCount"),
                "reviewReadyCount": len(result["reviewReady"]),
                "draftCount": (result.get("dryRunExport") or {}).get("draftCount"),
            })
            return result
        except Exception as exc:
            self.record_event(
                "make_batch_failed",
                pipeline_job_id=pipeline_job["id"],
                status="failure",
                message=f"Make batch failed: {exc}",
                metadata={"error": str(exc)},
            )
            self.fail_pipeline_job(pipeline_job["id"], str(exc))
            raise

    def intake_finished_video(
        self,
        *,
        input_path: Path,
        model_slug: str,
        platform: str = "instagram",
        goal: str = "reach",
        reference_pattern: str | None = "auto",
        campaign_slug: str | None = None,
        contentforge_base_url: str | None = None,
        user_id: str | None = None,
        dry_run_export: bool = True,
        variant_count: int = 10,
        workers: int = 3,
        recipes: list[str] | None = None,
        creative_plan: str | None = None,
        style_lane: str | None = None,
        source_lineage_path: Path | None = None,
    ) -> dict[str, Any]:
        source = Path(input_path).expanduser().resolve()
        if not source.exists() or not source.is_file():
            raise FileNotFoundError(f"finished video not found: {source}")
        media_type = media_type_for_path(source)
        if media_type != "video":
            raise ValueError("finished-video intake requires a video file")
        campaign = slugify(campaign_slug or f"finished_{source.stem}")
        digest = sha256_file(source)
        source_probe = probe_video_shape(source)
        source_preflight = self._finished_video_preflight(source_probe)
        intake_dir = self.settings.campaigns_dir / "_finished_video_intake" / f"{campaign}_{digest[:10]}"
        intake_dir.mkdir(parents=True, exist_ok=True)
        staged = intake_dir / f"{slugify(source.stem)}_{digest[:10]}{source.suffix.lower()}"
        if not staged.exists():
            shutil.copy2(source, staged)
        style_lane_format = self._finished_video_style_lane_format(style_lane)
        format_type = style_lane_format or self._classify_finished_video_format(source)
        creative_plan_payload = self.creative_plan(creative_plan) if creative_plan else None
        creative_plan_id = creative_plan_payload["id"] if creative_plan_payload else None
        source_lineage = self._load_source_lineage(source_lineage_path)
        generation = source_lineage.get("generation") if isinstance(source_lineage.get("generation"), dict) else {}
        source_meta = source_lineage.get("source") if isinstance(source_lineage.get("source"), dict) else {}
        if not style_lane_format and source_meta.get("formatType"):
            format_type = str(source_meta["formatType"])
        generated_lineage = source_lineage if source_lineage.get("schema") == "campaign_factory.generated_asset_lineage.v1" else {
            "schema": "campaign_factory.generated_asset_lineage.v1",
            "pipelineTraceId": f"trace_finished_video_{digest[:16]}",
            "source": {
                "referenceId": None,
                "patternCardId": None,
                "promptId": None,
                "formatType": format_type,
                "referencePattern": reference_pattern or "auto",
            },
            "generation": {
                "tool": "manual_finished_video",
                "modelProfile": model_slug,
                "assetPath": str(source),
            },
            "review": {
                "humanReviewRequired": True,
                "status": "draft",
            },
            "quality": {
                "copyRisk": "unknown",
            },
        }
        generated_lineage.setdefault("source", {}).setdefault("formatType", format_type)
        generated_lineage.setdefault("generation", {}).setdefault("assetPath", str(source))
        generated_lineage.setdefault("generation", {}).setdefault("modelProfile", model_slug)
        generated_lineage.setdefault("review", {}).setdefault("humanReviewRequired", True)
        generated_lineage.setdefault("review", {}).setdefault("status", "draft")
        source_prompt = json.dumps(
            {
                "schema": "campaign_factory.finished_video_intake.v1",
                "creativePlanId": creative_plan_id,
                "creativePlanName": creative_plan_payload["name"] if creative_plan_payload else None,
                "styleLane": style_lane or format_type,
                "inputPath": str(source),
                "stagedPath": str(staged),
                "platform": platform,
                "goal": goal,
                "referencePattern": reference_pattern or source_meta.get("referencePattern") or "auto",
                "patternCardId": source_meta.get("patternCardId"),
                "promptId": source_meta.get("promptId"),
                "generationTool": generation.get("tool"),
                "modelProfile": generation.get("modelProfile") or model_slug,
                "formatType": format_type,
                "strategy": {
                    "distributionPriority": "instagram_reels_first" if platform == "instagram" else platform,
                    "primaryMetric": "views_reach",
                    "humanReviewRequired": True,
                    "nativeAudioRequired": platform == "instagram",
                    "useReferenceBank": True,
                },
                "sourcePreflight": {
                    "probe": source_probe,
                    "warnings": source_preflight,
                },
                "generatedAssetLineage": generated_lineage,
            },
            ensure_ascii=False,
            sort_keys=True,
        )
        result = self.make_batch(
            folder=intake_dir,
            campaign_slug=campaign,
            model_slug=model_slug,
            output_format="reel",
            variant_count=variant_count,
            reference_pattern=reference_pattern,
            contentforge_base_url=contentforge_base_url,
            user_id=user_id,
            dry_run_export=dry_run_export,
            workers=workers,
            recipes=recipes,
            auto_approve_warning_only=True,
            source_prompt=source_prompt,
            import_notes="finished-video intake source import",
        )
        result["finishedVideoIntake"] = {
            "schema": "campaign_factory.finished_video_intake.v1",
            "inputPath": str(source),
            "stagedFolder": str(intake_dir),
            "stagedPath": str(staged),
            "campaign": campaign,
            "model": model_slug,
            "platform": platform,
            "goal": goal,
            "formatType": format_type,
            "sourcePrompt": json_load(source_prompt, {}),
            "sourceLineagePath": str(source_lineage_path) if source_lineage_path else None,
            "sourcePreflight": source_preflight,
            "creativePlan": creative_plan_payload,
            "draftFirst": True,
            "humanReviewRequired": True,
        }
        if creative_plan_payload and campaign:
            self.conn.execute("UPDATE creative_plans SET linked_campaign_slug = ?, updated_at = ? WHERE id = ?", (campaign, utc_now(), creative_plan_id))
            self._record_creative_plan_event(creative_plan_id, "finished_video_ingested", status="success", message=f"Finished video ingested: {source.name}", metadata={"campaign": campaign, "inputPath": str(source)})
        return result

    def register_surface_asset(
        self,
        *,
        input_path: Path | list[Path] | tuple[Path, ...],
        surface: str,
        creator: str,
        campaign_slug: str,
        instagram_post_caption: str | None = None,
        target_ratio: str | None = None,
        model_slug: str | None = None,
        operator: str | None = None,
        alt_text: list[str] | None = None,
        story_asset_class: str | None = None,
        story_cta_type: str | None = None,
        story_cta_text: str | None = None,
        story_cta_target_url: str | None = None,
        story_intent: str | None = None,
        story_goal: str | None = None,
        story_style: str | None = None,
        snapchat_username: str | None = None,
        snapchat_display_name: str | None = None,
        snapchat_cta_text: str | None = None,
    ) -> dict[str, Any]:
        content_surface = normalize_content_surface(surface)
        if content_surface not in {"feed_single", "story", "feed_carousel"}:
            raise ValueError("register-surface-asset supports feed_single, story, and feed_carousel")
        creator_label = self._creator_label(creator)
        model = self.upsert_model(slugify(model_slug or creator_label), creator_label)
        campaign = self.upsert_campaign(campaign_slug, model["slug"], platform="instagram")
        dirs = self.campaign_dirs(model["slug"], campaign["slug"])
        post_caption = (instagram_post_caption or "").strip()
        if content_surface in {"feed_single", "feed_carousel"} and not post_caption:
            raise ValueError("instagram_post_caption is required for feed_single and feed_carousel")
        components = self._surface_registration_components(
            input_path=input_path,
            surface=content_surface,
            target_ratio=target_ratio,
        )
        if content_surface == "feed_single" and components[0]["mediaType"] != "image":
            raise ValueError("feed_single registration requires an image file")
        if content_surface == "story" and components[0]["mediaType"] not in {"image", "video"}:
            raise ValueError("story registration requires an image or video file")
        if content_surface == "story":
            story_source_blockers = self._story_source_blockers(components)
            if story_source_blockers:
                raise ValueError(f"story source is not story-native: {', '.join(story_source_blockers)}")
        if content_surface == "feed_carousel":
            if not (2 <= len(components) <= 10):
                raise ValueError("carousel requires 2 to 10 components")
            if not self._aspect_ratio_safe(components[0]["aspectRatio"], "feed_carousel"):
                raise ValueError("carousel cover aspect ratio is not safe")

        component_hashes = [item["contentHash"] for item in components]
        content_hash = component_hashes[0] if len(component_hashes) == 1 else hashlib.sha256("|".join(component_hashes).encode("utf-8")).hexdigest()
        staged_components = [
            {
                **item,
                "stagedPath": self._stage_surface_registration_file(
                    item["path"],
                    dirs["rendered"],
                    content_surface=content_surface,
                    content_hash=item["contentHash"],
                    component_index=index,
                ),
            }
            for index, item in enumerate(components)
        ]
        representative = staged_components[0]
        now = utc_now()
        scoped_key = hashlib.sha256(f"{campaign['id']}:{content_hash}".encode("utf-8")).hexdigest()[:12]
        source_asset_id = f"src_surface_{scoped_key}"
        render_job_id = f"render_surface_{scoped_key}"
        rendered_id = f"asset_surface_{scoped_key}"
        media_type = representative["mediaType"] if content_surface != "feed_carousel" else "carousel"
        ratio = target_ratio or representative.get("aspectRatio") or "9:16"
        caption_hash_value = hashlib.sha256(post_caption.lower().encode("utf-8")).hexdigest() if post_caption else None
        ig_media_type = self._ig_media_type_for_surface(content_surface, media_type)
        source_prompt = {
            "schema": "campaign_factory.surface_asset_registration.v1",
            "contentSurface": content_surface,
            "igMediaType": ig_media_type,
            "inputPaths": [str(item["path"]) for item in components],
            "stagedPaths": [str(item["stagedPath"]) for item in staged_components],
            "operator": operator,
            "instagramPostCaptionPresent": bool(post_caption),
        }
        caption_context = {
            "schema": "campaign_factory.caption_outcome_context.v1",
            "creator_mix": creator_label,
            "creator_model": creator_label,
            "render_recipe": "surface_asset_registered",
            "content_surface": content_surface,
            "instagram_post_caption_hash": caption_hash_value,
            "visualQcStatus": "passed",
            "identityVerificationStatus": "passed",
            "visualQc": {"status": "passed"},
            "identityVerification": {"status": "passed"},
        }
        caption_generation = {
            "schema": "campaign_factory.surface_asset_caption_generation.v1",
            "instagram_post_caption": post_caption,
            "instagramPostCaption": post_caption,
            "instagramPostCaptionHash": caption_hash_value,
            "captionOutcomeContext": caption_context,
            "allow_empty_instagram_post_caption": content_surface == "story" and not post_caption,
            "operatorReview": {
                "operator": operator,
                "approvedAt": now,
            },
        }
        if content_surface == "story":
            caption_generation.update({
                "story_asset_class": (story_asset_class or "").strip() or None,
                "story_cta_type": (story_cta_type or "").strip() or None,
                "story_cta_text": (story_cta_text or "").strip() or None,
                "story_cta_target_url": (story_cta_target_url or "").strip() or None,
                "story_intent": self._normalize_story_enum(story_intent, STORY_INTENTS),
                "story_goal": self._normalize_story_enum(story_goal, STORY_GOALS),
                "story_style": self._normalize_story_enum(story_style, STORY_STYLES),
                "snapchat_username": (snapchat_username or "").strip() or None,
                "snapchat_display_name": (snapchat_display_name or "").strip() or None,
                "snapchat_cta_text": (snapchat_cta_text or "").strip() or None,
            })
        self.conn.execute(
            """
            INSERT INTO source_assets
            (id, campaign_id, model_id, content_hash, original_path, stored_path, filename,
             media_type, content_surface, platform, source_prompt, notes, account_ids_json,
             status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'instagram', ?, ?, '[]', 'imported', ?, ?)
            ON CONFLICT(campaign_id, content_hash) DO UPDATE SET
              original_path = excluded.original_path,
              stored_path = excluded.stored_path,
              filename = excluded.filename,
              media_type = excluded.media_type,
              content_surface = excluded.content_surface,
              source_prompt = excluded.source_prompt,
              notes = excluded.notes,
              updated_at = excluded.updated_at
            """,
            (
                source_asset_id,
                campaign["id"],
                model["id"],
                content_hash,
                str(representative["path"]),
                str(representative["stagedPath"]),
                representative["stagedPath"].name,
                media_type,
                content_surface,
                json.dumps(source_prompt, ensure_ascii=False, sort_keys=True),
                "surface asset registration source",
                now,
                now,
            ),
        )
        source_row = self.conn.execute(
            "SELECT * FROM source_assets WHERE campaign_id = ? AND content_hash = ?",
            (campaign["id"], content_hash),
        ).fetchone()
        if not source_row:
            raise RuntimeError("registered surface source asset could not be loaded")
        source_asset_id = source_row["id"]
        self.conn.execute(
            """
            INSERT INTO render_jobs
            (id, campaign_id, source_asset_id, reel_clip_stem, hooks_json, recipes_json,
             caption_color, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, 'none', 'rendered', ?, ?)
            ON CONFLICT(id) DO UPDATE SET
              source_asset_id = excluded.source_asset_id,
              status = 'rendered',
              updated_at = excluded.updated_at
            """,
            (
                render_job_id,
                campaign["id"],
                source_asset_id,
                representative["stagedPath"].stem,
                json.dumps([post_caption] if post_caption else [], ensure_ascii=False),
                json.dumps(["surface_asset_registered"], ensure_ascii=False),
                now,
                now,
            ),
        )
        self.conn.execute(
            """
            INSERT INTO rendered_assets
            (id, campaign_id, source_asset_id, render_job_id, content_hash, output_path,
             campaign_path, filename, media_type, content_surface, caption, caption_hash,
             caption_bank, caption_banks_json, creator_mix, creator_model, frame_type,
             length_class, format_class, caption_fit_version, suitability_decision,
             suitability_reason, source_clip, caption_outcome_context_json,
             caption_generation_json, recipe, target_ratio, audit_status, review_state,
             story_asset_class, story_cta_type, story_cta_text, story_cta_target_url,
             story_intent, story_goal, story_style, snapchat_username, snapchat_display_name,
             snapchat_cta_text,
             created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'operator_surface_asset', ?,
                    ?, ?, ?, 'static', ?, 'surface_asset_v1', 'allowed',
                    'operator registered surface asset', ?, ?, ?, 'surface_asset_registered',
                    ?, 'passed', 'approved', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(campaign_id, content_hash) DO UPDATE SET
              source_asset_id = excluded.source_asset_id,
              render_job_id = excluded.render_job_id,
              output_path = excluded.output_path,
              campaign_path = excluded.campaign_path,
              filename = excluded.filename,
              media_type = excluded.media_type,
              content_surface = excluded.content_surface,
              caption = excluded.caption,
              caption_hash = excluded.caption_hash,
              caption_bank = excluded.caption_bank,
              caption_banks_json = excluded.caption_banks_json,
              creator_mix = excluded.creator_mix,
              creator_model = excluded.creator_model,
              frame_type = excluded.frame_type,
              length_class = excluded.length_class,
              format_class = excluded.format_class,
              caption_fit_version = excluded.caption_fit_version,
              suitability_decision = excluded.suitability_decision,
              suitability_reason = excluded.suitability_reason,
              source_clip = excluded.source_clip,
              caption_outcome_context_json = excluded.caption_outcome_context_json,
              caption_generation_json = excluded.caption_generation_json,
              recipe = excluded.recipe,
              target_ratio = excluded.target_ratio,
              audit_status = excluded.audit_status,
              review_state = excluded.review_state,
              story_asset_class = excluded.story_asset_class,
              story_cta_type = excluded.story_cta_type,
              story_cta_text = excluded.story_cta_text,
              story_cta_target_url = excluded.story_cta_target_url,
              story_intent = excluded.story_intent,
              story_goal = excluded.story_goal,
              story_style = excluded.story_style,
              snapchat_username = excluded.snapchat_username,
              snapchat_display_name = excluded.snapchat_display_name,
              snapchat_cta_text = excluded.snapchat_cta_text,
              updated_at = excluded.updated_at
            """,
            (
                rendered_id,
                campaign["id"],
                source_asset_id,
                render_job_id,
                content_hash,
                str(representative["stagedPath"]),
                str(representative["stagedPath"]),
                representative["stagedPath"].name,
                media_type,
                content_surface,
                post_caption,
                caption_hash_value,
                json.dumps(["operator_surface_asset"], ensure_ascii=False),
                creator_label,
                creator_label,
                content_surface,
                content_surface,
                str(representative["path"]),
                json.dumps(caption_context, ensure_ascii=False, sort_keys=True),
                json.dumps(caption_generation, ensure_ascii=False, sort_keys=True),
                ratio,
                (story_asset_class or "").strip() or None,
                (story_cta_type or "").strip() or None,
                (story_cta_text or "").strip() or None,
                (story_cta_target_url or "").strip() or None,
                self._normalize_story_enum(story_intent, STORY_INTENTS),
                self._normalize_story_enum(story_goal, STORY_GOALS),
                self._normalize_story_enum(story_style, STORY_STYLES),
                (snapchat_username or "").strip() or None,
                (snapchat_display_name or "").strip() or None,
                (snapchat_cta_text or "").strip() or None,
                now,
                now,
            ),
        )
        rendered_row = self.conn.execute(
            "SELECT * FROM rendered_assets WHERE campaign_id = ? AND content_hash = ?",
            (campaign["id"], content_hash),
        ).fetchone()
        if not rendered_row:
            raise RuntimeError("registered surface rendered asset could not be loaded")
        rendered_id = rendered_row["id"]
        self.conn.execute("DELETE FROM asset_components WHERE asset_id = ?", (rendered_id,))
        if content_surface == "feed_carousel":
            for index, item in enumerate(staged_components):
                self.conn.execute(
                    """
                    INSERT INTO asset_components
                    (id, asset_id, component_index, media_path, media_hash, media_type,
                     aspect_ratio, alt_text, publishability_state, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'passed', ?, ?)
                    """,
                    (
                        f"component_{rendered_id}_{index}",
                        rendered_id,
                        index,
                        str(item["stagedPath"]),
                        item["contentHash"],
                        item["mediaType"],
                        item["aspectRatio"],
                        (alt_text or [None] * len(staged_components))[index] if index < len(alt_text or []) else None,
                        now,
                        now,
                    ),
                )
        audit_id = f"audit_surface_{scoped_key}"
        audit_payload = {
            "schema": "campaign_factory.surface_asset_audit.v1",
            "contentSurface": content_surface,
            "igMediaType": ig_media_type,
            "overallVerdict": "pass",
            "visualQcStatus": "passed",
            "identityVerificationStatus": "passed",
            "visualQc": {"status": "passed"},
            "identityVerification": {"status": "passed"},
            "readinessSummary": {
                "uploadReady": True,
                "blockingReasons": [],
                "blockingCodes": [],
                "warnings": [],
                "warningCodes": [],
                "visualQcStatus": "passed",
                "identityVerificationStatus": "passed",
            },
            "mediaItems": [
                {
                    "mediaPath": str(item["stagedPath"]),
                    "mediaHash": item["contentHash"],
                    "mediaType": item["mediaType"],
                    "aspectRatio": item["aspectRatio"],
                }
                for item in staged_components
            ],
        }
        audit_dir = dirs["audits"] / "surface_asset_registration"
        audit_dir.mkdir(parents=True, exist_ok=True)
        audit_path = audit_dir / f"{audit_id}.json"
        audit_path.write_text(json.dumps(audit_payload, indent=2, ensure_ascii=False), encoding="utf-8")
        self.conn.execute(
            """
            INSERT INTO audit_reports
            (id, campaign_id, rendered_asset_id, contentforge_run_id, report_path, score,
             status, layers_json, verdicts_json, overall_verdict, files_analyzed,
             failed_checks_json, warnings_json, created_at)
            VALUES (?, ?, ?, 'surface_asset_registration', ?, 90, 'pass', '{}', '{}',
                    'pass', ?, '[]', '[]', ?)
            ON CONFLICT(id) DO UPDATE SET
              rendered_asset_id = excluded.rendered_asset_id,
              report_path = excluded.report_path,
              status = excluded.status,
              overall_verdict = excluded.overall_verdict,
              files_analyzed = excluded.files_analyzed,
              created_at = excluded.created_at
            """,
            (audit_id, campaign["id"], rendered_id, str(audit_path), len(staged_components), now),
        )
        self.record_event(
            "surface_asset_registered",
            campaign_id=campaign["id"],
            source_asset_id=source_asset_id,
            rendered_asset_id=rendered_id,
            render_job_id=render_job_id,
            audit_report_id=audit_id,
            status="success",
            message=f"Surface asset registered: {representative['stagedPath'].name}",
            metadata={
                "contentSurface": content_surface,
                "igMediaType": ig_media_type,
                "contentHash": content_hash,
            },
            commit=False,
        )
        self.conn.commit()
        readiness_report = self.surface_handoff_readiness_report(
            creator=creator_label,
            campaign_slug=campaign["slug"],
            rendered_asset_id=rendered_id,
        )
        readiness = readiness_report["assets"][0] if readiness_report["assets"] else {"canHandoff": False, "igMediaType": ig_media_type}
        return {
            "schema": "campaign_factory.register_surface_asset.v1",
            "campaign": campaign["slug"],
            "creator": creator_label,
            "renderedAssetId": rendered_id,
            "sourceAssetId": source_asset_id,
            "renderJobId": render_job_id,
            "auditReportId": audit_id,
            "contentHash": content_hash,
            "contentSurface": content_surface,
            "mediaType": media_type,
            "igMediaType": readiness["igMediaType"],
            "instagramPostCaptionPresent": bool(post_caption),
            "componentCount": len(staged_components),
            "mediaItems": (readiness.get("handoffManifestV2") or {}).get("mediaItems", []),
            "publishability": "passed" if readiness.get("canHandoff") else "blocked",
            "handoffManifestV2": readiness.get("handoffManifestV2"),
            "wouldSchedule": False,
            "wouldPublish": False,
        }

    def _surface_registration_components(
        self,
        *,
        input_path: Path | list[Path] | tuple[Path, ...],
        surface: str,
        target_ratio: str | None,
    ) -> list[dict[str, Any]]:
        if surface == "feed_carousel":
            paths = [Path(input_path)] if isinstance(input_path, (str, Path)) else [Path(path) for path in input_path]
        else:
            if isinstance(input_path, (list, tuple)):
                if len(input_path) != 1:
                    raise ValueError(f"{surface} registration requires exactly one media file")
                paths = [Path(input_path[0])]
            else:
                paths = [Path(input_path)]
        return [self._surface_registration_component(path, surface=surface, target_ratio=target_ratio) for path in paths]

    def _surface_registration_component(self, path: Path, *, surface: str, target_ratio: str | None) -> dict[str, Any]:
        source = path.expanduser().resolve()
        if not source.exists() or not source.is_file():
            raise FileNotFoundError(f"surface media not found: {source}")
        media_type = media_type_for_path(source)
        if media_type not in {"image", "video"}:
            raise ValueError("surface asset requires an image or video file")
        shape = probe_image_shape(source) if media_type == "image" else probe_video_shape(source)
        width = int(shape.get("effectiveWidth") or shape.get("width") or 0) if isinstance(shape, dict) else 0
        height = int(shape.get("effectiveHeight") or shape.get("height") or 0) if isinstance(shape, dict) else 0
        aspect_ratio = (target_ratio or ratio_label_from_shape(width, height) or "").strip()
        if media_type == "image" and (not shape.get("ok") or not width or not height):
            raise ValueError("valid image dimensions are required")
        if media_type == "video" and not aspect_ratio:
            raise ValueError("valid video dimensions or target_ratio are required")
        readiness_surface = "feed_carousel" if surface == "feed_carousel" else surface
        if aspect_ratio and not self._aspect_ratio_safe(aspect_ratio, readiness_surface):
            raise ValueError(f"{surface} aspect ratio is not safe")
        return {
            "path": source,
            "mediaType": media_type,
            "contentHash": sha256_file(source),
            "aspectRatio": aspect_ratio or target_ratio or "9:16",
            "shape": shape,
        }

    def _story_source_blockers(self, components: list[dict[str, Any]]) -> list[str]:
        blockers: list[str] = []
        for item in components:
            path = Path(str(item.get("path") or "")).expanduser()
            path_text = str(path)
            lower_path = path_text.lower()
            parts = {part.lower() for part in path.parts}
            name = path.name.lower()
            if "campaign_factory" in parts and {"02_rendered", "04_approved"} & parts:
                blockers.append("story_source_must_be_raw_not_rendered_reel_asset")
            if item.get("mediaType") == "video" and any(marker in lower_path for marker in ("variant_fanout", "parent_repair", "asset_finished", "caption_family", "contentforge")):
                blockers.append("story_video_source_looks_like_reel_or_contentforge_output")
            if any(marker in name for marker in ("captioned", "caption_bg", "burned_caption", "parent_repair")):
                blockers.append("story_source_appears_to_have_burned_caption_or_reel_lineage")
        return sorted(set(blockers))

    def _story_existing_asset_source_blockers(self, asset: dict[str, Any]) -> list[str]:
        paths = [
            asset.get("source_clip"),
            asset.get("campaign_path"),
            asset.get("output_path"),
            asset.get("filename"),
        ]
        blockers: list[str] = []
        for raw in paths:
            if not raw:
                continue
            lower = str(raw).lower()
            parts = {part.lower() for part in Path(str(raw)).parts}
            if "campaign_factory" in parts and {"04_approved"} & parts:
                blockers.append("story_source_must_be_raw_not_approved_reel_asset")
            if "campaign_factory" in parts and "02_rendered" in parts and any(marker in lower for marker in ("variant_fanout", "parent_repair", "asset_finished", "contentforge")):
                blockers.append("story_source_must_be_raw_not_rendered_reel_asset")
            if any(marker in lower for marker in ("captioned", "caption_bg", "burned_caption", "parent_repair")):
                blockers.append("story_source_appears_to_have_burned_caption_or_reel_lineage")
        return sorted(set(blockers))

    def _stage_surface_registration_file(
        self,
        path: Path,
        rendered_dir: Path,
        *,
        content_surface: str,
        content_hash: str,
        component_index: int,
    ) -> Path:
        prefix = f"{content_surface}_{component_index}_{slugify(path.stem)}_{content_hash[:10]}"
        staged = rendered_dir / f"{prefix}{path.suffix.lower()}"
        if not staged.exists():
            shutil.copy2(path, staged)
        return staged

    def register_finished_video(
        self,
        *,
        input_path: Path,
        campaign_slug: str,
        model_slug: str,
        caption: str,
        instagram_post_caption: str | None = None,
        caption_hash: str | None = None,
        caption_bank: str | None = None,
        creator_mix: str | None = None,
        creator_model: str | None = None,
        track_id: str | None = None,
        track_name: str | None = None,
        audio_source: str | None = None,
        selected_reason: str | None = None,
        operator: str | None = None,
        approval_reason: str | None = None,
        review_batch: str | None = None,
        caption_placement_policy: str | None = None,
        caption_placement_decision: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        source = Path(input_path).expanduser().resolve()
        if not source.exists() or not source.is_file():
            raise FileNotFoundError(f"finished video not found: {source}")
        if media_type_for_path(source) != "video":
            raise ValueError("register-finished-video requires a video file")
        if not caption.strip():
            raise ValueError("caption is required for publishability lineage")
        model = self.upsert_model(model_slug, model_slug.title())
        campaign = self.upsert_campaign(campaign_slug, model["slug"], platform="instagram")
        normalized_caption = caption.strip()
        normalized_post_caption = (instagram_post_caption or normalized_caption).strip()
        pre_render_gate = self.discoverability_pre_render_gate({
            "caption_text": normalized_caption,
            "burned_caption_text": normalized_caption,
            "instagram_post_caption": normalized_post_caption,
        })
        if not pre_render_gate["canProceed"]:
            capture = self._capture_discoverability_gate_rejection_evidence(
                gate_result=pre_render_gate,
                failed_stage="discoverability_pre_render_gate",
                campaign_id=campaign["id"],
                content_surface="reel",
                commit=True,
            )
            return {
                "schema": "campaign_factory.register_finished_video.v1",
                "campaign": campaign["slug"],
                "renderedAssetId": "",
                "sourceAssetId": "",
                "renderJobId": "",
                "auditReportId": "",
                "contentHash": "",
                "captionHash": "",
                "mediaPath": str(source),
                "canProceed": False,
                "blockedAt": "discoverability_pre_render_gate",
                "discoverabilityGate": pre_render_gate,
                "rejectionEvidenceCapture": capture,
            }
        dirs = self.campaign_dirs(model["slug"], campaign["slug"])
        digest = sha256_file(source)
        staged = dirs["rendered"] / f"{slugify(source.stem)}_{digest[:10]}{source.suffix.lower()}"
        if not staged.exists():
            shutil.copy2(source, staged)
        now = utc_now()
        source_asset_id = f"src_finished_{digest[:12]}"
        source_prompt = {
            "schema": "campaign_factory.finished_video_registration.v1",
            "inputPath": str(source),
            "stagedPath": str(staged),
            "reviewBatch": review_batch,
            "operator": operator,
            "approvalReason": approval_reason,
            "audio": {
                "trackId": track_id,
                "trackName": track_name,
                "source": audio_source,
                "selectedReason": selected_reason,
            },
        }
        self.conn.execute(
            """
            INSERT INTO source_assets
            (id, campaign_id, model_id, content_hash, original_path, stored_path, filename,
             media_type, platform, source_prompt, notes, account_ids_json, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'video', 'instagram', ?, ?, '[]', 'imported', ?, ?)
            ON CONFLICT(campaign_id, content_hash) DO UPDATE SET
              original_path = excluded.original_path,
              stored_path = excluded.stored_path,
              filename = excluded.filename,
              source_prompt = excluded.source_prompt,
              notes = excluded.notes,
              updated_at = excluded.updated_at
            """,
            (
                source_asset_id,
                campaign["id"],
                model["id"],
                digest,
                str(source),
                str(staged),
                staged.name,
                json.dumps(source_prompt, ensure_ascii=False, sort_keys=True),
                "finished-video registration source",
                now,
                now,
            ),
        )
        source_row = self.conn.execute(
            "SELECT * FROM source_assets WHERE campaign_id = ? AND content_hash = ?",
            (campaign["id"], digest),
        ).fetchone()
        if not source_row:
            raise RuntimeError("registered source asset could not be loaded")
        source_asset_id = source_row["id"]
        render_job_id = f"render_finished_{digest[:12]}"
        self.conn.execute(
            """
            INSERT INTO render_jobs
            (id, campaign_id, source_asset_id, reel_clip_stem, hooks_json, recipes_json,
             caption_color, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, 'light', 'rendered', ?, ?)
            ON CONFLICT(id) DO UPDATE SET
              status = 'rendered',
              updated_at = excluded.updated_at
            """,
            (
                render_job_id,
                campaign["id"],
                source_asset_id,
                staged.stem,
                json.dumps([caption], ensure_ascii=False),
                json.dumps(["finished_video_registered"], ensure_ascii=False),
                now,
                now,
            ),
        )
        caption_hash_value = (caption_hash or "").strip() or hashlib.sha256(normalized_caption.lower().encode("utf-8")).hexdigest()
        caption_bank_value = (caption_bank or "").strip() or "operator_finished_video"
        creator_value = (creator_mix or creator_model or model_slug)
        caption_context = {
            "schema": "campaign_factory.caption_outcome_context.v1",
            "caption_hash": caption_hash_value,
            "caption_text": normalized_caption,
            "burned_caption_text": normalized_caption,
            "burned_caption_hash": caption_hash_value,
            "instagram_post_caption": normalized_post_caption,
            "instagram_post_caption_hash": self._text_hash(normalized_post_caption) if normalized_post_caption else None,
            "caption_bank": caption_bank_value,
            "caption_banks": [caption_bank_value],
            "creator_mix": creator_value,
            "creator_model": creator_model or creator_value,
            "render_recipe": "finished_video_registered",
            "source_clip": str(source),
            "rendered_output": str(staged),
            "audio_track_id": track_id,
            "audio_source": audio_source,
            "audio_selected_reason": selected_reason,
            "review_batch": review_batch,
            "visualQcStatus": "passed",
            "identityVerificationStatus": "passed",
            "visualQc": {"status": "passed"},
            "identityVerification": {"status": "passed"},
        }
        if caption_placement_policy:
            caption_context["captionPlacementPolicy"] = caption_placement_policy
        if isinstance(caption_placement_decision, dict):
            caption_context["captionPlacementDecision"] = caption_placement_decision
        audio_intent = {
            "schema": "pipeline.audio_intent.v1",
            "status": "attached" if track_id else "missing",
            "source": audio_source or "operator_muxed_audio",
            "operator_selection": {
                "audio_id": track_id,
                "track_id": track_id,
                "track_name": track_name,
                "audio_title": track_name,
                "source": audio_source,
                "selected_reason": selected_reason,
                "selected_at": now,
                "attached_at": now if track_id else None,
                "operator": operator,
                "notes": "Audio is embedded in the registered MP4.",
            },
        }
        caption_generation = {
            "schema": "campaign_factory.finished_video_caption_generation.v1",
            "caption": normalized_caption,
            "captionHash": caption_hash_value,
            "burned_caption_text": normalized_caption,
            "burned_caption_hash": caption_hash_value,
            "instagram_post_caption": normalized_post_caption,
            "instagram_post_caption_hash": self._text_hash(normalized_post_caption) if normalized_post_caption else None,
            "captionOutcomeContext": caption_context,
            "audioIntent": audio_intent,
            "captionPlacementPolicy": caption_placement_policy,
            "captionPlacementDecision": caption_placement_decision if isinstance(caption_placement_decision, dict) else None,
            "operatorReview": {
                "operator": operator,
                "approvalReason": approval_reason,
                "reviewBatch": review_batch,
                "approvedAt": now,
            },
        }
        rendered_id = f"asset_finished_{digest[:12]}"
        self.conn.execute(
            """
            INSERT INTO rendered_assets
            (id, campaign_id, source_asset_id, render_job_id, content_hash, output_path,
             campaign_path, filename, caption, caption_hash, caption_bank, caption_banks_json,
             creator_mix, creator_model, frame_type, length_class, format_class,
             caption_fit_version, suitability_decision, suitability_reason, source_clip,
             caption_outcome_context_json, caption_generation_json, recipe, target_ratio,
             audit_status, review_state, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'selfie_video', 'short',
             'reel', 'operator_finished_video_v1', 'allowed', 'operator approved finished video',
             ?, ?, ?, 'finished_video_registered', '9:16', 'passed', 'approved', ?, ?)
            ON CONFLICT(campaign_id, content_hash) DO UPDATE SET
              output_path = excluded.output_path,
              campaign_path = excluded.campaign_path,
              filename = excluded.filename,
              caption = excluded.caption,
              caption_hash = excluded.caption_hash,
              caption_bank = excluded.caption_bank,
              caption_banks_json = excluded.caption_banks_json,
              creator_mix = excluded.creator_mix,
              creator_model = excluded.creator_model,
              frame_type = excluded.frame_type,
              length_class = excluded.length_class,
              format_class = excluded.format_class,
              caption_fit_version = excluded.caption_fit_version,
              suitability_decision = excluded.suitability_decision,
              suitability_reason = excluded.suitability_reason,
              source_clip = excluded.source_clip,
              caption_outcome_context_json = excluded.caption_outcome_context_json,
              caption_generation_json = excluded.caption_generation_json,
              recipe = excluded.recipe,
              target_ratio = excluded.target_ratio,
              audit_status = excluded.audit_status,
              review_state = excluded.review_state,
              updated_at = excluded.updated_at
            """,
            (
                rendered_id,
                campaign["id"],
                source_asset_id,
                render_job_id,
                digest,
                str(staged),
                str(staged),
                staged.name,
                normalized_caption,
                caption_hash_value,
                caption_bank_value,
                json.dumps([caption_bank_value], ensure_ascii=False),
                creator_value,
                creator_model or creator_value,
                str(source),
                json.dumps(caption_context, ensure_ascii=False, sort_keys=True),
                json.dumps(caption_generation, ensure_ascii=False, sort_keys=True),
                now,
                now,
            ),
        )
        rendered_row = self.conn.execute(
            "SELECT * FROM rendered_assets WHERE campaign_id = ? AND content_hash = ?",
            (campaign["id"], digest),
        ).fetchone()
        if not rendered_row:
            raise RuntimeError("registered rendered asset could not be loaded")
        rendered_id = rendered_row["id"]
        audit_id = f"audit_finished_{digest[:12]}"
        audit_payload = {
            "schema": "campaign_factory.finished_video_operator_audit.v1",
            "targetFile": str(staged),
            "overallVerdict": "pass",
            "readinessSummary": {
                "state": "ready",
                "blockingReasons": [],
                "blockingCodes": [],
                "warnings": [],
                "warningCodes": [],
                "visualQcStatus": "passed",
                "identityVerificationStatus": "passed",
            },
            "visualQcStatus": "passed",
            "identityVerificationStatus": "passed",
            "visualQc": {"status": "passed"},
            "identityVerification": {"status": "passed"},
            "operatorReview": caption_generation["operatorReview"],
            "probe": probe_video_shape(staged),
        }
        audit_dir = dirs["audits"] / "finished_video_operator"
        audit_dir.mkdir(parents=True, exist_ok=True)
        audit_path = audit_dir / f"{audit_id}.json"
        audit_path.write_text(json.dumps(audit_payload, indent=2, ensure_ascii=False), encoding="utf-8")
        self.conn.execute(
            """
            INSERT INTO audit_reports
            (id, campaign_id, rendered_asset_id, contentforge_run_id, report_path, score,
             status, layers_json, verdicts_json, overall_verdict, files_analyzed,
             failed_checks_json, warnings_json, created_at)
            VALUES (?, ?, ?, ?, ?, 90, 'pass', '{}', '{}', 'pass', 1, '[]', '[]', ?)
            ON CONFLICT(id) DO UPDATE SET
              report_path = excluded.report_path,
              score = excluded.score,
              status = excluded.status,
              overall_verdict = excluded.overall_verdict,
              failed_checks_json = excluded.failed_checks_json,
              warnings_json = excluded.warnings_json,
              created_at = excluded.created_at
            """,
            (
                audit_id,
                campaign["id"],
                rendered_id,
                "operator_finished_video_audit",
                str(audit_path),
                now,
            ),
        )
        self.record_event(
            "finished_video_registered",
            campaign_id=campaign["id"],
            source_asset_id=source_asset_id,
            rendered_asset_id=rendered_id,
            render_job_id=render_job_id,
            audit_report_id=audit_id,
            status="success",
            message=f"Finished video registered: {staged.name}",
            metadata={
                "inputPath": str(source),
                "stagedPath": str(staged),
                "contentHash": digest,
                "captionHash": caption_hash_value,
                "audioTrackId": track_id,
                "reviewBatch": review_batch,
            },
            commit=False,
        )
        self.conn.commit()
        publishability = self.explain_publishability(rendered_id)
        rejection_capture = None
        if not publishability.get("publishableCandidate"):
            rejection_capture = self._capture_publishability_rejection_evidence_from_result(
                rendered_id,
                publishability,
                commit=True,
            )
        return {
            "schema": "campaign_factory.register_finished_video.v1",
            "campaign": campaign["slug"],
            "renderedAssetId": rendered_id,
            "sourceAssetId": source_asset_id,
            "renderJobId": render_job_id,
            "auditReportId": audit_id,
            "contentHash": digest,
            "captionHash": caption_hash_value,
            "mediaPath": str(staged),
            "audioIntent": audio_intent,
            "publishability": publishability,
            "rejectionEvidenceCapture": rejection_capture,
        }

    def _load_source_lineage(self, source_lineage_path: Path | None) -> dict[str, Any]:
        if not source_lineage_path:
            return {}
        path = Path(source_lineage_path).expanduser()
        if not path.exists():
            raise FileNotFoundError(f"source lineage not found: {path}")
        payload = json_load(path.read_text(encoding="utf-8"), {})
        if not isinstance(payload, dict):
            raise ValueError(f"source lineage must be a JSON object: {path}")
        self._record_lineage_costs(payload)
        return payload

    def _record_lineage_costs(self, lineage: dict[str, Any]) -> None:
        """Extract AI cost data from imported lineage and record it."""
        try:
            ensure_cost_table(self.conn)
            lineage_hash = hashlib.sha256(
                json.dumps(lineage, ensure_ascii=False, sort_keys=True, default=str).encode("utf-8")
            ).hexdigest()[:24]
            # Grok prompt generation costs (from reel_factory lineage)
            usage = lineage.get("usage")
            if isinstance(usage, dict):
                record_ai_cost(
                    self.conn,
                    provider="grok",
                    operation="image_prompt",
                    campaign_id=lineage.get("campaign"),
                    input_tokens=usage.get("input_tokens"),
                    output_tokens=usage.get("output_tokens"),
                    metadata={"lineage_schema": lineage.get("schema"), "model": lineage.get("model")},
                    source_event_key=f"lineage:{lineage_hash}:grok:image_prompt",
                )
            # Higgsfield/Kling generation costs (from generation block)
            gen = lineage.get("generation")
            if isinstance(gen, dict):
                tool = gen.get("tool", "")
                if "higgsfield" in tool or "soul" in tool:
                    record_ai_cost(
                        self.conn,
                        provider="higgsfield",
                        operation="soul_grid",
                        campaign_id=lineage.get("campaign"),
                        generations=1,
                        metadata={"tool": tool, "modelProfile": gen.get("modelProfile")},
                        source_event_key=f"lineage:{lineage_hash}:higgsfield:soul_grid",
                    )
                if "kling" in tool:
                    record_ai_cost(
                        self.conn,
                        provider="kling",
                        operation="video_animate",
                        campaign_id=lineage.get("campaign"),
                        generations=1,
                        metadata={"tool": tool, "modelProfile": gen.get("modelProfile")},
                        source_event_key=f"lineage:{lineage_hash}:kling:video_animate",
                    )
        except Exception:
            pass  # Cost tracking is best-effort; never block the import pipeline

    def _finished_video_preflight(self, probe: dict[str, Any]) -> list[dict[str, str]]:
        warnings: list[dict[str, str]] = []
        aspect = probe.get("effectiveAspectRatio")
        if isinstance(aspect, (int, float)) and aspect > 0:
            if aspect < 0.48 or aspect > 0.66:
                warnings.append(
                    {
                        "code": "finished_video_not_reels_canvas",
                        "message": "Finished video is not close to a clean 9:16 Reels canvas; check for platform UI, borders, or screen-recorded wrapper before posting.",
                    }
                )
        elif not probe:
            warnings.append(
                {
                    "code": "finished_video_probe_unavailable",
                    "message": "Could not probe finished video dimensions before intake.",
                }
            )
        return warnings

    def archive_inventory_report(
        self,
        *,
        folder: Path,
        campaign_slug: str,
        creator: str = "Stacey",
        requested_count: int = 25,
        model_slug: str | None = None,
        recent_days: int = 30,
    ) -> dict[str, Any]:
        archive = Path(folder).expanduser().resolve()
        if not archive.exists() or not archive.is_dir():
            raise FileNotFoundError(f"archive folder not found: {archive}")
        if requested_count <= 0:
            raise ValueError("requested_count must be positive")

        creator_slug = slugify(creator)
        model_slug_value = model_slug or creator_slug
        model = self.upsert_model(model_slug_value, creator)
        campaign = self.upsert_campaign(campaign_slug, model["slug"], platform="instagram")
        dirs = self.campaign_dirs(model["slug"], campaign["slug"])
        report_dir = dirs["root"] / "06_reports" / "archive_inventory"
        report_dir.mkdir(parents=True, exist_ok=True)

        video_paths = sorted(path for path in archive.iterdir() if path.is_file() and path.suffix.lower() == ".mp4")
        seen_source_fingerprints: set[str] = set()
        items: list[dict[str, Any]] = []
        duplicate_source_fingerprint = 0
        duplicate_content_hash = 0
        duplicate_recent_publish = 0
        corrupted_or_invalid = 0
        clean_stacey_candidates = 0
        audio_present_count = 0
        audio_missing_count = 0

        recent_cutoff = datetime.now(timezone.utc) - timedelta(days=recent_days)
        for index, path in enumerate(video_paths, start=1):
            digest = sha256_file(path)
            probe = probe_video_metadata(path)
            blocking_reasons: list[str] = []
            warnings: list[str] = []

            if digest in seen_source_fingerprints:
                blocking_reasons.append("duplicate_source_fingerprint")
                duplicate_source_fingerprint += 1
            else:
                seen_source_fingerprints.add(digest)

            existing_duplicate = self._archive_existing_content_duplicate(digest)
            if existing_duplicate:
                blocking_reasons.append("duplicate_existing_campaign_asset")
                duplicate_content_hash += 1

            recent_duplicate = self._archive_recent_publish_duplicate(digest, recent_cutoff)
            if recent_duplicate:
                blocking_reasons.append("duplicate_recent_publish")
                duplicate_recent_publish += 1

            if not probe.get("ok"):
                blocking_reasons.append(str(probe.get("error") or "probe_failed"))
                corrupted_or_invalid += 1
            elif not isinstance(probe.get("durationSeconds"), (int, float)) or float(probe.get("durationSeconds") or 0) <= 0:
                blocking_reasons.append("invalid_duration")
                corrupted_or_invalid += 1

            audio_present = bool(probe.get("audioPresent"))
            if audio_present:
                audio_present_count += 1
                audio_status = "present"
            else:
                audio_missing_count += 1
                audio_status = "missing_needs_campaign_audio"

            aspect = probe.get("effectiveAspectRatio")
            if isinstance(aspect, (int, float)) and aspect > 0 and (aspect < 0.35 or aspect > 0.9):
                warnings.append("source_aspect_ratio_needs_reels_render")

            creator_match = {
                "required": True,
                "creator": creator,
                "decision": "operator_source_required",
                "reason": "Archive folder is treated as operator-supplied Stacey inventory until source review approves candidates.",
            }

            status = "blocked" if blocking_reasons else "clean_source_candidate"
            if status == "clean_source_candidate":
                clean_stacey_candidates += 1

            items.append(
                {
                    "index": index,
                    "filename": path.name,
                    "sourcePath": str(path),
                    "sourceFingerprint": digest,
                    "contentHash": digest,
                    "status": status,
                    "blockingReasons": blocking_reasons,
                    "warnings": warnings,
                    "creatorMatch": creator_match,
                    "audioStatus": audio_status,
                    "audioPresent": audio_present,
                    "probe": probe,
                    "duplicate": {
                        "sourceFingerprint": "duplicate" if "duplicate_source_fingerprint" in blocking_reasons else "clear",
                        "existingCampaignAsset": existing_duplicate,
                        "recentPublish": recent_duplicate,
                    },
                }
            )

        status = "ready_for_source_approval" if clean_stacey_candidates >= requested_count else "blocked"
        blocking_reason = None if status == "ready_for_source_approval" else "insufficient_clean_archive_inventory"
        now = utc_now()
        result = {
            "schema": "campaign_factory.archive_inventory_report.v1",
            "campaign": campaign["slug"],
            "campaignId": campaign["id"],
            "creator": creator,
            "creatorMatchRequired": True,
            "archiveFolder": str(archive),
            "generatedAt": now,
            "requestedCount": requested_count,
            "archiveVideosFound": len(video_paths),
            "cleanStaceyCandidates": clean_stacey_candidates,
            "duplicateContentHash": duplicate_content_hash,
            "duplicateSourceFingerprint": duplicate_source_fingerprint,
            "duplicateRecentPublish": duplicate_recent_publish,
            "corruptedOrInvalid": corrupted_or_invalid,
            "audioPresent": audio_present_count,
            "audioMissingNeedsCampaignAudio": audio_missing_count,
            "status": status,
            "blockingReason": blocking_reason,
            "wouldProceedToRendering": False,
            "canProceedAfterOperatorSourceApproval": status == "ready_for_source_approval",
            "nextOperatorAction": "approve_25_source_candidates_before_caption_rendering"
            if status == "ready_for_source_approval"
            else "provide_more_clean_stacey_archive_inventory",
            "items": items,
        }
        report_path = report_dir / f"archive_inventory_{datetime.now(timezone.utc).strftime('%Y%m%dT%H%M%SZ')}.json"
        result["reportPath"] = str(report_path)
        report_path.write_text(json.dumps(result, indent=2, ensure_ascii=False, sort_keys=True), encoding="utf-8")
        self.record_event(
            "archive_inventory_report",
            campaign_id=campaign["id"],
            status="success" if status == "ready_for_source_approval" else "warning",
            message=f"Archive inventory report: {clean_stacey_candidates}/{requested_count} clean {creator} source candidates",
            metadata={
                "reportPath": str(report_path),
                "archiveVideosFound": len(video_paths),
                "cleanCandidates": clean_stacey_candidates,
                "blockingReason": blocking_reason,
            },
            commit=False,
        )
        self.conn.commit()
        return result

    def _archive_existing_content_duplicate(self, digest: str) -> dict[str, Any] | None:
        source = self.conn.execute(
            """
            SELECT source_assets.id, source_assets.campaign_id, campaigns.slug AS campaign_slug
            FROM source_assets
            JOIN campaigns ON campaigns.id = source_assets.campaign_id
            WHERE source_assets.content_hash = ?
            LIMIT 1
            """,
            (digest,),
        ).fetchone()
        if source:
            return {
                "table": "source_assets",
                "id": source["id"],
                "campaignId": source["campaign_id"],
                "campaign": source["campaign_slug"],
            }
        rendered = self.conn.execute(
            """
            SELECT rendered_assets.id, rendered_assets.campaign_id, campaigns.slug AS campaign_slug
            FROM rendered_assets
            JOIN campaigns ON campaigns.id = rendered_assets.campaign_id
            WHERE rendered_assets.content_hash = ?
            LIMIT 1
            """,
            (digest,),
        ).fetchone()
        if rendered:
            return {
                "table": "rendered_assets",
                "id": rendered["id"],
                "campaignId": rendered["campaign_id"],
                "campaign": rendered["campaign_slug"],
            }
        return None

    def _archive_recent_publish_duplicate(self, digest: str, recent_cutoff: datetime) -> dict[str, Any] | None:
        rows = self.conn.execute(
            """
            SELECT performance_snapshots.id, performance_snapshots.post_id, performance_snapshots.published_at,
                   performance_snapshots.campaign_id, campaigns.slug AS campaign_slug
            FROM performance_snapshots
            JOIN campaigns ON campaigns.id = performance_snapshots.campaign_id
            WHERE performance_snapshots.content_hash = ?
               OR performance_snapshots.source_content_hash = ?
            ORDER BY performance_snapshots.published_at DESC
            LIMIT 5
            """,
            (digest, digest),
        ).fetchall()
        for row in rows:
            published_at = row["published_at"]
            if not published_at:
                continue
            try:
                parsed = datetime.fromisoformat(str(published_at).replace("Z", "+00:00"))
            except ValueError:
                continue
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=timezone.utc)
            if parsed >= recent_cutoff:
                return {
                    "table": "performance_snapshots",
                    "id": row["id"],
                    "postId": row["post_id"],
                    "campaignId": row["campaign_id"],
                    "campaign": row["campaign_slug"],
                    "publishedAt": published_at,
                }
        return None

    def archive_candidate_quality_report(
        self,
        *,
        inventory_report_path: Path,
        requested_count: int = 25,
        exclude_indices: list[int] | None = None,
    ) -> dict[str, Any]:
        path = Path(inventory_report_path).expanduser().resolve()
        if not path.exists():
            raise FileNotFoundError(f"archive inventory report not found: {path}")
        if requested_count <= 0:
            raise ValueError("requested_count must be positive")
        inventory = json_load(path.read_text(encoding="utf-8"), {})
        if not isinstance(inventory, dict) or inventory.get("schema") != "campaign_factory.archive_inventory_report.v1":
            raise ValueError(f"not an archive inventory report: {path}")

        excluded = set(exclude_indices or [])
        clean_items = [item for item in inventory.get("items", []) if isinstance(item, dict) and item.get("status") == "clean_source_candidate"]
        ranked: list[dict[str, Any]] = []
        for item in clean_items:
            index = int(item.get("index") or 0)
            probe = item.get("probe") if isinstance(item.get("probe"), dict) else {}
            severity, crop_score, crop_delta = self._archive_crop_severity(probe)
            visual_score = self._archive_visual_quality_score(probe, item.get("warnings") or [], crop_score)
            duplicate_confidence = self._archive_duplicate_confidence(item)
            recommendation = "excluded_by_operator" if index in excluded else "candidate"
            ranked.append(
                {
                    "index": index,
                    "filename": item.get("filename"),
                    "sourcePath": item.get("sourcePath"),
                    "contentHash": item.get("contentHash"),
                    "sourceFingerprint": item.get("sourceFingerprint"),
                    "aspectRatio": probe.get("effectiveAspectRatio"),
                    "durationSeconds": probe.get("durationSeconds"),
                    "resolution": f"{probe.get('effectiveWidth') or probe.get('width')}x{probe.get('effectiveHeight') or probe.get('height')}",
                    "bitrate": probe.get("bitrate"),
                    "audioStatus": item.get("audioStatus"),
                    "warnings": item.get("warnings") or [],
                    "estimatedCropSeverity": severity,
                    "cropDeviationFrom9x16": crop_delta,
                    "cropSeverityScore": crop_score,
                    "visualQualityScore": visual_score,
                    "duplicateConfidence": duplicate_confidence,
                    "recommendation": recommendation,
                    "selectionReason": None,
                }
            )

        selectable = [item for item in ranked if item["recommendation"] != "excluded_by_operator"]
        selectable.sort(key=lambda item: (-item["visualQualityScore"], item["cropSeverityScore"], item["index"]))
        selected = selectable[:requested_count]
        selected_indices = {item["index"] for item in selected}
        for item in ranked:
            if item["recommendation"] == "excluded_by_operator":
                item["selectionReason"] = "operator excluded before rendering"
            elif item["index"] in selected_indices:
                item["recommendation"] = "selected_for_source_approval"
                item["selectionReason"] = "top ranked clean source candidate"
            else:
                item["recommendation"] = "alternate"
                item["selectionReason"] = "clean but lower ranked than requested pilot count"

        ranked.sort(key=lambda item: item["index"])
        recommended_indices = [item["index"] for item in selected]
        recommended_indices.sort()
        status = "ready_for_source_approval" if len(selected) >= requested_count else "blocked"
        blocking_reason = None if status == "ready_for_source_approval" else "insufficient_ranked_archive_inventory"
        report_dir = path.parent.parent / "candidate_quality"
        report_dir.mkdir(parents=True, exist_ok=True)
        report_path = report_dir / f"archive_candidate_quality_{datetime.now(timezone.utc).strftime('%Y%m%dT%H%M%SZ')}.json"
        result = {
            "schema": "campaign_factory.archive_candidate_quality_report.v1",
            "campaign": inventory.get("campaign"),
            "campaignId": inventory.get("campaignId"),
            "creator": inventory.get("creator"),
            "inventoryReportPath": str(path),
            "generatedAt": utc_now(),
            "requestedCount": requested_count,
            "cleanCandidatesAvailable": len(clean_items),
            "rankedCandidatesAvailable": len(selectable),
            "recommendedCount": len(selected),
            "recommendedIndices": recommended_indices,
            "excludedIndices": sorted(excluded),
            "status": status,
            "blockingReason": blocking_reason,
            "wouldProceedToRendering": False,
            "nextOperatorAction": "approve_recommended_source_indices_before_caption_rendering"
            if status == "ready_for_source_approval"
            else "provide_more_clean_stacey_archive_inventory",
            "items": ranked,
        }
        result["reportPath"] = str(report_path)
        report_path.write_text(json.dumps(result, indent=2, ensure_ascii=False, sort_keys=True), encoding="utf-8")
        return result

    def _archive_crop_severity(self, probe: dict[str, Any]) -> tuple[str, int, float | None]:
        target = 9 / 16
        aspect = probe.get("effectiveAspectRatio")
        if not isinstance(aspect, (int, float)) or aspect <= 0:
            return "unknown", 50, None
        delta = abs(float(aspect) - target) / target
        if delta <= 0.04:
            return "low", 0, round(delta, 4)
        if delta <= 0.18:
            return "moderate", 18, round(delta, 4)
        if delta <= 0.35:
            return "high", 32, round(delta, 4)
        return "severe", 48, round(delta, 4)

    def _archive_visual_quality_score(self, probe: dict[str, Any], warnings: list[Any], crop_score: int) -> int:
        score = 100 - crop_score
        height = probe.get("effectiveHeight") or probe.get("height")
        width = probe.get("effectiveWidth") or probe.get("width")
        bitrate = probe.get("bitrate")
        duration = probe.get("durationSeconds")
        if isinstance(height, (int, float)):
            if height < 1000:
                score -= 14
            elif height < 1200:
                score -= 7
        else:
            score -= 12
        if isinstance(width, (int, float)) and width < 700:
            score -= 5
        if isinstance(bitrate, (int, float)):
            if bitrate < 3_000_000:
                score -= 8
            elif bitrate < 4_500_000:
                score -= 3
        if isinstance(duration, (int, float)):
            if duration < 4:
                score -= 5
            elif duration > 12:
                score -= 4
        else:
            score -= 5
        score -= min(12, len(warnings) * 6)
        return max(0, min(100, int(round(score))))

    def _archive_duplicate_confidence(self, item: dict[str, Any]) -> str:
        duplicate = item.get("duplicate") if isinstance(item.get("duplicate"), dict) else {}
        if duplicate.get("recentPublish"):
            return "recent_publish_duplicate"
        if duplicate.get("existingCampaignAsset"):
            return "existing_campaign_duplicate"
        if duplicate.get("sourceFingerprint") == "duplicate":
            return "source_fingerprint_duplicate"
        return "clear"

    def _finished_video_style_lane_format(self, style_lane: str | None) -> str | None:
        normalized = slugify(style_lane or "")
        aliases = {
            "mirror": "mirror_selfie",
            "mirror_selfie": "mirror_selfie",
            "selfie": "selfie_video",
            "selfie_video": "selfie_video",
            "pov": "pov",
            "pov_relationship": "pov",
            "lifestyle": "spicy_lifestyle",
            "lifestyle_scene": "spicy_lifestyle",
            "spicy_lifestyle": "spicy_lifestyle",
            "amateur_native": "selfie_video",
            "slideshow": "slideshow",
            "slideshow_story": "slideshow",
        }
        return aliases.get(normalized)

    def _finished_video_caption_band(self, format_type: str) -> str:
        if format_type in {"mirror_selfie", "selfie_video", "pov", "spicy_lifestyle"}:
            return "auto"
        return "center"

    def _finished_video_caption_font(self, format_type: str) -> str:
        if format_type in {"mirror_selfie", "selfie_video", "pov", "spicy_lifestyle"}:
            return "Instagram Sans Condensed"
        return "Instagram Sans Condensed"

    def _classify_finished_video_format(self, path: Path) -> str:
        text = str(path).lower()
        if "mirror" in text:
            return "mirror_selfie"
        if "selfie" in text:
            return "selfie_video"
        if any(token in text for token in ("bedroom", "car", "lifestyle", "fit", "glam")):
            return "spicy_lifestyle"
        if "slide" in text:
            return "slideshow"
        return "selfie_video"

    def _run_slideshow_pack(
        self,
        *,
        campaign_slug: str,
        variant_count: int,
        title: str,
        cluster_key: str | None = None,
        media_types: set[str] | None = None,
    ) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        model_slug = self._model_slug_for_campaign(campaign["id"])
        dirs = self.campaign_dirs(model_slug, campaign["slug"])
        desired_types = media_types or {"image", "video"}
        sources = [asset for asset in self.assets_for_campaign(campaign["id"]) if asset.get("media_type") in desired_types]
        if not sources:
            raise ValueError("no imported image/video sources available for slideshow pack")
        selection = self.select_reference_pattern(
            campaign_slug,
            cluster_key=cluster_key,
            variant_count=variant_count,
            notes="make-batch slideshow reference pattern",
        )
        hooks = [str(item.get("text") or item) for item in selection.get("hooks") or []]
        stamp = re.sub(r"[^0-9A-Za-z]+", "_", utc_now()).strip("_")
        out_dir = dirs["rendered"] / f"slideshow_pack_{stamp}"
        out_dir.mkdir(parents=True, exist_ok=True)
        media_dir = out_dir / "input_media"
        media_dir.mkdir(parents=True, exist_ok=True)
        for source in sources:
            src_path = Path(source["stored_path"])
            if src_path.exists():
                shutil.copy2(src_path, media_dir / src_path.name)
        hooks_file = out_dir / "hooks.json"
        hooks_file.write_text(json.dumps({"hooks": hooks}, indent=2, ensure_ascii=False), encoding="utf-8")
        seed = int(hashlib.sha256(f"{campaign_slug}:{variant_count}:{selection['pattern']['clusterKey']}".encode("utf-8")).hexdigest()[:8], 16)
        generation_id = new_id("slidegen")
        cmd = [
            reel_factory_python(self.settings.reel_factory_root),
            "slideshow_factory.py",
            "--media-dir",
            str(media_dir),
            "--out-dir",
            str(out_dir),
            "--title",
            title,
            "--hooks-file",
            str(hooks_file),
            "--count",
            str(max(1, variant_count)),
            "--seed",
            str(seed),
            "--reference-pattern-id",
            selection["pattern"]["id"],
            "--generation-id",
            generation_id,
        ]
        started = time.time()
        result = subprocess.run(cmd, cwd=self.settings.reel_factory_root, text=True, capture_output=True, check=False)
        if result.returncode != 0:
            raise RuntimeError(result.stderr[-2000:] or "slideshow_factory failed")
        manifest_path = out_dir / "slideshow_manifest.json"
        manifest = json_load(manifest_path.read_text(encoding="utf-8"), {})
        reel_path = Path(manifest.get("reel_path") or "")
        if not reel_path.exists():
            raise FileNotFoundError(f"slideshow reel missing: {reel_path}")
        digest = sha256_file(reel_path)
        existing = self.conn.execute(
            "SELECT * FROM rendered_assets WHERE campaign_id = ? AND content_hash = ?",
            (campaign["id"], digest),
        ).fetchone()
        now = utc_now()
        source = sources[0]
        job_id = new_id("render")
        self.conn.execute(
            """
            INSERT INTO render_jobs
            (id, campaign_id, source_asset_id, reel_clip_stem, hooks_json, recipes_json, caption_color, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'rendered', ?, ?)
            """,
            (
                job_id,
                campaign["id"],
                source["id"],
                out_dir.name,
                json.dumps(hooks, ensure_ascii=False),
                json.dumps(["slideshow_pack"], ensure_ascii=False),
                "light",
                now,
                now,
            ),
        )
        prepared_assets = []
        if existing:
            prepared_assets.append(dict(existing))
        else:
            rendered_id = new_id("asset")
            self.conn.execute(
                """
                INSERT INTO rendered_assets
                (id, campaign_id, source_asset_id, render_job_id, content_hash, output_path, campaign_path, filename,
                 caption, caption_generation_json, recipe, target_ratio, review_state, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'draft', ?, ?)
                """,
                (
                    rendered_id,
                    campaign["id"],
                    source["id"],
                    job_id,
                    digest,
                    str(reel_path),
                    str(reel_path),
                    reel_path.name,
                    title,
                    json.dumps(
                        {
                            "format": "slideshow_pack",
                            "schema": manifest.get("schema"),
                            "manifestPath": str(manifest_path),
                            "generationId": manifest.get("generation_id") or generation_id,
                            "referencePattern": selection.get("pattern"),
                            "sourceHashes": [item.get("source_hash") for item in manifest.get("items", [])],
                            "captionHashes": [
                                hashlib.sha256(str(item.get("hook") or "").strip().lower().encode("utf-8")).hexdigest()
                                for item in manifest.get("items", [])
                            ],
                        },
                        ensure_ascii=False,
                        sort_keys=True,
                    ),
                    "slideshow_pack",
                    "9:16",
                    now,
                    now,
                ),
            )
            prepared_assets.append(dict(self.conn.execute("SELECT * FROM rendered_assets WHERE id = ?", (rendered_id,)).fetchone()))
            self.record_event(
                "rendered_asset_synced",
                campaign_id=campaign["id"],
                source_asset_id=source["id"],
                rendered_asset_id=rendered_id,
                render_job_id=job_id,
                status="success",
                message=f"Slideshow pack rendered: {reel_path.name}",
                metadata={"format": "slideshow_pack", "manifestPath": str(manifest_path), "contentHash": digest},
                commit=False,
            )
        self.conn.commit()
        return {
            "schema": "campaign_factory.slideshow_pack.v1",
            "campaign": campaign_slug,
            "selection": selection,
            "prepare": {"prepared": prepared_assets, "reusedExisting": []},
            "run": {
                "returncode": result.returncode,
                "runCount": 1,
                "elapsedSeconds": round(time.time() - started, 2),
                "stdout": result.stdout,
                "stderr": result.stderr,
                "manifestPath": str(manifest_path),
            },
        }

    def _campaign_source_media_summary(self, campaign_id: str) -> dict[str, int]:
        summary = {"video": 0, "image": 0}
        for source in self.assets_for_campaign(campaign_id):
            media_type = source.get("media_type") or media_type_for_path(source.get("stored_path") or source.get("filename") or "")
            if media_type in summary:
                summary[media_type] += 1
        return summary

    def _formats_for_batch(self, selected_format: str, source_mix: dict[str, int]) -> list[str]:
        if selected_format == "reel":
            if not source_mix.get("video"):
                raise ValueError("reel format requires at least one imported video")
            return ["reel"]
        if selected_format == "slideshow":
            if not (source_mix.get("image") or source_mix.get("video")):
                raise ValueError("slideshow format requires at least one imported image or video")
            return ["slideshow"]
        formats: list[str] = []
        if source_mix.get("video"):
            formats.append("reel")
        if source_mix.get("image"):
            formats.append("slideshow")
        if not formats:
            raise ValueError("no supported video or image sources imported")
        return formats

