    def dashboard(self, campaign_slug: str | None = None) -> dict[str, Any]:
        campaigns = self.list_campaigns()
        selected = self.campaign_by_slug(campaign_slug) if campaign_slug else self._default_dashboard_campaign(campaigns)
        if not selected:
            return {"campaigns": [], "campaign": None, "sources": [], "rendered": [], "health": None, "ranking": []}
        rendered = [self._dashboard_rendered_asset(asset) for asset in self.rendered_for_campaign(selected["id"])]
        ranking = self.ranking(selected["slug"])
        audio_workflow = self.audio_workflow_summary(rendered)
        sources = self.assets_for_campaign(selected["id"])
        summary_dashboard = {"campaign": selected, "sources": sources, "rendered": rendered}
        daily_production = self.daily_production_counters(selected["slug"], dashboard=summary_dashboard)
        creative_plan = self.creative_plan_for_campaign(selected["slug"], dashboard=summary_dashboard)
        return {
            "campaigns": campaigns,
            "campaign": selected,
            "sources": sources,
            "rendered": sorted(rendered, key=lambda asset: (ranking["byAsset"].get(asset["id"], {}) or {}).get("score", 0), reverse=True),
            "activity": self.events_for_campaign(selected["slug"], limit=50),
            "jobs": self.jobs_for_campaign(selected["slug"], limit=50),
            "health": self.campaign_health(selected["slug"]),
            "audioWorkflow": audio_workflow,
            "dailyProduction": daily_production,
            "creativePlan": creative_plan,
            "distribution": self.distribution_summary(selected["slug"]),
            "trust": self.trust_summary(selected["slug"]),
            "ranking": ranking["assets"],
        }

    def audio_workflow_summary(self, rendered: list[dict[str, Any]]) -> dict[str, Any]:
        counts = {
            "needs_audio": 0,
            "selected_not_attached": 0,
            "blocked": 0,
            "ready": 0,
        }
        tasks = {
            "open": 0,
            "selected": 0,
            "proof_missing": 0,
            "blocked": 0,
            "needs_review": 0,
            "completed": 0,
            "not_required": 0,
        }
        top: dict[str, dict[str, Any]] = {}
        for asset in rendered:
            intent = self._dashboard_audio_intent_for_asset(asset)
            status = str(intent.get("status") or "needs_operator_selection").strip().lower()
            task = intent.get("task") if isinstance(intent.get("task"), dict) else {}
            task_status = str(task.get("status") or "open").strip().lower()
            if task_status in tasks:
                tasks[task_status] += 1
            required = intent.get("required") is not False
            if not required or status in {"attached", "verified", "skipped", "not_required"}:
                counts["ready"] += 1
            elif status == "selected":
                counts["selected_not_attached"] += 1
            elif status == "blocked":
                counts["blocked"] += 1
            else:
                counts["needs_audio"] += 1
            for rec in intent.get("recommendations") or []:
                if not isinstance(rec, dict):
                    continue
                key = "|".join([
                    str(rec.get("platform_audio_id") or rec.get("audioId") or ""),
                    str(rec.get("audio_title") or rec.get("audioTitle") or rec.get("title") or "Untitled audio"),
                    str(rec.get("artist_name") or rec.get("artistName") or ""),
                ])
                item = top.setdefault(key, {
                    "audio_title": rec.get("audio_title") or rec.get("audioTitle") or rec.get("title"),
                    "artist_name": rec.get("artist_name") or rec.get("artistName"),
                    "platform_audio_id": rec.get("platform_audio_id") or rec.get("audioId"),
                    "platform_url": rec.get("platform_url") or rec.get("platformUrl"),
                    "freshness": rec.get("freshness") or rec.get("trendStatus"),
                    "confidence": rec.get("confidence"),
                    "count": 0,
                    "rendered_asset_ids": [],
                })
                item["count"] += 1
                item["rendered_asset_ids"].append(asset.get("id"))
        return {
            "schema": "campaign_factory.audio_workflow_summary.v1",
            "counts": counts,
            "taskCounts": tasks,
            "topRecommendedAudio": sorted(
                top.values(),
                key=lambda item: (-int(item["count"]), str(item.get("audio_title") or "")),
            )[:10],
        }

    def _dashboard_audio_intent_for_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        caption_generation = asset.get("captionGeneration") or {}
        reference_pattern = asset.get("referencePattern") or {}
        existing = (
            caption_generation.get("audioIntent")
            or caption_generation.get("audio_intent")
            or reference_pattern.get("audioIntent")
            or reference_pattern.get("audio_intent")
        )
        recommendations = asset.get("audioRecommendations") or {}
        recommendation_items = recommendations.get("recommendations") if isinstance(recommendations, dict) else []
        if isinstance(existing, dict):
            intent = dict(existing)
            intent.setdefault("required", True)
            intent.setdefault("status", "recommended" if recommendation_items else "needs_operator_selection")
            intent.setdefault("recommendations", recommendation_items if isinstance(recommendation_items, list) else [])
            if isinstance(recommendations, dict) and recommendations.get("decision"):
                intent.setdefault("decision", recommendations.get("decision"))
            intent["task"] = self._audio_task_for_dashboard_intent(intent)
            return intent
        intent = {
            "schema": "pipeline.audio_intent.v1",
            "mode": "native_platform_audio",
            "required": True,
            "status": "recommended" if recommendation_items else "needs_operator_selection",
            "recommendations": recommendation_items if isinstance(recommendation_items, list) else [],
            "decision": recommendations.get("decision") if isinstance(recommendations, dict) else None,
        }
        intent["task"] = self._audio_task_for_dashboard_intent(intent)
        return intent

    def _audio_task_for_dashboard_intent(self, intent: dict[str, Any]) -> dict[str, Any]:
        existing = intent.get("task") if isinstance(intent.get("task"), dict) else {}
        status = str(intent.get("status") or "needs_operator_selection").strip().lower()
        safe = status in {"skipped", "not_required"}
        if status in {"attached", "verified"}:
            selection = intent.get("operator_selection") if isinstance(intent.get("operator_selection"), dict) else {}
            final_key = "verified_at" if status == "verified" else "attached_at"
            safe = bool(
                any(isinstance(selection.get(key), str) and selection.get(key).strip() for key in ("platform_audio_id", "platform_url", "native_audio_id", "native_audio_url", "audio_id"))
                and isinstance(selection.get("selected_at"), str)
                and selection.get("selected_at").strip()
                and isinstance(selection.get(final_key), str)
                and selection.get(final_key).strip()
            )
        task_status = {
            "not_required": "not_required",
            "recommended": "open",
            "needs_operator_selection": "open",
            "selected": "selected",
            "attached": "completed" if safe else "proof_missing",
            "verified": "completed" if safe else "proof_missing",
            "skipped": "completed",
            "blocked": "blocked",
            "needs_review": "needs_review",
            "burned": "blocked",
        }.get(status, "open")
        return {
            **existing,
            "schema": existing.get("schema") or "pipeline.audio_task.v1",
            "status": task_status,
            "proof_required": bool(intent.get("required", False) and status in {"attached", "verified"}),
            "assignee": existing.get("assignee"),
            "due_at": existing.get("due_at"),
            "created_at": existing.get("created_at"),
            "updated_at": existing.get("updated_at"),
            "completed_at": existing.get("completed_at"),
        }

    def distribution_summary(self, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        rendered = [self._dashboard_rendered_asset(asset) for asset in self.rendered_for_campaign(campaign["id"])]
        plans = self.distribution_plans_for_campaign(campaign_slug)
        planned_assets = {plan["renderedAssetId"] for plan in plans if plan.get("surface") != "story_cta"}
        surface_counts: dict[str, int] = {}
        preview_count = 0
        live_count = 0
        for plan in plans:
            surface = plan.get("surface") or "regular_reel"
            surface_counts[surface] = surface_counts.get(surface, 0) + 1
            if plan.get("plannedWindowStart"):
                preview_count += 1
        return {
            "schema": "campaign_factory.distribution_summary.v1",
            "campaign": campaign["slug"],
            "generatedAt": utc_now(),
            "surfaceCounts": surface_counts,
            "plannedAssets": len(planned_assets),
            "unplannedApprovedAssets": len([
                asset for asset in rendered
                if asset.get("review_state") in {"approved", "review_ready"} and asset["id"] not in planned_assets
            ]),
            "previewScheduledPlans": preview_count,
            "liveScheduledPlans": live_count,
            "plans": plans,
        }

    def multi_surface_inventory_audit(
        self,
        *,
        creator: str,
        campaign_slug: str | None = None,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        built = self._build_surface_inventory(creator=creator_label, campaign_slug=campaign_slug)
        inventory = built["inventoryBySurface"]
        missing = [
            surface
            for surface, counts in inventory.items()
            if counts["total"] == 0 or counts["scheduleSafe"] == 0
        ]
        return {
            "schema": "campaign_factory.multi_surface_inventory_audit.v1",
            "creator": creator_label,
            "inventoryBySurface": inventory,
            "surfacesMissingInventory": missing,
            "wouldWrite": False,
        }

    def account_surface_obligations_plan(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        target_date = datetime.fromisoformat(date).date()
        rows = self.conn.execute(
            """
            SELECT r.*, a.handle, a.external_id
            FROM account_content_requirements r
            LEFT JOIN accounts a ON a.id = r.account_id
            WHERE r.active = 1 AND LOWER(r.creator) = LOWER(?)
            ORDER BY r.account_id, r.content_surface
            """,
            (creator_label,),
        ).fetchall()
        by_account: dict[str, dict[str, Any]] = {}
        for row in rows:
            req = dict(row)
            account_id = req["account_id"]
            account = by_account.setdefault(
                account_id,
                {
                    "accountId": account_id,
                    "instagramAccountId": req.get("external_id"),
                    "username": req.get("handle"),
                    "surfaceStatus": {
                        surface: {"needed": False, "scheduled": False, "completed": False, "blockedReason": ""}
                        for surface in CONTENT_SURFACES
                    },
                },
            )
            surface = normalize_content_surface(req.get("content_surface"))
            if surface not in CONTENT_SURFACES:
                continue
            active_today = self._requirement_active_on_date(req, target_date)
            scheduled = self._surface_scheduled_for_account(account_id, req.get("external_id"), surface, target_date)
            completed = self._surface_completed_for_account(account_id, req.get("external_id"), surface, target_date)
            needed = active_today and not scheduled and not completed
            blocked = ""
            if needed and self.multi_surface_inventory_audit(creator=creator_label)["inventoryBySurface"][surface]["scheduleSafe"] == 0:
                blocked = "inventory_missing"
            account["surfaceStatus"][surface] = {
                "needed": bool(needed),
                "scheduled": bool(scheduled),
                "completed": bool(completed),
                "blockedReason": blocked,
            }
        return {
            "schema": "campaign_factory.account_surface_obligations_plan.v1",
            "creator": creator_label,
            "date": target_date.isoformat(),
            "accounts": list(by_account.values()),
            "wouldWrite": False,
        }

    def account_content_needs(
        self,
        *,
        account_id: str,
        creator: str | None = None,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator) if creator else None
        target_date = datetime.fromisoformat(date).date()
        rows = self._account_content_requirement_rows(
            creator=creator_label,
            account_id=account_id,
        )
        obligations = [
            self._content_obligation_for_requirement(dict(row), target_date)
            for row in rows
        ]
        surface_status = {
            surface: {
                "needed": False,
                "scheduled": 0,
                "completed": 0,
                "blocked": False,
                "overdue": False,
                "blockedReason": "",
            }
            for surface in CONTENT_SURFACES
        }
        for obligation in obligations:
            surface_status[obligation["surface"]] = {
                "needed": obligation["needed"],
                "scheduled": obligation["scheduled"],
                "completed": obligation["completed"],
                "blocked": obligation["blocked"],
                "overdue": obligation["overdue"],
                "blockedReason": obligation["blockedReason"],
            }
        account_row = self._account_row_for_requirement_account(account_id)
        return {
            "schema": "campaign_factory.account_content_needs.v1",
            "creator": creator_label,
            "date": target_date.isoformat(),
            "accountId": account_row.get("id") if account_row else account_id,
            "account": account_row.get("handle") if account_row else account_id,
            "instagramAccountId": account_row.get("external_id") if account_row else None,
            "surfaceRequirementsTracked": list(CONTENT_SURFACES),
            "obligations": obligations,
            "surfaceStatus": surface_status,
            "wouldWrite": False,
        }

    def account_surface_status(
        self,
        *,
        account_id: str,
        creator: str | None = None,
        date: str,
    ) -> dict[str, Any]:
        needs = self.account_content_needs(
            account_id=account_id,
            creator=creator,
            date=date,
        )
        return {
            "schema": "campaign_factory.account_surface_status.v1",
            "creator": needs.get("creator"),
            "date": needs.get("date"),
            "accountId": needs.get("accountId"),
            "account": needs.get("account"),
            "instagramAccountId": needs.get("instagramAccountId"),
            "trackedStates": list(CONTENT_SURFACES),
            "surfaceStatus": needs.get("surfaceStatus") or {},
            "obligations": needs.get("obligations") or [],
            "wouldWrite": False,
        }

    def creator_content_needs(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        target_date = datetime.fromisoformat(date).date()
        rows = self._account_content_requirement_rows(creator=creator_label)
        by_account: dict[str, list[dict[str, Any]]] = {}
        for row in rows:
            by_account.setdefault(row["account_id"], []).append(dict(row))
        accounts: list[dict[str, Any]] = []
        totals = self._empty_surface_totals()
        for account_id in sorted(by_account):
            obligations = [
                self._content_obligation_for_requirement(req, target_date)
                for req in sorted(by_account[account_id], key=lambda item: normalize_content_surface(item.get("content_surface")))
            ]
            account_row = self._account_row_for_requirement_account(account_id)
            for obligation in obligations:
                self._add_obligation_to_totals(totals, obligation)
            accounts.append({
                "accountId": account_row.get("id") if account_row else account_id,
                "account": account_row.get("handle") if account_row else account_id,
                "instagramAccountId": account_row.get("external_id") if account_row else None,
                "obligations": obligations,
            })
        return {
            "schema": "campaign_factory.creator_content_needs.v1",
            "creator": creator_label,
            "date": target_date.isoformat(),
            "accountsAnalyzed": len(accounts),
            "surfaceRequirementsTracked": list(CONTENT_SURFACES),
            "accounts": accounts,
            "totalsBySurface": totals,
            "wouldWrite": False,
        }

    def surface_gap_report(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        status = self._build_surface_status(creator=creator_label, date=date)
        needs = status["needs"]
        inventory = status["inventoryBySurface"]
        gaps: dict[str, dict[str, Any]] = {}
        for surface in CONTENT_SURFACES:
            totals = needs["totalsBySurface"].get(surface) or {}
            needed = int(totals.get("remaining") or 0)
            available = int((inventory.get(surface) or {}).get("scheduleSafe") or 0)
            shortfall = max(0, needed - available)
            gaps[surface] = {
                "surface": surface,
                "required": int(totals.get("required") or 0),
                "completed": int(totals.get("completed") or 0),
                "scheduled": int(totals.get("scheduled") or 0),
                "needed": needed,
                "available": available,
                "shortfall": shortfall,
                "blocked": shortfall > 0,
                "blockedReason": "inventory_shortfall" if shortfall > 0 else "",
            }
        return {
            "schema": "campaign_factory.surface_gap_report.v1",
            "creator": creator_label,
            "date": datetime.fromisoformat(date).date().isoformat(),
            "accountsAnalyzed": needs["accountsAnalyzed"],
            "surfaceRequirementsTracked": list(CONTENT_SURFACES),
            "surfaceGaps": gaps,
            "wouldWrite": False,
        }

    def surface_handoff_readiness_report(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        rendered_asset_id: str | None = None,
    ) -> dict[str, Any]:
        assets = self._surface_report_assets(creator=self._creator_label(creator) if creator else None, campaign_slug=campaign_slug)
        if rendered_asset_id:
            assets = [asset for asset in assets if asset["id"] == rendered_asset_id]
        items = self._build_surface_readiness(assets)
        return {
            "schema": "campaign_factory.surface_handoff_readiness_report.v1",
            "creator": self._creator_label(creator) if creator else None,
            "campaign": slugify(campaign_slug) if campaign_slug else None,
            "assets": items,
            "wouldWrite": False,
        }

    def surface_draft_proof(
        self,
        *,
        creator: str | None = None,
        campaign: str | None = None,
        rendered_asset_id: str | None = None,
    ) -> dict[str, Any]:
        assets = self._surface_report_assets(
            creator=self._creator_label(creator) if creator else None,
            campaign_slug=campaign,
        )
        if rendered_asset_id:
            assets = [asset for asset in assets if asset["id"] == rendered_asset_id]
        readiness_items = self._build_surface_readiness(assets)
        drafts = [
            self._surface_draft_payload_for_readiness(item)
            for item in readiness_items
            if item.get("canHandoff")
        ]
        blocking = [
            {
                "assetId": item["assetId"],
                "blockingReasons": item.get("blockingReasons") or [],
            }
            for item in readiness_items
            if not item.get("canHandoff")
        ]
        return {
            "schema": "campaign_factory.surface_draft_proof.v1",
            "creator": self._creator_label(creator) if creator else None,
            "campaign": slugify(campaign) if campaign else None,
            "renderedAssetId": rendered_asset_id,
            "canProduceDraftPayload": bool(drafts) and not blocking,
            "draftCount": len(drafts),
            "drafts": drafts,
            "blockedAssets": blocking,
            "wouldWrite": False,
        }

    def carousel_integrity_report(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        rendered_asset_id: str | None = None,
    ) -> dict[str, Any]:
        assets = self._carousel_report_assets(
            creator=self._creator_label(creator) if creator else None,
            campaign_slug=campaign_slug,
            rendered_asset_id=rendered_asset_id,
        )
        rows = [self._carousel_integrity_for_asset(asset) for asset in assets]
        return {
            "schema": "campaign_factory.carousel_integrity_report.v1",
            "creator": self._creator_label(creator) if creator else None,
            "campaign": slugify(campaign_slug) if campaign_slug else None,
            "renderedAssetId": rendered_asset_id,
            "carouselAssetsAnalyzed": len(rows),
            "passed": sum(1 for row in rows if row.get("overallIntegrityPassed")),
            "failed": sum(1 for row in rows if not row.get("overallIntegrityPassed")),
            "assets": rows,
            "wouldWrite": False,
        }

    def carousel_child_metrics_plan(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        rendered_asset_id: str | None = None,
    ) -> dict[str, Any]:
        assets = self._carousel_report_assets(
            creator=self._creator_label(creator) if creator else None,
            campaign_slug=campaign_slug,
            rendered_asset_id=rendered_asset_id,
        )
        rows = []
        for asset in assets:
            integrity = self._carousel_integrity_for_asset(asset)
            children = []
            for component in integrity["assetComponents"]["components"]:
                children.append({
                    "renderedAssetId": asset["id"],
                    "componentIndex": component["componentIndex"],
                    "componentHash": component["mediaHash"],
                    "mediaType": component["mediaType"],
                    "contentSurface": "feed_carousel",
                    "futureMetricKeys": {
                        "rendered_asset_id": asset["id"],
                        "carousel_child_index": component["componentIndex"],
                        "carousel_child_hash": component["mediaHash"],
                        "content_surface": "feed_carousel",
                    },
                    "wouldWrite": False,
                })
            rows.append({
                "assetId": asset["id"],
                "contentSurface": "feed_carousel",
                "igMediaType": "CAROUSEL",
                "childCount": len(children),
                "parentMetricsCanonical": True,
                "parentMetricKeys": [
                    "post_id",
                    "rendered_asset_id",
                    "content_surface",
                    "views",
                    "reach",
                    "likes",
                    "comments",
                    "shares",
                    "saves",
                ],
                "childMetricsSupplemental": True,
                "childMetricsPlan": children,
                "metricsRollupKeys": [
                    "rendered_asset_id",
                    "carousel_child_index",
                    "carousel_child_hash",
                    "content_surface",
                ],
                "integrityPassed": bool(integrity.get("overallIntegrityPassed")),
                "wouldWrite": False,
            })
        return {
            "schema": "campaign_factory.carousel_child_metrics_plan.v1",
            "creator": self._creator_label(creator) if creator else None,
            "campaign": slugify(campaign_slug) if campaign_slug else None,
            "renderedAssetId": rendered_asset_id,
            "carouselAssetsAnalyzed": len(rows),
            "assets": rows,
            "wouldWrite": False,
        }

    def _carousel_report_assets(
        self,
        *,
        creator: str | None,
        campaign_slug: str | None,
        rendered_asset_id: str | None,
    ) -> list[dict[str, Any]]:
        assets = self._surface_report_assets(creator=creator, campaign_slug=campaign_slug)
        rows = [
            asset for asset in assets
            if normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")) == "feed_carousel"
        ]
        if rendered_asset_id:
            rows = [asset for asset in rows if asset["id"] == rendered_asset_id]
        return rows

    def _carousel_integrity_for_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        components = self._carousel_component_signature(self._asset_components(asset["id"]))
        readiness = self._surface_handoff_readiness_for_asset(asset)
        manifest = readiness.get("handoffManifestV2") if isinstance(readiness.get("handoffManifestV2"), dict) else {}
        manifest_items = manifest.get("mediaItems") if isinstance(manifest.get("mediaItems"), list) else []
        manifest_signature = self._carousel_media_item_signature(manifest_items)
        draft_proof = self.surface_draft_proof(
            creator=asset.get("creator_mix") or asset.get("creator_model") or asset.get("model_name"),
            campaign=asset.get("campaign_slug"),
            rendered_asset_id=asset["id"],
        )
        draft = draft_proof["drafts"][0] if draft_proof.get("drafts") else {}
        draft_signature = self._carousel_media_item_signature(draft.get("mediaItems") if isinstance(draft, dict) else [])
        threadsdash_signature = self._carousel_media_item_signature((draft.get("handoffManifestV2") or {}).get("mediaItems") if isinstance(draft.get("handoffManifestV2"), dict) else [])
        meta_preview = self._carousel_meta_child_payload_preview(asset=asset, draft=draft, components=components)
        meta_signature = self._carousel_media_item_signature(meta_preview.get("children") or [])
        caption_lineage_preserved = bool(
            manifest.get("instagramPostCaption")
            and manifest.get("caption_hash")
            and (draft.get("handoffManifestV2") or {}).get("caption_hash") == manifest.get("caption_hash")
        )
        content_surface_preserved = (
            readiness.get("contentSurface") == "feed_carousel"
            and manifest.get("contentSurface") == "feed_carousel"
            and draft.get("contentSurface") == "feed_carousel"
            and draft.get("igMediaType") == "CAROUSEL"
            and meta_preview.get("parentPayload", {}).get("media_type") == "CAROUSEL"
        )
        boundaries = [
            self._carousel_boundary_result("asset_components_to_handoff_manifest_v2", components, manifest_signature),
            self._carousel_boundary_result("handoff_manifest_v2_to_surface_draft_proof", manifest_signature, draft_signature),
            self._carousel_boundary_result("surface_draft_proof_to_threadsdash_payload", draft_signature, threadsdash_signature),
            self._carousel_boundary_result("threadsdash_payload_to_meta_child_payload_preview", threadsdash_signature, meta_signature),
        ]
        return {
            "assetId": asset["id"],
            "contentSurface": normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")),
            "igMediaType": readiness.get("igMediaType"),
            "canHandoff": bool(readiness.get("canHandoff")),
            "contentSurfacePreserved": bool(content_surface_preserved),
            "captionLineagePreserved": bool(caption_lineage_preserved),
            "assetComponents": self._carousel_signature_payload(components),
            "handoffManifestV2": self._carousel_signature_payload(manifest_signature, extra={
                "contentSurface": manifest.get("contentSurface"),
                "igMediaType": manifest.get("igMediaType"),
                "captionHash": manifest.get("caption_hash"),
                "instagramPostCaptionHash": manifest.get("instagram_post_caption_hash"),
            }),
            "surfaceDraftProof": self._carousel_signature_payload(draft_signature, extra={
                "canProduceDraftPayload": bool(draft_proof.get("canProduceDraftPayload")),
                "draftCount": int(draft_proof.get("draftCount") or 0),
            }),
            "threadDashPayload": self._carousel_signature_payload(threadsdash_signature, extra={
                "schema": draft.get("schema"),
                "contentSurface": draft.get("contentSurface"),
                "igMediaType": draft.get("igMediaType"),
            }),
            "metaChildPayloadPreview": self._carousel_signature_payload(meta_signature, extra=meta_preview),
            "boundaries": boundaries,
            "overallIntegrityPassed": bool(
                readiness.get("canHandoff")
                and content_surface_preserved
                and caption_lineage_preserved
                and boundaries
                and all(boundary["slideCountPreserved"] and boundary["slideOrderPreserved"] and boundary["componentHashesMatch"] for boundary in boundaries)
            ),
            "wouldWrite": False,
        }

    def _carousel_component_signature(self, components: list[dict[str, Any]]) -> list[dict[str, Any]]:
        return [
            {
                "componentIndex": int(component.get("component_index") or 0),
                "mediaPath": component.get("media_path"),
                "mediaHash": component.get("media_hash"),
                "mediaType": component.get("media_type"),
            }
            for component in components
        ]

    def _carousel_media_item_signature(self, media_items: Any) -> list[dict[str, Any]]:
        if not isinstance(media_items, list):
            return []
        rows = []
        for item in media_items:
            if not isinstance(item, dict):
                continue
            rows.append({
                "componentIndex": int(item.get("componentIndex") if item.get("componentIndex") is not None else item.get("component_index") or 0),
                "mediaPath": item.get("mediaPath") or item.get("media_path"),
                "mediaHash": item.get("mediaHash") or item.get("media_hash") or item.get("componentHash"),
                "mediaType": item.get("mediaType") or item.get("media_type"),
            })
        return rows

    def _carousel_signature_payload(self, signature: list[dict[str, Any]], *, extra: dict[str, Any] | None = None) -> dict[str, Any]:
        payload = {
            "slideCount": len(signature),
            "componentIndexes": [item["componentIndex"] for item in signature],
            "componentHashes": [item["mediaHash"] for item in signature],
            "components": signature,
        }
        if extra:
            payload.update(extra)
        return payload

    def _carousel_boundary_result(self, boundary: str, before: list[dict[str, Any]], after: list[dict[str, Any]]) -> dict[str, Any]:
        before_indexes = [item["componentIndex"] for item in before]
        after_indexes = [item["componentIndex"] for item in after]
        before_hashes = [item["mediaHash"] for item in before]
        after_hashes = [item["mediaHash"] for item in after]
        return {
            "boundary": boundary,
            "slideCountPreserved": len(before) == len(after),
            "slideOrderPreserved": before_indexes == after_indexes,
            "componentHashesMatch": before_hashes == after_hashes,
            "beforeComponentIndexes": before_indexes,
            "afterComponentIndexes": after_indexes,
            "beforeComponentHashes": before_hashes,
            "afterComponentHashes": after_hashes,
            "wouldWrite": False,
        }

    def _carousel_meta_child_payload_preview(self, *, asset: dict[str, Any], draft: dict[str, Any], components: list[dict[str, Any]]) -> dict[str, Any]:
        children = []
        for component in components:
            media_type = "VIDEO" if str(component.get("mediaType") or "").lower() == "video" else "IMAGE"
            children.append({
                "componentIndex": component["componentIndex"],
                "mediaPath": component["mediaPath"],
                "mediaHash": component["mediaHash"],
                "mediaType": component["mediaType"],
                "media_type": media_type,
                "is_carousel_item": True,
                "previewContainerId": f"carousel_child_preview_{asset['id']}_{component['componentIndex']}",
                "wouldWrite": False,
            })
        return {
            "parentPayload": {
                "media_type": "CAROUSEL",
                "caption": draft.get("instagramPostCaption") or "",
                "children": [child["previewContainerId"] for child in children],
            },
            "children": children,
            "wouldWrite": False,
        }

    def _build_surface_inventory(
        self,
        *,
        creator: str,
        campaign_slug: str | None = None,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        assets_by_surface = {surface: [] for surface in CONTENT_SURFACES}
        inventory = {
            surface: {"total": 0, "scheduleSafe": 0}
            for surface in CONTENT_SURFACES
        }
        assets = self._surface_report_assets(creator=creator_label, campaign_slug=campaign_slug)
        readiness_items = self._build_surface_readiness(assets)
        readiness_by_asset = {item.get("assetId"): item for item in readiness_items}
        for asset in assets:
            surface = normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface"))
            if surface not in inventory:
                continue
            assets_by_surface[surface].append(asset)
            inventory[surface]["total"] += 1
            if (readiness_by_asset.get(asset.get("id")) or {}).get("canHandoff"):
                inventory[surface]["scheduleSafe"] += 1
        return {
            "creator": creator_label,
            "campaign": slugify(campaign_slug) if campaign_slug else None,
            "assets": assets,
            "assetsBySurface": assets_by_surface,
            "readiness": readiness_items,
            "inventoryBySurface": inventory,
            "wouldWrite": False,
        }

    def _build_surface_status(
        self,
        *,
        creator: str,
        date: str,
    ) -> dict[str, Any]:
        creator_label = self._creator_label(creator)
        needs = self.creator_content_needs(creator=creator_label, date=date)
        inventory = self._build_surface_inventory(creator=creator_label).get("inventoryBySurface") or {}
        return {
            "creator": creator_label,
            "date": datetime.fromisoformat(date).date().isoformat(),
            "needs": needs,
            "inventoryBySurface": inventory,
            "wouldWrite": False,
        }

    def _build_surface_readiness(self, assets: list[dict[str, Any]]) -> list[dict[str, Any]]:
        return [self._surface_handoff_readiness_for_asset(asset) for asset in assets]

    def _surface_report_assets(self, *, creator: str | None = None, campaign_slug: str | None = None) -> list[dict[str, Any]]:
        params: list[Any] = []
        where = []
        if campaign_slug:
            where.append("c.slug = ?")
            params.append(slugify(campaign_slug))
        query = """
            SELECT r.*, c.slug AS campaign_slug, s.media_type AS source_media_type,
                   s.content_surface AS source_content_surface, m.slug AS model_slug, m.name AS model_name
            FROM rendered_assets r
            JOIN campaigns c ON c.id = r.campaign_id
            JOIN source_assets s ON s.id = r.source_asset_id
            JOIN models m ON m.id = s.model_id
        """
        if where:
            query += " WHERE " + " AND ".join(where)
        query += " ORDER BY r.created_at, r.id"
        rows = [dict(row) for row in self.conn.execute(query, params).fetchall()]
        if not creator:
            return rows
        return [row for row in rows if self._asset_matches_creator(row, creator)]

    def _requires_operator_visual_review_for_handoff(self, asset: dict[str, Any]) -> bool:
        operations: list[dict[str, Any]] = []
        raw_operations = json_load(asset.get("variant_operations_json"), [])
        if isinstance(raw_operations, list):
            operations.extend(item for item in raw_operations if isinstance(item, dict))
        metadata = json_load(asset.get("metadata_json"), {})
        if not isinstance(metadata, dict):
            metadata = {}
        asset_id = asset.get("id")
        if asset_id:
            lineage = self._variant_lineage_for_asset(str(asset_id))
            lineage_operations = lineage.get("variant_operations") if isinstance(lineage, dict) else None
            if isinstance(lineage_operations, list):
                operations.extend(item for item in lineage_operations if isinstance(item, dict))
        uses_ad_hoc_inventory_fill = any(
            operation.get("type") == "inventory_fill_ffmpeg_variant"
            for operation in operations
        )
        has_visual_review_pass = any(
            operation.get("type") in {"operator_visual_review_passed", "visual_qc_passed"}
            or operation.get("visualReviewPassed") is True
            or operation.get("visual_qc_passed") is True
            for operation in operations
        ) or metadata.get("operator_visual_review_passed") is True or metadata.get("visual_qc_passed") is True
        surface = normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface"))
        source_marker_parts = [
            str(asset.get("campaign_slug") or ""),
            str(asset.get("filename") or ""),
            Path(str(asset.get("campaign_path") or "")).name,
            Path(str(asset.get("output_path") or "")).name,
            str(asset.get("source_prompt") or ""),
            str(asset.get("notes") or ""),
        ]
        source_markers = " ".join(source_marker_parts).lower()
        uses_unreviewed_reel_proof_or_preview = surface == "reel" and any(
            marker in source_markers
            for marker in (
                "_audio_preview_",
                "parent_factory_53_production_trial",
                "inventory_fill",
                "variant_fanout_proof",
                "surface_proof",
            )
        )
        return bool((uses_ad_hoc_inventory_fill or uses_unreviewed_reel_proof_or_preview) and not has_visual_review_pass)

    def _content_trust_status_blockers(
        self,
        asset: dict[str, Any],
        latest_audit: dict[str, Any] | None,
        caption_context: dict[str, Any] | None,
    ) -> tuple[list[str], dict[str, str]]:
        metadata = json_load(asset.get("metadata_json"), {})
        if not isinstance(metadata, dict):
            metadata = {}
        audit = latest_audit if isinstance(latest_audit, dict) else {}
        readiness = audit.get("readinessSummary") if isinstance(audit.get("readinessSummary"), dict) else {}

        def nested_status(source: dict[str, Any], *keys: str) -> str:
            for key in keys:
                value = source.get(key)
                if isinstance(value, str) and value.strip():
                    return value.strip().lower()
                if isinstance(value, dict):
                    for nested_key in ("status", key, "visualQcStatus", "identityVerificationStatus"):
                        nested = value.get(nested_key)
                        if isinstance(nested, str) and nested.strip():
                            return nested.strip().lower()
            return ""

        passed_statuses = {"passed", "pass", "approved", "ready"}

        def resolved_status(*keys: str) -> str:
            statuses = [nested_status(source, *keys) for source in [metadata, caption_context or {}, audit, readiness]]
            statuses = [status for status in statuses if status]
            blocking_status = next((status for status in statuses if status not in passed_statuses), "")
            if blocking_status:
                return blocking_status
            return "passed" if statuses else ""

        visual_status = resolved_status("visualQcStatus", "visual_qc_status", "visualQc", "visual_qc")
        identity_status = resolved_status(
            "identityVerificationStatus",
            "identity_verification_status",
            "identityVerification",
            "identity_verification",
        )
        blockers: list[str] = []
        unavailable_statuses = {"", "missing", "none", "null", "pending", "queued", "unknown", "unavailable", "not_available", "not_found"}

        def blocker_code(prefix: str, status: str) -> str:
            suffix = "unavailable" if status in unavailable_statuses else "failed"
            return f"{prefix}_{suffix}"

        if visual_status != "passed":
            blockers.append(blocker_code("visual_qc", visual_status))
        if identity_status != "passed":
            blockers.append(blocker_code("identity_verification", identity_status))
        return blockers, {
            "visualQcStatus": visual_status or "unavailable",
            "identityVerificationStatus": identity_status or "unavailable",
        }

    def _asset_matches_creator(self, asset: dict[str, Any], creator: str) -> bool:
        expected = self._creator_label(creator).lower()
        caption_context = load_context_json(asset.get("caption_outcome_context_json"))
        candidates = [
            asset.get("creator_mix"),
            asset.get("creator_model"),
            asset.get("model_slug"),
            asset.get("model_name"),
            caption_context.get("creator_mix") if isinstance(caption_context, dict) else None,
            caption_context.get("creator_model") if isinstance(caption_context, dict) else None,
        ]
        return any(self._creator_label(candidate).lower() == expected for candidate in candidates if candidate)

    def _surface_handoff_readiness_for_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        surface = normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface"))
        media_type = str(asset.get("media_type") or asset.get("source_media_type") or media_type_for_path(asset.get("campaign_path") or asset.get("filename") or "")).lower()
        blocking: list[str] = []
        warnings: list[str] = []
        caption_context = load_context_json(asset.get("caption_outcome_context_json"))
        post_caption = self._instagram_post_caption_for_asset(asset, caption_context if isinstance(caption_context, dict) else {})
        caption_generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(caption_generation, dict):
            caption_generation = {}
        latest_audit = self._latest_audit_for_asset(str(asset["id"]))
        trust_blockers, trust_statuses = self._content_trust_status_blockers(
            asset,
            latest_audit,
            caption_context if isinstance(caption_context, dict) else {},
        )
        blocking.extend(trust_blockers)
        discoverability_contract = self.discoverability_safe_content_contract(
            post_caption.get("instagram_post_caption"),
            post_caption.get("burned_caption_text"),
            asset.get("caption"),
            caption_generation.get("story_cta_text"),
            caption_generation.get("story_cta_target_url"),
        )
        media_path = str(asset.get("campaign_path") or asset.get("output_path") or "")
        media_items = [{
            "mediaPath": media_path,
            "mediaHash": asset.get("content_hash"),
            "mediaType": media_type,
            "componentIndex": 0,
        }]
        can_handoff = False
        legacy_handoff = None
        story_quality: dict[str, Any] | None = None
        story_style_approved = False
        if surface != "feed_carousel":
            if not media_path or not Path(media_path).exists():
                blocking.append("media_file_missing")
            if not asset.get("content_hash"):
                blocking.append("content_hash_missing")

        if surface == "reel":
            plan = self._latest_distribution_plan_for_asset(asset["id"])
            publishability = self.explain_publishability(asset["id"], distribution_plan_id=plan["id"] if plan else None)
            legacy_handoff = publishability.get("handoff_manifest")
            if not publishability.get("publishableCandidate"):
                blocking.extend(str(reason) for reason in publishability.get("publishability_failure_reasons") or ["publishability_blocked"])
            if not legacy_handoff:
                blocking.append("handoff_manifest_missing")
            if media_type != "video":
                blocking.append("reel_requires_video")
            if self._requires_operator_visual_review_for_handoff(asset):
                blocking.append("operator_visual_review_required")
            can_handoff = not blocking
        elif surface == "story":
            if media_type not in {"image", "video"}:
                blocking.append("story_requires_image_or_video")
            if not self._aspect_ratio_safe(asset.get("target_ratio"), "story"):
                blocking.append("story_aspect_ratio_not_safe")
            story_quality = self._story_quality_gate_for_asset(asset)
            style = self._story_style_value(asset)
            story_asset_class = str(asset.get("story_asset_class") or caption_generation.get("story_asset_class") or "").strip()
            story_intent = self._story_intent_value(asset)
            story_style_approved = bool(style in STORY_NATIVE_PROOF_STYLES and (story_asset_class or story_intent))
            if not story_style_approved:
                blocking.append("story_style_not_approved")
            if not story_quality.get("story_quality_gate_passed"):
                blocking.append("story_quality_gate_failed")
                blocking.extend(str(reason) for reason in story_quality.get("failureReasons") or [])
            can_handoff = not blocking
        elif surface == "feed_single":
            if media_type != "image":
                blocking.append("feed_single_requires_image")
            if not self._aspect_ratio_safe(asset.get("target_ratio"), "feed_single"):
                blocking.append("feed_single_aspect_ratio_not_safe")
            if not post_caption.get("instagram_post_caption") and not self._allows_blank_instagram_post_caption(asset):
                blocking.append("instagram_post_caption_missing")
            can_handoff = not blocking
        elif surface == "feed_carousel":
            components = self._asset_components(asset["id"])
            media_items = [
                {
                    "mediaPath": item["media_path"],
                    "mediaHash": item["media_hash"],
                    "mediaType": item["media_type"],
                    "componentIndex": item["component_index"],
                }
                for item in components
            ]
            if not (2 <= len(components) <= 10):
                blocking.append("carousel_requires_2_to_10_components")
            indexes = [int(item["component_index"]) for item in components]
            if indexes != list(range(len(components))):
                blocking.append("carousel_components_not_ordered")
            for item in components:
                if item["media_type"] not in {"image", "video"}:
                    blocking.append("carousel_component_media_invalid")
                if not Path(item["media_path"]).exists():
                    blocking.append("carousel_component_media_missing")
                if str(item["publishability_state"] or "").lower() not in {"passed", "pass", "ready", "approved"}:
                    blocking.append("carousel_component_publishability_failed")
            if components and not self._aspect_ratio_safe(components[0]["aspect_ratio"], "feed_carousel"):
                blocking.append("carousel_cover_aspect_ratio_not_safe")
            if not post_caption.get("instagram_post_caption") and not self._allows_blank_instagram_post_caption(asset):
                blocking.append("instagram_post_caption_missing")
            can_handoff = not blocking
        else:
            blocking.append("unsupported_content_surface")

        if not discoverability_contract["discoverabilitySafe"]:
            blocking.append("discoverability_safety_failed")
            warnings.append(discoverability_contract["blockedReason"])
            can_handoff = False

        ig_media_type = self._ig_media_type_for_surface(surface, media_type)
        manifest_v2 = None
        if can_handoff:
            manifest_v2 = {
                "manifest_version": 2,
                "asset_id": asset["id"],
                "rendered_asset_id": asset["id"],
                "source_asset_id": asset.get("source_asset_id"),
                "content_fingerprint": asset.get("content_hash"),
                "content_hash": asset.get("content_hash"),
                "caption_hash": asset.get("caption_hash"),
                "contentSurface": surface,
                "content_surface": surface,
                "igMediaType": ig_media_type,
                "ig_media_type": ig_media_type,
                "mediaItems": media_items,
                "instagramPostCaption": post_caption.get("instagram_post_caption") or "",
                "instagram_post_caption": post_caption.get("instagram_post_caption") or "",
                "instagram_post_caption_hash": post_caption.get("instagram_post_caption_hash"),
                "hashtags": post_caption.get("hashtags") or [],
                "post_caption_style": post_caption.get("post_caption_style"),
                "visualQcStatus": trust_statuses["visualQcStatus"],
                "identityVerificationStatus": trust_statuses["identityVerificationStatus"],
                "visualQc": {"status": trust_statuses["visualQcStatus"]},
                "identityVerification": {"status": trust_statuses["identityVerificationStatus"]},
                "exported_by_system": "campaign_factory",
                "exported_at": utc_now(),
                "surfaceReadiness": {
                    "canHandoff": True,
                    "blockingReasons": [],
                    "warnings": warnings,
                },
                "discoverabilitySafe": discoverability_contract["discoverabilitySafe"],
                "discoverabilityContract": discoverability_contract,
            }
            if surface == "story" and story_quality is not None:
                manifest_v2.update({
                    "storyQualityGatePassed": bool(story_quality.get("storyQualityGatePassed")),
                    "storySourceNative": bool(story_quality.get("storySourceNative")),
                    "storyNoTextRequired": bool(story_quality.get("storyNoTextRequired")),
                    "storyNoTextPassed": bool(story_quality.get("storyNoTextPassed")),
                    "storyStyleApproved": bool(story_style_approved),
                    "sourceLineageBlockers": story_quality.get("sourceLineageBlockers") or [],
                    "visualQualityStatus": story_quality.get("visualQualityStatus") or "passed",
                })
        return {
            "assetId": asset["id"],
            "contentSurface": surface,
            "igMediaType": ig_media_type,
            "mediaType": media_type,
            "canHandoff": bool(can_handoff),
            "scheduleSafe": bool(can_handoff),
            "blockingReasons": sorted(set(blocking)),
            "warnings": sorted(set(warnings)),
            "visualQcStatus": trust_statuses["visualQcStatus"],
            "identityVerificationStatus": trust_statuses["identityVerificationStatus"],
            "discoverabilitySafe": discoverability_contract["discoverabilitySafe"],
            "discoverabilityContract": discoverability_contract,
            "storyQuality": story_quality,
            "storyStyleApproved": story_style_approved if surface == "story" else None,
            "handoffManifestV2": manifest_v2,
            "handoffManifest": legacy_handoff,
            "wouldWrite": False,
        }

    def _surface_draft_payload_for_readiness(self, readiness: dict[str, Any]) -> dict[str, Any]:
        manifest = readiness.get("handoffManifestV2") if isinstance(readiness.get("handoffManifestV2"), dict) else {}
        media_items = manifest.get("mediaItems") if isinstance(manifest.get("mediaItems"), list) else []
        return {
            "schema": "threadsdash.surface_draft.preview.v1",
            "status": "draft",
            "platform": "instagram",
            "assetId": readiness.get("assetId"),
            "contentSurface": readiness.get("contentSurface"),
            "igMediaType": readiness.get("igMediaType"),
            "mediaType": readiness.get("mediaType"),
            "mediaItems": media_items,
            "instagramPostCaption": manifest.get("instagramPostCaption") or "",
            "handoffManifestV2": manifest,
            "metadata": {
                "campaign_factory": {
                    "rendered_asset_id": readiness.get("assetId"),
                    "content_surface": readiness.get("contentSurface"),
                    "ig_media_type": readiness.get("igMediaType"),
                    "asset_state": "exportable",
                    "publishability_failure_reasons": [],
                    "content_fingerprint": manifest.get("content_fingerprint") or manifest.get("content_hash"),
                    "caption_hash": manifest.get("caption_hash"),
                    "instagram_post_caption": manifest.get("instagramPostCaption") or manifest.get("instagram_post_caption") or "",
                    "instagram_post_caption_hash": manifest.get("instagram_post_caption_hash"),
                    "hashtags": manifest.get("hashtags") or [],
                    "post_caption_style": manifest.get("post_caption_style") or "short_natural",
                    "handoff_manifest": manifest,
                    "handoff_manifest_v2": manifest,
                    "dry_run": True,
                }
            },
            "wouldWrite": False,
        }

    def _latest_distribution_plan_for_asset(self, rendered_asset_id: str) -> dict[str, Any] | None:
        row = self.conn.execute(
            "SELECT * FROM distribution_plans WHERE rendered_asset_id = ? ORDER BY created_at DESC LIMIT 1",
            (rendered_asset_id,),
        ).fetchone()
        return self._distribution_plan_payload(dict(row)) if row else None

    def _asset_components(self, rendered_asset_id: str) -> list[dict[str, Any]]:
        rows = self.conn.execute(
            "SELECT * FROM asset_components WHERE asset_id = ? ORDER BY component_index",
            (rendered_asset_id,),
        ).fetchall()
        return [dict(row) for row in rows]

    def _ig_media_type_for_surface(self, surface: str, media_type: str) -> str:
        return IG_MEDIA_TYPE_BY_SURFACE.get(surface, "REELS")

    def _aspect_ratio_safe(self, ratio: Any, surface: str) -> bool:
        text = str(ratio or "").strip()
        if not text:
            return True
        safe = {
            "story": {"9:16", "4:5", "1:1"},
            "feed_single": {"1:1", "4:5", "1.91:1", "9:16"},
            "feed_carousel": {"1:1", "4:5", "1.91:1", "9:16"},
        }
        return text in safe.get(surface, {text})

    def _allows_blank_instagram_post_caption(self, asset: dict[str, Any]) -> bool:
        generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(generation, dict):
            return False
        return self._truthy(generation.get("allow_empty_instagram_post_caption") or generation.get("allowEmptyInstagramPostCaption"))

    def _account_content_requirement_rows(
        self,
        *,
        creator: str | None = None,
        account_id: str | None = None,
    ) -> list[dict[str, Any]]:
        clauses = ["r.active = 1"]
        params: list[Any] = []
        if creator:
            clauses.append("LOWER(r.creator) = LOWER(?)")
            params.append(creator)
        if account_id:
            clauses.append("(r.account_id = ? OR a.external_id = ? OR a.handle = ?)")
            params.extend([account_id, account_id, account_id])
        rows = self.conn.execute(
            f"""
            SELECT r.*, a.handle, a.external_id
            FROM account_content_requirements r
            LEFT JOIN accounts a ON a.id = r.account_id
            WHERE {" AND ".join(clauses)}
            ORDER BY r.account_id, r.content_surface
            """,
            params,
        ).fetchall()
        return [dict(row) for row in rows]

    def _account_row_for_requirement_account(self, account_id: str) -> dict[str, Any] | None:
        row = self.conn.execute(
            """
            SELECT * FROM accounts
            WHERE id = ? OR external_id = ? OR handle = ?
            LIMIT 1
            """,
            (account_id, account_id, account_id),
        ).fetchone()
        return dict(row) if row else None

    def _content_obligation_for_requirement(self, requirement: dict[str, Any], target_date: datetime.date) -> dict[str, Any]:
        surface = normalize_content_surface(requirement.get("content_surface"))
        required = self._required_content_count(requirement, target_date)
        completed = self._surface_completed_count(
            requirement["account_id"],
            requirement.get("external_id"),
            surface,
            target_date,
        )
        scheduled = self._surface_scheduled_count(
            requirement["account_id"],
            requirement.get("external_id"),
            surface,
            target_date,
        )
        remaining = max(0, required - completed - scheduled)
        return {
            "account": requirement.get("handle") or requirement.get("external_id") or requirement["account_id"],
            "accountId": requirement["account_id"],
            "instagramAccountId": requirement.get("external_id"),
            "surface": surface,
            "cadence": requirement.get("cadence") or "daily",
            "required": required,
            "completed": completed,
            "scheduled": scheduled,
            "remaining": remaining,
            "needed": remaining > 0,
            "blocked": False,
            "overdue": False,
            "blockedReason": "",
        }

    def _required_content_count(self, requirement: dict[str, Any], target_date: datetime.date) -> int:
        if not self._requirement_active_on_date(requirement, target_date):
            return 0
        cadence = str(requirement.get("cadence") or "daily").strip().lower()
        per_day = re.fullmatch(r"(\d+)[_-]per[_-]day", cadence)
        if per_day:
            return max(0, int(per_day.group(1)))
        if cadence in {"every_other_day", "alternate_days", "every_2_days", "every-other-day"}:
            if target_date.toordinal() % 2:
                return 0
        try:
            return max(0, int(requirement.get("max_per_day") or 0))
        except (TypeError, ValueError):
            return 0

    def _empty_surface_totals(self) -> dict[str, dict[str, int]]:
        return {
            surface: {
                "required": 0,
                "completed": 0,
                "scheduled": 0,
                "remaining": 0,
                "accountsNeeding": 0,
            }
            for surface in CONTENT_SURFACES
        }

    def _add_obligation_to_totals(self, totals: dict[str, dict[str, int]], obligation: dict[str, Any]) -> None:
        surface = obligation["surface"]
        if surface not in totals:
            return
        totals[surface]["required"] += int(obligation.get("required") or 0)
        totals[surface]["completed"] += int(obligation.get("completed") or 0)
        totals[surface]["scheduled"] += int(obligation.get("scheduled") or 0)
        totals[surface]["remaining"] += int(obligation.get("remaining") or 0)
        if obligation.get("needed"):
            totals[surface]["accountsNeeding"] += 1

    def _requirement_active_on_date(self, requirement: dict[str, Any], target_date: datetime.date) -> bool:
        allowed_days = json_load(requirement.get("allowed_days"), [])
        if isinstance(allowed_days, list) and allowed_days:
            normalized_days = {int(day) for day in allowed_days if str(day).isdigit()}
            if target_date.weekday() not in normalized_days and ((target_date.weekday() + 1) % 7) not in normalized_days:
                return False
        cadence = str(requirement.get("cadence") or "daily").lower()
        if cadence in {"daily", "every_day"}:
            return True
        if cadence in {"weekly", "once_weekly"}:
            return True
        return True

    def _surface_scheduled_count(self, account_id: str, instagram_account_id: str | None, surface: str, target_date: datetime.date) -> int:
        start = f"{target_date.isoformat()}T00:00:00"
        end = f"{(target_date + timedelta(days=1)).isoformat()}T00:00:00"
        row = self.conn.execute(
            """
            SELECT COUNT(DISTINCT id) AS count FROM distribution_plans
            WHERE content_surface = ?
              AND (account_id = ? OR instagram_account_id = ?)
              AND planned_window_start >= ? AND planned_window_start < ?
            """,
            (surface, account_id, instagram_account_id, start, end),
        ).fetchone()
        return int(row["count"] or 0) if row else 0

    def _surface_completed_count(self, account_id: str, instagram_account_id: str | None, surface: str, target_date: datetime.date) -> int:
        start = f"{target_date.isoformat()}T00:00:00"
        end = f"{(target_date + timedelta(days=1)).isoformat()}T00:00:00"
        row = self.conn.execute(
            """
            SELECT COUNT(DISTINCT post_id) AS count FROM performance_snapshots
            WHERE content_surface = ?
              AND (account_id = ? OR instagram_account_id = ?)
              AND published_at >= ? AND published_at < ?
            """,
            (surface, account_id, instagram_account_id, start, end),
        ).fetchone()
        return int(row["count"] or 0) if row else 0

    def _last_surface_posted_at(
        self,
        *,
        account_id: str,
        instagram_account_id: str | None,
        surface: str,
        before_date: datetime.date,
    ) -> str | None:
        end = f"{before_date.isoformat()}T00:00:00"
        row = self.conn.execute(
            """
            SELECT published_at FROM performance_snapshots
            WHERE content_surface = ?
              AND (account_id = ? OR instagram_account_id = ?)
              AND published_at < ?
            ORDER BY published_at DESC
            LIMIT 1
            """,
            (surface, account_id, instagram_account_id, end),
        ).fetchone()
        return str(row["published_at"]) if row and row["published_at"] else None

    def _surface_scheduled_for_account(self, account_id: str, instagram_account_id: str | None, surface: str, target_date: datetime.date) -> bool:
        start = f"{target_date.isoformat()}T00:00:00"
        end = f"{(target_date + timedelta(days=1)).isoformat()}T00:00:00"
        row = self.conn.execute(
            """
            SELECT 1 FROM distribution_plans
            WHERE content_surface = ?
              AND (account_id = ? OR instagram_account_id = ?)
              AND planned_window_start >= ? AND planned_window_start < ?
            LIMIT 1
            """,
            (surface, account_id, instagram_account_id, start, end),
        ).fetchone()
        return bool(row)

    def _surface_completed_for_account(self, account_id: str, instagram_account_id: str | None, surface: str, target_date: datetime.date) -> bool:
        start = f"{target_date.isoformat()}T00:00:00"
        end = f"{(target_date + timedelta(days=1)).isoformat()}T00:00:00"
        row = self.conn.execute(
            """
            SELECT 1 FROM performance_snapshots
            WHERE content_surface = ?
              AND (account_id = ? OR instagram_account_id = ?)
              AND published_at >= ? AND published_at < ?
            LIMIT 1
            """,
            (surface, account_id, instagram_account_id, start, end),
        ).fetchone()
        return bool(row)

    def _default_dashboard_campaign(self, campaigns: list[dict[str, Any]]) -> dict[str, Any] | None:
        for campaign in campaigns:
            row = self.conn.execute(
                "SELECT 1 FROM rendered_assets WHERE campaign_id = ? LIMIT 1",
                (campaign["id"],),
            ).fetchone()
            if row:
                return campaign
        return campaigns[0] if campaigns else None

    def campaign_health(self, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        sources = self.assets_for_campaign(campaign["id"])
        rendered = [self._dashboard_rendered_asset(asset) for asset in self.rendered_for_campaign(campaign["id"])]
        jobs = self.jobs_for_campaign(campaign["slug"], limit=200)
        audited = [asset for asset in rendered if asset.get("latest_audit")]
        approved = [asset for asset in rendered if asset["review_state"] == "approved"]
        rejected = [asset for asset in rendered if asset["review_state"] == "rejected"]
        ready = [asset for asset in rendered if (asset.get("export_readiness") or {}).get("state") == "ready"]
        warning = [asset for asset in rendered if (asset.get("export_readiness") or {}).get("state") == "warning"]
        blocked = [asset for asset in rendered if (asset.get("export_readiness") or {}).get("state") == "blocked"]
        audio_workflow = self.audio_workflow_summary(rendered)
        failed_jobs = self._unresolved_failed_jobs(jobs)
        return {
            "schema": "campaign_factory.campaign_health.v1",
            "campaign": campaign["slug"],
            "generatedAt": utc_now(),
            "counts": {
                "sourcesImported": len(sources),
                "renderedAssets": len(rendered),
                "auditedAssets": len(audited),
                "approvedAssets": len(approved),
                "rejectedAssets": len(rejected),
                "exportReadyAssets": len(ready),
                "warningAssets": len(warning),
                "blockedAssets": len(blocked),
                "failedJobs": len(failed_jobs),
                "audioNeedsAudio": audio_workflow["counts"]["needs_audio"],
                "audioSelectedNotAttached": audio_workflow["counts"]["selected_not_attached"],
                "audioBlocked": audio_workflow["counts"]["blocked"],
                "audioReady": audio_workflow["counts"]["ready"],
            },
            "audioWorkflow": audio_workflow,
            "failedJobs": failed_jobs[:10],
        }

    def _unresolved_failed_jobs(self, jobs: list[dict[str, Any]]) -> list[dict[str, Any]]:
        latest_success_by_type: dict[str, str] = {}
        for job in jobs:
            if job["status"] != "succeeded":
                continue
            timestamp = job.get("finishedAt") or job.get("updatedAt") or job.get("createdAt") or ""
            latest_success_by_type[job["jobType"]] = max(latest_success_by_type.get(job["jobType"], ""), timestamp)
        unresolved = []
        for job in jobs:
            if job["status"] != "failed":
                continue
            failed_at = job.get("finishedAt") or job.get("updatedAt") or job.get("createdAt") or ""
            if latest_success_by_type.get(job["jobType"], "") > failed_at:
                continue
            unresolved.append(job)
        return unresolved

    def asset_detail(self, rendered_asset_id: str) -> dict[str, Any]:
        asset = self._dashboard_rendered_asset(self.rendered_asset(rendered_asset_id))
        campaign = dict(self.conn.execute("SELECT * FROM campaigns WHERE id = ?", (asset["campaign_id"],)).fetchone())
        source = dict(self.conn.execute("SELECT * FROM source_assets WHERE id = ?", (asset["source_asset_id"],)).fetchone())
        approvals = [
            dict(row)
            for row in self.conn.execute(
                "SELECT * FROM approval_decisions WHERE rendered_asset_id = ? ORDER BY created_at DESC",
                (rendered_asset_id,),
            ).fetchall()
        ]
        audits = [
            self._audit_report_payload(dict(row))
            for row in self.conn.execute(
                "SELECT * FROM audit_reports WHERE rendered_asset_id = ? ORDER BY created_at DESC",
                (rendered_asset_id,),
            ).fetchall()
        ]
        exports = [
            dict(row)
            for row in self.conn.execute(
                """
                SELECT * FROM threadsdash_exports
                WHERE campaign_id = ? AND manifest_path IN (
                  SELECT manifest_path FROM threadsdash_exports WHERE campaign_id = ?
                )
                ORDER BY created_at DESC
                """,
                (campaign["id"], campaign["id"]),
            ).fetchall()
        ]
        assignments = self.assignments_for_asset(rendered_asset_id)
        return {
            "schema": "campaign_factory.asset_detail.v1",
            "campaign": campaign,
            "source": source,
            "asset": asset,
            "assignments": assignments,
            "audits": audits,
            "approvals": approvals,
            "exports": exports,
            "activity": self.events_for_asset(rendered_asset_id, limit=100),
            "performance": self._performance_for_asset(asset),
            "ranking": self.ranking(campaign["slug"])["byAsset"].get(rendered_asset_id),
        }

    def assign_asset_account(
        self,
        rendered_asset_id: str,
        *,
        account_id: str | None = None,
        instagram_account_id: str | None = None,
        planned_window_start: str | None = None,
        planned_window_end: str | None = None,
        notes: str | None = None,
    ) -> dict[str, Any]:
        asset = self.rendered_asset(rendered_asset_id)
        if account_id:
            row = self.conn.execute("SELECT * FROM accounts WHERE id = ?", (account_id,)).fetchone()
            if not row:
                raise ValueError(f"account not found: {account_id}")
        now = utc_now()
        assignment_id = new_id("assign")
        self.conn.execute(
            """
            INSERT INTO asset_account_assignments
            (id, campaign_id, rendered_asset_id, account_id, instagram_account_id, planned_window_start,
             planned_window_end, notes, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                assignment_id,
                asset["campaign_id"],
                rendered_asset_id,
                account_id,
                instagram_account_id,
                planned_window_start,
                planned_window_end,
                notes,
                now,
                now,
            ),
        )
        self.record_event(
            "asset_account_assigned",
            campaign_id=asset["campaign_id"],
            source_asset_id=asset["source_asset_id"],
            rendered_asset_id=rendered_asset_id,
            status="success",
            message=f"Assigned asset to Instagram account {instagram_account_id or account_id or 'unassigned'}",
            metadata={"assignmentId": assignment_id, "accountId": account_id, "instagramAccountId": instagram_account_id},
            commit=False,
        )
        self.conn.commit()
        return dict(self.conn.execute("SELECT * FROM asset_account_assignments WHERE id = ?", (assignment_id,)).fetchone())

    def assignments_for_asset(self, rendered_asset_id: str) -> list[dict[str, Any]]:
        rows = self.conn.execute(
            "SELECT * FROM asset_account_assignments WHERE rendered_asset_id = ? ORDER BY created_at",
            (rendered_asset_id,),
        ).fetchall()
        return [dict(row) for row in rows]

    def assignments_for_campaign(self, campaign_slug: str) -> list[dict[str, Any]]:
        campaign = self.campaign_by_slug(campaign_slug)
        rows = self.conn.execute(
            "SELECT * FROM asset_account_assignments WHERE campaign_id = ? ORDER BY created_at",
            (campaign["id"],),
        ).fetchall()
        return [dict(row) for row in rows]

    def recommend_next_batch(
        self,
        campaign_slug: str,
        *,
        count: int = 20,
        account: str | None = None,
        persist: bool = False,
    ) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        campaign_graph_id = self.graph_id_for(
            "campaigns",
            campaign["id"],
            entity_type="campaign",
            payload={"slug": campaign["slug"], "platform": campaign["platform"]},
        )
        performance = self.performance_summary(campaign["slug"])
        ranking = self.ranking(campaign["slug"])
        reference_pattern_rankings = self._ranked_reference_patterns_for_campaign(campaign["id"])
        reference_pattern = (
            reference_pattern_rankings[0]["pattern"]
            if reference_pattern_rankings
            else self.active_reference_pattern_for_campaign(campaign["id"]) or self._top_reference_pattern()
        )
        variation_preset_rankings = self._ranked_variation_presets_for_campaign(campaign["id"], account=account)
        recommendation_trust = self._latest_recommendation_trust_context(campaign["id"], account=account)
        reference_pattern_id = reference_pattern.get("id") if reference_pattern else None
        reference_pattern_graph_id = self.graph_id_for(
            "reference_patterns",
            reference_pattern_id,
            entity_type="reference_pattern",
            payload=reference_pattern,
        ) if reference_pattern_id else None
        candidates = ranking.get("assets") or []
        input_snapshot = {
            "schema": "campaign_factory.recommendations.input_snapshot.v1",
            "campaignId": campaign["id"],
            "campaign": campaign["slug"],
            "account": account,
            "count": max(1, int(count)),
            "scoringVersion": "recommendation_score.v1",
            "performanceSnapshotCount": performance.get("snapshotCount") or 0,
            "candidateRenderedAssetIds": [item.get("renderedAssetId") for item in candidates],
            "referencePatternId": reference_pattern_id,
            "referencePatternRankings": self._compact_recommendation_rankings(reference_pattern_rankings),
            "variationPresetRankings": self._compact_recommendation_rankings(variation_preset_rankings),
            "recommendationTrust": recommendation_trust,
        }
        input_hash = hashlib.sha256(json.dumps(input_snapshot, sort_keys=True).encode("utf-8")).hexdigest()[:16]
        run_id = f"recrun_{input_hash}"
        run_graph_id = None
        now = utc_now()
        if persist:
            row = self.conn.execute(
                "SELECT id FROM recommendation_runs WHERE campaign_id = ? AND scope = 'next_batch' AND input_hash = ?",
                (campaign["id"], input_hash),
            ).fetchone()
            run_id = row["id"] if row else run_id
            self.conn.execute(
                """
                INSERT INTO recommendation_runs (
                  id, campaign_id, scope, scoring_version, input_hash,
                  input_snapshot_json, created_at, updated_at
                )
                VALUES (?, ?, 'next_batch', 'recommendation_score.v1', ?, ?, ?, ?)
                ON CONFLICT(campaign_id, scope, input_hash) DO UPDATE SET
                  scoring_version = excluded.scoring_version,
                  input_snapshot_json = excluded.input_snapshot_json,
                  updated_at = excluded.updated_at
                """,
                (
                    run_id,
                    campaign["id"],
                    input_hash,
                    json.dumps(sanitize_for_storage(input_snapshot), ensure_ascii=False, sort_keys=True),
                    now,
                    now,
                ),
            )
            run_graph_id = self.ensure_graph_node(
                "recommendation_run",
                local_table="recommendation_runs",
                local_id=run_id,
                payload={"campaign": campaign["slug"], "inputHash": input_hash, "scope": "next_batch"},
            )
            if campaign_graph_id:
                self.ensure_graph_edge(
                    campaign_graph_id,
                    run_graph_id,
                    "campaign_to_recommendation_run",
                    evidence={"source": "campaign_factory.recommend_next_batch"},
                )

        items = []
        warnings = []
        for rank, candidate in enumerate(candidates[:max(1, int(count))], start=1):
            asset = self.rendered_asset(candidate["renderedAssetId"])
            enriched = self._dashboard_rendered_asset(asset)
            item = self._recommendation_item_payload(
                campaign=campaign,
                campaign_graph_id=campaign_graph_id,
                run_graph_id=run_graph_id,
                rank=rank,
                account=account,
                candidate=candidate,
                asset=enriched,
                reference_pattern=reference_pattern,
                reference_pattern_graph_id=reference_pattern_graph_id,
                reference_pattern_rankings=reference_pattern_rankings,
                variation_preset_rankings=variation_preset_rankings,
                recommendation_trust=recommendation_trust,
                persist=persist,
                run_id=run_id,
            )
            items.append(item)
        if not items:
            warnings.append("no_rendered_assets_available")
            fallback = self._reference_only_recommendation_item(
                campaign=campaign,
                campaign_graph_id=campaign_graph_id,
                run_graph_id=run_graph_id,
                account=account,
                reference_pattern=reference_pattern,
                reference_pattern_graph_id=reference_pattern_graph_id,
                reference_pattern_rankings=reference_pattern_rankings,
                variation_preset_rankings=variation_preset_rankings,
                recommendation_trust=recommendation_trust,
                persist=persist,
                run_id=run_id,
            )
            if fallback:
                items.append(fallback)
        if persist:
            self.record_event(
                "recommendation_run_created",
                campaign_id=campaign["id"],
                status="success" if items else "warning",
                message=f"Recommended next batch for {campaign['slug']}",
                metadata={"runId": run_id, "itemCount": len(items), "inputHash": input_hash, "warnings": warnings},
                commit=False,
            )
            self.conn.commit()
        return {
            "schema": "campaign_factory.recommendations.next_batch.v1",
            "campaign": campaign["slug"],
            "campaignGraphId": campaign_graph_id,
            "runId": run_id if persist else None,
            "runGraphId": run_graph_id,
            "persisted": bool(persist),
            "scoringVersion": "recommendation_score.v1",
            "generatedAt": now,
            "count": len(items),
            "requestedCount": max(1, int(count)),
            "account": account,
            "inputHash": input_hash,
            "warnings": warnings,
            "items": items,
        }

    def recommendation_runs(self, campaign_slug: str, *, limit: int = 10) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        rows = self.conn.execute(
            """
            SELECT * FROM recommendation_runs
            WHERE campaign_id = ?
            ORDER BY created_at DESC
            LIMIT ?
            """,
            (campaign["id"], max(1, min(int(limit), 100))),
        ).fetchall()
        runs = []
        for row in rows:
            items = self.conn.execute(
                "SELECT * FROM recommendation_items WHERE run_id = ? ORDER BY rank",
                (row["id"],),
            ).fetchall()
            runs.append({
                "id": row["id"],
                "scope": row["scope"],
                "scoringVersion": row["scoring_version"],
                "inputHash": row["input_hash"],
                "inputSnapshot": json_load(row["input_snapshot_json"], {}),
                "runGraphId": self.graph_id_for("recommendation_runs", row["id"]),
                "createdAt": row["created_at"],
                "updatedAt": row["updated_at"],
                "items": [self._stored_recommendation_item_payload(dict(item)) for item in items],
            })
        return {"schema": "campaign_factory.recommendation_runs.v1", "campaign": campaign["slug"], "runs": runs}

    def _top_reference_pattern(self) -> dict[str, Any] | None:
        row = self.conn.execute(
            "SELECT * FROM reference_patterns ORDER BY COALESCE(rank, 999999), label LIMIT 1"
        ).fetchone()
        return self._reference_pattern_payload(dict(row)) if row else None

    def _ranked_reference_patterns_for_campaign(self, campaign_id: str) -> list[dict[str, Any]]:
        pattern_rows = self.conn.execute(
            "SELECT * FROM reference_patterns ORDER BY COALESCE(rank, 999999), label"
        ).fetchall()
        patterns = [self._reference_pattern_payload(dict(row)) for row in pattern_rows]
        if not patterns:
            return []
        pattern_by_key: dict[str, dict[str, Any]] = {}
        for pattern in patterns:
            keys = {
                pattern.get("id"),
                pattern.get("clusterKey"),
                pattern.get("label"),
                slugify(str(pattern.get("label") or "")),
            }
            for key in keys:
                if key:
                    pattern_by_key[str(key)] = pattern
                    pattern_by_key[slugify(str(key))] = pattern
        rows = self.conn.execute(
            """
            SELECT * FROM performance_snapshots
            WHERE campaign_id = ? AND metrics_eligible = 1
            ORDER BY snapshot_at DESC, created_at DESC
            """,
            (campaign_id,),
        ).fetchall()
        all_snapshots = [self._performance_snapshot_payload(dict(row)) for row in rows]
        account_baselines = account_reward_baselines(all_snapshots)
        buckets: dict[str, dict[str, Any]] = {}
        for snapshot in all_snapshots:
            dimensions = snapshot.get("dimensions") or {}
            candidate_keys: set[str] = set()
            for dimension_key in ("promptPattern", "patternCard", "hook"):
                dimension = dimensions.get(dimension_key)
                if not isinstance(dimension, dict):
                    continue
                for key_name in ("key", "label", "clusterKey", "patternCardId"):
                    value = dimension.get(key_name)
                    if value:
                        candidate_keys.add(str(value))
                        candidate_keys.add(slugify(str(value)))
            matched_patterns = {
                pattern_by_key[key]["id"]: pattern_by_key[key]
                for key in candidate_keys
                if key in pattern_by_key
            }
            for pattern_id, pattern in matched_patterns.items():
                bucket = buckets.setdefault(pattern_id, {"pattern": pattern, "snapshots": {}})
                bucket["snapshots"][snapshot["id"]] = snapshot
        rankings = []
        for bucket in buckets.values():
            snapshots = list(bucket["snapshots"].values())
            performance = self._aggregate_performance(snapshots, account_baselines=account_baselines)
            rankings.append({
                "pattern": bucket["pattern"],
                "patternId": bucket["pattern"].get("id"),
                "clusterKey": bucket["pattern"].get("clusterKey"),
                "label": bucket["pattern"].get("label"),
                "sampleSize": int(performance.get("count") or 0),
                "performanceScore": self._performance_quality_score(performance),
                "planningScore": self._performance_planning_score(performance),
                "bandit": (performance.get("learning") or {}).get("bandit"),
                "performance": performance,
            })
        return sorted(
            rankings,
            key=lambda item: (
                -(item["planningScore"] if item.get("planningScore") is not None else -1),
                -(item["performanceScore"] if item.get("performanceScore") is not None else -1),
                -int(item.get("sampleSize") or 0),
                int((item.get("pattern") or {}).get("rank") or 999999),
                str(item.get("label") or ""),
            ),
        )

    def _ranked_variation_presets_for_campaign(self, campaign_id: str, *, account: str | None = None) -> list[dict[str, Any]]:
        rows = self.conn.execute(
            """
            SELECT * FROM performance_snapshots
            WHERE campaign_id = ? AND metrics_eligible = 1
            ORDER BY snapshot_at DESC, created_at DESC
            """,
            (campaign_id,),
        ).fetchall()
        all_snapshots = [self._performance_snapshot_payload(dict(row)) for row in rows]
        account_baselines = account_reward_baselines(all_snapshots)
        buckets: dict[str, list[dict[str, Any]]] = {}
        for snapshot in all_snapshots:
            if account and account not in {snapshot.get("instagramAccountId"), snapshot.get("accountId")}:
                continue
            preset = (snapshot.get("dimensions") or {}).get("variationPreset")
            if not isinstance(preset, dict) or not preset.get("key"):
                continue
            buckets.setdefault(str(preset["key"]), []).append(snapshot)
        rankings = []
        for preset_name, snapshots in buckets.items():
            performance = self._aggregate_performance(snapshots, account_baselines=account_baselines)
            latest = snapshots[0]
            preset = (latest.get("dimensions") or {}).get("variationPreset") or {}
            rankings.append({
                "presetName": preset_name,
                "label": preset.get("label") or preset_name,
                "sampleSize": int(performance.get("count") or 0),
                "performanceScore": self._performance_quality_score(performance),
                "planningScore": self._performance_planning_score(performance),
                "bandit": (performance.get("learning") or {}).get("bandit"),
                "performance": performance,
            })
        return sorted(
            rankings,
            key=lambda item: (
                -(item["planningScore"] if item.get("planningScore") is not None else -1),
                -(item["performanceScore"] if item.get("performanceScore") is not None else -1),
                -int(item.get("sampleSize") or 0),
                str(item.get("presetName") or ""),
            ),
        )

    def _compact_recommendation_rankings(self, rankings: list[dict[str, Any]], *, limit: int = 5) -> list[dict[str, Any]]:
        compact = []
        for item in rankings[:limit]:
            compact.append({
                key: item.get(key)
                for key in ("patternId", "clusterKey", "presetName", "label", "sampleSize", "performanceScore", "planningScore", "bandit")
                if item.get(key) is not None
            })
        return compact

    def _recommendation_reference_pattern_evidence(
        self,
        rankings: list[dict[str, Any]],
        selected_pattern: dict[str, Any] | None,
    ) -> dict[str, Any]:
        return {
            "selectedPatternId": (selected_pattern or {}).get("id"),
            "selectedClusterKey": (selected_pattern or {}).get("clusterKey"),
            "selectionSource": "performance_snapshots" if rankings else "active_or_static_fallback",
            "rankings": self._compact_recommendation_rankings(rankings),
        }

    def _recommendation_variation_preset_evidence(
        self,
        rankings: list[dict[str, Any]],
        selected_preset: str | None,
    ) -> dict[str, Any]:
        return {
            "selectedPresetName": selected_preset,
            "selectionSource": "performance_snapshots" if rankings else "default_fallback",
            "rankings": self._compact_recommendation_rankings(rankings),
        }

    def _latest_recommendation_trust_context(self, campaign_id: str, *, account: str | None) -> dict[str, Any]:
        account_key = account or ""
        row = self.conn.execute(
            """
            SELECT * FROM recommendation_accuracy_reports
            WHERE campaign_id = ?
              AND account_key IN (?, '')
            ORDER BY CASE WHEN account_key = ? THEN 0 ELSE 1 END, updated_at DESC
            LIMIT 1
            """,
            (campaign_id, account_key, account_key),
        ).fetchone()
        if not row:
            return {
                "status": "unmeasured",
                "score": None,
                "trustConfidence": "insufficient",
                "measuredCount": 0,
                "source": "no_recommendation_accuracy_report",
            }
        payload = json_load(row["report_json"], {})
        overall = payload.get("overall") if isinstance(payload.get("overall"), dict) else {}
        score = payload.get("recommendationTrustScore")
        score_int = int(score) if isinstance(score, (int, float)) else None
        if score_int is None:
            status = "unmeasured"
        elif score_int < 50:
            status = "low"
        elif score_int < 70:
            status = "directional"
        else:
            status = "trusted"
        return {
            "status": status,
            "score": score_int,
            "trustConfidence": payload.get("trustConfidence") or "insufficient",
            "measuredCount": int(overall.get("measuredCount") or 0),
            "accuracyRate": overall.get("accuracyRate"),
            "reportId": payload.get("reportId") or row["id"],
            "reportGraphId": payload.get("reportGraphId"),
            "accountScope": row["account_key"] or "all_accounts",
            "windowDays": row["window_days"],
            "updatedAt": row["updated_at"],
            "source": "recommendation_accuracy_report",
        }

    def _apply_recommendation_trust(
        self,
        *,
        score: int | float,
        confidence: str,
        confidence_reason: str,
        recommendation_trust: dict[str, Any],
    ) -> tuple[int, str, str, list[str]]:
        trust_score = recommendation_trust.get("score")
        if not isinstance(trust_score, int):
            return int(max(0, min(100, round(score)))), confidence, confidence_reason, []
        risks = []
        adjusted_score = int(max(0, min(100, round(score))))
        adjusted_confidence = confidence
        adjusted_reason = confidence_reason
        if trust_score < 50:
            risks.append("low_recommendation_trust")
            adjusted_score = min(adjusted_score, max(25, trust_score + 20))
            adjusted_confidence = "low"
            adjusted_reason = f"{confidence_reason}; recommendation trust score {trust_score} is low from measured outcomes"
        elif trust_score < 70 and adjusted_confidence == "high":
            risks.append("directional_recommendation_trust")
            adjusted_score = min(adjusted_score, trust_score + 15)
            adjusted_confidence = "medium"
            adjusted_reason = f"{confidence_reason}; recommendation trust score {trust_score} is directional"
        return adjusted_score, adjusted_confidence, adjusted_reason, risks

    def _recommendation_item_payload(
        self,
        *,
        campaign: dict[str, Any],
        campaign_graph_id: str | None,
        run_graph_id: str | None,
        rank: int,
        account: str | None,
        candidate: dict[str, Any],
        asset: dict[str, Any],
        reference_pattern: dict[str, Any] | None,
        reference_pattern_graph_id: str | None,
        reference_pattern_rankings: list[dict[str, Any]],
        variation_preset_rankings: list[dict[str, Any]],
        recommendation_trust: dict[str, Any],
        persist: bool,
        run_id: str,
    ) -> dict[str, Any]:
        breakdown = candidate.get("breakdown") or {}
        performance_score = int(asset.get("performanceScore") or self._best_asset_history_score(asset) or 50)
        reference_score = self._reference_pattern_score(reference_pattern)
        audit_score = int(breakdown.get("quality") or 50)
        account_score = self._recommendation_account_score(asset, account)
        account_fit_evidence = self._recommendation_account_fit_evidence(campaign["id"], asset, account)
        novelty_score = int(breakdown.get("novelty") or 50)
        operational_score = self._operational_recommendation_score(asset)
        score = round(
            performance_score * 0.40
            + reference_score * 0.20
            + audit_score * 0.15
            + account_score * 0.10
            + novelty_score * 0.10
            + operational_score * 0.05
        )
        readiness = asset.get("export_readiness") or {}
        risks = list(candidate.get("blockingReasons") or []) + list(candidate.get("warnings") or [])
        if readiness.get("state") == "blocked":
            score = min(score, 45)
        confidence, confidence_reason = self._recommendation_confidence(asset, reference_pattern)
        score, confidence, confidence_reason, trust_risks = self._apply_recommendation_trust(
            score=score,
            confidence=confidence,
            confidence_reason=confidence_reason,
            recommendation_trust=recommendation_trust,
        )
        risks.extend(trust_risks)
        data_quality = self._recommendation_data_quality(asset, reference_pattern)
        account_memory_payload = account_fit_evidence.get("memory")
        recommended_variation_preset = (
            variation_preset_rankings[0].get("presetName")
            if variation_preset_rankings
            else "ig_subtle"
        )
        reference_pattern_evidence = self._recommendation_reference_pattern_evidence(reference_pattern_rankings, reference_pattern)
        variation_preset_evidence = self._recommendation_variation_preset_evidence(variation_preset_rankings, recommended_variation_preset)
        reasons = self._recommendation_reasons(
            performance_score=performance_score,
            reference_score=reference_score,
            audit_score=audit_score,
            account_score=account_score,
            novelty_score=novelty_score,
            operational_score=operational_score,
            candidate=candidate,
            reference_pattern=reference_pattern,
        )
        source_graph_id = self.graph_id_for("source_assets", asset.get("source_asset_id"), entity_type="source_asset")
        rendered_graph_id = self.graph_id_for("rendered_assets", asset.get("id"), entity_type="rendered_asset")
        latest_performance = asset.get("latestPerformance") or {}
        performance_graph_id = None
        recommendation_input_graph_id = None
        if latest_performance.get("id"):
            performance_graph_id = self.ensure_graph_node(
                "performance_snapshot",
                local_table="performance_snapshots",
                local_id=latest_performance["id"],
                payload=latest_performance,
            )
            recommendation_input_graph_id = self.ensure_graph_node(
                "recommendation_input",
                external_system="campaign_factory.recommendation_input",
                external_id=f"recommendation_input:{latest_performance['id']}",
                payload={"performanceSnapshotId": latest_performance["id"], "campaign": campaign["slug"]},
            )
        graph_evidence = {
            "campaignGraphId": campaign_graph_id,
            "runGraphId": run_graph_id,
            "referencePatternGraphId": reference_pattern_graph_id,
            "sourceAssetGraphId": source_graph_id,
            "renderedAssetGraphId": rendered_graph_id,
            "performanceSnapshotGraphId": performance_graph_id,
            "recommendationInputGraphId": recommendation_input_graph_id,
        }
        evidence = {
            "graph": graph_evidence,
            "reasons": reasons,
            "risks": sorted(set(str(risk) for risk in risks if risk)),
            "recommendationTrust": recommendation_trust,
            "accountFit": account_fit_evidence,
            "referencePatternRankings": reference_pattern_evidence,
            "variationPresetRankings": variation_preset_evidence,
            "scores": {
                "performance": performance_score,
                "referencePattern": reference_score,
                "auditReadiness": audit_score,
                "accountFitFatigue": account_score,
                "novelty": novelty_score,
                "operationalReadiness": operational_score,
                "recommendationTrust": recommendation_trust.get("score"),
            },
        }
        item_key = f"{run_id}:{rank}:{asset.get('id')}"
        item_id = f"recitem_{hashlib.sha256(item_key.encode('utf-8')).hexdigest()[:12]}"
        audio_context_tags = [
            (reference_pattern or {}).get("visualFormat"),
            (reference_pattern or {}).get("hookType"),
            (reference_pattern or {}).get("captionArchetype"),
            asset.get("recipe"),
        ]
        audio_recommendations = self.recommend_audio(
            platform=campaign.get("platform") or "instagram",
            campaign_slug=campaign.get("slug"),
            recommendation_item_id=None,
            content_tags=[str(tag) for tag in audio_context_tags if tag],
            account_tags=[str(tag) for tag in [account or self._asset_target_account(asset)] if tag],
            account=account or self._asset_target_account(asset),
            limit=5,
        )
        audio_memory_evidence = {
            "recommendationCount": len(audio_recommendations.get("recommendations") or []),
            "topAudioMemoryGraphIds": [
                item.get("audioMemoryGraphId")
                for item in (audio_recommendations.get("recommendations") or [])[:3]
                if item.get("audioMemoryGraphId")
            ],
        }
        recommendation_graph_id = None
        output = {
            "recommendationId": item_id,
            "recommendationGraphId": None,
            "status": "proposed",
            "campaignGraphId": campaign_graph_id,
            "referencePatternGraphId": reference_pattern_graph_id,
            "sourceAssetGraphId": source_graph_id,
            "renderedAssetGraphId": rendered_graph_id,
            "rank": rank,
            "score": int(max(0, min(100, score))),
            "confidence": confidence,
            "confidenceReason": confidence_reason,
            "autonomyLevel": self.autonomy_level(),
            "executionStatus": "not_started",
            "targetAccount": account or self._asset_target_account(asset),
            "renderedAssetId": asset.get("id"),
            "filename": asset.get("filename"),
            "referencePatternId": reference_pattern.get("id") if reference_pattern else None,
            "referencePattern": self._recommendation_reference_summary(reference_pattern),
            "referencePatternEvidence": reference_pattern_evidence,
            "recommendedVariationPreset": recommended_variation_preset,
            "variationPresetEvidence": variation_preset_evidence,
            "suggestedRecipe": asset.get("recipe") or self._first_suggested_recipe(reference_pattern),
            "hookGuidance": self._hook_guidance(reference_pattern, asset),
            "captionGuidance": self._caption_guidance(reference_pattern, asset),
            "audioRecommendations": audio_recommendations,
            "audioDecision": audio_recommendations.get("decision") or {},
            "audioMemoryEvidence": audio_memory_evidence,
            "selectedAudio": None,
            "audioSelectionStatus": "recommended" if audio_recommendations.get("recommendations") else "needs_operator_selection",
            "reasons": reasons,
            "risks": sorted(set(str(risk) for risk in risks if risk)),
            "scoreBreakdown": {
                "performance": performance_score,
                "referencePattern": reference_score,
                "auditReadiness": audit_score,
                "accountFitFatigue": account_score,
                "novelty": novelty_score,
                "operationalReadiness": operational_score,
                "recommendationTrust": recommendation_trust.get("score"),
            },
            "evidence": evidence,
            "dataQuality": data_quality,
            "accountMemory": account_memory_payload,
            "accountFitEvidence": account_fit_evidence,
            "decision": {},
            "outcome": {},
            "baseline": {},
            "exceptions": [],
            "measurementVersion": None,
            "acceptedAt": None,
            "rejectedAt": None,
            "executedAt": None,
            "postedAt": None,
            "measuredAt": None,
            "graphEvidence": graph_evidence,
        }
        if persist:
            recommendation_graph_id = self.ensure_graph_node(
                "recommendation_item",
                local_table="recommendation_items",
                local_id=item_id,
                payload={key: value for key, value in output.items() if key != "recommendationGraphId"},
            )
            output["recommendationGraphId"] = recommendation_graph_id
            self.conn.execute(
                """
                INSERT INTO recommendation_items (
                  id, run_id, rank, target_account, reference_pattern_id, source_asset_id,
                  rendered_asset_id, recommendation_graph_id, status, score, confidence,
                  reasons_json, risks_json, evidence_json, data_quality_json, decision_json,
                  outcome_json, baseline_json, measurement_version, output_json, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'proposed', ?, ?, ?, ?, ?, ?, '{}', '{}', '{}', NULL, ?, ?)
                ON CONFLICT(run_id, rank) DO UPDATE SET
                  target_account = excluded.target_account,
                  reference_pattern_id = excluded.reference_pattern_id,
                  source_asset_id = excluded.source_asset_id,
                  rendered_asset_id = excluded.rendered_asset_id,
                  recommendation_graph_id = excluded.recommendation_graph_id,
                  score = excluded.score,
                  confidence = excluded.confidence,
                  reasons_json = excluded.reasons_json,
                  risks_json = excluded.risks_json,
                  evidence_json = excluded.evidence_json,
                  data_quality_json = excluded.data_quality_json,
                  output_json = excluded.output_json
                """,
                (
                    item_id,
                    run_id,
                    rank,
                    output["targetAccount"],
                    output["referencePatternId"],
                    asset.get("source_asset_id"),
                    asset.get("id"),
                    recommendation_graph_id,
                    output["score"],
                    confidence,
                    json.dumps(reasons, ensure_ascii=False, sort_keys=True),
                    json.dumps(output["risks"], ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(evidence), ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(data_quality), ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(output), ensure_ascii=False, sort_keys=True),
                    utc_now(),
                ),
            )
            self._write_recommendation_graph_edges(
                performance_graph_id=performance_graph_id,
                recommendation_input_graph_id=recommendation_input_graph_id,
                run_graph_id=run_graph_id,
                item_graph_id=recommendation_graph_id,
                rendered_graph_id=rendered_graph_id,
                reference_pattern_graph_id=reference_pattern_graph_id,
            )
            self._write_audio_recommendation_graph_edges(
                recommendation_item_id=item_id,
                recommendation_graph_id=recommendation_graph_id,
                reference_pattern_graph_id=reference_pattern_graph_id,
                audio_recommendations=audio_recommendations,
                campaign_id=campaign["id"],
            )
        return output

    def _reference_only_recommendation_item(
        self,
        *,
        campaign: dict[str, Any],
        campaign_graph_id: str | None,
        run_graph_id: str | None,
        account: str | None,
        reference_pattern: dict[str, Any] | None,
        reference_pattern_graph_id: str | None,
        reference_pattern_rankings: list[dict[str, Any]],
        variation_preset_rankings: list[dict[str, Any]],
        recommendation_trust: dict[str, Any],
        persist: bool,
        run_id: str,
    ) -> dict[str, Any] | None:
        if not reference_pattern:
            return None
        item_key = f"{run_id}:reference_only:{reference_pattern.get('id')}"
        item_id = f"recitem_{hashlib.sha256(item_key.encode('utf-8')).hexdigest()[:12]}"
        recommended_variation_preset = (
            variation_preset_rankings[0].get("presetName")
            if variation_preset_rankings
            else "ig_subtle"
        )
        reference_pattern_evidence = self._recommendation_reference_pattern_evidence(reference_pattern_rankings, reference_pattern)
        variation_preset_evidence = self._recommendation_variation_preset_evidence(variation_preset_rankings, recommended_variation_preset)
        score, confidence, confidence_reason, trust_risks = self._apply_recommendation_trust(
            score=self._reference_pattern_score(reference_pattern),
            confidence="low",
            confidence_reason="No rendered assets are available yet; recommendation is based on the active reference pattern only.",
            recommendation_trust=recommendation_trust,
        )
        output = {
            "recommendationId": item_id,
            "recommendationGraphId": None,
            "status": "proposed",
            "campaignGraphId": campaign_graph_id,
            "referencePatternGraphId": reference_pattern_graph_id,
            "sourceAssetGraphId": None,
            "renderedAssetGraphId": None,
            "rank": 1,
            "score": score,
            "confidence": confidence,
            "confidenceReason": confidence_reason,
            "autonomyLevel": self.autonomy_level(),
            "executionStatus": "not_started",
            "targetAccount": account,
            "renderedAssetId": None,
            "filename": None,
            "referencePatternId": reference_pattern.get("id"),
            "referencePattern": self._recommendation_reference_summary(reference_pattern),
            "referencePatternEvidence": reference_pattern_evidence,
            "recommendedVariationPreset": recommended_variation_preset,
            "variationPresetEvidence": variation_preset_evidence,
            "suggestedRecipe": self._first_suggested_recipe(reference_pattern),
            "hookGuidance": self._hook_guidance(reference_pattern, {}),
            "captionGuidance": self._caption_guidance(reference_pattern, {}),
            "reasons": ["active reference pattern is available for the next generation batch"],
            "risks": ["missing_rendered_assets", "missing_performance_history", *trust_risks],
            "scoreBreakdown": {
                "performance": 50,
                "referencePattern": self._reference_pattern_score(reference_pattern),
                "auditReadiness": 0,
                "accountFitFatigue": 50,
                "novelty": 50,
                "operationalReadiness": 0,
                "recommendationTrust": recommendation_trust.get("score"),
            },
            "evidence": {
                "graph": {
                    "campaignGraphId": campaign_graph_id,
                    "runGraphId": run_graph_id,
                    "referencePatternGraphId": reference_pattern_graph_id,
                },
                "reasons": ["active reference pattern is available for the next generation batch"],
                "risks": ["missing_rendered_assets", "missing_performance_history", *trust_risks],
                "recommendationTrust": recommendation_trust,
                "referencePatternRankings": reference_pattern_evidence,
                "variationPresetRankings": variation_preset_evidence,
            },
            "dataQuality": {
                "sampleSize": 0,
                "level": "low",
                "reasons": ["missing_rendered_assets", "missing_performance_history"],
            },
            "accountMemory": None,
            "accountFitEvidence": {"level": "low", "reasons": ["missing_rendered_assets"]},
            "decision": {},
            "outcome": {},
            "baseline": {},
            "exceptions": [],
            "measurementVersion": None,
            "acceptedAt": None,
            "rejectedAt": None,
            "executedAt": None,
            "postedAt": None,
            "measuredAt": None,
            "graphEvidence": {
                "campaignGraphId": campaign_graph_id,
                "runGraphId": run_graph_id,
                "referencePatternGraphId": reference_pattern_graph_id,
            },
        }
        if persist:
            recommendation_graph_id = self.ensure_graph_node(
                "recommendation_item",
                local_table="recommendation_items",
                local_id=item_id,
                payload=output,
            )
            output["recommendationGraphId"] = recommendation_graph_id
            self.conn.execute(
                """
                INSERT INTO recommendation_items (
                  id, run_id, rank, target_account, reference_pattern_id,
                  recommendation_graph_id, status, score, confidence, reasons_json,
                  risks_json, evidence_json, data_quality_json, decision_json,
                  outcome_json, baseline_json, measurement_version, output_json, created_at
                )
                VALUES (?, ?, 1, ?, ?, ?, 'proposed', ?, ?, ?, ?, ?, ?, '{}', '{}', '{}', NULL, ?, ?)
                ON CONFLICT(run_id, rank) DO UPDATE SET
                  recommendation_graph_id = excluded.recommendation_graph_id,
                  score = excluded.score,
                  confidence = excluded.confidence,
                  evidence_json = excluded.evidence_json,
                  data_quality_json = excluded.data_quality_json,
                  output_json = excluded.output_json
                """,
                (
                    item_id,
                    run_id,
                    account,
                    reference_pattern.get("id"),
                    recommendation_graph_id,
                    output["score"],
                    output["confidence"],
                    json.dumps(output["reasons"], ensure_ascii=False, sort_keys=True),
                    json.dumps(output["risks"], ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(output["evidence"]), ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(output["dataQuality"]), ensure_ascii=False, sort_keys=True),
                    json.dumps(sanitize_for_storage(output), ensure_ascii=False, sort_keys=True),
                    utc_now(),
                ),
            )
            self._write_recommendation_graph_edges(
                performance_graph_id=None,
                recommendation_input_graph_id=None,
                run_graph_id=run_graph_id,
                item_graph_id=recommendation_graph_id,
                rendered_graph_id=None,
                reference_pattern_graph_id=reference_pattern_graph_id,
            )
        return output

    def _write_recommendation_graph_edges(
        self,
        *,
        performance_graph_id: str | None,
        recommendation_input_graph_id: str | None,
        run_graph_id: str | None,
        item_graph_id: str | None,
        rendered_graph_id: str | None,
        reference_pattern_graph_id: str | None,
    ) -> None:
        self.ensure_graph_edge(performance_graph_id, recommendation_input_graph_id, "performance_snapshot_to_recommendation_input")
        self.ensure_graph_edge(recommendation_input_graph_id, run_graph_id, "recommendation_input_to_recommendation_run")
        self.ensure_graph_edge(run_graph_id, item_graph_id, "recommendation_run_to_recommendation_item")
        self.ensure_graph_edge(reference_pattern_graph_id, item_graph_id, "reference_pattern_to_recommendation_item")
        self.ensure_graph_edge(rendered_graph_id, item_graph_id, "rendered_asset_to_recommendation_item")

    def _write_audio_recommendation_graph_edges(
        self,
        *,
        recommendation_item_id: str,
        recommendation_graph_id: str | None,
        reference_pattern_graph_id: str | None,
        audio_recommendations: dict[str, Any],
        campaign_id: str | None = None,
    ) -> None:
        for rec in audio_recommendations.get("recommendations") or []:
            if not isinstance(rec, dict):
                continue
            catalog_audio_id = rec.get("catalogAudioId") or rec.get("catalog_audio_id")
            if not catalog_audio_id:
                continue
            audio_graph_id = rec.get("audioMemoryGraphId") or self.graph_id_for(
                "audio_catalog",
                str(catalog_audio_id),
                entity_type="audio_memory",
                payload=rec,
            )
            audio_rec_id = f"audiorec_{hashlib.sha256(f'{recommendation_item_id}:{catalog_audio_id}'.encode('utf-8')).hexdigest()[:12]}"
            audio_rec_graph_id = self.ensure_graph_node(
                "audio_recommendation",
                local_table="audio_selections",
                local_id=f"recommendation:{audio_rec_id}",
                payload={"recommendationItemId": recommendation_item_id, "audio": rec},
            )
            self.ensure_graph_edge_strict(
                recommendation_graph_id,
                audio_rec_graph_id,
                "recommendation_item_to_audio_recommendation",
                evidence={"catalogAudioId": catalog_audio_id, "selectionRank": rec.get("selectionRank")},
                campaign_id=campaign_id,
                recommendation_item_id=recommendation_item_id,
                source_operation="audio_memory_recommendation",
            )
            self.ensure_graph_edge(
                audio_graph_id,
                audio_rec_graph_id,
                "audio_memory_to_audio_recommendation",
                evidence={"catalogAudioId": catalog_audio_id},
            )
            self.ensure_graph_edge(
                reference_pattern_graph_id,
                audio_graph_id,
                "reference_pattern_to_audio_memory",
                evidence={"source": "audio_memory_v1"},
            )

    def _stored_recommendation_item_payload(self, row: dict[str, Any]) -> dict[str, Any]:
        payload = json_load(row.get("output_json"), {})
        if isinstance(payload, dict):
            payload.setdefault("recommendationId", row["id"])
            payload.setdefault("recommendationGraphId", row.get("recommendation_graph_id"))
            payload["status"] = row.get("status") or payload.get("status") or "proposed"
            payload["executionStatus"] = row.get("execution_status") or payload.get("executionStatus") or "not_started"
            payload["evidence"] = json_load(row.get("evidence_json"), payload.get("evidence") or {})
            payload["dataQuality"] = json_load(row.get("data_quality_json"), payload.get("dataQuality") or {})
            payload["decision"] = json_load(row.get("decision_json"), payload.get("decision") or {})
            payload["outcome"] = json_load(row.get("outcome_json"), payload.get("outcome") or {})
            payload["baseline"] = json_load(row.get("baseline_json"), payload.get("baseline") or {})
            payload["measurementVersion"] = row.get("measurement_version") or payload.get("measurementVersion")
            payload["acceptedAt"] = row.get("accepted_at")
            payload["rejectedAt"] = row.get("rejected_at")
            payload["executedAt"] = row.get("executed_at")
            payload["postedAt"] = row.get("posted_at")
            payload["measuredAt"] = row.get("measured_at")
            payload["autonomyLevel"] = payload.get("autonomyLevel") or self.autonomy_level()
            payload["exceptions"] = self._exceptions_for_recommendation(row["id"])
            return payload
        return {
            "recommendationId": row["id"],
            "recommendationGraphId": row.get("recommendation_graph_id"),
            "status": row.get("status") or "proposed",
            "executionStatus": row.get("execution_status") or "not_started",
            "rank": row["rank"],
            "score": row["score"],
            "confidence": row["confidence"],
            "reasons": json_load(row.get("reasons_json"), []),
            "risks": json_load(row.get("risks_json"), []),
            "evidence": json_load(row.get("evidence_json"), {}),
            "dataQuality": json_load(row.get("data_quality_json"), {}),
            "decision": json_load(row.get("decision_json"), {}),
            "outcome": json_load(row.get("outcome_json"), {}),
            "baseline": json_load(row.get("baseline_json"), {}),
            "measurementVersion": row.get("measurement_version"),
            "autonomyLevel": self.autonomy_level(),
            "exceptions": self._exceptions_for_recommendation(row["id"]),
        }

    def _exceptions_for_recommendation(self, recommendation_item_id: str) -> list[dict[str, Any]]:
        rows = self.conn.execute(
            """
            SELECT * FROM trust_exceptions
            WHERE recommendation_item_id = ?
            ORDER BY CASE severity WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END, updated_at DESC
            """,
            (recommendation_item_id,),
        ).fetchall()
        return [self._exception_payload(dict(row)) for row in rows]

    def recommendation_item(self, recommendation_item_id: str) -> dict[str, Any]:
        row = self._recommendation_item_row(recommendation_item_id)
        return self._stored_recommendation_item_payload(row)

    def accept_recommendation_item(
        self,
        recommendation_item_id: str,
        *,
        operator: str | None = None,
        notes: str | None = None,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> dict[str, Any]:
        decision = {"action": "accepted", "operator": operator, "notes": notes, "decidedAt": utc_now()}
        return self._update_recommendation_lifecycle(
            recommendation_item_id,
            status="accepted",
            decision=decision,
            timestamp_column="accepted_at",
            event_type="recommendation_item_accepted",
            message="Recommendation accepted",
            admin_override=admin_override,
            override_reason=override_reason,
        )

    def reject_recommendation_item(
        self,
        recommendation_item_id: str,
        *,
        reason: str | None = None,
        operator: str | None = None,
        notes: str | None = None,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> dict[str, Any]:
        decision = {"action": "rejected", "reason": reason, "operator": operator, "notes": notes, "decidedAt": utc_now()}
        return self._update_recommendation_lifecycle(
            recommendation_item_id,
            status="rejected",
            decision=decision,
            timestamp_column="rejected_at",
            event_type="recommendation_item_rejected",
            message="Recommendation rejected",
            admin_override=admin_override,
            override_reason=override_reason,
        )

    def link_recommendation_item(
        self,
        recommendation_item_id: str,
        *,
        source_asset_id: str | None = None,
        render_job_id: str | None = None,
        rendered_asset_id: str | None = None,
        post_id: str | None = None,
        performance_snapshot_id: str | None = None,
        evidence: dict[str, Any] | None = None,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> dict[str, Any]:
        row = self._recommendation_item_row(recommendation_item_id)
        campaign = self._recommendation_item_campaign(row)
        item_graph_id = row.get("recommendation_graph_id") or self.graph_id_for("recommendation_items", recommendation_item_id, entity_type="recommendation_item")
        link_evidence = json_load(row.get("evidence_json"), {})
        links = link_evidence.setdefault("links", {})
        status = "executed"
        now = utc_now()
        updates: dict[str, Any] = {}
        if source_asset_id:
            source_graph_id = self.graph_id_for("source_assets", source_asset_id, entity_type="source_asset")
            self.ensure_graph_edge_strict(
                item_graph_id,
                source_graph_id,
                "recommendation_item_to_source_asset",
                evidence=evidence or {},
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                recommendation_item_id=recommendation_item_id,
                source_operation="link_recommendation_item",
            )
            links["sourceAssetId"] = source_asset_id
            links["sourceAssetGraphId"] = source_graph_id
            updates["source_asset_id"] = source_asset_id
        if render_job_id:
            render_graph_id = self.graph_id_for("render_jobs", render_job_id, entity_type="render_job")
            self.ensure_graph_edge_strict(
                item_graph_id,
                render_graph_id,
                "recommendation_item_to_render_job",
                evidence=evidence or {},
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                recommendation_item_id=recommendation_item_id,
                source_operation="link_recommendation_item",
            )
            links["renderJobId"] = render_job_id
            links["renderJobGraphId"] = render_graph_id
        if rendered_asset_id:
            rendered_graph_id = self.graph_id_for("rendered_assets", rendered_asset_id, entity_type="rendered_asset")
            self.ensure_graph_edge_strict(
                item_graph_id,
                rendered_graph_id,
                "recommendation_item_to_rendered_asset",
                evidence=evidence or {},
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                recommendation_item_id=recommendation_item_id,
                source_operation="link_recommendation_item",
            )
            links["renderedAssetId"] = rendered_asset_id
            links["renderedAssetGraphId"] = rendered_graph_id
            updates["rendered_asset_id"] = rendered_asset_id
        if post_id:
            post_graph_id = self.ensure_graph_node("threadsdash_post", external_system="threadsdash.posts", external_id=post_id, payload={"postId": post_id})
            self.ensure_graph_edge_strict(
                item_graph_id,
                post_graph_id,
                "recommendation_item_to_threadsdash_post",
                evidence=evidence or {},
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                recommendation_item_id=recommendation_item_id,
                source_operation="link_recommendation_item",
            )
            links["postId"] = post_id
            links["postGraphId"] = post_graph_id
            status = "posted"
        if performance_snapshot_id:
            perf = self.conn.execute("SELECT * FROM performance_snapshots WHERE id = ?", (performance_snapshot_id,)).fetchone()
            if not perf:
                raise ValueError(f"performance snapshot not found: {performance_snapshot_id}")
            perf_graph_id = self.ensure_graph_node("performance_snapshot", local_table="performance_snapshots", local_id=performance_snapshot_id, payload=self._performance_snapshot_payload(dict(perf)))
            self.ensure_graph_edge_strict(
                item_graph_id,
                perf_graph_id,
                "recommendation_item_to_performance_snapshot",
                evidence=evidence or {},
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                recommendation_item_id=recommendation_item_id,
                source_operation="link_recommendation_item",
            )
            links["performanceSnapshotId"] = performance_snapshot_id
            links["performanceSnapshotGraphId"] = perf_graph_id
            status = "posted"
        self._validate_recommendation_transition(
            row.get("status") or "proposed",
            status,
            admin_override=admin_override,
            override_reason=override_reason,
        )
        if evidence:
            link_evidence.setdefault("operatorEvidence", []).append({"at": now, **sanitize_for_storage(evidence)})
        if admin_override:
            link_evidence.setdefault("adminOverrides", []).append({"at": now, "reason": override_reason, "toStatus": status})
        set_parts = ["status = ?", "execution_status = ?", "evidence_json = ?", "output_json = ?", "executed_at = COALESCE(executed_at, ?)"]
        params: list[Any] = [status, "completed", json.dumps(sanitize_for_storage(link_evidence), ensure_ascii=False, sort_keys=True), "", now]
        if status == "posted":
            set_parts.append("posted_at = COALESCE(posted_at, ?)")
            params.append(now)
        for column, value in updates.items():
            set_parts.append(f"{column} = ?")
            params.append(value)
        payload = self._stored_recommendation_item_payload(dict(row))
        payload["status"] = status
        payload["evidence"] = link_evidence
        if source_asset_id:
            payload["sourceAssetGraphId"] = links.get("sourceAssetGraphId")
        if rendered_asset_id:
            payload["renderedAssetId"] = rendered_asset_id
            payload["renderedAssetGraphId"] = links.get("renderedAssetGraphId")
        payload["executedAt"] = payload.get("executedAt") or now
        if status == "posted":
            payload["postedAt"] = payload.get("postedAt") or now
        params[3] = json.dumps(sanitize_for_storage(payload), ensure_ascii=False, sort_keys=True)
        params.append(recommendation_item_id)
        self.conn.execute(f"UPDATE recommendation_items SET {', '.join(set_parts)} WHERE id = ?", params)
        self.record_event(
            "recommendation_item_linked",
            campaign_id=campaign["id"],
            rendered_asset_id=rendered_asset_id or row.get("rendered_asset_id"),
            status="success",
            message="Recommendation linked to lifecycle artifact",
            metadata={"recommendationItemId": recommendation_item_id, "status": status, "links": links},
            commit=False,
        )
        self.conn.commit()
        return self.recommendation_item(recommendation_item_id)

    def measure_recommendation_item(
        self,
        recommendation_item_id: str,
        *,
        performance_snapshot_id: str | None = None,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> dict[str, Any]:
        row = self._recommendation_item_row(recommendation_item_id)
        campaign = self._recommendation_item_campaign(row)
        if performance_snapshot_id:
            self.link_recommendation_item(recommendation_item_id, performance_snapshot_id=performance_snapshot_id)
            row = self._recommendation_item_row(recommendation_item_id)
        perf_rows = self._recommendation_performance_rows(row)
        if not perf_rows:
            raise ValueError("recommendation has no linked or matching performance snapshots")
        snapshots = [self._performance_snapshot_payload(dict(perf)) for perf in perf_rows]
        baseline_rows = self.conn.execute(
            """
            SELECT * FROM performance_snapshots
            WHERE campaign_id = ? AND (rendered_asset_id IS NULL OR rendered_asset_id != ?)
            ORDER BY snapshot_at DESC, created_at DESC
            """,
            (campaign["id"], row.get("rendered_asset_id") or ""),
        ).fetchall()
        baseline_snapshots = [self._performance_snapshot_payload(dict(perf)) for perf in baseline_rows]
        account_baselines = account_reward_baselines(snapshots + baseline_snapshots)
        outcome_summary = self._aggregate_performance(snapshots, account_baselines=account_baselines)
        outcome_score = self._performance_quality_score(outcome_summary)
        baseline_summary = self._aggregate_performance(baseline_snapshots, account_baselines=account_baselines)
        baseline_score = self._performance_quality_score(baseline_summary)
        status = "measured"
        baseline = self._recommendation_baseline_payload(
            baseline_summary,
            baseline_score=baseline_score,
            threshold=RECOMMENDATION_MEASUREMENT_THRESHOLD,
        )
        if outcome_score is not None and baseline_score is not None and int(baseline_summary.get("count") or 0) >= 3:
            if outcome_score >= baseline_score + RECOMMENDATION_MEASUREMENT_THRESHOLD:
                status = "proved"
            elif outcome_score <= baseline_score - RECOMMENDATION_MEASUREMENT_THRESHOLD:
                status = "disproved"
        outcome = {
            "status": status,
            "outcomeScore": outcome_score,
            "baselineScore": baseline_score,
            "snapshotCount": len(snapshots),
            "baselineSnapshotCount": len(baseline_snapshots),
            "snapshots": snapshots[:20],
            "measuredAt": utc_now(),
            "measurementVersion": RECOMMENDATION_MEASUREMENT_VERSION,
        }
        return self._update_recommendation_lifecycle(
            recommendation_item_id,
            status=status,
            outcome=outcome,
            baseline=baseline,
            measurement_version=RECOMMENDATION_MEASUREMENT_VERSION,
            timestamp_column="measured_at",
            event_type="recommendation_item_measured",
            message=f"Recommendation measured: {status}",
            admin_override=admin_override,
            override_reason=override_reason,
        )

    def execute_accepted_recommendation(
        self,
        recommendation_item_id: str,
        *,
        mode: str = DEFAULT_AUTONOMY_LEVEL,
        force: bool = False,
        dry_run_render: bool = False,
        run_audit: bool = True,
        contentforge_base_url: str | None = None,
    ) -> dict[str, Any]:
        if mode not in AUTONOMY_LEVELS:
            raise ValueError(f"mode must be one of {sorted(AUTONOMY_LEVELS)}")
        row = self._recommendation_item_row(recommendation_item_id)
        campaign = self._recommendation_item_campaign(row)
        active_level = self.autonomy_level()
        if active_level == "level_1" or mode == "level_1":
            exception = self.create_exception(
                reason_code="autonomy_level_blocks_execution",
                severity="medium",
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                entity_graph_id=row.get("recommendation_graph_id"),
                recommendation_item_id=recommendation_item_id,
                payload={"activeLevel": active_level, "requestedMode": mode},
            )
            raise ValueError(f"auto execute blocked by autonomy level: {exception['id']}")
        if row.get("status") not in {"accepted", "executed"}:
            exception = self.create_exception(
                reason_code="recommendation_not_accepted",
                severity="high",
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                entity_graph_id=row.get("recommendation_graph_id"),
                recommendation_item_id=recommendation_item_id,
                payload={"status": row.get("status")},
            )
            raise ValueError(f"recommendation must be accepted before execute: {exception['id']}")
        pipeline_job = self.create_pipeline_job(
            "execute_recommendation",
            campaign["id"],
            {
                "recommendationItemId": recommendation_item_id,
                "mode": mode,
                "activeAutonomyLevel": active_level,
                "force": force,
                "dryRunRender": dry_run_render,
                "runAudit": run_audit,
                "contentforgeBaseUrl": contentforge_base_url,
            },
        )
        self.start_pipeline_job(pipeline_job["id"])
        steps: list[dict[str, Any]] = []
        self.conn.execute(
            "UPDATE recommendation_items SET execution_status = ? WHERE id = ?",
            ("running", recommendation_item_id),
        )
        self.conn.commit()
        linked_rendered_id = row.get("rendered_asset_id")
        existing_links = json_load(row.get("evidence_json"), {}).get("links") or {}
        if not force and not linked_rendered_id:
            linked_rendered_id = existing_links.get("renderedAssetId")
        try:
            if not linked_rendered_id and row.get("reference_pattern_id"):
                prepared = self.prepare_reel_from_reference(
                    campaign_slug=campaign["slug"],
                    reference_pattern_id=row["reference_pattern_id"],
                    variant_count=1,
                    notes=f"auto execute recommendation {recommendation_item_id}",
                    force_new=force,
                )
                steps.append({"step": "prepare_from_reference", "status": "completed", "result": prepared})
                rendered = self.run_reel_factory(campaign_slug=campaign["slug"], dry_run=dry_run_render, max_outputs_per_clip=1)
                steps.append({"step": "run_reel", "status": "completed", "result": self._compact_execution_result(rendered)})
                synced = self.sync_reel_outputs(campaign_slug=campaign["slug"])
                steps.append({"step": "sync_reel", "status": "completed", "result": self._compact_execution_result(synced)})
                synced_assets = synced.get("synced") or []
                if synced_assets:
                    linked_rendered_id = synced_assets[0].get("id")
            if linked_rendered_id:
                self.link_recommendation_item(
                    recommendation_item_id,
                    rendered_asset_id=linked_rendered_id,
                    evidence={"source": "execute_accepted_recommendation", "pipelineJobId": pipeline_job["id"], "mode": mode},
                    admin_override=row.get("status") == "executed",
                    override_reason="refresh execution links" if row.get("status") == "executed" else None,
                )
            else:
                self.create_exception(
                    reason_code="execution_missing_rendered_asset",
                    severity="high",
                    campaign_id=campaign["id"],
                    account_id=row.get("target_account"),
                    entity_graph_id=row.get("recommendation_graph_id"),
                    recommendation_item_id=recommendation_item_id,
                    payload={"steps": steps},
                    commit=False,
                )
            if run_audit and linked_rendered_id:
                from .adapters.contentforge import audit_campaign

                audit_result = audit_campaign(self, campaign_slug=campaign["slug"], contentforge_base_url=contentforge_base_url)
                steps.append({"step": "audit", "status": "completed", "result": self._compact_execution_result(audit_result)})
            current = self._recommendation_item_row(recommendation_item_id)
            asset_payload = None
            if linked_rendered_id:
                asset_payload = self._dashboard_rendered_asset(self.rendered_asset(linked_rendered_id))
                self._create_trust_exceptions_for_recommendation(current, asset_payload, commit=False)
            exceptions = self._exceptions_for_recommendation(recommendation_item_id)
            blocking_exceptions = [
                item for item in exceptions
                if item.get("status") in {"open", "snoozed"} and item.get("severity") in {"medium", "high", "critical"}
            ]
            execution_status = "blocked" if blocking_exceptions or not linked_rendered_id else "completed"
            payload = self._stored_recommendation_item_payload(current)
            payload["executionStatus"] = execution_status
            payload["autonomyLevel"] = mode
            payload["execution"] = {
                "pipelineJobId": pipeline_job["id"],
                "steps": steps,
                "dryRunRender": dry_run_render,
                "runAudit": run_audit,
                "force": force,
            }
            self.conn.execute(
                "UPDATE recommendation_items SET execution_status = ?, output_json = ? WHERE id = ?",
                (execution_status, json.dumps(sanitize_for_storage(payload), ensure_ascii=False, sort_keys=True), recommendation_item_id),
            )
            self.record_event(
                "recommendation_item_executed",
                campaign_id=campaign["id"],
                rendered_asset_id=linked_rendered_id,
                pipeline_job_id=pipeline_job["id"],
                status="success",
                message="Accepted recommendation executed",
                metadata={
                    "recommendationItemId": recommendation_item_id,
                    "mode": mode,
                    "force": force,
                    "executionStatus": execution_status,
                    "steps": [step["step"] for step in steps],
                },
                commit=False,
            )
            self.conn.commit()
            self.finish_pipeline_job(
                pipeline_job["id"],
                {"steps": [step["step"] for step in steps], "renderedAssetId": linked_rendered_id, "executionStatus": execution_status},
            )
            return {
                "schema": "campaign_factory.recommendation_execution.v1",
                "recommendation": self.recommendation_item(recommendation_item_id),
                "pipelineJobId": pipeline_job["id"],
                "steps": steps,
                "exceptions": exceptions,
                "publishesAutomatically": False,
            }
        except Exception as exc:
            self.conn.execute(
                "UPDATE recommendation_items SET execution_status = ? WHERE id = ?",
                ("failed", recommendation_item_id),
            )
            self.create_exception(
                reason_code="auto_execute_failed",
                severity="high",
                campaign_id=campaign["id"],
                account_id=row.get("target_account"),
                entity_graph_id=row.get("recommendation_graph_id"),
                recommendation_item_id=recommendation_item_id,
                payload={"error": str(exc), "steps": steps},
                commit=False,
            )
            self.record_event(
                "recommendation_item_execution_failed",
                campaign_id=campaign["id"],
                rendered_asset_id=linked_rendered_id,
                pipeline_job_id=pipeline_job["id"],
                status="failure",
                message=f"Recommendation execution failed: {exc}",
                metadata={"recommendationItemId": recommendation_item_id, "error": str(exc)},
                commit=False,
            )
            self.conn.commit()
            self.fail_pipeline_job(pipeline_job["id"], str(exc), {"steps": steps})
            raise

    def _compact_execution_result(self, result: dict[str, Any]) -> dict[str, Any]:
        compact = {}
        for key in ("schema", "pipelineJobId", "campaign", "returncode", "elapsed_seconds"):
            if key in result:
                compact[key] = result[key]
        for key in ("prepared", "reusedExisting", "synced", "reports", "runs"):
            if isinstance(result.get(key), list):
                compact[f"{key}Count"] = len(result[key])
        return compact or sanitize_for_storage(result)

    def _create_trust_exceptions_for_recommendation(
        self,
        row: dict[str, Any],
        asset: dict[str, Any],
        *,
        commit: bool = True,
    ) -> list[dict[str, Any]]:
        campaign = self._recommendation_item_campaign(row)
        recommendation_item_id = row["id"]
        account_id = row.get("target_account") or self._asset_target_account(asset)
        entity_graph_id = row.get("recommendation_graph_id") or self.graph_id_for("recommendation_items", recommendation_item_id, entity_type="recommendation_item")
        created = []
        readiness = asset.get("export_readiness") or {}
        data_quality = json_load(row.get("data_quality_json"), {})
        account_fit = self._recommendation_account_fit_evidence(campaign["id"], asset, account_id)
        if not account_id:
            created.append(self.create_exception(
                reason_code="missing_account_assignment",
                severity="medium",
                campaign_id=campaign["id"],
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"renderedAssetId": asset.get("id")},
                commit=False,
            ))
        for reason in readiness.get("blockingReasons") or []:
            created.append(self.create_exception(
                reason_code=f"audit_blocked:{reason}",
                severity="high",
                campaign_id=campaign["id"],
                account_id=account_id,
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"renderedAssetId": asset.get("id"), "readiness": readiness},
                commit=False,
            ))
        if data_quality.get("level") in {"low", "medium"}:
            created.append(self.create_exception(
                reason_code=f"qc_confidence_{data_quality.get('level')}",
                severity="medium" if data_quality.get("level") == "medium" else "high",
                campaign_id=campaign["id"],
                account_id=account_id,
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"dataQuality": data_quality},
                commit=False,
            ))
        fatigue = ((account_fit.get("memory") or {}).get("fatigue") or {})
        if fatigue.get("level") in {"medium", "high"}:
            created.append(self.create_exception(
                reason_code=f"account_fatigue_{fatigue.get('level')}",
                severity="high" if fatigue.get("level") == "high" else "medium",
                campaign_id=campaign["id"],
                account_id=account_id,
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"fatigue": fatigue},
                commit=False,
            ))
        warnings = readiness.get("warnings") or []
        if any("reuse" in str(warning) or "duplicate" in str(warning) for warning in warnings):
            created.append(self.create_exception(
                reason_code="duplicate_or_reuse_risk",
                severity="medium",
                campaign_id=campaign["id"],
                account_id=account_id,
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"warnings": warnings},
                commit=False,
            ))
        audio = asset.get("audioRecommendations") if isinstance(asset.get("audioRecommendations"), dict) else {}
        if audio.get("recommendations") and not self._asset_has_final_audio_proof(asset):
            created.append(self.create_exception(
                reason_code="unresolved_native_audio",
                severity="high",
                campaign_id=campaign["id"],
                account_id=account_id,
                entity_graph_id=entity_graph_id,
                recommendation_item_id=recommendation_item_id,
                payload={"audioRecommendations": audio},
                commit=False,
            ))
        if commit:
            self.conn.commit()
        return created

    def _asset_has_final_audio_proof(self, asset: dict[str, Any]) -> bool:
        caption_generation = asset.get("captionGeneration") if isinstance(asset.get("captionGeneration"), dict) else {}
        intent = caption_generation.get("audioIntent") or caption_generation.get("audio_intent") or {}
        if not isinstance(intent, dict):
            return False
        status = str(intent.get("status") or "").strip().lower()
        return status in {"attached", "verified", "not_required", "skipped"}

    def _recommendation_item_row(self, recommendation_item_id: str) -> dict[str, Any]:
        row = self.conn.execute("SELECT * FROM recommendation_items WHERE id = ?", (recommendation_item_id,)).fetchone()
        if not row:
            raise ValueError(f"recommendation item not found: {recommendation_item_id}")
        return dict(row)

    def _recommendation_item_campaign(self, row: dict[str, Any]) -> dict[str, Any]:
        campaign = self.conn.execute(
            """
            SELECT c.*
            FROM recommendation_runs rr
            JOIN campaigns c ON c.id = rr.campaign_id
            WHERE rr.id = ?
            """,
            (row["run_id"],),
        ).fetchone()
        if not campaign:
            raise ValueError(f"campaign not found for recommendation item: {row['id']}")
        return dict(campaign)

    def _update_recommendation_lifecycle(
        self,
        recommendation_item_id: str,
        *,
        status: str,
        decision: dict[str, Any] | None = None,
        outcome: dict[str, Any] | None = None,
        baseline: dict[str, Any] | None = None,
        measurement_version: str | None = None,
        timestamp_column: str | None = None,
        event_type: str,
        message: str,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> dict[str, Any]:
        if status not in RECOMMENDATION_ITEM_STATUSES:
            raise ValueError(f"invalid recommendation status: {status}")
        row = self._recommendation_item_row(recommendation_item_id)
        current_status = row.get("status") or "proposed"
        self._validate_recommendation_transition(
            current_status,
            status,
            admin_override=admin_override,
            override_reason=override_reason,
        )
        payload = self._stored_recommendation_item_payload(row)
        now = utc_now()
        payload["status"] = status
        if decision is not None:
            payload["decision"] = sanitize_for_storage(decision)
        if outcome is not None:
            payload["outcome"] = sanitize_for_storage(outcome)
        if baseline is not None:
            payload["baseline"] = sanitize_for_storage(baseline)
        if measurement_version is not None:
            payload["measurementVersion"] = measurement_version
        if admin_override:
            decision_payload = dict(payload.get("decision") or {})
            decision_payload.setdefault("adminOverrides", []).append({
                "at": now,
                "fromStatus": current_status,
                "toStatus": status,
                "reason": override_reason,
            })
            payload["decision"] = decision_payload
            decision = decision_payload
        if timestamp_column:
            payload_key = {
                "accepted_at": "acceptedAt",
                "rejected_at": "rejectedAt",
                "executed_at": "executedAt",
                "posted_at": "postedAt",
                "measured_at": "measuredAt",
            }[timestamp_column]
            payload[payload_key] = row.get(timestamp_column) or now
        set_parts = ["status = ?", "output_json = ?"]
        params: list[Any] = [status, json.dumps(sanitize_for_storage(payload), ensure_ascii=False, sort_keys=True)]
        if decision is not None:
            set_parts.append("decision_json = ?")
            params.append(json.dumps(sanitize_for_storage(decision), ensure_ascii=False, sort_keys=True))
        if outcome is not None:
            set_parts.append("outcome_json = ?")
            params.append(json.dumps(sanitize_for_storage(outcome), ensure_ascii=False, sort_keys=True))
        if baseline is not None:
            set_parts.append("baseline_json = ?")
            params.append(json.dumps(sanitize_for_storage(baseline), ensure_ascii=False, sort_keys=True))
        if measurement_version is not None:
            set_parts.append("measurement_version = ?")
            params.append(measurement_version)
        if timestamp_column:
            set_parts.append(f"{timestamp_column} = COALESCE({timestamp_column}, ?)")
            params.append(now)
        params.append(recommendation_item_id)
        self.conn.execute(f"UPDATE recommendation_items SET {', '.join(set_parts)} WHERE id = ?", params)
        if row.get("recommendation_graph_id"):
            self.ensure_graph_node(
                "recommendation_item",
                local_table="recommendation_items",
                local_id=recommendation_item_id,
                payload=payload,
            )
        campaign = self._recommendation_item_campaign(row)
        self.record_event(
            event_type,
            campaign_id=campaign["id"],
            rendered_asset_id=row.get("rendered_asset_id"),
            status="success",
            message=message,
            metadata={"recommendationItemId": recommendation_item_id, "status": status},
            commit=False,
        )
        self.conn.commit()
        return self.recommendation_item(recommendation_item_id)

    def _validate_recommendation_transition(
        self,
        current_status: str,
        next_status: str,
        *,
        admin_override: bool = False,
        override_reason: str | None = None,
    ) -> None:
        current_status = current_status or "proposed"
        if current_status == next_status:
            return
        if admin_override:
            if not override_reason:
                raise ValueError("override_reason is required when admin_override is true")
            return
        allowed = RECOMMENDATION_STATUS_TRANSITIONS.get(current_status, set())
        if next_status not in allowed:
            raise ValueError(f"invalid recommendation status transition: {current_status} -> {next_status}")

    def _recommendation_baseline_payload(
        self,
        baseline_summary: dict[str, Any],
        *,
        baseline_score: int | None,
        threshold: int,
    ) -> dict[str, Any]:
        count = int(baseline_summary.get("count") or 0)
        avg = baseline_summary.get("averages") or {}
        snapshots = []
        latest = baseline_summary.get("latest")
        if latest:
            snapshots.append(latest)
        confidence = "usable" if count >= 3 and baseline_score is not None else "insufficient"
        return {
            "baselineType": "campaign_account_history",
            "sampleSize": count,
            "avgScore": baseline_score,
            "medianScore": None,
            "threshold": threshold,
            "confidence": confidence,
            "averages": avg,
            "rates": baseline_summary.get("rates") or {},
            "latestSnapshot": snapshots[0] if snapshots else None,
            "measurementVersion": RECOMMENDATION_MEASUREMENT_VERSION,
        }

    def _recommendation_performance_rows(self, row: dict[str, Any]) -> list[sqlite3.Row]:
        evidence = json_load(row.get("evidence_json"), {})
        links = evidence.get("links") if isinstance(evidence, dict) else {}
        snapshot_id = links.get("performanceSnapshotId") if isinstance(links, dict) else None
        if snapshot_id:
            rows = self.conn.execute("SELECT * FROM performance_snapshots WHERE id = ?", (snapshot_id,)).fetchall()
            if rows:
                return rows
        if row.get("rendered_asset_id"):
            return self.conn.execute(
                "SELECT * FROM performance_snapshots WHERE rendered_asset_id = ? ORDER BY snapshot_at DESC, created_at DESC",
                (row["rendered_asset_id"],),
            ).fetchall()
        return []

    def _best_asset_history_score(self, asset: dict[str, Any]) -> int | None:
        scores = [
            self._performance_quality_score(asset.get("sourcePerformance") or {}),
            self._performance_quality_score(asset.get("captionPerformance") or {}),
            self._performance_quality_score(asset.get("recipePerformance") or {}),
        ]
        available = [score for score in scores if score is not None]
        return max(available) if available else None

    def _reference_pattern_score(self, pattern: dict[str, Any] | None) -> int:
        if not pattern:
            return 45
        rank = pattern.get("rank")
        score = 70
        if isinstance(rank, int):
            score = max(50, 92 - min(rank, 50))
        if pattern.get("audioRecommendations"):
            score += 4
        if pattern.get("captionFormulas"):
            score += 4
        if pattern.get("promptTemplate"):
            score += 3
        return int(max(0, min(100, score)))

    def _recommendation_account_score(self, asset: dict[str, Any], account: str | None) -> int:
        evidence = self._recommendation_account_fit_evidence(asset["campaign_id"], asset, account)
        if evidence.get("score") is not None:
            return int(evidence["score"])
        assignments = self.assignments_for_asset(asset["id"])
        if account and any(account in {row.get("instagram_account_id"), row.get("account_id")} for row in assignments):
            return 72
        if assignments:
            return 62
        account_ids = asset.get("account_ids") or []
        if account and account in account_ids:
            return 65
        return 50

    def _recommendation_account_fit_evidence(
        self,
        campaign_id: str,
        asset: dict[str, Any],
        account: str | None,
    ) -> dict[str, Any]:
        target = account or self._asset_target_account(asset)
        if not target:
            return {"level": "low", "score": None, "reasons": ["missing_account_assignment"], "memory": None}
        memory = self._account_memory_for(campaign_id, target)
        if not memory:
            return {"level": "low", "score": None, "account": target, "reasons": ["account_memory_missing_or_not_rebuilt"], "memory": None}
        score = int(memory.get("performanceScore") or 50)
        fatigue = memory.get("fatigue") or {}
        fatigue_level = fatigue.get("level")
        reasons = [f"account memory confidence {memory.get('confidence')} with {memory.get('sampleSize')} samples"]
        if fatigue_level == "high":
            score -= 20
            reasons.append("high account fatigue pressure")
        elif fatigue_level == "medium":
            score -= 10
            reasons.append("medium account fatigue pressure")
        if memory.get("confidence") == "low":
            score = round((score + 50) / 2)
        return {
            "level": memory.get("confidence") or "low",
            "score": int(max(0, min(100, score))),
            "account": target,
            "reasons": reasons,
            "memory": memory,
        }

    def _account_memory_for(self, campaign_id: str, account_id: str | None) -> dict[str, Any] | None:
        if not account_id:
            return None
        row = self.conn.execute(
            "SELECT * FROM account_memory WHERE campaign_id = ? AND account_id = ?",
            (campaign_id, account_id),
        ).fetchone()
        return self._account_memory_payload(dict(row)) if row else None

    def _operational_recommendation_score(self, asset: dict[str, Any]) -> int:
        readiness = asset.get("export_readiness") or {}
        if readiness.get("state") == "ready":
            score = 100
        elif readiness.get("state") == "warning":
            score = 65
        else:
            score = 20
        audio = asset.get("audioRecommendations") if isinstance(asset.get("audioRecommendations"), dict) else {}
        if audio.get("recommendations") or audio.get("primaryStrategy"):
            score += 5
        return int(max(0, min(100, score)))

    def _recommendation_confidence(self, asset: dict[str, Any], pattern: dict[str, Any] | None) -> tuple[str, str]:
        summaries = [asset.get("sourcePerformance") or {}, asset.get("captionPerformance") or {}, asset.get("recipePerformance") or {}]
        sample_size = sum(int(summary.get("count") or 0) for summary in summaries)
        completeness = 0
        completeness += 1 if asset.get("latest_audit") else 0
        completeness += 1 if pattern else 0
        completeness += 1 if sample_size else 0
        rendered_asset_id = asset.get("id") or asset.get("renderedAssetId")
        completeness += 1 if asset.get("graphId") or self.graph_id_for("rendered_assets", rendered_asset_id, entity_type="rendered_asset") else 0
        if sample_size >= 10 and completeness >= 3:
            return "high", f"{sample_size} matched performance samples and complete graph/audit context"
        if sample_size >= 3 or completeness >= 3:
            return "medium", f"{sample_size} matched performance samples with partial context"
        return "low", "Limited performance history; score is mostly quality, readiness, and reference-pattern based"

    def _recommendation_data_quality(self, asset: dict[str, Any], pattern: dict[str, Any] | None) -> dict[str, Any]:
        summaries = [asset.get("sourcePerformance") or {}, asset.get("captionPerformance") or {}, asset.get("recipePerformance") or {}]
        sample_size = sum(int(summary.get("count") or 0) for summary in summaries)
        missing = []
        if not sample_size:
            missing.append("performance_history")
        if not asset.get("latest_audit"):
            missing.append("audit_report")
        if not pattern:
            missing.append("reference_pattern")
        rendered_asset_id = asset.get("id") or asset.get("renderedAssetId")
        if not asset.get("graphId") and not self.graph_id_for("rendered_assets", rendered_asset_id, entity_type="rendered_asset"):
            missing.append("rendered_asset_graph_id")
        if sample_size >= 10 and not missing:
            level = "high"
        elif sample_size >= 3 or len(missing) <= 1:
            level = "medium"
        else:
            level = "low"
        return {
            "level": level,
            "sampleSize": sample_size,
            "missing": missing,
            "hasAudit": bool(asset.get("latest_audit")),
            "hasReferencePattern": bool(pattern),
            "hasGraphEvidence": not bool("rendered_asset_graph_id" in missing),
        }

    def _recommendation_reasons(
        self,
        *,
        performance_score: int,
        reference_score: int,
        audit_score: int,
        account_score: int,
        novelty_score: int,
        operational_score: int,
        candidate: dict[str, Any],
        reference_pattern: dict[str, Any] | None,
    ) -> list[str]:
        reasons = list(candidate.get("reasons") or [])
        if performance_score >= 70:
            reasons.append("performance history is positive")
        if reference_score >= 80 and reference_pattern:
            reasons.append(f"reference pattern is strong: {reference_pattern.get('label')}")
        if audit_score >= 80:
            reasons.append("ContentForge/readiness quality is strong")
        if account_score > 55:
            reasons.append("account assignment or account fit is available")
        if novelty_score >= 80:
            reasons.append("low reuse/fatigue warning pressure")
        if operational_score >= 80:
            reasons.append("operational gates are ready or near-ready")
        return sorted(set(str(reason) for reason in reasons if reason))

    def _asset_target_account(self, asset: dict[str, Any]) -> str | None:
        assignments = self.assignments_for_asset(asset["id"])
        for row in assignments:
            if row.get("instagram_account_id") or row.get("account_id"):
                return row.get("instagram_account_id") or row.get("account_id")
        account_ids = asset.get("account_ids") or []
        return str(account_ids[0]) if account_ids else None

    def _recommendation_reference_summary(self, pattern: dict[str, Any] | None) -> dict[str, Any] | None:
        if not pattern:
            return None
        return {
            "id": pattern.get("id"),
            "clusterKey": pattern.get("clusterKey"),
            "rank": pattern.get("rank"),
            "label": pattern.get("label"),
            "visualFormat": pattern.get("visualFormat"),
            "hookType": pattern.get("hookType"),
            "captionArchetype": pattern.get("captionArchetype"),
        }

    def _first_suggested_recipe(self, pattern: dict[str, Any] | None) -> str | None:
        recipes = ((pattern or {}).get("raw") or {}).get("bank", {}).get("suggestedVariantRecipes") if pattern else []
        if isinstance(recipes, list) and recipes:
            return str(recipes[0])
        suggested = (pattern or {}).get("suggestedVariantRecipes") if pattern else []
        return str(suggested[0]) if isinstance(suggested, list) and suggested else None

    def _hook_guidance(self, pattern: dict[str, Any] | None, asset: dict[str, Any]) -> str:
        if pattern and pattern.get("hookType"):
            return f"Use a {pattern['hookType']} hook from {pattern.get('label') or pattern.get('clusterKey')}."
        caption = asset.get("caption")
        return f"Adapt the existing hook/caption: {caption[:120]}" if caption else "Use a proven short curiosity hook."

    def _caption_guidance(self, pattern: dict[str, Any] | None, asset: dict[str, Any]) -> str:
        formulas = (pattern or {}).get("captionFormulas") or []
        if formulas and isinstance(formulas[0], dict):
            formula = formulas[0].get("formula") or formulas[0].get("label")
            if formula:
                return str(formula)
        caption = asset.get("caption")
        return caption[:160] if caption else "Keep caption short, native, and matched to the visual pattern."

    def campaign_readiness(self, campaign_slug: str, *, user_id: str | None = None) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        dashboard = self.dashboard(campaign_slug)
        jobs = self.jobs_for_campaign(campaign_slug, limit=100)
        blocking = []
        warnings = []
        for source in dashboard["sources"]:
            has_render_job = self.conn.execute("SELECT 1 FROM render_jobs WHERE source_asset_id = ? LIMIT 1", (source["id"],)).fetchone()
            if not has_render_job:
                warnings.append(f"source_missing_render_job:{source['id']}")
        for asset in dashboard["rendered"]:
            if asset["review_state"] == "rejected":
                blocking.append(f"asset_rejected:{asset['id']}")
            if not asset.get("latest_audit"):
                warnings.append(f"missing_audit:{asset['id']}")
            readiness = asset.get("export_readiness") or {}
            for reason in readiness.get("blockingReasons") or []:
                blocking.append(f"{asset['id']}:{reason}")
        failed_jobs = [job for job in jobs if job["status"] == "failed"]
        for job in failed_jobs[:20]:
            warnings.append(f"failed_job:{job['id']}:{job['jobType']}")
        latest_perf = self.conn.execute("SELECT MAX(snapshot_at) AS snapshot_at FROM performance_snapshots WHERE campaign_id = ?", (campaign["id"],)).fetchone()
        if not latest_perf or not latest_perf["snapshot_at"]:
            warnings.append("performance_not_synced")
        return {
            "schema": "campaign_factory.campaign_readiness.v1",
            "campaign": campaign["slug"],
            "userId": user_id,
            "checkedAt": utc_now(),
            "ready": not blocking,
            "blockingReasons": sorted(set(blocking)),
            "warnings": sorted(set(warnings)),
            "health": dashboard["health"],
            "ranking": dashboard["ranking"][:20],
        }

    def lifecycle_report(
        self,
        campaign_slug: str,
        *,
        user_id: str | None = None,
        threadsdash_posts: list[dict[str, Any]] | None = None,
        include_threadsdash: str = "auto",
        state: str | None = None,
        blocking_reason: str | None = None,
        rendered_asset_id: str | None = None,
    ) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        dashboard = self.dashboard(campaign_slug)
        plans_by_asset: dict[str, list[dict[str, Any]]] = {}
        for plan in self.distribution_plans_for_campaign(campaign_slug):
            plans_by_asset.setdefault(plan["renderedAssetId"], []).append(plan)
        assignments_by_asset: dict[str, list[dict[str, Any]]] = {}
        for assignment in self.assignments_for_campaign(campaign_slug):
            assignments_by_asset.setdefault(assignment["rendered_asset_id"], []).append(assignment)
        snapshots_by_asset = self._lifecycle_snapshots_by_asset(campaign["id"])
        posts_by_plan, posts_by_asset, td_evidence = self._lifecycle_threadsdash_indexes(
            campaign_slug=campaign_slug,
            user_id=user_id,
            include_threadsdash=include_threadsdash,
            threadsdash_posts=threadsdash_posts,
        )
        rows: list[dict[str, Any]] = []
        for asset in dashboard["rendered"]:
            if rendered_asset_id and asset["id"] != rendered_asset_id:
                continue
            plans = plans_by_asset.get(asset["id"]) or [None]
            for plan in plans:
                row = self._lifecycle_row(
                    campaign=campaign,
                    asset=asset,
                    plan=plan,
                    assignments=assignments_by_asset.get(asset["id"]) or [],
                    snapshots=snapshots_by_asset.get(asset["id"]) or [],
                    threadsdash_posts=(
                        posts_by_plan.get(plan["id"], []) if plan else []
                    ) or posts_by_asset.get(asset["id"], []),
                )
                if state and row["currentState"] != state:
                    continue
                if blocking_reason and row["blockingReason"] != blocking_reason:
                    continue
                rows.append(row)
        state_counts: dict[str, int] = {}
        stuck: dict[str, list[dict[str, Any]]] = {}
        for row in rows:
            state_counts[row["currentState"]] = state_counts.get(row["currentState"], 0) + 1
            reason = row.get("blockingReason")
            if reason:
                stuck.setdefault(reason, []).append({
                    "renderedAssetId": row["renderedAssetId"],
                    "distributionPlanId": row.get("distributionPlanId"),
                    "threadsDashboardPostId": row.get("threadsDashboardPostId"),
                    "currentState": row["currentState"],
                    "nextOperatorAction": row["nextOperatorAction"],
                })
        return {
            "schema": "campaign_factory.lifecycle_report.v1",
            "campaign": campaign["slug"],
            "campaignId": campaign["id"],
            "userId": user_id,
            "generatedAt": utc_now(),
            "includeThreadsDashboard": include_threadsdash,
            "threadsdash": td_evidence,
            "summary": {
                "totalRows": len(rows),
                "stateCounts": dict(sorted(state_counts.items())),
                "stuckCounts": {key: len(value) for key, value in sorted(stuck.items())},
            },
            "stuck": {key: value for key, value in sorted(stuck.items())},
            "rows": rows,
        }

    def creator_os_lifecycle_dashboard(
        self,
        *,
        campaign: str,
        user_id: str | None = None,
        threadsdash_posts: list[dict[str, Any]] | None = None,
        include_threadsdash: str = "auto",
        generated_at: str | None = None,
    ) -> dict[str, Any]:
        report = self.lifecycle_report(
            campaign,
            user_id=user_id,
            threadsdash_posts=threadsdash_posts,
            include_threadsdash=include_threadsdash,
        )
        buckets = {
            "approved": 0,
            "publishable": 0,
            "exported": 0,
            "scheduled": 0,
            "published": 0,
            "metricsImported": 0,
            "quarantined": 0,
            "failed": 0,
        }
        rows = []
        for row in report.get("rows") or []:
            bucket = self._creator_os_lifecycle_bucket(row)
            buckets[bucket] += 1
            rows.append({
                "renderedAssetId": row.get("renderedAssetId"),
                "distributionPlanId": row.get("distributionPlanId"),
                "threadsDashboardPostId": row.get("threadsDashboardPostId"),
                "currentState": row.get("currentState"),
                "bucket": bucket,
                "blockingReason": row.get("blockingReason"),
                "nextOperatorAction": row.get("nextOperatorAction"),
                "lastStateChange": row.get("lastStateChange"),
                "wouldWrite": False,
            })
        return {
            "schema": "creator_os.lifecycle_dashboard.v1",
            "generatedAt": generated_at or utc_now(),
            "campaign": report.get("campaign"),
            "campaignId": report.get("campaignId"),
            "userId": user_id,
            "counts": buckets,
            "commandCenter": dict(buckets),
            "stuckCounts": (report.get("summary") or {}).get("stuckCounts") or {},
            "rows": rows,
            "wouldWrite": False,
            "inputs": {
                "lifecycleReportSchema": report.get("schema"),
                "includeThreadsDashboard": include_threadsdash,
                "threadsdashAvailable": (report.get("threadsdash") or {}).get("available"),
            },
        }

    def _creator_os_lifecycle_bucket(self, row: dict[str, Any]) -> str:
        state = str(row.get("currentState") or "").strip()
        reason = str(row.get("blockingReason") or "").strip()
        if state == "metrics_imported":
            return "metricsImported"
        if state == "published":
            return "published"
        if state in {"scheduled", "past_due_schedule"}:
            return "scheduled"
        if state in {"platform_draft_validated", "exported"}:
            return "exported"
        if state in {"publishable_candidate", "exportable", "ready_for_export"}:
            return "publishable"
        if state in {"creative_approved", "approved", "assigned", "distribution_planned", "rendered"}:
            return "approved"
        if state == "failed" and reason in {"quarantined_asset", "asset_quarantined", "operator_quarantine"}:
            return "quarantined"
        if state == "failed" and "quarantine" in reason:
            return "quarantined"
        if state == "failed":
            return "failed"
        return "approved"

    def _lifecycle_snapshots_by_asset(self, campaign_id: str) -> dict[str, list[dict[str, Any]]]:
        rows = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE campaign_id = ? ORDER BY snapshot_at DESC, created_at DESC",
            (campaign_id,),
        ).fetchall()
        grouped: dict[str, list[dict[str, Any]]] = {}
        for row in rows:
            payload = self._performance_snapshot_payload(dict(row))
            asset_id = payload.get("renderedAssetId")
            if asset_id:
                grouped.setdefault(asset_id, []).append(payload)
        return grouped

    def _lifecycle_threadsdash_indexes(
        self,
        *,
        campaign_slug: str,
        user_id: str | None,
        include_threadsdash: str,
        threadsdash_posts: list[dict[str, Any]] | None,
    ) -> tuple[dict[str, list[dict[str, Any]]], dict[str, list[dict[str, Any]]], dict[str, Any]]:
        mode = (include_threadsdash or "auto").strip().lower()
        if mode not in {"auto", "live", "off"}:
            raise ValueError("include_threadsdash must be one of: auto, live, off")
        posts = threadsdash_posts
        evidence = {
            "mode": mode,
            "available": posts is not None,
            "rowCount": len(posts or []),
            "source": "provided" if posts is not None else "not_requested",
        }
        if posts is None and mode != "off":
            supabase_url = os.environ.get("SUPABASE_URL")
            service_key = os.environ.get("SUPABASE_SERVICE_ROLE_KEY") or os.environ.get("SUPABASE_SERVICE_KEY") or os.environ.get("SUPABASE_SECRET_KEY")
            if supabase_url and service_key and user_id:
                try:
                    from .adapters.threadsdash import SupabaseRestClient

                    client = SupabaseRestClient(supabase_url.rstrip("/"), service_key)
                    posts = client.select("posts", {
                        "select": "id,status,scheduled_for,published_at,created_at,updated_at,platform,instagram_account_id,account_id,user_id,metadata",
                        "user_id": f"eq.{user_id}",
                        "order": "created_at.desc",
                        "limit": "1000",
                    })
                    evidence.update({"available": True, "rowCount": len(posts), "source": "supabase"})
                except Exception as exc:
                    if mode == "live":
                        raise
                    evidence.update({"available": False, "source": "supabase_error", "error": str(exc)})
                    posts = []
            else:
                evidence.update({"available": False, "source": "missing_credentials_or_user"})
                posts = []
        posts = posts or []
        by_plan: dict[str, list[dict[str, Any]]] = {}
        by_asset: dict[str, list[dict[str, Any]]] = {}
        for post in posts:
            metadata = post.get("metadata") if isinstance(post.get("metadata"), dict) else {}
            meta = metadata.get("campaign_factory") if isinstance(metadata, dict) else None
            if not isinstance(meta, dict) or meta.get("campaign_id") != campaign_slug:
                continue
            plan_id = meta.get("distribution_plan_id") or meta.get("distributionPlanId")
            asset_id = meta.get("rendered_asset_id") or meta.get("renderedAssetId")
            if plan_id:
                by_plan.setdefault(str(plan_id), []).append(post)
            if asset_id:
                by_asset.setdefault(str(asset_id), []).append(post)
        return by_plan, by_asset, evidence

    def _lifecycle_row(
        self,
        *,
        campaign: dict[str, Any],
        asset: dict[str, Any],
        plan: dict[str, Any] | None,
        assignments: list[dict[str, Any]],
        snapshots: list[dict[str, Any]],
        threadsdash_posts: list[dict[str, Any]],
    ) -> dict[str, Any]:
        latest_post = self._latest_lifecycle_post(threadsdash_posts)
        latest_snapshot = snapshots[0] if snapshots else None
        readiness = asset.get("export_readiness") or {}
        context = asset.get("captionOutcomeContext") or load_context_json(asset.get("caption_outcome_context_json")) or {}
        context_fingerprint = self._lifecycle_fingerprint(context) if context else None
        media_issue = self._lifecycle_media_validation_issue(asset=asset, post=latest_post)
        mismatch = self._lifecycle_mismatch(asset=asset, plan=plan, post=latest_post, snapshot=latest_snapshot, context_fingerprint=context_fingerprint)
        current_state, blocking_reason, next_action = self._derive_lifecycle_state(
            asset=asset,
            plan=plan,
            assignments=assignments,
            readiness=readiness,
            post=latest_post,
            snapshot=latest_snapshot,
            mismatch=mismatch,
            media_issue=media_issue,
        )
        last_state_change = self._lifecycle_last_state_change(asset=asset, plan=plan, post=latest_post, snapshot=latest_snapshot)
        return {
            "campaignId": campaign["id"],
            "campaign": campaign["slug"],
            "renderedAssetId": asset["id"],
            "distributionPlanId": plan.get("id") if plan else None,
            "threadsDashboardPostId": latest_post.get("id") if latest_post else (latest_snapshot or {}).get("postId"),
            "performanceSnapshotId": (latest_snapshot or {}).get("id"),
            "instagramAccountId": (plan or {}).get("instagramAccountId") or (latest_post or {}).get("instagram_account_id") or (latest_snapshot or {}).get("instagramAccountId"),
            "accountId": (plan or {}).get("accountId") or (latest_post or {}).get("account_id") or (latest_snapshot or {}).get("accountId"),
            "contentFingerprint": asset.get("content_hash") or asset.get("contentHash"),
            "captionHash": asset.get("caption_hash") or asset.get("captionHash"),
            "captionOutcomeContextFingerprint": context_fingerprint,
            "currentState": current_state,
            "blockingReason": blocking_reason,
            "nextOperatorAction": next_action,
            "lastStateChange": last_state_change,
            "evidence": {
                "reviewState": asset.get("review_state"),
                "exportReadiness": readiness,
                "assignmentCount": len(assignments),
                "threadsdashPost": self._compact_lifecycle_post(latest_post),
                "performanceSnapshot": self._compact_lifecycle_snapshot(latest_snapshot),
                "lineageMismatch": mismatch,
                "mediaValidation": media_issue,
                "pastDueScheduleResolved": self._lifecycle_past_due_resolved(latest_post),
            },
        }

    def _derive_lifecycle_state(
        self,
        *,
        asset: dict[str, Any],
        plan: dict[str, Any] | None,
        assignments: list[dict[str, Any]],
        readiness: dict[str, Any],
        post: dict[str, Any] | None,
        snapshot: dict[str, Any] | None,
        mismatch: dict[str, Any],
        media_issue: dict[str, Any] | None,
    ) -> tuple[str, str | None, str]:
        quarantine = self._active_quarantine_for_asset(asset["id"]) if asset.get("id") else None
        if quarantine:
            return "failed", str(quarantine.get("blocking_reason") or quarantine.get("reason") or "quarantined_asset"), "replace_draft_with_verified_captioned_asset"
        if media_issue:
            return "failed", str(media_issue.get("reason") or "invalid_export_payload"), "replace_draft_with_verified_captioned_asset"
        if mismatch:
            reason = next(iter(mismatch))
            return "failed", reason, "inspect_lineage_mismatch"
        if snapshot and self._lifecycle_snapshot_has_metrics(snapshot):
            return "metrics_imported", None, "run_performance_and_caption_reports"
        if post:
            status = str(post.get("status") or "").lower()
            if status == "published" or (snapshot and str(snapshot.get("status") or "").lower() == "published"):
                return "published", "awaiting_metrics", "sync_performance_after_metrics_available"
            if status == "scheduled":
                if self._lifecycle_is_past_due(post.get("scheduled_for")):
                    return "past_due_schedule", "past_due_schedule", "reschedule_or_manual_publish"
                return "scheduled", "awaiting_publish", "wait_for_publish_or_verify_scheduler"
            meta = self._lifecycle_post_meta(post)
            if (
                str(meta.get("platform_state") or "").lower() == "platform_draft_validated"
                or str(meta.get("asset_state") or "").lower() in {"publishable_candidate", "exportable"}
                and isinstance(meta.get("handoff_manifest"), dict)
            ):
                return "platform_draft_validated", None, "schedule_or_publish_from_threadsdashboard"
            return "exported", None, "schedule_or_publish_from_threadsdashboard"
        if snapshot and str(snapshot.get("status") or "").lower() == "published":
            return "published", "awaiting_metrics", "sync_performance_after_metrics_available"
        if snapshot and snapshot.get("postId"):
            return "exported", None, "verify_threadsdashboard_post_status"
        review_state = str(asset.get("review_state") or "").lower()
        if review_state in {"failed", "rejected"}:
            return "failed", f"review_state:{review_state}", "replace_or_re_review_asset"
        if plan:
            blocking = readiness.get("blockingReasons") or []
            if blocking:
                return "distribution_planned", self._lifecycle_blocking_reason(blocking), "clear_export_readiness_blockers"
            publishability = readiness.get("publishability") if isinstance(readiness.get("publishability"), dict) else {}
            if readiness.get("state") == "ready" and publishability.get("publishableCandidate"):
                return "exportable", None, "run_live_export_after_operator_approval"
            if publishability and not publishability.get("publishableCandidate"):
                return "creative_approved", publishability.get("blockingReason") or "publishability_blocked", "resolve_publishability_failures"
            return "distribution_planned", "export_readiness_blocked", "run_export_readiness"
        if assignments:
            return "assigned", "missing_distribution_plan", "create_distribution_plan"
        if review_state == "approved":
            return "creative_approved", "missing_distribution_plan", "assign_account_and_plan_distribution"
        if asset.get("id"):
            return "rendered", "needs_approval", "review_and_approve_or_reject"
        return "promoted", None, "inspect_asset_state"

    def _lifecycle_blocking_reason(self, blocking: list[Any]) -> str:
        reasons = [str(item) for item in blocking if item]
        if any("campaign_audio_unresolved" in reason for reason in reasons):
            return "campaign_audio_unresolved"
        if any("missing_audit" in reason for reason in reasons):
            return "missing_audit"
        return "export_readiness_blocked"

    def _lifecycle_media_validation_issue(self, *, asset: dict[str, Any], post: dict[str, Any] | None) -> dict[str, Any] | None:
        meta = self._lifecycle_post_meta(post) if post else {}
        if meta.get("invalid_export_payload"):
            return {
                "reason": str(meta.get("invalid_reason") or "invalid_export_payload"),
                "source": "threadsdash_metadata",
                "invalidatedAt": meta.get("invalidated_at"),
                "details": meta.get("invalid_details") if isinstance(meta.get("invalid_details"), dict) else {},
            }
        if not post:
            return None
        recipe = str(asset.get("recipe") or "").strip().lower()
        filename = str(asset.get("filename") or asset.get("filePath") or "").strip().lower()
        caption = str(asset.get("caption") or "").strip()
        if caption and ("passthrough" in recipe or "passthrough" in filename):
            return {
                "reason": "threadsdash_draft_media_invalid_missing_burned_captions",
                "source": "campaign_factory_asset_recipe",
                "details": {
                    "recipe": asset.get("recipe"),
                    "filename": asset.get("filename") or asset.get("filePath"),
                    "captionPresent": True,
                    "note": "Caption metadata exists but selected media is a pass-through variant, which is not safe for caption-burned reel proof.",
                },
            }
        return None

    def _latest_lifecycle_post(self, posts: list[dict[str, Any]]) -> dict[str, Any] | None:
        if not posts:
            return None
        return sorted(
            posts,
            key=lambda row: str(row.get("updated_at") or row.get("created_at") or row.get("scheduled_for") or ""),
            reverse=True,
        )[0]

    def _lifecycle_snapshot_has_metrics(self, snapshot: dict[str, Any]) -> bool:
        metrics = snapshot.get("metrics") if isinstance(snapshot.get("metrics"), dict) else {}
        return any(metrics.get(key) is not None for key in ("views", "likes", "comments", "shares", "saves", "impressions", "reach", "watchTimeSeconds"))

    def _lifecycle_is_past_due(self, scheduled_for: Any) -> bool:
        if not isinstance(scheduled_for, str) or not scheduled_for.strip():
            return False
        parsed = self._parse_lifecycle_time(scheduled_for)
        return bool(parsed and parsed < datetime.now(timezone.utc))

    def _lifecycle_past_due_resolved(self, post: dict[str, Any] | None) -> bool:
        if not post:
            return False
        metadata = post.get("metadata") if isinstance(post.get("metadata"), dict) else {}
        meta = metadata.get("campaign_factory") if isinstance(metadata, dict) else {}
        return bool(isinstance(meta, dict) and meta.get("past_due_schedule") and str(post.get("status") or "").lower() != "scheduled")

    def _lifecycle_last_state_change(
        self,
        *,
        asset: dict[str, Any],
        plan: dict[str, Any] | None,
        post: dict[str, Any] | None,
        snapshot: dict[str, Any] | None,
    ) -> str | None:
        candidates = [
            (snapshot or {}).get("snapshotAt"),
            (snapshot or {}).get("publishedAt"),
            (post or {}).get("updated_at"),
            (post or {}).get("published_at"),
            (post or {}).get("scheduled_for"),
            (plan or {}).get("updatedAt"),
            (plan or {}).get("createdAt"),
            asset.get("updated_at") or asset.get("updatedAt"),
            asset.get("created_at") or asset.get("createdAt"),
        ]
        parsed = [(self._parse_lifecycle_time(value), value) for value in candidates if value]
        parsed = [(dt, value) for dt, value in parsed if dt]
        if not parsed:
            return None
        return str(max(parsed, key=lambda item: item[0])[1])

    def _parse_lifecycle_time(self, value: Any) -> datetime | None:
        if not isinstance(value, str) or not value.strip():
            return None
        try:
            normalized = value.replace("Z", "+00:00")
            parsed = datetime.fromisoformat(normalized)
        except ValueError:
            return None
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)

    def _lifecycle_mismatch(
        self,
        *,
        asset: dict[str, Any],
        plan: dict[str, Any] | None,
        post: dict[str, Any] | None,
        snapshot: dict[str, Any] | None,
        context_fingerprint: str | None,
    ) -> dict[str, Any]:
        mismatches: dict[str, Any] = {}
        expected_asset_id = asset.get("id")
        expected_content_hash = asset.get("content_hash") or asset.get("contentHash")
        expected_caption_hash = asset.get("caption_hash") or asset.get("captionHash")
        for label, payload in (("threadsdash", post), ("performance", snapshot)):
            if not payload:
                continue
            meta = self._lifecycle_post_meta(payload) if label == "threadsdash" else {}
            asset_id = meta.get("rendered_asset_id") or meta.get("renderedAssetId") or payload.get("renderedAssetId")
            content_hash = meta.get("content_hash") or meta.get("contentHash") or payload.get("contentHash")
            caption_hash = meta.get("caption_hash") or meta.get("captionHash") or payload.get("captionHash")
            if asset_id and expected_asset_id and asset_id != expected_asset_id:
                mismatches["rendered_asset_id_mismatch"] = {"stage": label, "expected": expected_asset_id, "actual": asset_id}
            if content_hash and expected_content_hash and content_hash != expected_content_hash:
                mismatches["content_fingerprint_mismatch"] = {"stage": label, "expected": expected_content_hash, "actual": content_hash}
            if caption_hash and expected_caption_hash and caption_hash != expected_caption_hash:
                mismatches["caption_hash_mismatch"] = {"stage": label, "expected": expected_caption_hash, "actual": caption_hash}
            context = meta.get("captionOutcomeContext") if label == "threadsdash" else payload.get("captionOutcomeContext")
            if context_fingerprint and isinstance(context, dict) and context:
                actual_fingerprint = self._lifecycle_fingerprint(context)
                if actual_fingerprint != context_fingerprint:
                    mismatches["caption_outcome_context_fingerprint_mismatch"] = {"stage": label, "expected": context_fingerprint, "actual": actual_fingerprint}
        if plan:
            plan_caption_hash = (plan.get("captionOutcomeContext") or {}).get("caption_hash")
            if plan_caption_hash and expected_caption_hash and plan_caption_hash != expected_caption_hash:
                mismatches["caption_hash_mismatch"] = {"stage": "distribution_plan", "expected": expected_caption_hash, "actual": plan_caption_hash}
        return mismatches

    def _lifecycle_post_meta(self, post: dict[str, Any]) -> dict[str, Any]:
        metadata = post.get("metadata") if isinstance(post.get("metadata"), dict) else {}
        meta = metadata.get("campaign_factory") if isinstance(metadata, dict) else {}
        return meta if isinstance(meta, dict) else {}

    def _lifecycle_fingerprint(self, value: Any) -> str:
        payload = self._canonical_lifecycle_context(value)
        return hashlib.sha256(json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()

    def _canonical_lifecycle_context(self, value: Any) -> Any:
        if isinstance(value, dict):
            normalized: dict[str, Any] = {}
            for key, item in value.items():
                if key == "render_recipe":
                    continue
                canonical = self._canonical_lifecycle_context(item)
                if canonical is None:
                    continue
                normalized[key] = canonical
            return normalized
        if isinstance(value, list):
            return [self._canonical_lifecycle_context(item) for item in value]
        return value

    def _compact_lifecycle_post(self, post: dict[str, Any] | None) -> dict[str, Any] | None:
        if not post:
            return None
        return {
            "id": post.get("id"),
            "status": post.get("status"),
            "scheduledFor": post.get("scheduled_for"),
            "publishedAt": post.get("published_at") or post.get("publishedAt"),
            "createdAt": post.get("created_at"),
            "updatedAt": post.get("updated_at"),
            "instagramAccountId": post.get("instagram_account_id"),
        }

    def _compact_lifecycle_snapshot(self, snapshot: dict[str, Any] | None) -> dict[str, Any] | None:
        if not snapshot:
            return None
        return {
            "id": snapshot.get("id"),
            "postId": snapshot.get("postId"),
            "status": snapshot.get("status"),
            "publishedAt": snapshot.get("publishedAt"),
            "snapshotAt": snapshot.get("snapshotAt"),
            "metrics": snapshot.get("metrics") or {},
        }

    def account_plan(self, campaign_slug: str, *, user_id: str, usage: dict[str, Any] | None = None) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        payload_rows = []
        assignments = self.assignments_for_campaign(campaign_slug)
        assignment_by_asset: dict[str, list[dict[str, Any]]] = {}
        for assignment in assignments:
            assignment_by_asset.setdefault(assignment["rendered_asset_id"], []).append(assignment)
        distribution_by_asset: dict[str, list[dict[str, Any]]] = {}
        for plan in self.distribution_plans_for_campaign(campaign_slug):
            distribution_by_asset.setdefault(plan["renderedAssetId"], []).append(plan)
        usage_by_asset = {item["renderedAssetId"]: item for item in (usage or {}).get("assets", [])}
        for asset in self.dashboard(campaign_slug)["rendered"]:
            distribution_plans = distribution_by_asset.get(asset["id"]) or []
            if distribution_plans:
                destinations = [
                    {
                        "account_id": plan.get("accountId"),
                        "instagram_account_id": plan.get("instagramAccountId"),
                        "planned_window_start": plan.get("plannedWindowStart"),
                        "planned_window_end": plan.get("plannedWindowEnd"),
                        "notes": plan.get("reasonCode"),
                        "surface": plan.get("surface"),
                        "distribution_plan_id": plan.get("id"),
                        "smart_link": plan.get("smartLink"),
                        "cta_text": plan.get("ctaText"),
                    }
                    for plan in distribution_plans
                ]
            else:
                destinations = assignment_by_asset.get(asset["id"]) or []
            if not destinations:
                destinations = [{"account_id": None, "instagram_account_id": None, "planned_window_start": None, "planned_window_end": None, "notes": None}]
            for destination in destinations:
                warnings = []
                asset_usage = usage_by_asset.get(asset["id"], {}).get("usage") or {}
                compatible, mismatch_reason, profile = self.account_compatible_with_model(
                    asset.get("model_slug") or asset.get("modelId") or "",
                    instagram_account_id=destination.get("instagram_account_id"),
                )
                if not compatible and mismatch_reason:
                    warnings.append(mismatch_reason)
                if asset_usage.get("published", 0) > 0:
                    warnings.append("exact_render_published")
                if asset_usage.get("draft", 0) > 0 or asset_usage.get("scheduled", 0) > 0:
                    warnings.append("exact_render_already_queued")
                if (asset.get("export_readiness") or {}).get("state") == "warning":
                    warnings.append("asset_has_export_warnings")
                if asset.get("performanceScore") is not None and asset["performanceScore"] < 45:
                    warnings.append("weak_recent_performance")
                payload_rows.append({
                    "renderedAssetId": asset["id"],
                    "filename": asset["filename"],
                    "accountId": destination.get("account_id"),
                    "instagramAccountId": destination.get("instagram_account_id"),
                    "modelSlug": asset.get("model_slug") or asset.get("modelId"),
                    "accountProfile": profile,
                    "distributionPlanId": destination.get("distribution_plan_id"),
                    "distributionSurface": destination.get("surface") or "regular_reel",
                    "plannedWindowStart": destination.get("planned_window_start"),
                    "plannedWindowEnd": destination.get("planned_window_end"),
                    "smartLink": destination.get("smart_link"),
                    "ctaText": destination.get("cta_text"),
                    "reviewState": asset["review_state"],
                    "exportState": (asset.get("export_readiness") or {}).get("state"),
                    "rankingScore": (self.ranking(campaign_slug)["byAsset"].get(asset["id"]) or {}).get("score"),
                    "warnings": sorted(set(warnings)),
                })
        by_account: dict[str, int] = {}
        for row in payload_rows:
            account = row["instagramAccountId"] or row["accountId"] or "unassigned"
            by_account[account] = by_account.get(account, 0) + 1
        for row in payload_rows:
            account = row["instagramAccountId"] or row["accountId"] or "unassigned"
            if by_account[account] > 2:
                row["warnings"].append("account_batch_volume_review")
        return {
            "schema": "campaign_factory.account_plan.v1",
            "campaign": campaign["slug"],
            "userId": user_id,
            "generatedAt": utc_now(),
            "assignments": assignments,
            "rows": payload_rows,
            "threadsdashAccountUsage": (usage or {}).get("accountUsage") or {},
            "threadsdashSurfaceUsage": (usage or {}).get("surfaceUsage") or {},
            "warnings": sorted(set(w for row in payload_rows for w in row["warnings"])),
        }

    def ranking(self, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        rows = []
        for asset in [self._dashboard_rendered_asset(asset) for asset in self.rendered_for_campaign(campaign["id"])]:
            readiness = asset.get("export_readiness") or {}
            blocked = bool(readiness.get("blockingReasons"))
            quality_score = self._quality_score_for_ranking(asset)
            source_score = self._history_score(asset.get("sourcePerformance"))
            caption_score = self._history_score(asset.get("captionPerformance"))
            recipe_score = self._history_score(asset.get("recipePerformance"))
            account_score = self._account_fit_score(asset)
            novelty_score = self._novelty_score(asset)
            score = round(
                quality_score * 0.30
                + source_score * 0.20
                + caption_score * 0.15
                + recipe_score * 0.15
                + account_score * 0.10
                + novelty_score * 0.10
            )
            if blocked:
                score = min(score, 35)
            reasons = []
            if blocked:
                reasons.append("blocked assets stay low regardless of performance")
            if source_score > 55:
                reasons.append("source family has positive history")
            if caption_score > 55:
                reasons.append("caption hash has positive history")
            if recipe_score > 55:
                reasons.append("recipe has positive history")
            if quality_score >= 85:
                reasons.append("strong audit/readiness quality")
            if novelty_score < 50:
                reasons.append("reuse/novelty warnings reduce score")
            rows.append({
                "renderedAssetId": asset["id"],
                "filename": asset["filename"],
                "reviewState": asset["review_state"],
                "exportState": readiness.get("state"),
                "score": int(max(0, min(100, score))),
                "breakdown": {
                    "quality": quality_score,
                    "sourceHistory": source_score,
                    "captionHistory": caption_score,
                    "recipeHistory": recipe_score,
                    "accountFit": account_score,
                    "novelty": novelty_score,
                },
                "reasons": reasons or ["neutral history; score is mostly quality/readiness based"],
                "blockingReasons": readiness.get("blockingReasons") or [],
                "warnings": readiness.get("warnings") or [],
            })
        rows = sorted(rows, key=lambda row: row["score"], reverse=True)
        return {
            "schema": "campaign_factory.ranking.v1",
            "campaign": campaign["slug"],
            "generatedAt": utc_now(),
            "assets": rows,
            "byAsset": {row["renderedAssetId"]: row for row in rows},
        }

    def _quality_score_for_ranking(self, asset: dict[str, Any]) -> int:
        readiness = asset.get("export_readiness") or {}
        audit = asset.get("latest_audit") or {}
        score = int(readiness.get("operatorScore") or 50)
        if audit.get("readabilityScore") is not None:
            score = round((score + int(audit["readabilityScore"])) / 2)
        if audit.get("safeZoneScore") is not None:
            score = round((score + int(audit["safeZoneScore"])) / 2)
        return max(0, min(100, score))

    def _history_score(self, summary: dict[str, Any] | None) -> int:
        if not summary or not summary.get("count"):
            return 50
        score = self._performance_quality_score(summary)
        if score is None:
            return 45
        return int(max(35, min(100, score)))

    def _account_fit_score(self, asset: dict[str, Any]) -> int:
        assignments = self.assignments_for_asset(asset["id"])
        return 58 if assignments else 50

    def _novelty_score(self, asset: dict[str, Any]) -> int:
        warnings = (asset.get("export_readiness") or {}).get("warnings") or []
        penalty = sum(10 for warning in warnings if "reuse" in warning or "queued" in warning)
        return max(0, 100 - penalty)

    def _dashboard_rendered_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        source = self.conn.execute(
            """
            SELECT s.id, s.content_hash, s.filename, s.account_ids_json, m.slug AS model_slug
                 , s.source_prompt
            FROM source_assets s
            JOIN models m ON m.id = s.model_id
            WHERE s.id = ?
            """,
            (asset["source_asset_id"],),
        ).fetchone()
        latest_audit = self.conn.execute(
            "SELECT * FROM audit_reports WHERE rendered_asset_id = ? ORDER BY created_at DESC LIMIT 1",
            (asset["id"],),
        ).fetchone()
        enriched = dict(asset)
        source_dict = dict(source) if source else None
        enriched["source"] = source_dict
        enriched["captionGeneration"] = json_load(asset.get("caption_generation_json"), {})
        caption_context = load_context_json(asset.get("caption_outcome_context_json"))
        enriched["captionOutcomeContext"] = caption_context
        enriched["captionHash"] = asset.get("caption_hash") or caption_context.get("caption_hash")
        enriched["referencePattern"] = self.active_reference_pattern_for_campaign(asset["campaign_id"])
        enriched["audioRecommendations"] = self._audio_recommendations_for_asset(
            caption_generation=enriched.get("captionGeneration") or {},
            reference_pattern=enriched.get("referencePattern") or {},
            recipe=asset.get("recipe"),
            account_tags=json_load(source_dict["account_ids_json"], []) if source_dict else [],
        )
        if source_dict:
            enriched["account_ids"] = json_load(source_dict["account_ids_json"], [])
            enriched["model_slug"] = source_dict["model_slug"]
            enriched["sourcePrompt"] = json_load(source_dict["source_prompt"], {}) if source_dict.get("source_prompt") else {}
            enriched["generatedAssetLineage"] = self._generated_asset_lineage(enriched["sourcePrompt"], enriched.get("referencePattern") or {})
        audit_payload = self._audit_report_payload(dict(latest_audit)) if latest_audit else None
        enriched["latest_audit"] = audit_payload
        performance = self._performance_for_asset(asset)
        enriched["latestPerformance"] = performance["latestPerformance"]
        enriched["sourcePerformance"] = performance["sourcePerformance"]
        enriched["captionPerformance"] = performance["captionPerformance"]
        enriched["recipePerformance"] = performance["recipePerformance"]
        enriched["performanceScore"] = performance["performanceScore"]
        enriched["export_readiness"] = self._local_export_readiness(asset, audit_payload)
        if enriched["performanceScore"] is not None:
            base_score = enriched["export_readiness"].get("operatorScore", 0)
            adjustment = int(round((enriched["performanceScore"] - 50) * 0.3))
            enriched["export_readiness"]["operatorScore"] = max(0, min(100, base_score + adjustment))
        return enriched

    def _generated_asset_lineage(self, source_prompt: dict[str, Any], reference_pattern: dict[str, Any] | None) -> dict[str, Any]:
        reference_pattern = reference_pattern if isinstance(reference_pattern, dict) else {}
        existing = source_prompt.get("generatedAssetLineage") if isinstance(source_prompt.get("generatedAssetLineage"), dict) else {}
        if existing.get("schema") == "campaign_factory.generated_asset_lineage.v1":
            lineage = dict(existing)
        else:
            lineage = {
                "schema": "campaign_factory.generated_asset_lineage.v1",
                "source": {},
                "generation": {},
                "review": {"humanReviewRequired": True, "status": "draft"},
                "quality": {},
            }
        source = lineage.setdefault("source", {})
        if isinstance(source, dict):
            source.setdefault("formatType", source_prompt.get("formatType") or reference_pattern.get("visualFormat"))
            source.setdefault("referencePattern", source_prompt.get("referencePattern") or reference_pattern.get("clusterKey") or reference_pattern.get("id"))
            source.setdefault("patternCardId", source_prompt.get("patternCardId") or reference_pattern.get("patternCardId"))
            source.setdefault("promptId", source_prompt.get("promptId"))
        generation = lineage.setdefault("generation", {})
        if isinstance(generation, dict):
            generation.setdefault("tool", source_prompt.get("generationTool") or "manual_finished_video")
            generation.setdefault("modelProfile", source_prompt.get("modelProfile"))
        review = lineage.setdefault("review", {})
        if isinstance(review, dict):
            review.setdefault("humanReviewRequired", True)
            review.setdefault("status", "draft")
        if not lineage.get("pipelineTraceId"):
            source_prompt_id = source_prompt.get("promptId")
            if not source_prompt_id and isinstance(source, dict):
                source_prompt_id = source.get("promptId")
            generation_tool = source_prompt.get("generationTool")
            if not generation_tool and isinstance(generation, dict):
                generation_tool = generation.get("tool")
            asset_path = generation.get("assetPath") if isinstance(generation, dict) else None
            trace_seed = {
                "promptId": source_prompt_id,
                "referencePattern": source_prompt.get("referencePattern") or reference_pattern.get("clusterKey") or reference_pattern.get("id"),
                "generationTool": generation_tool,
                "assetPath": asset_path,
            }
            lineage["pipelineTraceId"] = f"trace_generated_asset_{hashlib.sha256(json.dumps(trace_seed, sort_keys=True).encode('utf-8')).hexdigest()[:16]}"
        return lineage

    def _audio_recommendations_for_asset(
        self,
        *,
        caption_generation: dict[str, Any],
        reference_pattern: dict[str, Any] | None,
        recipe: str | None,
        account_tags: list[str],
    ) -> dict[str, Any]:
        existing = (
            (caption_generation or {}).get("audioRecommendations")
            or (reference_pattern or {}).get("audioRecommendations")
            or {}
        )
        content_tags = [
            (reference_pattern or {}).get("visualFormat"),
            (reference_pattern or {}).get("hookType"),
            (reference_pattern or {}).get("captionArchetype"),
            recipe,
        ]
        catalog = self.recommend_audio(
            platform="instagram",
            content_tags=[str(tag) for tag in content_tags if tag],
            account_tags=[str(tag) for tag in account_tags if tag],
            limit=5,
        )
        catalog_recs = catalog.get("recommendations") or []
        if not catalog_recs:
            return existing
        existing_recs = existing.get("recommendations") if isinstance(existing, dict) else []
        merged = {
            "schema": "campaign_factory.audio_recommendations.v1",
            "primaryStrategy": (existing or {}).get("primaryStrategy") if isinstance(existing, dict) else "native_audio_catalog_match",
            "fallbackInstruction": (existing or {}).get("fallbackInstruction") if isinstance(existing, dict) else "Attach selected native platform audio before publishing.",
            "nativeAudioPreferred": True,
            "recommendations": catalog_recs + (existing_recs if isinstance(existing_recs, list) else []),
            "decision": catalog.get("decision") or {},
            "catalogMatched": True,
        }
        return merged

    def performance_summary(self, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        rows = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE campaign_id = ? AND metrics_eligible = 1 ORDER BY snapshot_at DESC, created_at DESC",
            (campaign["id"],),
        ).fetchall()
        snapshots = [self._performance_snapshot_payload(dict(row)) for row in rows]
        account_baselines = account_reward_baselines(snapshots)
        return {
            "schema": "campaign_factory.performance_summary.v1",
            "campaign": campaign["slug"],
            "snapshotCount": len(snapshots),
            "generatedAt": utc_now(),
            "renderedAssets": self._group_performance(snapshots, "renderedAssetId", account_baselines=account_baselines),
            "sourceAssets": self._group_performance(snapshots, "sourceAssetId", account_baselines=account_baselines),
            "captionHashes": self._group_performance(snapshots, "captionHash", account_baselines=account_baselines),
            "recipes": self._group_performance(snapshots, "recipe", account_baselines=account_baselines),
            "accounts": self._group_performance(snapshots, "instagramAccountId", account_baselines=account_baselines),
            "surfaces": self._group_performance(snapshots, "contentSurface", account_baselines=account_baselines),
            "leaderboards": self._performance_leaderboards(snapshots, account_baselines=account_baselines),
            "captionOutcomeReview": self._caption_outcome_manual_review(snapshots),
            "snapshots": snapshots[:100],
        }

    def caption_outcome_report(self, campaign_slug: str) -> dict[str, Any]:
        campaign = self.campaign_by_slug(campaign_slug)
        summary = self.performance_summary(campaign_slug)
        report = dict(summary["captionOutcomeReview"])
        report["campaign"] = campaign["slug"]
        report["generatedAt"] = summary["generatedAt"]
        return report

    def _performance_for_asset(self, asset: dict[str, Any]) -> dict[str, Any]:
        caption_hash = hashlib.sha256(" ".join((asset.get("caption") or "").strip().lower().split()).encode("utf-8")).hexdigest()
        latest = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE rendered_asset_id = ? ORDER BY snapshot_at DESC, created_at DESC LIMIT 1",
            (asset["id"],),
        ).fetchone()
        source_rows = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE source_asset_id = ? ORDER BY snapshot_at DESC, created_at DESC",
            (asset["source_asset_id"],),
        ).fetchall()
        caption_rows = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE caption_hash = ? ORDER BY snapshot_at DESC, created_at DESC",
            (caption_hash,),
        ).fetchall()
        recipe_rows = self.conn.execute(
            "SELECT * FROM performance_snapshots WHERE recipe = ? ORDER BY snapshot_at DESC, created_at DESC",
            (asset.get("recipe"),),
        ).fetchall() if asset.get("recipe") else []
        source_snapshots = [self._performance_snapshot_payload(dict(row)) for row in source_rows]
        caption_snapshots = [self._performance_snapshot_payload(dict(row)) for row in caption_rows]
        recipe_snapshots = [self._performance_snapshot_payload(dict(row)) for row in recipe_rows]
        account_baselines = account_reward_baselines(source_snapshots + caption_snapshots + recipe_snapshots)
        source = self._aggregate_performance(source_snapshots, account_baselines=account_baselines)
        caption = self._aggregate_performance(caption_snapshots, account_baselines=account_baselines)
        recipe = self._aggregate_performance(recipe_snapshots, account_baselines=account_baselines)
        score = self._performance_score(source=source, caption=caption, recipe=recipe)
        return {
            "latestPerformance": self._performance_snapshot_payload(dict(latest)) if latest else None,
            "sourcePerformance": source,
            "captionPerformance": caption,
            "recipePerformance": recipe,
            "performanceScore": score,
        }

    def _performance_snapshot_payload(self, row: dict[str, Any]) -> dict[str, Any]:
        caption_outcome_context = load_context_json(row.get("caption_outcome_context_json"))
        return {
            "id": row["id"],
            "campaignId": row["campaign_id"],
            "renderedAssetId": row["rendered_asset_id"],
            "sourceAssetId": row["source_asset_id"],
            "contentHash": row["content_hash"],
            "sourceContentHash": row["source_content_hash"],
            "captionHash": row["caption_hash"],
            "captionText": row.get("caption_text"),
            "captionBank": row.get("caption_bank"),
            "creatorMix": row.get("creator_mix"),
            "creatorModel": row.get("creator_model"),
            "frameType": row.get("frame_type"),
            "lengthClass": row.get("length_class"),
            "formatClass": row.get("format_class"),
            "captionFitVersion": row.get("caption_fit_version"),
            "captionOutcomeContext": caption_outcome_context,
            "captionFamilyId": caption_outcome_context.get("caption_family_id") or caption_outcome_context.get("captionFamilyId"),
            "captionVersionId": caption_outcome_context.get("caption_version_id") or caption_outcome_context.get("captionVersionId"),
            "conceptId": row.get("concept_id"),
            "parentReelId": row.get("parent_reel_id"),
            "variantFamilyId": row.get("variant_family_id"),
            "variantId": row.get("variant_id"),
            "variantIndex": row.get("variant_index"),
            "variantOperations": json_load(row.get("variant_operations_json"), []),
            "audioId": row.get("audio_id"),
            "recipe": row["recipe"],
            "postId": row["post_id"],
            "platform": row["platform"],
            "contentSurface": row.get("content_surface") or "reel",
            "status": row["status"],
            "accountId": row["account_id"],
            "instagramAccountId": row["instagram_account_id"],
            "permalink": row["permalink"],
            "publishedAt": row["published_at"],
            "snapshotAt": row["snapshot_at"],
            "metrics": {
                "views": row["views"],
                "likes": row["likes"],
                "comments": row["comments"],
                "shares": row["shares"],
                "saves": row["saves"],
                "impressions": row["impressions"],
                "reach": row["reach"],
                "watchTimeSeconds": row["watch_time_seconds"],
            },
            "metricContract": self._performance_metric_contract(row),
            "dimensions": self._performance_snapshot_dimensions(row),
        }

    def _account_memory_payload(self, row: dict[str, Any]) -> dict[str, Any]:
        return {
            "id": row["id"],
            "campaignId": row["campaign_id"],
            "accountId": row["account_id"],
            "platform": row["platform"],
            "sampleSize": row["sample_size"],
            "confidence": row["confidence"],
            "performanceScore": row["performance_score"],
            "patternStats": json_load(row["pattern_stats_json"], []),
            "postingWindows": json_load(row["posting_windows_json"], []),
            "fatigue": json_load(row["fatigue_json"], {}),
            "audienceNotes": json_load(row["audience_notes_json"], {}),
            "recommendationOutcomes": json_load(row["recommendation_outcomes_json"], {}),
            "updatedAt": row["updated_at"],
            "graphId": self.graph_id_for("account_memory", row["id"]),
        }

    def _account_pattern_stats_from_snapshots(
        self,
        campaign_id: str,
        account_id: str,
        snapshots: list[dict[str, Any]],
        updated_at: str,
        *,
        account_baselines: dict[str, float] | None = None,
    ) -> list[dict[str, Any]]:
        buckets: dict[tuple[str, str], dict[str, Any]] = {}
        for snapshot in snapshots:
            dimensions = snapshot.get("dimensions") or {}
            candidates: list[tuple[str, str, str | None]] = []
            if snapshot.get("recipe"):
                candidates.append(("recipe", str(snapshot["recipe"]), str(snapshot["recipe"])))
            for key in ("hook", "audio", "referenceFormat", "promptPattern", "patternCard", "captionFormula", "modelAccount", "variationPreset"):
                value = dimensions.get(key)
                if isinstance(value, dict) and value.get("key"):
                    candidates.append((key, str(value["key"]), str(value.get("label") or value["key"])))
            for pattern_type, pattern_key, label in candidates:
                bucket = buckets.setdefault((pattern_type, pattern_key), {"patternType": pattern_type, "patternKey": pattern_key, "label": label, "snapshots": []})
                bucket["snapshots"].append(snapshot)
        stats = []
        for (pattern_type, pattern_key), bucket in buckets.items():
            aggregate = self._aggregate_performance(bucket["snapshots"], account_baselines=account_baselines)
            sample_size = int(aggregate.get("count") or 0)
            performance_score = self._performance_quality_score(aggregate)
            fatigue_score = min(100, round((sample_size / max(1, len(snapshots))) * 100))
            stat = {
                "patternType": pattern_type,
                "patternKey": pattern_key,
                "label": bucket.get("label"),
                "sampleSize": sample_size,
                "performanceScore": performance_score,
                "fatigueScore": fatigue_score,
                "performance": aggregate,
            }
            stats.append(stat)
            stat_id = f"acctpat_{hashlib.sha256(f'{campaign_id}:{account_id}:{pattern_type}:{pattern_key}'.encode('utf-8')).hexdigest()[:12]}"
            self.conn.execute(
                """
                INSERT INTO account_pattern_stats (
                  id, campaign_id, account_id, pattern_key, pattern_type, label,
                  sample_size, performance_score, fatigue_score, stats_json, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(campaign_id, account_id, pattern_type, pattern_key) DO UPDATE SET
                  label = excluded.label,
                  sample_size = excluded.sample_size,
                  performance_score = excluded.performance_score,
                  fatigue_score = excluded.fatigue_score,
                  stats_json = excluded.stats_json,
                  updated_at = excluded.updated_at
                """,
                (
                    stat_id,
                    campaign_id,
                    account_id,
                    pattern_key,
                    pattern_type,
                    bucket.get("label"),
                    sample_size,
                    performance_score,
                    fatigue_score,
                    json.dumps(sanitize_for_storage(stat), ensure_ascii=False, sort_keys=True),
                    updated_at,
                ),
            )
        stats.sort(key=lambda item: (item.get("performanceScore") or 0, item.get("sampleSize") or 0), reverse=True)
        return stats

    def _account_posting_windows_from_snapshots(
        self,
        campaign_id: str,
        account_id: str,
        snapshots: list[dict[str, Any]],
        updated_at: str,
        *,
        account_baselines: dict[str, float] | None = None,
    ) -> list[dict[str, Any]]:
        buckets: dict[tuple[int, int], list[dict[str, Any]]] = {}
        for snapshot in snapshots:
            published_at = snapshot.get("publishedAt") or snapshot.get("snapshotAt")
            if not published_at:
                continue
            try:
                dt = datetime.fromisoformat(str(published_at).replace("Z", "+00:00"))
            except ValueError:
                continue
            buckets.setdefault((dt.weekday(), dt.hour), []).append(snapshot)
        windows = []
        for (weekday, hour), rows in buckets.items():
            aggregate = self._aggregate_performance(rows, account_baselines=account_baselines)
            score = self._performance_quality_score(aggregate)
            payload = {"weekday": weekday, "hour": hour, "sampleSize": len(rows), "performanceScore": score, "performance": aggregate}
            windows.append(payload)
            window_id = f"acctwin_{hashlib.sha256(f'{campaign_id}:{account_id}:{weekday}:{hour}'.encode('utf-8')).hexdigest()[:12]}"
            self.conn.execute(
                """
                INSERT INTO account_posting_windows (
                  id, campaign_id, account_id, weekday, hour, sample_size, performance_score, stats_json, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(campaign_id, account_id, weekday, hour) DO UPDATE SET
                  sample_size = excluded.sample_size,
                  performance_score = excluded.performance_score,
                  stats_json = excluded.stats_json,
                  updated_at = excluded.updated_at
                """,
                (
                    window_id,
                    campaign_id,
                    account_id,
                    weekday,
                    hour,
                    len(rows),
                    score,
                    json.dumps(sanitize_for_storage(payload), ensure_ascii=False, sort_keys=True),
                    updated_at,
                ),
            )
        windows.sort(key=lambda item: (item.get("performanceScore") or 0, item.get("sampleSize") or 0), reverse=True)
        return windows

    def _account_fatigue_from_pattern_stats(self, pattern_stats: list[dict[str, Any]]) -> dict[str, Any]:
        overused = [item for item in pattern_stats if int(item.get("sampleSize") or 0) >= 2 and int(item.get("fatigueScore") or 0) >= 40]
        max_score = max([int(item.get("fatigueScore") or 0) for item in overused], default=0)
        if max_score >= 60:
            level = "high"
        elif max_score >= 40:
            level = "medium"
        else:
            level = "low"
        return {
            "level": level,
            "score": max_score,
            "overusedPatterns": sorted(overused, key=lambda item: item.get("fatigueScore") or 0, reverse=True)[:10],
        }

    def _account_recommendation_outcomes(self, campaign_id: str, account_id: str, updated_at: str) -> dict[str, Any]:
        rows = self.conn.execute(
            """
            SELECT ri.*
            FROM recommendation_items ri
            JOIN recommendation_runs rr ON rr.id = ri.run_id
            WHERE rr.campaign_id = ?
              AND (ri.target_account = ? OR ri.target_account IS NULL)
              AND ri.status IN ('measured', 'proved', 'disproved')
            ORDER BY COALESCE(ri.measured_at, ri.created_at) DESC
            """,
            (campaign_id, account_id),
        ).fetchall()
        totals = {"measured": 0, "proved": 0, "disproved": 0}
        latest = []
        for row in rows:
            item = dict(row)
            status = item["status"]
            totals[status] = totals.get(status, 0) + 1
            outcome = json_load(item.get("outcome_json"), {})
            lift = None
            if outcome.get("outcomeScore") is not None and outcome.get("baselineScore") is not None:
                lift = int(outcome["outcomeScore"]) - int(outcome["baselineScore"])
            outcome_key = f"{campaign_id}:{account_id}:{item['id']}"
            outcome_id = f"acctout_{hashlib.sha256(outcome_key.encode('utf-8')).hexdigest()[:12]}"
            payload = {
                "recommendationItemId": item["id"],
                "status": status,
                "outcome": outcome,
                "baseline": json_load(item.get("baseline_json"), {}),
                "lift": lift,
            }
            self.conn.execute(
                """
                INSERT INTO account_recommendation_outcomes (
                  id, campaign_id, account_id, recommendation_item_id, status,
                  outcome_score, baseline_score, lift, payload_json, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(campaign_id, account_id, recommendation_item_id) DO UPDATE SET
                  status = excluded.status,
                  outcome_score = excluded.outcome_score,
                  baseline_score = excluded.baseline_score,
                  lift = excluded.lift,
                  payload_json = excluded.payload_json,
                  updated_at = excluded.updated_at
                """,
                (
                    outcome_id,
                    campaign_id,
                    account_id,
                    item["id"],
                    status,
                    outcome.get("outcomeScore"),
                    outcome.get("baselineScore"),
                    lift,
                    json.dumps(sanitize_for_storage(payload), ensure_ascii=False, sort_keys=True),
                    updated_at,
                ),
            )
            latest.append(payload)
        measured_total = sum(totals.values())
        accuracy = (totals["proved"] / (totals["proved"] + totals["disproved"])) if (totals["proved"] + totals["disproved"]) else None
        return {"counts": totals, "measuredTotal": measured_total, "proofAccuracy": accuracy, "latest": latest[:10]}

    def _account_memory_confidence(self, sample_size: int, outcomes: dict[str, Any]) -> str:
        measured = int(outcomes.get("measuredTotal") or 0)
        if sample_size >= 20 and measured >= 5:
            return "high"
        if sample_size >= 5 or measured >= 2:
            return "medium"
        return "low"

    def _group_performance(self, snapshots: list[dict[str, Any]], key: str, *, account_baselines: dict[str, float] | None = None) -> dict[str, Any]:
        groups: dict[str, list[dict[str, Any]]] = {}
        for snapshot in snapshots:
            value = snapshot.get(key)
            if value:
                groups.setdefault(str(value), []).append(snapshot)
        return {key: self._aggregate_performance(group, account_baselines=account_baselines) for key, group in groups.items()}

    def _aggregate_performance(self, snapshots: list[dict[str, Any]], *, account_baselines: dict[str, float] | None = None) -> dict[str, Any]:
        return aggregate_performance(snapshots, account_baselines=account_baselines)

    def _performance_metric_contract(self, row: dict[str, Any]) -> dict[str, Any]:
        raw = json_load(row.get("raw_json"), {})
        contract = raw.get("metric_contract") if isinstance(raw, dict) else {}
        if not isinstance(contract, dict):
            contract = {}
        names = contract.get("metricNames")
        surface = contract.get("surface") or row.get("content_surface") or "reel"
        return {
            "version": contract.get("version") or "instagram_metrics_contract_v1",
            "surface": surface,
            "fallbackUsed": bool(contract.get("fallbackUsed") or contract.get("fallback_used")),
            "metricNames": names if isinstance(names, list) else self._default_performance_metric_names(str(surface)),
        }

    def _default_performance_metric_names(self, surface: str) -> list[str]:
        if surface == "story":
            return ["views", "reach", "replies", "navigation", "follows", "shares", "total_interactions"]
        if surface == "reel":
            return ["views", "reach", "likes", "comments", "shares", "saved", "ig_reels_avg_watch_time", "reels_skip_rate", "ig_reels_video_view_total_time"]
        return ["views", "reach", "likes", "comments", "shares", "saved"]

    def _performance_leaderboards(self, snapshots: list[dict[str, Any]], *, account_baselines: dict[str, float] | None = None) -> dict[str, list[dict[str, Any]]]:
        boards: dict[str, dict[str, dict[str, Any]]] = {
            "hooks": {},
            "recipes": {},
            "audioRecommendations": {},
            "referenceFormats": {},
            "promptPatterns": {},
            "patternCards": {},
            "modelAccounts": {},
            "captionFormulas": {},
            "variationPresets": {},
            "hookRecipeCombos": {},
            "hookAudioCombos": {},
            "formatRecipeCombos": {},
            "formatAudioCombos": {},
            "recipeAudioCombos": {},
            "hookRecipeAudioCombos": {},
        }
        for snapshot in snapshots:
            dimensions = snapshot.get("dimensions") or {}
            hook = dimensions.get("hook") if isinstance(dimensions.get("hook"), dict) else None
            recipe = dimensions.get("recipe") or snapshot.get("recipe")
            audio = dimensions.get("audio") if isinstance(dimensions.get("audio"), dict) else None
            reference_format = dimensions.get("referenceFormat") if isinstance(dimensions.get("referenceFormat"), dict) else None
            prompt_pattern = dimensions.get("promptPattern") if isinstance(dimensions.get("promptPattern"), dict) else None
            pattern_card = dimensions.get("patternCard") if isinstance(dimensions.get("patternCard"), dict) else None
            model_account = dimensions.get("modelAccount") if isinstance(dimensions.get("modelAccount"), dict) else None
            caption_formula = dimensions.get("captionFormula") if isinstance(dimensions.get("captionFormula"), dict) else None
            variation_preset = dimensions.get("variationPreset") if isinstance(dimensions.get("variationPreset"), dict) else None
            if hook:
                self._add_leaderboard_snapshot(boards["hooks"], hook["key"], snapshot, {"hook": hook})
            if recipe:
                self._add_leaderboard_snapshot(boards["recipes"], str(recipe), snapshot, {"recipe": str(recipe)})
            if audio:
                self._add_leaderboard_snapshot(boards["audioRecommendations"], audio["key"], snapshot, {"audio": audio})
            if reference_format:
                self._add_leaderboard_snapshot(boards["referenceFormats"], reference_format["key"], snapshot, {"referenceFormat": reference_format})
            if prompt_pattern:
                self._add_leaderboard_snapshot(boards["promptPatterns"], prompt_pattern["key"], snapshot, {"promptPattern": prompt_pattern})
            if pattern_card:
                self._add_leaderboard_snapshot(boards["patternCards"], pattern_card["key"], snapshot, {"patternCard": pattern_card})
            if model_account:
                self._add_leaderboard_snapshot(boards["modelAccounts"], model_account["key"], snapshot, {"modelAccount": model_account})
            if caption_formula:
                self._add_leaderboard_snapshot(boards["captionFormulas"], caption_formula["key"], snapshot, {"captionFormula": caption_formula})
            if variation_preset:
                self._add_leaderboard_snapshot(boards["variationPresets"], variation_preset["key"], snapshot, {"variationPreset": variation_preset})
            if hook and recipe:
                self._add_leaderboard_snapshot(
                    boards["hookRecipeCombos"],
                    f"{hook['key']}|{recipe}",
                    snapshot,
                    {"hook": hook, "recipe": str(recipe)},
                )
            if hook and audio:
                self._add_leaderboard_snapshot(
                    boards["hookAudioCombos"],
                    f"{hook['key']}|{audio['key']}",
                    snapshot,
                    {"hook": hook, "audio": audio},
                )
            if reference_format and recipe:
                self._add_leaderboard_snapshot(
                    boards["formatRecipeCombos"],
                    f"{reference_format['key']}|{recipe}",
                    snapshot,
                    {"referenceFormat": reference_format, "recipe": str(recipe)},
                )
            if reference_format and audio:
                self._add_leaderboard_snapshot(
                    boards["formatAudioCombos"],
                    f"{reference_format['key']}|{audio['key']}",
                    snapshot,
                    {"referenceFormat": reference_format, "audio": audio},
                )
            if recipe and audio:
                self._add_leaderboard_snapshot(
                    boards["recipeAudioCombos"],
                    f"{recipe}|{audio['key']}",
                    snapshot,
                    {"recipe": str(recipe), "audio": audio},
                )
            if hook and recipe and audio:
                self._add_leaderboard_snapshot(
                    boards["hookRecipeAudioCombos"],
                    f"{hook['key']}|{recipe}|{audio['key']}",
                    snapshot,
                    {"hook": hook, "recipe": str(recipe), "audio": audio},
                )
        return {name: self._rank_leaderboard_entries(items, account_baselines=account_baselines) for name, items in boards.items()}

    def _caption_outcome_manual_review(self, snapshots: list[dict[str, Any]]) -> dict[str, Any]:
        with_context = [
            self._caption_outcome_snapshot_with_placement(snapshot)
            for snapshot in snapshots
            if self._has_caption_outcome_context(snapshot)
        ]
        return {
            "schema": "campaign_factory.caption_outcome_manual_review.v1",
            "manualReviewOnly": True,
            "coverage": {
                "snapshots": len(snapshots),
                "snapshotsWithCaptionOutcomeContext": len(with_context),
                "snapshotsMissingCaptionOutcomeContext": max(0, len(snapshots) - len(with_context)),
                "coverageRatio": round(len(with_context) / len(snapshots), 4) if snapshots else 0.0,
            },
            "byCaptionBank": self._caption_outcome_group(with_context, "captionBank", "captionBank"),
            "byCreatorMix": self._caption_outcome_group(with_context, "creatorMix", "creatorMix"),
            "byCreatorModel": self._caption_outcome_group(with_context, "creatorModel", "creatorModel"),
            "byFrameType": self._caption_outcome_group(with_context, "frameType", "frameType"),
            "byLengthClass": self._caption_outcome_group(with_context, "lengthClass", "lengthClass"),
            "byFormatClass": self._caption_outcome_group(with_context, "formatClass", "formatClass"),
            "byCaptionFitVersion": self._caption_outcome_group(with_context, "captionFitVersion", "captionFitVersion"),
            "byCaptionHash": self._caption_outcome_group(with_context, "captionHash", "captionHash"),
            "byCaptionPlacementLane": self._caption_outcome_group(with_context, "captionPlacementLane", "captionPlacementLane"),
            "byCaptionPlacementStatus": self._caption_outcome_group(with_context, "captionPlacementStatus", "captionPlacementStatus"),
        }

    def _has_caption_outcome_context(self, snapshot: dict[str, Any]) -> bool:
        context = snapshot.get("captionOutcomeContext") if isinstance(snapshot.get("captionOutcomeContext"), dict) else {}
        return bool(context) or any(snapshot.get(key) for key in ("captionBank", "creatorMix", "frameType", "lengthClass", "formatClass", "captionFitVersion"))

    def _caption_outcome_snapshot_with_placement(self, snapshot: dict[str, Any]) -> dict[str, Any]:
        context = snapshot.get("captionOutcomeContext") if isinstance(snapshot.get("captionOutcomeContext"), dict) else {}
        decision = context.get("captionPlacementDecision") if isinstance(context, dict) else {}
        if not isinstance(decision, dict):
            decision = {}
        enriched = dict(snapshot)
        enriched["captionPlacementLane"] = decision.get("selectedLane") or decision.get("lane") or context.get("captionPlacementLane")
        enriched["captionPlacementStatus"] = decision.get("status") or context.get("captionPlacementStatus")
        return enriched

    def _caption_outcome_group(self, snapshots: list[dict[str, Any]], source_key: str, output_key: str) -> list[dict[str, Any]]:
        groups: dict[str, list[dict[str, Any]]] = {}
        for snapshot in snapshots:
            value = snapshot.get(source_key)
            if value:
                groups.setdefault(str(value), []).append(snapshot)
        rows = []
        for value, group in groups.items():
            performance = self._aggregate_performance(group)
            contexts = self._caption_outcome_contexts_for_group(group)
            context_fields: dict[str, Any] = {"captionOutcomeContexts": contexts}
            if len(contexts) == 1:
                context_fields["captionOutcomeContext"] = contexts[0]
            rows.append({
                output_key: value,
                "performance": performance,
                "score": self._performance_quality_score(performance),
                "renderedAssetIds": sorted({str(snapshot["renderedAssetId"]) for snapshot in group if snapshot.get("renderedAssetId")}),
                "postIds": sorted({str(snapshot["postId"]) for snapshot in group if snapshot.get("postId")}),
                **context_fields,
            })
        return sorted(
            rows,
            key=lambda item: (
                -(item["score"] if item["score"] is not None else -1),
                -int((item.get("performance") or {}).get("count") or 0),
                str(item.get(output_key) or ""),
            ),
        )[:20]

    def _caption_outcome_contexts_for_group(self, snapshots: list[dict[str, Any]]) -> list[dict[str, Any]]:
        seen: set[str] = set()
        contexts: list[dict[str, Any]] = []
        for snapshot in snapshots:
            context = snapshot.get("captionOutcomeContext")
            if not isinstance(context, dict) or not context:
                continue
            key = json.dumps(context, ensure_ascii=False, sort_keys=True)
            if key in seen:
                continue
            seen.add(key)
            contexts.append(context)
            if len(contexts) >= 5:
                break
        return contexts

    def _add_leaderboard_snapshot(
        self,
        items: dict[str, dict[str, Any]],
        key: str,
        snapshot: dict[str, Any],
        dimensions: dict[str, Any],
    ) -> None:
        item = items.setdefault(key, {"key": key, **dimensions, "snapshots": []})
        item["snapshots"].append(snapshot)

    def _rank_leaderboard_entries(
        self,
        items: dict[str, dict[str, Any]],
        *,
        limit: int = 20,
        account_baselines: dict[str, float] | None = None,
    ) -> list[dict[str, Any]]:
        entries = []
        for item in items.values():
            snapshots = item["snapshots"]
            summary = self._aggregate_performance(snapshots, account_baselines=account_baselines)
            entries.append({
                **{key: value for key, value in item.items() if key != "snapshots"},
                "performance": summary,
                "score": self._performance_quality_score(summary),
                "recommendation": self._performance_recommendation_label(summary),
                "renderedAssetIds": sorted({str(snapshot["renderedAssetId"]) for snapshot in snapshots if snapshot.get("renderedAssetId")}),
                "postIds": sorted({str(snapshot["postId"]) for snapshot in snapshots if snapshot.get("postId")}),
            })
        return sorted(
            entries,
            key=lambda item: (
                -(item["score"] if item["score"] is not None else -1),
                -int((item.get("performance") or {}).get("count") or 0),
                str(item.get("key") or ""),
            ),
        )[:limit]

    def _performance_recommendation_label(self, summary: dict[str, Any]) -> str:
        count = int(summary.get("count") or 0)
        if count < 3:
            return "needs_more_data"
        score = self._performance_quality_score(summary)
        totals = summary.get("totals") or {}
        reach = float(totals.get("reach") or totals.get("impressions") or totals.get("views") or 0)
        rates = summary.get("rates") or {}
        engagement_rate = float(rates.get("engagementRate") or 0)
        if score is not None and score >= 78:
            return "make_more_like_this"
        if score is not None and score <= 42:
            return "stop_using"
        if reach >= 10000 and engagement_rate < 0.01:
            return "good_views_bad_conversion_signal"
        return "needs_more_data"

    def _performance_quality_score(self, summary: dict[str, Any]) -> int | None:
        return performance_score(summary)

    def _performance_planning_score(self, summary: dict[str, Any]) -> int | None:
        return performance_planning_score(summary)

    def _performance_snapshot_dimensions(self, row: dict[str, Any]) -> dict[str, Any]:
        raw = json_load(row.get("raw_json"), {})
        metadata = raw.get("metadata") if isinstance(raw, dict) else {}
        campaign_meta = metadata.get("campaign_factory") if isinstance(metadata, dict) else {}
        if not isinstance(campaign_meta, dict):
            campaign_meta = {}
        recipe = row.get("recipe") or campaign_meta.get("recipe")
        hook = self._performance_hook_dimension(campaign_meta)
        audio = self._performance_audio_dimension(campaign_meta)
        reference_format = self._performance_reference_format_dimension(campaign_meta)
        prompt_pattern = self._performance_prompt_pattern_dimension(campaign_meta)
        pattern_card = self._performance_pattern_card_dimension(campaign_meta)
        model_account = self._performance_model_account_dimension(campaign_meta, row)
        caption_formula = self._performance_caption_formula_dimension(campaign_meta)
        variation_preset = self._performance_variation_preset_dimension(campaign_meta, row)
        dimensions: dict[str, Any] = {}
        if recipe:
            dimensions["recipe"] = str(recipe)
        if hook:
            dimensions["hook"] = hook
        if audio:
            dimensions["audio"] = audio
        if reference_format:
            dimensions["referenceFormat"] = reference_format
        if prompt_pattern:
            dimensions["promptPattern"] = prompt_pattern
        if pattern_card:
            dimensions["patternCard"] = pattern_card
        if model_account:
            dimensions["modelAccount"] = model_account
        if caption_formula:
            dimensions["captionFormula"] = caption_formula
        if variation_preset:
            dimensions["variationPreset"] = variation_preset
        return dimensions

    def _performance_hook_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        caption_generation = campaign_meta.get("caption_generation") if isinstance(campaign_meta.get("caption_generation"), dict) else {}
        reference_pattern = campaign_meta.get("reference_pattern") if isinstance(campaign_meta.get("reference_pattern"), dict) else {}
        generated_reference = caption_generation.get("referencePattern") if isinstance(caption_generation.get("referencePattern"), dict) else {}
        hook_key = (
            campaign_meta.get("hook_key")
            or reference_pattern.get("clusterKey")
            or reference_pattern.get("cluster_key")
            or generated_reference.get("clusterKey")
            or generated_reference.get("cluster_key")
            or generated_reference.get("hookType")
            or generated_reference.get("hook_type")
        )
        if not hook_key:
            return None
        return {
            "key": str(hook_key),
            "label": (
                campaign_meta.get("hook_label")
                or reference_pattern.get("label")
                or generated_reference.get("label")
                or generated_reference.get("hookType")
                or generated_reference.get("hook_type")
            ),
            "hookType": reference_pattern.get("hookType") or reference_pattern.get("hook_type") or generated_reference.get("hookType") or generated_reference.get("hook_type"),
            "captionArchetype": reference_pattern.get("captionArchetype") or reference_pattern.get("caption_archetype") or generated_reference.get("captionArchetype") or generated_reference.get("caption_archetype"),
        }

    def _performance_audio_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        intent = campaign_meta.get("audio_intent") if isinstance(campaign_meta.get("audio_intent"), dict) else {}
        recommendations = intent.get("recommendations") if isinstance(intent.get("recommendations"), list) else []
        audio_recommendations = campaign_meta.get("audio_recommendations") if isinstance(campaign_meta.get("audio_recommendations"), dict) else {}
        if not recommendations and isinstance(audio_recommendations.get("recommendations"), list):
            recommendations = audio_recommendations["recommendations"]
        selection = intent.get("operator_selection") if isinstance(intent.get("operator_selection"), dict) else {}
        candidates = [selection, *(item for item in recommendations if isinstance(item, dict))]
        for candidate in candidates:
            audio_id = (
                candidate.get("platform_audio_id")
                or candidate.get("platformAudioId")
                or candidate.get("native_audio_id")
                or candidate.get("nativeAudioId")
                or candidate.get("audio_id")
                or candidate.get("audioId")
            )
            title = candidate.get("audio_title") or candidate.get("audioTitle") or candidate.get("title")
            artist = candidate.get("artist_name") or candidate.get("artistName") or candidate.get("artist")
            if not audio_id and not title:
                continue
            key = str(audio_id or "|".join(str(part) for part in [title, artist] if part))
            return {
                "key": key,
                "audioTitle": title,
                "artistName": artist,
                "platformAudioId": audio_id,
                "platformUrl": candidate.get("platform_url") or candidate.get("platformUrl") or candidate.get("native_audio_url") or candidate.get("nativeAudioUrl"),
                "status": intent.get("status"),
                "source": candidate.get("source") or audio_recommendations.get("source") or "campaign_factory",
            }
        return None

    def _performance_reference_format_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        caption_generation = campaign_meta.get("caption_generation") if isinstance(campaign_meta.get("caption_generation"), dict) else {}
        reference_pattern = campaign_meta.get("reference_pattern") if isinstance(campaign_meta.get("reference_pattern"), dict) else {}
        generated_reference = caption_generation.get("referencePattern") if isinstance(caption_generation.get("referencePattern"), dict) else {}
        finished_intake = campaign_meta.get("finished_video_intake") if isinstance(campaign_meta.get("finished_video_intake"), dict) else {}
        source_prompt = campaign_meta.get("source_prompt") if isinstance(campaign_meta.get("source_prompt"), dict) else {}
        candidates = [
            campaign_meta.get("reference_format"),
            campaign_meta.get("format_type"),
            finished_intake.get("formatType"),
            finished_intake.get("format_type"),
            source_prompt.get("formatType"),
            source_prompt.get("format_type"),
            reference_pattern.get("visualFormat"),
            reference_pattern.get("visual_format"),
            generated_reference.get("visualFormat"),
            generated_reference.get("visual_format"),
        ]
        value = next((str(item).strip() for item in candidates if str(item or "").strip()), "")
        if not value:
            return None
        key = slugify(value)
        return {
            "key": key,
            "label": value,
            "source": "campaign_factory",
        }

    def _performance_prompt_pattern_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        caption_generation = campaign_meta.get("caption_generation") if isinstance(campaign_meta.get("caption_generation"), dict) else {}
        reference_pattern = campaign_meta.get("reference_pattern") if isinstance(campaign_meta.get("reference_pattern"), dict) else {}
        generated_reference = caption_generation.get("referencePattern") if isinstance(caption_generation.get("referencePattern"), dict) else {}
        source_prompt = campaign_meta.get("source_prompt") if isinstance(campaign_meta.get("source_prompt"), dict) else {}
        strategy = source_prompt.get("strategy") if isinstance(source_prompt.get("strategy"), dict) else {}
        key = (
            campaign_meta.get("prompt_pattern")
            or campaign_meta.get("promptPattern")
            or source_prompt.get("referencePattern")
            or source_prompt.get("reference_pattern")
            or reference_pattern.get("clusterKey")
            or reference_pattern.get("cluster_key")
            or generated_reference.get("clusterKey")
            or generated_reference.get("cluster_key")
        )
        if not key:
            return None
        return {
            "key": str(key),
            "label": (
                campaign_meta.get("prompt_pattern_label")
                or reference_pattern.get("label")
                or generated_reference.get("label")
                or str(key)
            ),
            "primaryMetric": strategy.get("primaryMetric") or campaign_meta.get("primary_metric") or "views_reach",
            "source": "campaign_factory",
        }

    def _performance_pattern_card_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        lineage = campaign_meta.get("generated_asset_lineage") if isinstance(campaign_meta.get("generated_asset_lineage"), dict) else {}
        source_prompt = campaign_meta.get("source_prompt") if isinstance(campaign_meta.get("source_prompt"), dict) else {}
        if not lineage and isinstance(source_prompt.get("generatedAssetLineage"), dict):
            lineage = source_prompt["generatedAssetLineage"]
        source = lineage.get("source") if isinstance(lineage.get("source"), dict) else {}
        reference_pattern = campaign_meta.get("reference_pattern") if isinstance(campaign_meta.get("reference_pattern"), dict) else {}
        key = (
            source.get("patternCardId")
            or source.get("pattern_card_id")
            or reference_pattern.get("patternCardId")
            or reference_pattern.get("id")
        )
        if not key:
            return None
        return {
            "key": str(key),
            "label": source.get("referencePattern") or reference_pattern.get("label") or str(key),
            "formatType": source.get("formatType") or reference_pattern.get("visualFormat"),
            "source": "reference_factory",
        }

    def _performance_model_account_dimension(self, campaign_meta: dict[str, Any], row: dict[str, Any]) -> dict[str, Any] | None:
        lineage = campaign_meta.get("generated_asset_lineage") if isinstance(campaign_meta.get("generated_asset_lineage"), dict) else {}
        source_prompt = campaign_meta.get("source_prompt") if isinstance(campaign_meta.get("source_prompt"), dict) else {}
        if not lineage and isinstance(source_prompt.get("generatedAssetLineage"), dict):
            lineage = source_prompt["generatedAssetLineage"]
        generation = lineage.get("generation") if isinstance(lineage.get("generation"), dict) else {}
        account = campaign_meta.get("account_profile") if isinstance(campaign_meta.get("account_profile"), dict) else {}
        model = generation.get("modelProfile") or campaign_meta.get("model_slug") or campaign_meta.get("model_id")
        account_id = row.get("instagram_account_id") or row.get("account_id") or account.get("handle") or account.get("slug")
        if not model and not account_id:
            return None
        key = "|".join(str(part) for part in (model or "unknown_model", account_id or "unknown_account"))
        return {"key": key, "modelProfile": model, "account": account_id, "source": "threadsdash_performance"}

    def _performance_caption_formula_dimension(self, campaign_meta: dict[str, Any]) -> dict[str, Any] | None:
        caption_generation = campaign_meta.get("caption_generation") if isinstance(campaign_meta.get("caption_generation"), dict) else {}
        reference_pattern = campaign_meta.get("reference_pattern") if isinstance(campaign_meta.get("reference_pattern"), dict) else {}
        generated_reference = caption_generation.get("referencePattern") if isinstance(caption_generation.get("referencePattern"), dict) else {}
        formula = (
            caption_generation.get("captionFormula")
            or caption_generation.get("caption_formula")
            or reference_pattern.get("captionArchetype")
            or reference_pattern.get("caption_archetype")
            or generated_reference.get("captionArchetype")
            or generated_reference.get("caption_archetype")
            or generated_reference.get("hookType")
        )
        if not formula:
            return None
        return {"key": slugify(str(formula)), "label": str(formula), "source": "campaign_factory"}

    def _performance_variation_preset_dimension(self, campaign_meta: dict[str, Any], row: dict[str, Any]) -> dict[str, Any] | None:
        assignment = campaign_meta.get("variant_assignment") if isinstance(campaign_meta.get("variant_assignment"), dict) else {}
        candidate_values = [
            campaign_meta.get("variationPreset"),
            campaign_meta.get("variation_preset"),
            campaign_meta.get("variantPreset"),
            campaign_meta.get("variant_preset"),
            assignment.get("presetName"),
            assignment.get("preset_name"),
        ]
        operations = json_load(row.get("variant_operations_json"), [])
        if isinstance(operations, list):
            for operation in operations:
                if not isinstance(operation, dict):
                    continue
                candidate_values.extend([
                    operation.get("presetName"),
                    operation.get("preset_name"),
                    operation.get("preset"),
                ])
                result = operation.get("result") if isinstance(operation.get("result"), dict) else {}
                candidate_values.extend([
                    result.get("presetName"),
                    result.get("preset_name"),
                    result.get("preset"),
                ])
        preset = next((str(value).strip() for value in candidate_values if str(value or "").strip()), "")
        if not preset:
            return None
        return {"key": preset, "label": preset, "source": "variant_assignment"}

    def _performance_score(self, *, source: dict[str, Any], caption: dict[str, Any], recipe: dict[str, Any]) -> int | None:
        weights = [(source, 0.45), (caption, 0.35), (recipe, 0.20)]
        available = [(summary, weight) for summary, weight in weights if summary.get("count")]
        if not available:
            return None
        weighted = 0.0
        total_weight = 0.0
        for summary, weight in available:
            component = self._performance_quality_score(summary) or 50
            weighted += component * weight
            total_weight += weight
        return int(round(weighted / total_weight)) if total_weight else None

    def _audit_report_payload(self, row: dict[str, Any]) -> dict[str, Any]:
        from . import audit_payload as _audit_payload

        return _audit_payload._audit_report_payload(self, row)
    def _local_export_readiness(self, asset: dict[str, Any], latest_audit: dict[str, Any] | None) -> dict[str, Any]:
        blocking = []
        warnings = []
        publishability = self._publishability_check(asset, latest_audit)
        blocking.extend(publishability.get("blockingReasons") or [])
        warnings.extend(publishability.get("warnings") or [])
        if asset["review_state"] != "approved":
            blocking.append(f"review_state:{asset['review_state']}")
        if not latest_audit:
            blocking.append("missing_audit")
        else:
            readiness = latest_audit.get("readinessSummary") or {}
            blocking_codes = readiness.get("blockingCodes") or []
            if blocking_codes:
                blocking.extend([f"audit_failed:{check}" for check in blocking_codes])
            for reason in readiness.get("blockingReasons") or []:
                blocking.append(f"upload_readiness:{reason}")
            if latest_audit.get("overallVerdict") == "fail":
                blocking.append("contentforge_verdict:fail")
            elif latest_audit.get("overallVerdict") == "warn":
                warnings.append("contentforge_verdict:warn")
            for warning in latest_audit.get("warnings") or []:
                warnings.append(f"audit_warning:{warning}")
        state = "blocked" if blocking else ("warning" if warnings else "ready")
        score = 100
        if state == "blocked":
            score -= 70
        elif state == "warning":
            score -= 10
        score -= min(30, len(set(warnings)) * 5)
        score -= min(40, len(set(blocking)) * 10)
        return {
            "state": state,
            "operatorScore": max(0, score),
            "blockingReasons": sorted(set(blocking)),
            "warnings": sorted(set(warnings)),
            "publishability": publishability,
        }

    def explain_publishability(
        self,
        rendered_asset_id: str,
        *,
        distribution_plan_id: str | None = None,
    ) -> dict[str, Any]:
        asset = self.rendered_asset(rendered_asset_id)
        latest_audit = self._latest_audit_for_asset(rendered_asset_id)
        plan = None
        if distribution_plan_id:
            row = self.conn.execute(
                "SELECT * FROM distribution_plans WHERE id = ?",
                (distribution_plan_id,),
            ).fetchone()
            if not row:
                raise ValueError(f"distribution plan not found: {distribution_plan_id}")
            plan = self._distribution_plan_payload(dict(row))
        return self._publishability_check(asset, latest_audit, distribution_plan=plan)

    def capture_publishability_rejection_evidence(self, rendered_asset_id: str) -> dict[str, Any]:
        result = self.explain_publishability(rendered_asset_id)
        return self._capture_publishability_rejection_evidence_from_result(rendered_asset_id, result, commit=True)

    def _capture_publishability_rejection_evidence_from_result(
        self,
        rendered_asset_id: str,
        result: dict[str, Any],
        *,
        commit: bool,
    ) -> dict[str, Any]:
        asset = self.rendered_asset(rendered_asset_id)
        now = utc_now()
        evidence_rows = [
            row for row in result.get("rejectionEvidence") or []
            if row.get("failedStage") == "discoverability_safety_pass"
        ]
        for row in evidence_rows:
            evidence_id = self._verification_id(
                "rejectev",
                rendered_asset_id,
                row.get("failedStage"),
                row.get("failureCategory"),
                row.get("matchedText"),
                row.get("sourceField"),
                row.get("policyVersion"),
            )
            self.conn.execute(
                """
                INSERT INTO asset_rejection_evidence
                (id, rendered_asset_id, source_asset_id, campaign_id, content_surface,
                 failed_stage, failure_category, matched_text, source_field, policy_version,
                 repairable, evidence_json, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(rendered_asset_id, failed_stage, failure_category, matched_text, source_field, policy_version)
                DO UPDATE SET
                  evidence_json = excluded.evidence_json,
                  updated_at = excluded.updated_at
                """,
                (
                    evidence_id,
                    rendered_asset_id,
                    asset.get("source_asset_id"),
                    asset.get("campaign_id"),
                    normalize_content_surface(asset.get("content_surface")),
                    row.get("failedStage"),
                    row.get("failureCategory"),
                    row.get("matchedText"),
                    row.get("sourceField"),
                    row.get("policyVersion"),
                    1 if row.get("repairable", True) else 0,
                    json.dumps(sanitize_for_storage(row), ensure_ascii=False, sort_keys=True),
                    now,
                    now,
                ),
            )
        if commit:
            self.conn.commit()
        captured_count = self.conn.execute(
            "SELECT COUNT(*) AS c FROM asset_rejection_evidence WHERE rendered_asset_id = ?",
            (rendered_asset_id,),
        ).fetchone()["c"]
        return {
            "schema": "campaign_factory.rejection_evidence_capture.v1",
            "renderedAssetId": rendered_asset_id,
            "failedStage": "discoverability_safety_pass" if evidence_rows else "",
            "capturedCount": int(captured_count or 0),
            "wouldWrite": True,
        }

    def _capture_discoverability_gate_rejection_evidence(
        self,
        *,
        gate_result: dict[str, Any],
        failed_stage: str,
        campaign_id: str | None = None,
        source_asset_id: str | None = None,
        rendered_asset_id: str | None = None,
        content_surface: str = "reel",
        commit: bool,
    ) -> dict[str, Any]:
        now = utc_now()
        evidence_rows = gate_result.get("violations") or []
        captured_ids: list[str] = []
        for row in evidence_rows:
            evidence = {
                **row,
                "failedStage": failed_stage,
                "gate": gate_result.get("gate"),
                "gateSchema": gate_result.get("schema"),
            }
            evidence_id = self._verification_id(
                "rejectev",
                rendered_asset_id or "",
                source_asset_id or "",
                campaign_id or "",
                failed_stage,
                row.get("failureCategory"),
                row.get("matchedText"),
                row.get("sourceField"),
                row.get("policyVersion"),
            )
            self.conn.execute(
                """
                INSERT INTO asset_rejection_evidence
                (id, rendered_asset_id, source_asset_id, campaign_id, content_surface,
                 failed_stage, failure_category, matched_text, source_field, policy_version,
                 repairable, evidence_json, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(id) DO UPDATE SET
                  evidence_json = excluded.evidence_json,
                  updated_at = excluded.updated_at
                """,
                (
                    evidence_id,
                    rendered_asset_id,
                    source_asset_id,
                    campaign_id,
                    normalize_content_surface(content_surface),
                    failed_stage,
                    row.get("failureCategory"),
                    row.get("matchedText"),
                    row.get("sourceField"),
                    row.get("policyVersion"),
                    1 if row.get("repairable", True) else 0,
                    json.dumps(sanitize_for_storage(evidence), ensure_ascii=False, sort_keys=True),
                    now,
                    now,
                ),
            )
            captured_ids.append(evidence_id)
        if commit:
            self.conn.commit()
        return {
            "schema": "campaign_factory.discoverability_gate_rejection_capture.v1",
            "failedStage": failed_stage if evidence_rows else "",
            "capturedCount": len(captured_ids),
            "evidenceIds": captured_ids,
            "wouldWrite": True,
        }

    def quarantine_asset(
        self,
        rendered_asset_id: str,
        *,
        reason: str,
        root_cause: str | None = None,
        blocking_reason: str | None = None,
        distribution_plan_id: str | None = None,
        threadsdash_post_id: str | None = None,
        created_by: str | None = None,
        metadata: dict[str, Any] | None = None,
        commit: bool = True,
    ) -> dict[str, Any]:
        asset = self.rendered_asset(rendered_asset_id)
        now = utc_now()
        quarantine_id = f"qasset_{hashlib.sha256(rendered_asset_id.encode('utf-8')).hexdigest()[:12]}"
        payload = sanitize_for_storage(metadata or {})
        self.conn.execute(
            """
            INSERT INTO quarantined_assets
            (id, campaign_id, rendered_asset_id, distribution_plan_id, threadsdash_post_id,
             reason, root_cause, blocking_reason, excluded_from_metrics, metadata_json,
             created_at, created_by)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?)
            ON CONFLICT(rendered_asset_id) DO UPDATE SET
              distribution_plan_id = COALESCE(excluded.distribution_plan_id, quarantined_assets.distribution_plan_id),
              threadsdash_post_id = COALESCE(excluded.threadsdash_post_id, quarantined_assets.threadsdash_post_id),
              reason = excluded.reason,
              root_cause = excluded.root_cause,
              blocking_reason = excluded.blocking_reason,
              excluded_from_metrics = 1,
              metadata_json = excluded.metadata_json,
              created_by = excluded.created_by
            """,
            (
                quarantine_id,
                asset["campaign_id"],
                rendered_asset_id,
                distribution_plan_id,
                threadsdash_post_id,
                reason,
                root_cause,
                blocking_reason or reason,
                json.dumps(payload, ensure_ascii=False, sort_keys=True),
                now,
                created_by,
            ),
        )
        self.record_event(
            "asset_quarantined",
            campaign_id=asset["campaign_id"],
            rendered_asset_id=rendered_asset_id,
            status="failure",
            message=f"Asset quarantined: {reason}",
            metadata={
                "reason": reason,
                "rootCause": root_cause,
                "blockingReason": blocking_reason or reason,
                "distributionPlanId": distribution_plan_id,
                "threadsdashPostId": threadsdash_post_id,
            },
            commit=False,
        )
        if commit:
            self.conn.commit()
        return self._active_quarantine_for_asset(rendered_asset_id) or {}

    def record_proof_run(
        self,
        *,
        campaign_id: str | None,
        rendered_asset_id: str,
        distribution_plan_id: str | None = None,
        threadsdash_draft_id: str | None = None,
        threadsdash_post_id: str | None = None,
        status: str = "started",
        current_state: str = "creative_approved",
        blocking_reason: str | None = None,
        root_cause: str | None = None,
        metrics_eligible: bool = False,
        metadata: dict[str, Any] | None = None,
        proof_run_id: str | None = None,
        commit: bool = True,
    ) -> dict[str, Any]:
        now = utc_now()
        key = proof_run_id or f"proof_{hashlib.sha256(':'.join(str(part or '') for part in (campaign_id, rendered_asset_id, distribution_plan_id, threadsdash_post_id)).encode('utf-8')).hexdigest()[:12]}"
        self.conn.execute(
            """
            INSERT INTO proof_runs
            (id, campaign_id, rendered_asset_id, distribution_plan_id, threadsdash_draft_id,
             threadsdash_post_id, status, current_state, blocking_reason, root_cause,
             metrics_eligible, metadata_json, started_at, completed_at, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
              distribution_plan_id = excluded.distribution_plan_id,
              threadsdash_draft_id = excluded.threadsdash_draft_id,
              threadsdash_post_id = excluded.threadsdash_post_id,
              status = excluded.status,
              current_state = excluded.current_state,
              blocking_reason = excluded.blocking_reason,
              root_cause = excluded.root_cause,
              metrics_eligible = excluded.metrics_eligible,
              metadata_json = excluded.metadata_json,
              completed_at = excluded.completed_at,
              updated_at = excluded.updated_at
            """,
            (
                key,
                campaign_id,
                rendered_asset_id,
                distribution_plan_id,
                threadsdash_draft_id,
                threadsdash_post_id,
                status,
                current_state,
                blocking_reason,
                root_cause,
                1 if metrics_eligible else 0,
                json.dumps(sanitize_for_storage(metadata or {}), ensure_ascii=False, sort_keys=True),
                now,
                now if status in {"passed", "failed", "complete", "completed"} else None,
                now,
                now,
            ),
        )
        if commit:
            self.conn.commit()
        row = self.conn.execute("SELECT * FROM proof_runs WHERE id = ?", (key,)).fetchone()
        return dict(row) if row else {}

    def _latest_audit_for_asset(self, rendered_asset_id: str) -> dict[str, Any] | None:
        row = self.conn.execute(
            "SELECT * FROM audit_reports WHERE rendered_asset_id = ? ORDER BY created_at DESC LIMIT 1",
            (rendered_asset_id,),
        ).fetchone()
        return self._audit_report_payload(dict(row)) if row else None

    def _active_quarantine_for_asset(self, rendered_asset_id: str) -> dict[str, Any] | None:
        row = self.conn.execute(
            "SELECT * FROM quarantined_assets WHERE rendered_asset_id = ? LIMIT 1",
            (rendered_asset_id,),
        ).fetchone()
        if not row:
            return None
        payload = dict(row)
        payload["metadata"] = json_load(payload.get("metadata_json"), {})
        return payload

    def _normalize_seconds(self, value: Any) -> float | None:
        if value is None or value == "":
            return None
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            return None
        if numeric < 0:
            return None
        return round(numeric, 3)

    def _first_metadata_value(self, payload: dict[str, Any], *keys: str) -> Any:
        for key in keys:
            value = payload.get(key)
            if value is not None and value != "":
                return value
        return None

    def _normalize_audio_segment(self, payload: Any) -> dict[str, Any] | None:
        if not isinstance(payload, dict):
            return None
        nested = payload.get("audio_segment") or payload.get("audioSegment")
        if isinstance(nested, dict):
            payload = {**payload, **nested}
        start_seconds = self._normalize_seconds(
            self._first_metadata_value(
                payload,
                "start_seconds",
                "startSeconds",
                "segment_start_seconds",
                "segmentStartSeconds",
                "audio_segment_start_seconds",
                "audioSegmentStartSeconds",
            )
        )
        if start_seconds is None:
            return None
        duration_seconds = self._normalize_seconds(
            self._first_metadata_value(
                payload,
                "duration_seconds",
                "durationSeconds",
                "segment_duration_seconds",
                "segmentDurationSeconds",
                "audio_segment_duration_seconds",
                "audioSegmentDurationSeconds",
            )
        )
        label = next(
            (
                str(value).strip()
                for value in (
                    payload.get("label"),
                    payload.get("segment_label"),
                    payload.get("segmentLabel"),
                    payload.get("audio_segment_label"),
                    payload.get("audioSegmentLabel"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        reason = next(
            (
                str(value).strip()
                for value in (
                    payload.get("reason"),
                    payload.get("segment_reason"),
                    payload.get("segmentReason"),
                    payload.get("audio_segment_reason"),
                    payload.get("audioSegmentReason"),
                    payload.get("selected_reason"),
                    payload.get("selectedReason"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        result: dict[str, Any] = {"start_seconds": start_seconds}
        if duration_seconds is not None:
            result["duration_seconds"] = duration_seconds
        if label:
            result["label"] = label
        if reason:
            result["reason"] = reason
        return result

    def _audio_segment_for_asset(self, audio_intent: dict[str, Any]) -> dict[str, Any] | None:
        if not isinstance(audio_intent, dict):
            return None
        selection = audio_intent.get("operator_selection") if isinstance(audio_intent.get("operator_selection"), dict) else {}
        for payload in (selection, audio_intent):
            normalized = self._normalize_audio_segment(payload)
            if normalized:
                return normalized
        return None

    def _normalize_cover_frame(self, payload: Any) -> dict[str, Any] | None:
        if not isinstance(payload, dict):
            return None
        nested = payload.get("cover_frame") or payload.get("coverFrame")
        if isinstance(nested, dict):
            payload = {**payload, **nested}
        seconds = self._normalize_seconds(
            self._first_metadata_value(
                payload,
                "seconds",
                "cover_frame_seconds",
                "coverFrameSeconds",
                "timestamp_seconds",
                "timestampSeconds",
                "time_seconds",
                "timeSeconds",
            )
        )
        if seconds is None:
            return None
        image_path = next(
            (
                str(value).strip()
                for value in (
                    payload.get("image_path"),
                    payload.get("imagePath"),
                    payload.get("cover_image_path"),
                    payload.get("coverImagePath"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        image_url = next(
            (
                str(value).strip()
                for value in (
                    payload.get("image_url"),
                    payload.get("imageUrl"),
                    payload.get("cover_image_url"),
                    payload.get("coverImageUrl"),
                    payload.get("cover_url"),
                    payload.get("coverUrl"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        image_hash = next(
            (
                str(value).strip()
                for value in (
                    payload.get("image_hash"),
                    payload.get("imageHash"),
                    payload.get("cover_image_hash"),
                    payload.get("coverImageHash"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        reason = next(
            (
                str(value).strip()
                for value in (
                    payload.get("reason"),
                    payload.get("cover_frame_reason"),
                    payload.get("coverFrameReason"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        result: dict[str, Any] = {"seconds": seconds}
        if image_path:
            result["image_path"] = image_path
        if image_url:
            result["image_url"] = image_url
        if image_hash:
            result["image_hash"] = image_hash
        if reason:
            result["reason"] = reason
        return result

    def _cover_frame_for_asset(self, asset: dict[str, Any], caption_context: dict[str, Any] | None = None) -> dict[str, Any] | None:
        caption_generation = asset.get("captionGeneration")
        if not isinstance(caption_generation, dict):
            caption_generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(caption_generation, dict):
            caption_generation = {}
        for payload in (caption_generation, caption_context or {}, asset):
            normalized = self._normalize_cover_frame(payload)
            if normalized:
                return normalized
        return None

    def _audio_selection_for_asset(self, asset: dict[str, Any]) -> tuple[dict[str, Any], str | None]:
        caption_generation = asset.get("captionGeneration")
        if not isinstance(caption_generation, dict):
            caption_generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(caption_generation, dict):
            caption_generation = {}
        audio_intent = caption_generation.get("audioIntent") or caption_generation.get("audio_intent") or {}
        if not isinstance(audio_intent, dict):
            return {}, None
        selection = audio_intent.get("operator_selection")
        if not isinstance(selection, dict):
            selection = {}
        audio_id = next(
            (
                str(value).strip()
                for value in (
                    selection.get("audio_id"),
                    selection.get("track_id"),
                    selection.get("platform_audio_id"),
                    selection.get("native_audio_id"),
                    selection.get("local_winner_audio_id"),
                    selection.get("platform_url"),
                    selection.get("native_audio_url"),
                )
                if isinstance(value, str) and value.strip()
            ),
            None,
        )
        return audio_intent, audio_id

    def _audio_intent_is_attached(self, audio_intent: dict[str, Any], audio_id: str | None) -> bool:
        status = str(audio_intent.get("status") or "").strip().lower()
        if status in {"skipped", "not_required"}:
            return True
        if status not in {"attached", "verified"} or not audio_id:
            return False
        selection = audio_intent.get("operator_selection") if isinstance(audio_intent.get("operator_selection"), dict) else {}
        selected_at = isinstance(selection.get("selected_at"), str) and bool(selection.get("selected_at").strip())
        final_key = "verified_at" if status == "verified" else "attached_at"
        final_at = isinstance(selection.get(final_key), str) and bool(selection.get(final_key).strip())
        return selected_at and final_at

    def _audio_intent_claims_embedded_media(self, audio_intent: dict[str, Any]) -> bool:
        selection = audio_intent.get("operator_selection") if isinstance(audio_intent.get("operator_selection"), dict) else {}
        probe_values = [
            audio_intent.get("source"),
            audio_intent.get("mode"),
            selection.get("source"),
            selection.get("selection_source"),
            selection.get("notes"),
            selection.get("selected_reason"),
        ]
        haystack = " ".join(str(value or "").lower() for value in probe_values)
        return "embedded" in haystack or "muxed" in haystack or "burned_audio" in haystack

    def _embedded_audio_verified(self, output_path: str) -> bool | None:
        if not output_path:
            return None
        path = Path(output_path)
        if path.suffix.lower() not in VIDEO_EXTS or not path.exists():
            return None
        metadata = probe_video_metadata(path)
        if not metadata.get("ok"):
            return None
        return bool(metadata.get("audioPresent"))

    def _verification_id(self, prefix: str, *parts: Any) -> str:
        digest = hashlib.sha256(":".join(str(part or "") for part in parts).encode("utf-8")).hexdigest()[:16]
        return f"{prefix}_{digest}"

    def _text_hash(self, value: str) -> str:
        normalized = " ".join((value or "").strip().lower().split())
        return hashlib.sha256(normalized.encode("utf-8")).hexdigest()

    def discoverability_safe_content_contract(self, *values: Any) -> dict[str, Any]:
        blocked_terms: list[dict[str, str]] = []
        seen: set[tuple[str, str]] = set()
        for value in values:
            if not isinstance(value, str) or not value.strip():
                continue
            for reason, pattern in DISCOVERABILITY_SAFE_CONTENT_PATTERNS:
                match = pattern.search(value)
                if not match:
                    continue
                key = (reason, match.group(0).lower())
                if key in seen:
                    continue
                seen.add(key)
                blocked_terms.append({
                    "reason": reason,
                    "matchedText": match.group(0),
                })
        return {
            "schema": "campaign_factory.discoverability_safe_content_contract.v1",
            "discoverabilitySafe": not blocked_terms,
            "blockedTerms": blocked_terms,
            "blockedReason": "discoverability_risk_link_dm_or_off_platform_reference" if blocked_terms else "",
            "wouldWrite": False,
        }

    def _reel_caption_account_safety_violations(self, *values: Any) -> list[dict[str, str]]:
        return list(self.discoverability_safe_content_contract(*values)["blockedTerms"])

    def _publishability_discoverability_fields(
        self,
        *,
        asset: dict[str, Any],
        caption_text: str,
        caption_context: dict[str, Any],
        post_caption: dict[str, Any],
    ) -> list[tuple[str, str]]:
        fields: list[tuple[str, str]] = []
        candidates = [
            ("asset_caption", asset.get("caption")),
            ("caption_text", caption_text),
            ("caption_context_caption_text", caption_context.get("caption_text")),
            ("burned_caption_text", post_caption.get("burned_caption_text") or caption_context.get("burned_caption_text")),
            ("instagram_post_caption", post_caption.get("instagram_post_caption") or caption_context.get("instagram_post_caption")),
            ("caption_cta", post_caption.get("caption_cta") or caption_context.get("caption_cta")),
        ]
        seen: set[tuple[str, str]] = set()
        for source_field, value in candidates:
            if not isinstance(value, str) or not value.strip():
                continue
            key = (source_field, value)
            if key in seen:
                continue
            seen.add(key)
            fields.append((source_field, value))
        return fields

    def _discoverability_evidence_for_fields(self, fields: list[tuple[str, str]]) -> list[dict[str, Any]]:
        evidence: list[dict[str, Any]] = []
        seen: set[tuple[str, str, str]] = set()
        for source_field, value in fields:
            if not isinstance(value, str) or not value.strip():
                continue
            for reason, pattern in DISCOVERABILITY_SAFE_CONTENT_PATTERNS:
                match = pattern.search(value)
                if not match:
                    continue
                matched = match.group(0)
                category = self._discoverability_loss_category(reason, matched)
                key = (source_field, category, matched.lower())
                if key in seen:
                    continue
                seen.add(key)
                evidence.append({
                    "failedStage": "discoverability_safety_pass",
                    "failureCategory": category,
                    "matchedText": matched,
                    "sourceField": source_field,
                    "policyVersion": "discoverability_safe_v1",
                    "repairable": True,
                    "reason": reason,
                    "preventableAt": self._discoverability_prevention_stage(category),
                    "wouldWrite": False,
                })
        return evidence

    def _instagram_post_caption_for_asset(
        self,
        asset: dict[str, Any],
        caption_context: dict[str, Any] | None,
        *,
        distribution_plan: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        caption_generation = asset.get("captionGeneration")
        if not isinstance(caption_generation, dict):
            caption_generation = json_load(asset.get("caption_generation_json"), {})
        if not isinstance(caption_generation, dict):
            caption_generation = {}
        source_records = [
            distribution_plan or {},
            caption_generation,
            caption_generation.get("instagramPostCaption") if isinstance(caption_generation.get("instagramPostCaption"), dict) else {},
            caption_generation.get("instagram_post_caption") if isinstance(caption_generation.get("instagram_post_caption"), dict) else {},
            caption_context or {},
            asset,
        ]
        post_caption = ""
        explicit_post_caption = False
        for record in source_records:
            if not isinstance(record, dict):
                continue
            for key in ("instagram_post_caption", "instagramPostCaption", "post_caption", "postCaption"):
                if key in record and isinstance(record.get(key), str):
                    post_caption = str(record.get(key) or "").strip()
                    explicit_post_caption = True
                    break
            if explicit_post_caption:
                break
        burned_caption = str(asset.get("caption") or (caption_context or {}).get("caption_text") or "").strip()
        caption_cta = next(
            (
                str(value).strip()
                for record in source_records
                if isinstance(record, dict)
                for value in (record.get("caption_cta"), record.get("captionCta"))
                if isinstance(value, str) and value.strip()
            ),
            "",
        )
        hashtags: list[str] = []
        for record in source_records:
            if not isinstance(record, dict):
                continue
            raw_tags = record.get("hashtags") or record.get("instagram_hashtags") or record.get("instagramHashtags")
            if not isinstance(raw_tags, list):
                continue
            for tag in raw_tags:
                if not isinstance(tag, str):
                    continue
                cleaned = re.sub(r"[^A-Za-z0-9_]", "", tag.strip().lstrip("#"))
                if cleaned and f"#{cleaned}" not in hashtags:
                    hashtags.append(f"#{cleaned}")
                if len(hashtags) >= 5:
                    break
            if len(hashtags) >= 5:
                break
        style = next(
            (
                str(value).strip()
                for record in source_records
                if isinstance(record, dict)
                for value in (record.get("post_caption_style"), record.get("postCaptionStyle"))
                if isinstance(value, str) and value.strip()
            ),
            "short_natural",
        )
        final_caption = post_caption
        if caption_cta and caption_cta.lower() not in final_caption.lower():
            final_caption = f"{final_caption}\n{caption_cta}".strip()
        missing_tags = [tag for tag in hashtags if tag.lower() not in final_caption.lower()]
        if missing_tags:
            final_caption = f"{final_caption}\n{' '.join(missing_tags)}".strip()
        return {
            "instagram_post_caption": final_caption,
            "instagram_post_caption_hash": self._text_hash(final_caption) if final_caption else None,
            "caption_cta": caption_cta or None,
            "hashtags": hashtags,
            "post_caption_style": style,
            "burned_caption_text": burned_caption,
            "burned_caption_hash": self._text_hash(burned_caption) if burned_caption else None,
        }

    def _instagram_post_caption_quality(self, post_caption: dict[str, Any]) -> dict[str, Any]:
        caption = str(post_caption.get("instagram_post_caption") or "").strip()
        burned = str(post_caption.get("burned_caption_text") or "").strip()
        hashtags = list(post_caption.get("hashtags") or [])
        reasons: list[str] = []
        if not caption:
            return {
                "passed": False,
                "reasons": ["blank_instagram_post_caption"],
                "policy": "simple_ig_post_caption_v1",
                "maxCharacters": 140,
                "maxLines": 3,
                "maxHashtags": 5,
            }
        lines = [line for line in caption.splitlines() if line.strip()]
        if len(caption) > 140:
            reasons.append("instagram_post_caption_too_long")
        if len(lines) > 3:
            reasons.append("instagram_post_caption_too_many_lines")
        if len(re.findall(r"#[A-Za-z0-9_]+", caption)) > 5 or len(hashtags) > 5:
            reasons.append("instagram_post_caption_too_many_hashtags")
        if re.search(r"https?://|www\.|link\s*in\s*bio|dm\s+me|message\s+me|text\s+me|telegram|whatsapp|onlyfans|fansly", caption, re.IGNORECASE):
            reasons.append("instagram_post_caption_platform_risk")
        caption_words = re.findall(r"[A-Za-z0-9']+", caption.lower())
        burned_words = re.findall(r"[A-Za-z0-9']+", burned.lower())
        if burned and caption.lower() == burned.lower() and len(burned_words) > 8:
            reasons.append("instagram_post_caption_copied_long_burned_caption")
        return {
            "passed": not reasons,
            "reasons": sorted(set(reasons)),
            "policy": "simple_ig_post_caption_v1",
            "maxCharacters": 140,
            "maxLines": 3,
            "maxHashtags": 5,
            "characterCount": len(caption),
            "lineCount": len(lines),
            "wordCount": len(caption_words),
            "hashtagCount": max(len(re.findall(r"#[A-Za-z0-9_]+", caption)), len(hashtags)),
        }

    def caption_quality_repair_plan(
        self,
        *,
        creator: str | None = None,
        campaign_slug: str | None = None,
        content_surface: str | None = None,
        limit: int = 200,
    ) -> dict[str, Any]:
        assets = self._surface_report_assets(creator=creator, campaign_slug=campaign_slug)
        if content_surface:
            normalized_surface = normalize_content_surface(content_surface)
            assets = [
                asset for asset in assets
                if normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface")) == normalized_surface
            ]
        candidates: list[dict[str, Any]] = []
        blocked_by_caption_quality = 0
        recoverable_by_caption_rewrite = 0
        recoverable_by_hashtag_trim = 0
        recoverable_by_cta_removal = 0
        unrecoverable = 0
        for asset in assets:
            surface = normalize_content_surface(asset.get("content_surface") or asset.get("source_content_surface"))
            if surface == "story":
                continue
            publishability = self.explain_publishability(str(asset["id"]))
            failure_reasons = list(publishability.get("publishability_failure_reasons") or [])
            if "instagram_post_caption_quality_failed" not in failure_reasons:
                continue
            blocked_by_caption_quality += 1
            non_caption_blockers = sorted(
                reason for reason in failure_reasons
                if reason not in {"instagram_post_caption_quality_failed", "unsafe_reel_caption_link_or_dm_reference"}
            )
            post_caption_quality = publishability.get("instagramPostCaptionQuality") if isinstance(publishability.get("instagramPostCaptionQuality"), dict) else {}
            quality_reasons = list(post_caption_quality.get("reasons") or [])
            current_caption = str(publishability.get("instagram_post_caption") or "")
            suggested_caption = self._suggest_simple_instagram_post_caption(
                asset_id=str(asset["id"]),
                current_caption=current_caption,
                burned_caption=str(publishability.get("burned_caption_text") or ""),
            )
            suggested_payload = {
                "instagram_post_caption": suggested_caption,
                "hashtags": [],
                "burned_caption_text": str(publishability.get("burned_caption_text") or ""),
            }
            suggested_quality = self._instagram_post_caption_quality(suggested_payload)
            discoverability_contract = self.discoverability_safe_content_contract(suggested_caption)
            would_pass = bool(suggested_quality.get("passed") and discoverability_contract.get("discoverabilitySafe") and not non_caption_blockers)
            recovery_class = self._caption_quality_recovery_class(quality_reasons)
            if non_caption_blockers:
                unrecoverable += 1
            elif recovery_class == "recoverableByHashtagTrim":
                recoverable_by_hashtag_trim += 1
            elif recovery_class == "recoverableByCTARemoval":
                recoverable_by_cta_removal += 1
            else:
                recoverable_by_caption_rewrite += 1
            if len(candidates) < max(1, int(limit or 200)):
                candidates.append({
                    "assetId": asset["id"],
                    "contentSurface": surface,
                    "currentCaption": current_caption,
                    "failureReasons": failure_reasons,
                    "qualityFailureReasons": quality_reasons,
                    "nonCaptionBlockers": non_caption_blockers,
                    "recoveryClass": "unrecoverable" if non_caption_blockers else recovery_class,
                    "suggestedInstagramPostCaption": suggested_caption,
                    "suggestedInstagramPostCaptionHash": self._text_hash(suggested_caption) if suggested_caption else "",
                    "suggestedCaptionQuality": suggested_quality,
                    "suggestedDiscoverabilitySafe": bool(discoverability_contract.get("discoverabilitySafe")),
                    "wouldPassQualityGate": would_pass,
                    "burnedCaptionText": publishability.get("burned_caption_text") or "",
                    "burnedCaptionHash": publishability.get("burned_caption_hash") or "",
                    "wouldWrite": False,
                })
        return {
            "schema": "campaign_factory.caption_quality_repair_plan.v1",
            "creator": creator,
            "campaign": campaign_slug,
            "contentSurface": normalize_content_surface(content_surface) if content_surface else "",
            "blockedByCaptionQuality": blocked_by_caption_quality,
            "recoverableByCaptionRewrite": recoverable_by_caption_rewrite,
            "recoverableByHashtagTrim": recoverable_by_hashtag_trim,
            "recoverableByCTARemoval": recoverable_by_cta_removal,
            "unrecoverable": unrecoverable,
            "replacementCandidates": candidates,
            "wouldWrite": False,
        }

    def _caption_quality_recovery_class(self, quality_reasons: list[str]) -> str:
        reason_set = set(quality_reasons)
        if reason_set and reason_set <= {"instagram_post_caption_too_many_hashtags", "instagram_post_caption_too_many_lines"}:
            return "recoverableByHashtagTrim"
        if "instagram_post_caption_platform_risk" in reason_set:
            return "recoverableByCTARemoval"
        return "recoverableByCaptionRewrite"

    def _suggest_simple_instagram_post_caption(self, *, asset_id: str, current_caption: str, burned_caption: str) -> str:
        start = int(hashlib.sha256(asset_id.encode("utf-8")).hexdigest()[:8], 16) % len(SIMPLE_INSTAGRAM_POST_CAPTION_REPAIR_POOL)
        current_normalized = " ".join(current_caption.lower().split())
        burned_normalized = " ".join(burned_caption.lower().split())
        for offset in range(len(SIMPLE_INSTAGRAM_POST_CAPTION_REPAIR_POOL)):
            suggestion = SIMPLE_INSTAGRAM_POST_CAPTION_REPAIR_POOL[(start + offset) % len(SIMPLE_INSTAGRAM_POST_CAPTION_REPAIR_POOL)]
            normalized = suggestion.lower()
            if normalized == current_normalized or normalized == burned_normalized:
                continue
            quality = self._instagram_post_caption_quality({
                "instagram_post_caption": suggestion,
                "hashtags": [],
                "burned_caption_text": burned_caption,
            })
            discoverability = self.discoverability_safe_content_contract(suggestion)
            if quality.get("passed") and discoverability.get("discoverabilitySafe"):
                return suggestion
        return SIMPLE_INSTAGRAM_POST_CAPTION_REPAIR_POOL[0]

    def _publishability_check(
        self,
        asset: dict[str, Any],
        latest_audit: dict[str, Any] | None = None,
        *,
        distribution_plan: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        caption_text = str(asset.get("caption") or "").strip()
        output_path = str(asset.get("campaign_path") or asset.get("output_path") or asset.get("filePath") or "")
        filename = str(asset.get("filename") or Path(output_path).name)
        sidecar = self._caption_lineage_sidecar(output_path)
        caption_context = load_context_json(asset.get("caption_outcome_context_json"))
        if not caption_context and isinstance(asset.get("captionOutcomeContext"), dict):
            caption_context = asset["captionOutcomeContext"]
        variant_lineage = self._variant_lineage_for_asset(asset["id"])
        if variant_lineage and isinstance(caption_context, dict):
            caption_context = {**caption_context, **variant_lineage}
        placement_policy = (caption_context or {}).get("captionPlacementPolicy")
        placement_decision = (caption_context or {}).get("captionPlacementDecision")
        placement_qc_passed = (
            placement_policy == "focal_safe_v1"
            and isinstance(placement_decision, dict)
            and placement_decision.get("status") == "passed"
        )
        render_recipe = (
            (caption_context or {}).get("render_recipe")
            or (sidecar.get("captionOutcomeContext") or {}).get("render_recipe")
            or sidecar.get("renderRecipe")
            or sidecar.get("recipe")
            or asset.get("recipe")
        )
        lower_hints = " ".join(str(value or "").lower() for value in (output_path, filename, render_recipe))
        quarantine = self._active_quarantine_for_asset(asset["id"])
        audio_intent, audio_id = self._audio_selection_for_asset(asset)
        audio_segment = self._audio_segment_for_asset(audio_intent)
        cover_frame = self._cover_frame_for_asset(asset, caption_context)
        post_caption = self._instagram_post_caption_for_asset(asset, caption_context, distribution_plan=distribution_plan)
        post_caption_quality = self._instagram_post_caption_quality(post_caption)
        trust_blockers, trust_statuses = self._content_trust_status_blockers(
            asset,
            latest_audit,
            caption_context if isinstance(caption_context, dict) else {},
        )
        asset_content_surface = normalize_content_surface(
            (distribution_plan or {}).get("contentSurface")
            or (distribution_plan or {}).get("content_surface")
            or asset.get("content_surface")
        )
        is_reel_surface = asset_content_surface == "reel"
        approved = asset.get("review_state") == "approved"
        caption_hash = asset.get("caption_hash") or (caption_context or {}).get("caption_hash")
        content_fingerprint = asset.get("content_hash") or asset.get("contentHash")
        readiness_blockers = list(((latest_audit or {}).get("readinessSummary") or {}).get("blockingReasons") or [])
        readiness_blockers.extend(((latest_audit or {}).get("readinessSummary") or {}).get("blockingCodes") or [])
        audit_warning_codes = set(((latest_audit or {}).get("readinessSummary") or {}).get("warningCodes") or [])
        audit_warning_codes.update(latest_audit.get("warnings") or [] if latest_audit else [])
        placement_warning_codes = sorted(audit_warning_codes & CAPTION_PLACEMENT_QC_WARNING_CODES)
        if placement_warning_codes:
            placement_qc_passed = False
        if (latest_audit or {}).get("overallVerdict") == "fail":
            readiness_blockers.append("contentforge_verdict_fail")
        embedded_audio_required = self._audio_intent_claims_embedded_media(audio_intent)
        embedded_audio_verified = self._embedded_audio_verified(output_path) if embedded_audio_required else None
        captioned_render_present = (bool(caption_text) and "passthrough" not in lower_hints) if is_reel_surface else bool(output_path)
        visible_caption_verification = captioned_render_present if is_reel_surface else True
        expected_visual_verification = "passthrough" not in lower_hints
        discoverability_fields = self._publishability_discoverability_fields(
            asset=asset,
            caption_text=caption_text,
            caption_context=caption_context if isinstance(caption_context, dict) else {},
            post_caption=post_caption,
        )
        discoverability_contract = self.discoverability_safe_content_contract(
            *(value for _, value in discoverability_fields)
        )
        discoverability_evidence = self._discoverability_evidence_for_fields(discoverability_fields)
        reel_caption_safety_violations = list(discoverability_contract["blockedTerms"]) if is_reel_surface else []
        burned_caption_quality_passed = self._reference_hook_is_schedule_safe(caption_text) if is_reel_surface else True
        checks = {
            "creative_approved": approved,
            "captioned_render_present": captioned_render_present,
            "visible_caption_verification": visible_caption_verification,
            "expected_visual_verification": expected_visual_verification,
            "content_fingerprint_present": bool(content_fingerprint),
            "caption_hash_present": bool(caption_hash),
            "captionOutcomeContext_present": bool(caption_context),
            "instagram_post_caption_present": bool(post_caption.get("instagram_post_caption")),
            "caption_placement_qc_passed": placement_qc_passed if is_reel_surface else True,
            "audio_assigned": self._audio_intent_is_attached(audio_intent, audio_id) if is_reel_surface else True,
            "embedded_audio_verified": embedded_audio_verified is not False,
            "reel_caption_account_safety_passed": not reel_caption_safety_violations,
            "burned_caption_quality_passed": burned_caption_quality_passed,
            "discoverability_safe": discoverability_contract["discoverabilitySafe"] if is_reel_surface else True,
            "instagram_post_caption_quality_passed": post_caption_quality["passed"] if asset_content_surface != "story" else True,
            "operator_visual_review_passed": not self._requires_operator_visual_review_for_handoff(asset) if is_reel_surface else True,
            "visual_qc_passed": trust_statuses["visualQcStatus"] == "passed",
            "identity_verification_passed": trust_statuses["identityVerificationStatus"] == "passed",
            "readiness_checks_pass": bool(latest_audit) and not readiness_blockers,
            "quarantine_clear": not bool(quarantine),
        }
        failures: list[str] = []
        warnings: list[str] = []
        if not approved:
            failures.append("not_approved")
        if not captioned_render_present:
            failures.append("missing_burned_captions")
        if asset_content_surface == "feed_single" and str(asset.get("media_type") or "").lower() != "image":
            failures.append("feed_single_requires_image")
        if not expected_visual_verification:
            failures.append("wrong_visual")
        if not content_fingerprint:
            failures.append("missing_content_fingerprint")
        if not caption_hash and asset_content_surface != "story":
            failures.append("missing_caption_hash")
        if not caption_context:
            failures.append("missing_caption_outcome_context")
        if not post_caption.get("instagram_post_caption") and asset_content_surface != "story":
            failures.append("missing_instagram_post_caption")
        if asset_content_surface != "story" and not post_caption_quality["passed"]:
            failures.append("instagram_post_caption_quality_failed")
        if is_reel_surface and not placement_qc_passed:
            failures.append("caption_placement_qc_failed")
        if is_reel_surface and not checks["audio_assigned"]:
            failures.append("missing_audio")
        if embedded_audio_verified is False:
            failures.append("embedded_audio_missing")
        if is_reel_surface and reel_caption_safety_violations:
            failures.append("unsafe_reel_caption_link_or_dm_reference")
        if is_reel_surface and caption_text and not burned_caption_quality_passed:
            failures.append("burned_caption_quality_failed")
        if is_reel_surface and not checks["operator_visual_review_passed"]:
            failures.append("operator_visual_review_required")
        failures.extend(trust_blockers)
        if not checks["readiness_checks_pass"]:
            failures.append("missing_audit" if not latest_audit else "readiness_failed")
        if quarantine:
            failures.append("quarantined_asset")
        failures = sorted(set(failures))
        asset_state = "publishable_candidate" if not failures else "approved_but_not_publishable"
        lifecycle_state = "publishable_candidate" if not failures else ("creative_approved" if approved else "rendered")
        root_cause = None
        if quarantine:
            root_cause = quarantine.get("root_cause")
        elif "missing_burned_captions" in failures or "wrong_visual" in failures:
            root_cause = "wrong_approved_asset"
        blocking_reason = failures[0] if failures else None
        manifest = None
        distribution_content_surface = normalize_content_surface((distribution_plan or {}).get("contentSurface") or (distribution_plan or {}).get("content_surface"))
        distribution_surface = _normalize_distribution_surface((distribution_plan or {}).get("surface")) if distribution_plan else None
        ig_media_type = self._ig_media_type_for_surface(distribution_content_surface, str(asset.get("media_type") or "video"))
        instagram_trial_reels = bool((distribution_plan or {}).get("instagramTrialReels") or (distribution_plan or {}).get("instagram_trial_reels"))
        trial_graduation_strategy = (distribution_plan or {}).get("trialGraduationStrategy") or (distribution_plan or {}).get("trial_graduation_strategy")
        if not failures and distribution_plan is not None:
            manifest = {
                "manifest_version": 2 if distribution_content_surface != "reel" else 1,
                "asset_id": asset["id"],
                "rendered_asset_id": asset["id"],
                "source_asset_id": asset.get("source_asset_id"),
                "render_file_id": self._verification_id("render_file", asset["id"], filename, content_fingerprint),
                "content_fingerprint": content_fingerprint,
                "content_hash": content_fingerprint,
                "caption_hash": caption_hash,
                "captionOutcomeContext": caption_context,
                "instagram_post_caption": post_caption["instagram_post_caption"],
                "instagramPostCaption": post_caption["instagram_post_caption"],
                "instagram_post_caption_hash": post_caption["instagram_post_caption_hash"],
                "caption_cta": post_caption["caption_cta"],
                "hashtags": post_caption["hashtags"],
                "post_caption_style": post_caption["post_caption_style"],
                "burned_caption_text": post_caption["burned_caption_text"],
                "burned_caption_hash": post_caption["burned_caption_hash"],
                "visualQcStatus": trust_statuses["visualQcStatus"],
                "identityVerificationStatus": trust_statuses["identityVerificationStatus"],
                "visualQc": {"status": trust_statuses["visualQcStatus"]},
                "identityVerification": {"status": trust_statuses["identityVerificationStatus"]},
                "visual_verification_id": self._verification_id("visual_verification", asset["id"], content_fingerprint, render_recipe),
                "caption_verification_id": self._verification_id("caption_verification", asset["id"], caption_hash, render_recipe),
                "audio_id": audio_id or "not_required",
                "distribution_plan_id": distribution_plan["id"],
                "content_surface": distribution_content_surface,
                "contentSurface": distribution_content_surface,
                "distribution_surface": distribution_surface,
                "ig_media_type": ig_media_type,
                "igMediaType": ig_media_type,
                "instagram_trial_reels": instagram_trial_reels,
                "trial_graduation_strategy": trial_graduation_strategy if instagram_trial_reels else None,
                "exported_by_system": "campaign_factory",
                "exported_at": utc_now(),
            }
            if distribution_content_surface != "reel":
                manifest["mediaItems"] = [{
                    "mediaPath": output_path,
                    "mediaHash": content_fingerprint,
                    "mediaType": str(asset.get("media_type") or "image").lower(),
                    "componentIndex": 0,
                }]
            if audio_segment:
                manifest["audio_segment"] = audio_segment
            if cover_frame:
                manifest["cover_frame"] = cover_frame
            if variant_lineage:
                manifest.update({
                    "concept_id": variant_lineage.get("concept_id"),
                    "parent_reel_id": variant_lineage.get("parent_reel_id"),
                    "parent_asset_id": variant_lineage.get("parent_asset_id"),
                    "variant_family_id": variant_lineage.get("variant_family_id"),
                    "variant_id": variant_lineage.get("variant_id"),
                    "variant_index": variant_lineage.get("variant_index"),
                    "variant_operations": variant_lineage.get("variant_operations"),
                })
            if isinstance(caption_context, dict):
                caption_family_id = caption_context.get("caption_family_id") or caption_context.get("captionFamilyId")
                caption_version_id = caption_context.get("caption_version_id") or caption_context.get("captionVersionId")
                if caption_family_id:
                    manifest["caption_family_id"] = caption_family_id
                if caption_version_id:
                    manifest["caption_version_id"] = caption_version_id
        return {
            "schema": "campaign_factory.publishability_check.v1",
            "decision": "pass" if not failures else "blocked",
            "asset_state": asset_state,
            "assetState": asset_state,
            "lifecycle_state": lifecycle_state,
            "publishableCandidate": not failures,
            "exportable": not failures and distribution_plan is not None and manifest is not None,
            "approved": approved,
            "captionedRenderPresent": captioned_render_present,
            "captioned_render_present": captioned_render_present,
            "visibleCaptionVerification": "heuristic_pass" if visible_caption_verification else "not_verified",
            "visible_caption_verification": visible_caption_verification,
            "expectedVisualVerification": "heuristic_pass" if expected_visual_verification else "failed",
            "expected_visual_verification": expected_visual_verification,
            "readinessChecksPass": checks["readiness_checks_pass"],
            "readiness_checks_pass": checks["readiness_checks_pass"],
            "renderRecipe": render_recipe,
            "mediaPath": output_path,
            "captionLineageSidecarPresent": bool(sidecar),
            "contentFingerprint": content_fingerprint,
            "content_fingerprint": content_fingerprint,
            "captionHash": caption_hash,
            "caption_hash": caption_hash,
            "captionOutcomeContext": caption_context,
            **post_caption,
            "instagramPostCaptionQuality": post_caption_quality,
            "instagram_post_caption_quality": post_caption_quality,
            "captionPlacementPolicy": placement_policy,
            "captionPlacementDecision": placement_decision,
            "discoverabilitySafe": discoverability_contract["discoverabilitySafe"] if is_reel_surface else True,
            "discoverabilityContract": discoverability_contract if is_reel_surface else {
                **discoverability_contract,
                "discoverabilitySafe": True,
                "blockedTerms": [],
                "blockedReason": "",
            },
            "rejectionEvidence": discoverability_evidence if is_reel_surface and reel_caption_safety_violations else [],
            "reelCaptionAccountSafetyViolations": reel_caption_safety_violations,
            "reel_caption_account_safety_violations": reel_caption_safety_violations,
            "burnedCaptionQualityPassed": burned_caption_quality_passed,
            "burned_caption_quality_passed": burned_caption_quality_passed,
            "visualQcStatus": trust_statuses["visualQcStatus"],
            "identityVerificationStatus": trust_statuses["identityVerificationStatus"],
            **variant_lineage,
            "audioIntent": audio_intent,
            "audio_id": audio_id,
            "audio_segment": audio_segment,
            "cover_frame": cover_frame,
            "checks": checks,
            "failureReasons": failures,
            "publishability_failure_reasons": failures,
            "blockingReasons": [f"publishability:{reason}" for reason in failures],
            "blockingReason": blocking_reason,
            "rootCause": root_cause,
            "nextOperatorAction": "replace_with_verified_captioned_asset" if root_cause == "wrong_approved_asset" else ("resolve_publishability_failures" if failures else "export_to_threadsdashboard"),
            "quarantine": quarantine,
            "metricsEligible": False,
            "metrics_eligible": False,
            "handoff_manifest": manifest,
            "contentSurface": distribution_content_surface if distribution_plan is not None else normalize_content_surface(asset.get("content_surface")),
            "content_surface": distribution_content_surface if distribution_plan is not None else normalize_content_surface(asset.get("content_surface")),
            "distributionSurface": distribution_surface,
            "distribution_surface": distribution_surface,
            "igMediaType": ig_media_type if distribution_plan is not None else self._ig_media_type_for_surface(normalize_content_surface(asset.get("content_surface")), str(asset.get("media_type") or "video")),
            "ig_media_type": ig_media_type if distribution_plan is not None else self._ig_media_type_for_surface(normalize_content_surface(asset.get("content_surface")), str(asset.get("media_type") or "video")),
            "instagramTrialReels": instagram_trial_reels,
            "instagram_trial_reels": instagram_trial_reels,
            "trialGraduationStrategy": trial_graduation_strategy if instagram_trial_reels else None,
            "trial_graduation_strategy": trial_graduation_strategy if instagram_trial_reels else None,
            "warnings": sorted(set(warnings)),
        }

    def _caption_lineage_sidecar(self, output_path: str) -> dict[str, Any]:
        if not output_path:
            return {}
        sidecar_path = Path(output_path + ".caption_lineage.json")
        if not sidecar_path.exists():
            return {}
        try:
            payload = json_load(sidecar_path.read_text(encoding="utf-8"), {})
        except OSError:
            return {}
        return payload if isinstance(payload, dict) else {}
